  function positionSlotTooltip(anchorEl, rectSnap) {
    const tip = getSlotTooltipEl();
    let r = null;
    if (
      rectSnap &&
      typeof rectSnap === "object" &&
      Number.isFinite(rectSnap.left) &&
      Number.isFinite(rectSnap.top) &&
      Number.isFinite(rectSnap.width) &&
      Number.isFinite(rectSnap.height)
    ) {
      r = rectSnap;
    } else if (anchorEl && anchorEl.isConnected && typeof anchorEl.getBoundingClientRect === "function") {
      r = anchorEl.getBoundingClientRect();
    } else {
      r = { left: 16, top: 16, right: 16, bottom: 16, width: 0, height: 0 };
    }
    const pad = 10;
    const tw = tip.offsetWidth || 320;
    const th = tip.offsetHeight || 200;
    let left = r.right + pad;
    if (left + tw > window.innerWidth - pad) left = r.left - tw - pad;
    if (left < pad) left = pad;
    let top = r.top + r.height / 2 - th / 2;
    const vh = window.innerHeight;
    const avail = Math.max(0, vh - 2 * pad);
    if (th <= avail) {
      top = clamp(top, pad, vh - th - pad);
    } else {
      top = pad;
    }
    tip.style.left = `${left}px`;
    tip.style.top = `${top}px`;
  }

  /**
   * Nudge **`#gp-slot-tooltip`** so it stays inside the viewport (** damage breakdown** swaps can grow tall while **`top`/`left` stay stale).
   */
  function clampGearPlannerTooltipInViewport(tipEl) {
    if (!tipEl || tipEl.hidden) return;
    const pad = 10;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const maxH = Math.max(96, vh - 2 * pad);

    for (let pass = 0; pass < 6; pass++) {
      let r = tipEl.getBoundingClientRect();
      if (!(r.width > 0 && r.height > 0)) return;

      if (r.height > maxH + 0.5) {
        tipEl.style.maxHeight = `${Math.floor(maxH)}px`;
        tipEl.style.overflowY = "auto";
        continue;
      }

      let dl = 0;
      let dt = 0;
      if (r.left < pad) dl = pad - r.left;
      else if (r.right > vw - pad) dl = vw - pad - r.right;
      if (r.top < pad) dt = pad - r.top;
      else if (r.bottom > vh - pad) dt = vh - pad - r.bottom;

      if (Math.abs(dl) < 0.5 && Math.abs(dt) < 0.5) break;

      const cs = window.getComputedStyle(tipEl);
      const curL = parseFloat(cs.left || "0") || 0;
      const curT = parseFloat(cs.top || "0") || 0;
      tipEl.style.left = `${curL + dl}px`;
      tipEl.style.top = `${curT + dt}px`;
    }
  }
