  /**
   * Default branch of `getAtbLevelScaling@19714` (`src/const/HAttributes.hx`): non-armor indices.
   * `level` is the **f64** passed from loot code — `generateItemAffixes` uses **iLevel / 10**.
   * Formula: `min * pow( pow(max/min, 1/(earlyMax-1)), level - 1 )`.
   * @param {number} min
   * @param {number} max
   * @param {number} level
   */
  function getAtbLevelScalingDefault(min, max, level) {
    const eps = 1e-10;
    if (min < eps || max === 0) return 0;
    const em = scalingParams.earlyMaxLevel;
    const denom = Math.max(em - 1, 1);
    const inner = Math.pow(max / min, 1 / denom);
    return min * Math.pow(inner, level - 1);
  }

  /** Bytecode `null` refs for armor aux → `-1` before `getResistanceLevelScaling` (`HAttributes.hx` ~15). */
