  /**
   * Item sheet **`level`** → planner tier clamp — used so picker cards / modal defaults match authored scaling instead of a
   * global **20** (CHAR_LEVEL_DEFAULT), which skewed **`lootCoordinateT`** vs regression tests (**11–16**).
   */
  function defaultGearPlannerTierForItem(item) {
    if (!item || item.level == null || !Number.isFinite(item.level)) return null;
    return lootScaleTier(Math.round(item.level));
  }

  /**
   * Craft templates use a fixed required level — no planner tier slider (`data.cdb` **`faction`: `"Craft"`**), or ids that
   * embed **`Craft`** (e.g. **`Finger_Z2RCraft_FerMP`**) when **`faction`** is missing from the extract.
   * **Weapons are never craft in this planner** (no fixed level / craft UI on weapon slots) even if **`faction`** or **`id`** suggest craft.
   */
  function itemFactionIsCraft(item) {
    if (!item) return false;
    if (item.type && weaponTypes.has(item.type)) return false;
    if (item.faction && String(item.faction).trim() === "Craft") return true;
    const id = item.id;
    return typeof id === "string" && /Craft/i.test(id);
  }

  /** Clamp slot **`ilvl`** to **`item.level`** for Craft faction gear (saved builds may carry an old slider value). */
  function enforceCraftFactionPlannerTiers() {
    for (let si = 0; si < SLOT_DEFS.length; si++) {
      const sd = SLOT_DEFS[si];
      const s = selection[sd.key];
      if (!s || !s.item || !itemFactionIsCraft(s.item)) continue;
      const fx = defaultGearPlannerTierForItem(s.item);
      if (fx != null) s.ilvl = fx;
    }
  }

  function iLevelBonusForRarity(rarityId) {
    const row = rarityById[rarityId || "Common"];
    const b = row && row.props && row.props.iLevelBonus;
    return typeof b === "number" ? b : 0;
  }

  /**
   * Loot coordinate **t** passed into `getAtbLevelScaling` / resistance helpers — same as
   * **`getBaseILevel(item) / 10`** (`HItem.hx`): `(requiredLevel × 10 + rarity.props.iLevelBonus) / 10`.
   * Planner slider is **required level**; Rare adds **+10** raw ilvl in shipped data.
   */
  /**
   * Loot coordinate **t** — optional **upgradeStars** adds raw ilvl per star (`Item_GearUpgradeILevelBonus`).
   */
  /**
   * @param {boolean} [flawless] — mirrors **`st.Item.getILevel`**: add **`round(Const.Items.Item_FlawlessILevelBonus)`** raw ilvl.
   */
  function lootCoordinateT(item, plannerRequiredTier, upgradeStars, flawless) {
    const tier = lootScaleTier(plannerRequiredTier);
    const bonus = iLevelBonusForRarity(item && item.rarity);
    const stars = clamp(Math.round(Number(upgradeStars) || 0), 0, 99);
    const starRaw = stars * scalingParams.gearUpgradeIlvelBonus;
    const flawRaw =
      flawless === true ? Math.round(Number(scalingParams.flawlessIlvlBonus) || 0) : 0;
    return (tier * 10 + bonus + starRaw + flawRaw) / 10;
  }

  /**
   * Raw **`iLevel`** integer (`×10` gear tier + rarity bonus + upgrade stars) — same numerator as **`lootCoordinateT × 10`**.
   * Compared in **`getItemAffixes@7543`** vs **`getILevel(kind)`**.
   */
  function rawIlvlFromPlannerSelection(item, plannerRequiredTier, upgradeStars, flawless) {
    const tier = lootScaleTier(plannerRequiredTier);
    const bonus = iLevelBonusForRarity(item && item.rarity);
    const stars = clamp(Math.round(Number(upgradeStars) || 0), 0, 99);
    const starRaw = stars * scalingParams.gearUpgradeIlvelBonus;
    const flawRaw =
      flawless === true ? Math.round(Number(scalingParams.flawlessIlvlBonus) || 0) : 0;
    return tier * 10 + bonus + starRaw + flawRaw;
  }

  /**
   * Mirrors **`getILevel@19783`** (`HItem.hx` ~261): template **`item.iLevel`** if set, else base ilvl from **`item.level`**.
   */
  function getILevelFromKind(item) {
    if (!item) return null;
    if (item.iLevel != null && Number.isFinite(item.iLevel)) return Math.round(item.iLevel);
    if (item.level != null && Number.isFinite(item.level)) {
      return rawIlvlFromPlannerSelection(item, Math.round(item.level), 0, false);
    }
    return null;
  }

  /**
   * Models **`Item.<field38>()`** in **`getItemAffixes@7543`** (`tools/hlbc-latest/_asm_getItemAffixes7543.txt`): same **`i32`** compared to **`getILevel@19783(kind)`**.
   * In **`st.Item`**, proto **`getILevel@7522`** (`tools/hlbc-latest/_item_hx_fns.txt`) returns runtime **`inf.iLevel`** (loot / upgrades).
   * The planner has no **`st.Item`** — we treat the required-level slider (+ rarity + ★) as that stored raw ilvl (**`generateItemAffixes@19789(inf, ilvl)`** second arg **reg1**).
   */
  function instanceRawIlvlFromPreview(sel, plannerTier) {
    const it = effectiveItem(sel);
    if (!it) return null;
    const stars = sel.stars != null ? sel.stars : 0;
    return rawIlvlFromPlannerSelection(it, plannerTier, stars, !!(sel && sel.flawless));
  }

  /**
   * **`getItemAffixes@7543`**: **`getILevel(kind) == Item.getILevel()`** → **`getDescriptions@19689`**; else **`generateItemAffixes@19789`**.
   * **`getDescriptions`** reads **`HAffixes.affixDescriptionPerSource`** filled by **`bakeAffixes@19684`** from **`item.affixes`** rows (`registerAffixDesc(EItem(id), …)`).
   */
  function shouldUseStaticAffixDescriptions(sel, plannerTier) {
    const kindIlvl = getILevelFromKind(sel && sel.item);
    const instIlvl = instanceRawIlvlFromPreview(sel, plannerTier);
    return kindIlvl != null && instIlvl != null && kindIlvl === instIlvl;
  }

  /** Global gear curve **G** at coordinate **t** (first `getAtbLevelScaling` in `generateItemAffixes`). */
  function gearCurveGFromT(t) {
    return getAtbLevelScaling19714(
      0,
      t,
      scalingParams.gearBoundsMin,
      scalingParams.gearBoundsMax,
      null,
      null
    );
  }

  /** **t** for scaling exported affix rows: explicit `iLevel` wins; else `level` + rarity bonus; else current preview. Never applies flawless — authored **`item.affixes`** are keyed to template tier only (`bakeAffixes`). */
  function referenceCurveT(item, plannerTier, sel) {
    const stars = sel && sel.stars ? sel.stars : 0;
    if (item.iLevel != null && Number.isFinite(item.iLevel)) return item.iLevel / 10;
    if (item.level != null && Number.isFinite(item.level))
      return lootCoordinateT(item, Math.round(item.level), stars, false);
    return lootCoordinateT(item, plannerTier, stars, false);
  }

  function maxUpgradeStarsForRarity(rarityId) {
    const r = rarityRank(rarityId || "Common");
    return MAX_UPGRADE_STARS_BY_RANK[Math.min(r, MAX_UPGRADE_STARS_BY_RANK.length - 1)];
  }

  /** Effective rarity: optional raise above template rarity for scaling (weapons). */
  function effectiveItemRarity(sel) {
    const base = sel && sel.item && sel.item.rarity;
    const ov = sel && sel.rarityOverride;
    if (!base) return ov || "Common";
    if (!ov || RARITY_ORDER.indexOf(ov) < 0) return base;
    return rarityRank(ov) >= rarityRank(base) ? ov : base;
  }

  /** Item payload with rarity override applied (reference only — clone when mutating). */
  function effectiveItem(sel) {
    const it = sel && sel.item;
    if (!it) return null;
    const r = effectiveItemRarity(sel);
    if (r === it.rarity) return it;
    return { ...it, rarity: r };
  }

  /**
   * Template item with optional **`rarityOverride`** (tests / API) — same rules as **`effectiveItemRarity`**
   * (override must be **≥** sheet rarity; invalid values are ignored).
   */
  function resolveSimulationItem(baseItem, opts) {
    if (!baseItem) return null;
    const ov = opts && opts.rarityOverride;
    if (ov == null || ov === "") return baseItem;
    const eff = effectiveItemRarity({ item: baseItem, rarityOverride: ov });
    if (eff === baseItem.rarity) return baseItem;
    return { ...baseItem, rarity: eff };
  }

  function slotEnchantCategory(slotKey) {
    if (slotKey === "gloves") return "AugmentEnchantHands";
    if (slotKey === "boots") return "AugmentEnchantFeet";
    if (slotKey === "mainHand" || slotKey === "offHand" || slotKey === "arsenal") {
      return "AugmentEnchantWeapon";
    }
    return null;
  }

  const AUGMENT_VENDOR_TYPE_IDS = ["AugmentBlacksmith", "AugmentJeweller", "AugmentOutfitter"];

  /** `itemType.props.augmentTargets[].itemType` for **`AugmentBlacksmith`** / **`AugmentJeweller`** / **`AugmentOutfitter`** (CastleDB). */
  function augmentTargetItemTypesForVendor(vendorRootId) {
    const row = itemTypeRowsById && itemTypeRowsById[vendorRootId];
    const at = row && row.props && row.props.augmentTargets;
    if (!Array.isArray(at)) return [];
    const out = [];
    for (let i = 0; i < at.length; i++) {
      const ref = at[i] && at[i].itemType;
      if (typeof ref === "string" && ref) out.push(ref);
    }
    return out;
  }

  /**
   * Gear **`itemType`** refs this slot accepts — **`SLOT_DEFS.types`** for armor/jewelry, else **`itemTypeAncestorIds`** for weapons.
   * Matched against vendor **`augmentTargets`** (e.g. plate → **Chest** only, embroidery → **Back**, gems → **GearFinger** / **GearNeck**).
   */
  function plannerSlotGearTargetRefs(slotKey, equippedItem) {
    const sd = SLOT_DEFS.find((s) => s.key === slotKey);
    if (!sd) return [];
    if (sd.types && sd.types.length) return sd.types.slice();
    if (sd.weaponSlot && equippedItem && equippedItem.type) {
      return itemTypeAncestorIds(equippedItem.type);
    }
    return [];
  }

  /** Crafted augment vendors whose **`augmentTargets`** intersect this slot’s gear types. */
  function slotAugmentVendorRoots(slotKey, equippedItem) {
    const slotRefs = new Set(plannerSlotGearTargetRefs(slotKey, equippedItem));
    if (!slotRefs.size) return [];
    const out = [];
    for (let i = 0; i < AUGMENT_VENDOR_TYPE_IDS.length; i++) {
      const vid = AUGMENT_VENDOR_TYPE_IDS[i];
      const targets = augmentTargetItemTypesForVendor(vid);
      if (targets.some((t) => slotRefs.has(t))) out.push(vid);
    }
    return out;
  }

  function augmentItemById(id) {
    if (!id || !itemById[id]) return null;
    const it = itemById[id];
    const ancestors = itemTypeAncestorIds(it.type);
    for (let i = 0; i < AUGMENT_VENDOR_TYPE_IDS.length; i++) {
      if (ancestors.includes(AUGMENT_VENDOR_TYPE_IDS[i])) return it;
    }
    return null;
  }

  function augmentItemsForSlot(slotKey, equippedItem) {
    const roots = slotAugmentVendorRoots(slotKey, equippedItem);
    if (!roots.length) return [];
    return itemLines
      .filter((r) => {
        const anc = itemTypeAncestorIds(r.type);
        return roots.some((root) => anc.includes(root));
      })
      .filter((r) => itemHasDisplayName(r))
      .sort(sortItemsByRarityDescThenId);
  }

  /** First matching vendor **`itemType`** root — used for modal **`optgroup`** labels. */
  function primaryAugmentVendorRoot(item) {
    if (!item || !item.type) return null;
    const anc = itemTypeAncestorIds(item.type);
    for (let i = 0; i < AUGMENT_VENDOR_TYPE_IDS.length; i++) {
      const id = AUGMENT_VENDOR_TYPE_IDS[i];
      if (anc.includes(id)) return id;
    }
    return null;
  }

  function augmentVendorShortLabel(rootId) {
    switch (rootId) {
      case "AugmentBlacksmith":
        return "Blacksmith";
      case "AugmentJeweller":
        return "Jeweller";
      case "AugmentOutfitter":
        return "Outfitter";
      default:
        return "Augment";
    }
  }

  function enchantItemById(id) {
    if (!id || !itemById[id]) return null;
    const it = itemById[id];
    const ancestors = itemTypeAncestorIds(it.type);
    if (
      ancestors.includes("AugmentEnchantHands") ||
      ancestors.includes("AugmentEnchantFeet") ||
      ancestors.includes("AugmentEnchantWeapon")
    ) {
      return it;
    }
    return null;
  }

  /** Modal picker preview HTML for enchant scrolls and crafted augments — same **`flatEnchantContribution`** path as tooltips. */
  function plannerModifierPreviewHtml(modItem, slotDef) {
    if (!modItem) return `<span class="gp-augment-pick__empty">No preview</span>`;
    const flats = flatEnchantContribution(modItem, slotDef, { displayOnly: true });
    mergeEnchantSkillStatusPreviewFlats(flats, modItem);
    const formatted = formatSimulatedStatLines(flats);
    const statHtml = previewPlainLinesAsHtml(formatted);
    const skillLines = [];
    for (const row of modItem.skills || []) {
      const sid = row && row.skill;
      if (typeof sid !== "string") continue;
      const sk = skillById[sid];
      const nm = sk ? skillDisplayName(sk) || sid : sid;
      skillLines.push(`<div class="gp-augment-pick__skill">${escapeHtml(nm)}</div>`);
    }
    const skillWrap =
      skillLines.length > 0
        ? `<div class="gp-augment-pick__skills">${skillLines.join("")}</div>`
        : "";
    if (!statHtml && !skillWrap) {
      return `<span class="gp-augment-pick__empty">No preview</span>`;
    }
    return statHtml + skillWrap;
  }

  /** Localized **`itemType`** label for the enchant category active on this slot (Hands / Feet / Weapon). */
  function enchantSlotSectionLabel(slotKey) {
    const cat = slotEnchantCategory(slotKey);
    if (!cat) return "Enchantment";
    const row = itemTypeRowsById && itemTypeRowsById[cat];
    const n = row && row.texts && row.texts.name;
    if (n && typeof n === "object" && n.v != null) return String(n.v);
    if (typeof n === "string") return n;
    return cat;
  }

  /**
   * @param {{ displayOnly?: boolean }} [opts] — when **`displayOnly`**, omit rows with **`displayed: false`** (tooltip parity).
   */
  function flatEnchantContribution(enchantItem, slotDef, opts) {
    const out = {};
    if (!enchantItem) return out;
    const affixFactor = affixFactorForWeaponSlotDef(slotDef);
    const displayOnly = !!(opts && opts.displayOnly);
    for (const ax of enchantItem.affixes || []) {
      if (ax.ref !== "TAttribute_Flat") continue;
      if (displayOnly && !affixRowDisplayed(ax)) continue;
      const attr = ax.target && ax.target.attribute;
      if (!attr || typeof ax.val !== "number") continue;
      out[attr] =
        (out[attr] || 0) + presentationFlatForAffixFactor(ax.val, affixFactor);
    }
    return out;
  }

  function mergeEnchantTotals(into, enchantItem, slotDef) {
    const add = flatEnchantContribution(enchantItem, slotDef);
    for (const k of Object.keys(add)) {
      into[k] = (into[k] || 0) + add[k];
    }
  }

  function enchantSkillStatusPreviewFlatTotals(enchantItem) {
    const totals = {};
    if (!enchantItem || !Array.isArray(enchantItem.skills)) return totals;
    for (let i = 0; i < enchantItem.skills.length; i++) {
      const sid = enchantItem.skills[i] && enchantItem.skills[i].skill;
      if (typeof sid !== "string" || !sid) continue;
      const host = skillById[sid];
      if (!host) continue;
      const refs = new Set();
      collectStatusRefIdsFromHostSkill(host, refs);
      if (skillIsPreviewableStackingStatusBuff(host)) refs.add(sid);
      for (const stId of refs) {
        const st = skillById[stId];
        if (!st) continue;
        const stacks = statusPreviewSheetAffixStacks(st);
        if (stacks <= 0) continue;
        const attrs = collectTalentFlatAffixAttributeOrder(st);
        for (let ai = 0; ai < attrs.length; ai++) {
          const attr = attrs[ai];
          const per = statusPreviewFlatPerStackAtGrantorRank(st, attr, 1);
          if (!per) continue;
          totals[attr] = (totals[attr] || 0) + per * stacks;
        }
      }
    }
    return totals;
  }

  function mergeEnchantSkillStatusPreviewFlats(into, enchantItem) {
    const add = enchantSkillStatusPreviewFlatTotals(enchantItem);
    for (const k of Object.keys(add)) {
      into[k] = (into[k] || 0) + add[k];
    }
  }

  function sortItemsByRarityDescThenId(a, b) {
    const dr = rarityRank(b.rarity) - rarityRank(a.rarity);
    if (dr !== 0) return dr;
    return String(a.id).localeCompare(String(b.id));
  }

  /**
   * @deprecated prefer `lootCoordinateT` / `gearCurveGFromT`
   */
  function gearStatRatioAtTier(plannerTier) {
    const fake = { rarity: "Common" };
    return gearCurveGFromT(lootCoordinateT(fake, plannerTier));
  }

  /** @deprecated */
  function gearStatRatioAtIlvl(plannerTier) {
    return gearStatRatioAtTier(plannerTier);
  }

  /**
   * `getResistanceLevelScaling@19713` — used when curve attribute is Armor / MagicArmor.
   * Bytecode: `aux * (a + b * level) / (1 - aux)` with **level** = loot **t**.
   */
  function getResistanceLevelScaling(aux, level) {
    if (aux == null || aux < 0 || aux >= 1) return 0;
    const { a, b } = resistanceParams;
    return (aux * (a + b * level)) / (1 - aux);
  }

  function rarityRank(r) {
    const i = RARITY_ORDER.indexOf(r || "Common");
    return i >= 0 ? i : 0;
  }

  /** `generateItemAffixes` asm ~158–205: `conds.minRarity` index vs item rarity; optional `factions` vs `item.faction`. */
  function aptitudeRowPassesFilters(row, item) {
    const c = row.conds || {};
    if (c.minRarity && rarityRank(item.rarity) < rarityRank(c.minRarity)) return false;
    if (Array.isArray(c.factions) && c.factions.length) {
      const fac = item.faction;
      if (!fac) return false;
      if (!c.factions.some((x) => x.ref === fac)) return false;
    }
    return true;
  }

  /**
   * Weapon skill **flat** aptitude rows: **Craft**-faction weapons often have **`faction: "Craft"`**, which fails
   * **`conds.factions`** on aptitude scaling — never gate those rows by faction for this path (still honor **`minRarity`**).
   */
  function aptitudeRowPassesFiltersWeaponSkill(row, item) {
    const c = row.conds || {};
    if (c.minRarity && rarityRank(item.rarity) < rarityRank(c.minRarity)) return false;
    if (itemFactionIsCraft(item)) return true;
    if (Array.isArray(c.factions) && c.factions.length) {
      const fac = item.faction;
      if (!fac) return false;
      if (!c.factions.some((x) => x.ref === fac)) return false;
    }
    return true;
  }

  function statGroupBucket(statGroup) {
    switch (statGroup) {
      case 0:
        return "primary";
      case 1:
        return "vitality";
      case 2:
        return "armor";
      case 3:
        return "ratings";
      default:
        return "primary";
    }
  }

  /** Merge `atbRatio` like runtime, including rarity overrides on `primary` / `vitality`. */
  function mergedAtbRatioForItemAndRarity(typeId, rarity) {
    const chain = itemTypeChainRows(typeId);
    const merged = {};
    const rar = rarity || "Common";
    for (let i = chain.length - 1; i >= 0; i--) {
      const row = chain[i];
      const ar = row.atbRatio;
      if (ar && typeof ar === "object") {
        for (const k of Object.keys(ar)) {
          const v = ar[k];
          if (typeof v === "number" && Number.isFinite(v)) merged[k] = v;
        }
      }
      const props = row.props;
      const rr = props && Array.isArray(props.rarities) ? props.rarities : null;
      if (rr) {
        const hit = rr.find((x) => x.rarity === rar);
        if (hit && hit.atbRatio && typeof hit.atbRatio === "object") {
          for (const k of Object.keys(hit.atbRatio)) {
            if (k !== "primary" && k !== "vitality") continue;
            const v = hit.atbRatio[k];
            if (typeof v === "number" && Number.isFinite(v)) merged[k] = v;
          }
        }
      }
    }
    return merged;
  }

  /** Average aptitude `props.armorReduction` — passed as `aux` to armor scaling (see `HItem.hx` / fn 19789). */
  function avgArmorReduction(item) {
    const apts = item.aptitudes || [];
    if (!apts.length) return 0;
    let sum = 0;
    let n = 0;
    for (const ap of apts) {
      const row = aptitudeById[ap.ref];
      const ar = row && row.props && typeof row.props.armorReduction === "number" ? row.props.armorReduction : null;
      if (ar != null) {
        sum += ar;
        n++;
      }
    }
    return n > 0 ? sum / n : 0;
  }

  /**
   * Aptitude **`atbScaling`** rows with **`endAtb === attrId`** for **`getExpectedAttributeAtAptitudesLevel@19718`**
   * (weapon skill flat). Uses **`aptitudeRowPassesFilters`** only — not affix-only **`atbScalingRowDroppedInGenerateItemAffixesDump`**.
   * @returns {object[]}
   */
  function collectAtbScalingRowsForWeaponSkillExpected(item, attrId) {
    const out = [];
    if (!item || typeof attrId !== "string" || !attrId) return out;
    for (const ap of item.aptitudes || []) {
      const arow = aptitudeById[ap.ref];
      if (!arow || !Array.isArray(arow.atbScaling)) continue;
      for (const row of arow.atbScaling) {
        if (!aptitudeRowPassesFiltersWeaponSkill(row, item)) continue;
        if (row.endAtb !== attrId) continue;
        if (row.start == null || row.end == null) continue;
        out.push(row);
      }
    }
    return out;
  }

  /**
   * Expected **`attrId`** from weapon aptitudes (averaged **`start`/`end`**, **`getAtbLevelScaling19714`**).
   * **`curveLevel`** is the **`level`** float into **`getAtbLevelScaling`** — bytecode **`getExpectedAttributeAtAptitudesLevel@19718`**
   * receives **`Item.level`** from **`getStepEffectItemScaling@19821`** (required level), not **`lootCoordinateT`**. When **`curveLevel`** is omitted, falls back to
   * CDB **`item.level`** (often a low authored minimum — wrong for upgraded previews).
   */
  function expectedAttributeForWeaponSkillFlat(item, attrId, curveLevel) {
    const rows = collectAtbScalingRowsForWeaponSkillExpected(item, attrId);
    if (!rows.length) return 0;
    const idx = attributeIndexById[attrId];
    if (idx === undefined) return 0;
    const levelL =
      curveLevel != null && Number.isFinite(curveLevel)
        ? Number(curveLevel)
        : item.level != null && Number.isFinite(item.level)
          ? Number(item.level)
          : 1;
    let sumS = 0;
    let sumE = 0;
    for (let i = 0; i < rows.length; i++) {
      sumS += rows[i].start;
      sumE += rows[i].end;
    }
    const n = rows.length;
    const avgS = sumS / n;
    const avgE = sumE / n;
    const armorAux = avgArmorReduction(item);
    return getAtbLevelScaling19714(idx, levelL, avgS, avgE, armorAux, armorAux);
  }

  /**
   * @param {string} slotKey `mainHand` | `offHand` | `arsenal`
   * @returns {object} shallow copy of **`combatCtx`** with **`weaponPowerPreview`** for **`computeEffectDamagePreview`**.
   * **`getStepEffectItemScaling@19821`** passes **`Item.level`** (required level, float) into **`getExpectedAttributeAtAptitudesLevel@19718`** —
   * not **`getILevel / 10`**, not rarity ilvl bonus, not upgrade-star raw ilvl (**`lootCoordinateT`** is for **`generateItemAffixes`**-style curves).
   * Both **`aptitudeCurveLevel`** and **`aptitudeCurveLevelTooltip`** use **`lootScaleTier(ilvl)`** so combat flat matches that bytecode path
   * (planner **`ilvl`** = slot required-level preview; CDB **`item.level`** is the same notion on templates).
   */
  function combatCtxWithWeaponSlotPower(combatCtx, slotKey) {
    if (!combatCtx || !slotKey) return combatCtx;
    const sel = selection[slotKey];
    const it = sel && effectiveItem(sel);
    if (!it) return combatCtx;
    const charLevel = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const classId = combatCtx.classId || plannerSelectedClassId();
    const sd = SLOT_DEFS.find((s) => s.key === slotKey);
    if (sd && !slotSelectionIsActive(sd, sel, classId, charLevel, selection)) return combatCtx;
    const plannerTier = sel.ilvl != null && Number.isFinite(sel.ilvl) ? sel.ilvl : charLevel;
    const tierClamped = lootScaleTier(plannerTier);
    const aptitudeCurveLevel = tierClamped;
    const aptitudeCurveLevelTooltip = tierClamped;
    return Object.assign({}, combatCtx, {
      weaponPowerPreview: {
        item: it,
        weaponPowerRatio: scalingParams.mainhandWeaponSkill,
        slotKey,
        aptitudeCurveLevel,
        aptitudeCurveLevelTooltip,
      },
    });
  }

  /**
   * Divisor before final `math_round` on affix values (`generateItemAffixes`).
   * When curve attribute equals display attribute (`reg24 == reg26`), bytecode skips SDiv — treat as **1**.
   * Otherwise use `scaling[]` on the **curve** row (e.g. MaxHealth → Vitality scale **3**).
   */
  function flatScaleForGearLine(displayAttrId, curveEndAtb) {
    if (displayAttrId === curveEndAtb) return 1;
    const src = attributeById[curveEndAtb];
    if (!src || !Array.isArray(src.scaling)) return 1;
    const hit = src.scaling.find((e) => e.attribute === displayAttrId);
    return hit && typeof hit.scale === "number" ? hit.scale : 1;
  }

  function displayNameForAttr(attrId) {
    const row = attributeById[attrId];
    if (!row) return attrId;
    const n = row.name;
    if (typeof n === "string" && n.trim()) return n;
    return attrId;
  }

  /**
   * `[Bracket]` tokens in skill `texts.desc`: **`attribute`** id → **`attribute.name`**, **`gameTerm`** (`WeaponSkill`),
   * **`item`** id → **`texts.name`** (e.g. **`[RefillableFlask]`** → Hess'tuss Flask), **`skill`** id → skill name.
   * Data uses sheet **`id`** strings inside **`[]`** for terminology links.
   */
  function displayNameForSkillDescBracket(id) {
    if (!id || typeof id !== "string") return "";
    const t = id.trim();
    if (!t) return "";
    const row = attributeById[t];
    if (row) {
      const n = row.name;
      if (typeof n === "string" && n.trim()) return n.trim();
    }
    const gt = gameTermById[t];
    const tx = gt && gt.texts;
    if (tx) {
      let nm = tx.name;
      if (nm && typeof nm === "object" && nm.v != null) nm = String(nm.v);
      if (typeof nm === "string" && nm.trim()) return nm.trim();
    }
    const it = itemById[t];
    if (it) {
      const nm = itemDisplayName(it);
      if (typeof nm === "string" && nm.trim()) return nm.trim();
    }
    const skRow = skillById[t];
    if (skRow) {
      const nm = skillDisplayName(skRow);
      if (typeof nm === "string" && nm.trim()) return nm.trim();
    }
    const tl = t.toLowerCase();
    for (const attrId in attributeById) {
      const r = attributeById[attrId];
      const n = r && r.name;
      if (typeof n === "string" && n.trim() && n.trim().toLowerCase() === tl) return n.trim();
    }
    return t;
  }

  /**
   * Matches `TipItem.init` (`Tooltip.hx` ~464): the client runs `makeAfxDescTextsComparisons` only when the definition item
   * type is **`Gear`** (or inherits it) **or** **`Augment`** (enchant scrolls inherit `Consumable` → `Augment`).
   */
  function itemTypeShowsGearAffixUi(typeId) {
    if (!typeId || typeof typeId !== "string") return false;
    const ids = itemTypeAncestorIds(typeId);
    return ids.includes("Gear") || ids.includes("Augment");
  }

  function normalizeAffixSheetDesc(d) {
    if (d == null) return "";
    if (typeof d === "string") return d;
    if (typeof d === "object" && d.v != null) return String(d.v);
    return "";
  }

  function attributeUsesPercentSheetFlag(attrId) {
    const row = attributeById[attrId];
    return !!(row && typeof row.flags === "number" && (row.flags & ATTR_FLAG_PERCENT) !== 0);
  }

  /** Fallback when an `affix.desc` template still has unknown `::tokens::` — matches legacy `formatAffixLine` numerics. */
  function legacyAffixLineNumeric(ref, v, attrDisplayName) {
    const label = attrDisplayName || "";
    if (ref === "TAttribute_Flat") {
      const vs = Math.abs(v) >= 10 ? v.toFixed(0) : v.toFixed(1).replace(/\.0$/, "");
      return `${v >= 0 ? "+" : ""}${vs} ${label}`.trim();
    }
    if (ref === "TAttribute_ARatio") {
      return `+${(v * 100).toFixed(1).replace(/\.0$/, "")}% ${label}`.trim();
    }
    if (ref === "TAttribute_MRatio") {
      return `×${v.toFixed(3)} ${label}`.trim();
    }
    const vs = Math.abs(v) >= 10 ? v.toFixed(0) : v.toFixed(1).replace(/\.0$/, "");
    return `${v >= 0 ? "+" : ""}${vs} ${label}`.trim();
  }

  function buildGearAffixTokenMap(ax, ref, v, attrDisplayName) {
    const target = attrDisplayName || "";
    const m = { target };
    if (ref === "TAttribute_Flat") {
      const abs = Math.abs(v);
      const vs = abs >= 10 ? v.toFixed(0) : v.toFixed(1).replace(/\.0$/, "");
      const signed = (v >= 0 ? "+" : "") + vs;
      m.s_atb_value = signed;
      m.s_value = signed;
    } else if (ref === "TAttribute_ARatio") {
      const p = (v * 100).toFixed(1).replace(/\.0$/, "");
      m.s_percent_value = `+${p}%`;
    } else if (ref === "TAttribute_MRatio") {
      m.percent = `×${v.toFixed(3)}`;
    } else {
      m.s_atb_value = (v >= 0 ? "+" : "") + String(Math.round(v * 1000) / 1000);
      if (typeof ref === "string" && ref.indexOf("ARatio") >= 0 && ref.indexOf("MRatio") < 0) {
        const p = (v * 100).toFixed(1).replace(/\.0$/, "");
        m.s_percent_value = `+${p}%`;
      }
    }
    return m;
  }

  function expandBracketLabelsInAffixDesc(s) {
    if (!s || typeof s !== "string") return "";
    return s.replace(/\[(.+?)\]/g, (_, inner) => displayNameForSkillDescBracket(inner));
  }

  function expandGearAffixDescTemplate(desc, tokenMap) {
    if (!desc || typeof desc !== "string") return "";
    let out = desc;
    const keys = Object.keys(tokenMap).sort((a, b) => b.length - a.length);
    for (let i = 0; i < keys.length; i++) {
      const k = keys[i];
      const val = tokenMap[k];
      if (val == null) continue;
      out = out.split(`::${k}::`).join(String(val));
    }
    return expandBracketLabelsInAffixDesc(out).trim();
  }

  /** Map simulated sheet totals to ratio units for `TAttribute_ARatio` (`Percent` attributes store percent points in some paths). */
  function simulatedRatioForPercentAttribute(attrId, n) {
    if (Math.abs(n) >= 1 || (n !== 0 && Number.isInteger(n))) return n / 100;
    return n;
  }

  /**
   * Filters aptitude rows excluded in `generateItemAffixes` (`_asm_generateItemAffixes.txt` ~142–157).
   * **`HItem.hx` ~345–352:** the **`rarity.id === Common`** branch (`reg4.id` vs **`global@2512`**, ~142–144) runs two continues:
   * **`statGroup === 1`** and **`1 >= aptitudes.length`** is false when multiple aptitudes (~146–151) → skip row; and
   * **`statGroup === 0`** and **`aptitudes.length === 1`** (~152–157) → skip row.
   * If **`rarity.id !== Common`**, control jumps past both (~144 → ~164), so **non-Common** items keep **`statGroup` 1** rows on
   * dual-aptitude gear (e.g. Rare **`Finger_Z2RCraft_FerMP`** Vitality).
   */
  function atbScalingRowDroppedInGenerateItemAffixesDump(row, item) {
    if (!row || !item) return false;
    const aptN = Array.isArray(item.aptitudes) ? item.aptitudes.length : 0;
    const sg = typeof row.statGroup === "number" ? row.statGroup : -1;
    const isCommon = (item.rarity || "Common") === "Common";
    if (isCommon && sg === 1 && aptN > 1) return true;
    if (!isCommon) return false;
    if (sg === 0 && aptN === 1) return true;
    return false;
  }

  /**
   * Collect aptitude `atbScaling` rows for `generateItemAffixes`. **`generateItemAffixes@19789`** loops **`item.aptitudes`** with no
   * hero-class filter — hybrid gear rolls **every** aptitude’s scaling (e.g. **Fighter** + **Wizard** → Strength and Intellect both).
   * Do **not** subset **`statGroup` 0** by planner **`viewerClassId`**; that broke parity vs tooltips on shared / hybrid pieces.
   * @param {{ viewerClassId?: string }} [opts] reserved (simulation does not filter aptitudes by viewer)
   */
  function collectAtbScalingRowsForItem(item, opts) {
    const out = [];
    for (const ap of item.aptitudes || []) {
      const aptitudeRef = ap.ref;
      const arow = aptitudeById[aptitudeRef];
      if (!arow || !Array.isArray(arow.atbScaling)) continue;
      for (const row of arow.atbScaling) {
        if (!aptitudeRowPassesFilters(row, item)) continue;
        if (atbScalingRowDroppedInGenerateItemAffixesDump(row, item)) continue;
        if (row.start == null || row.end == null) continue;
        if (!row.endAtb || attributeIndexById[row.endAtb] === undefined) continue;

        out.push(Object.assign({ _aptitudeRef: aptitudeRef }, row));
      }
    }
    return out;
  }

  /**
   * Whole-number gear lines from aptitude scaling match **`generateItemAffixes@19789`**: **`math_round@18131`** on the pipeline value
   * (`_asm_generateItemAffixes.txt` ~397–398, ~448–509), not attribute-flag rounding.
   */
  function integerGearFlat(_displayAttrId, x) {
    return Math.round(x);
  }

  /**
   * Tooltip gate from `getItemAffixes@7543`: **`displayed == null` → shown**; only explicit **`false`** hides a line.
   */
  function affixRowDisplayed(ax) {
    return ax == null || ax.displayed !== false;
  }

  /**
   * Mirrors `makeAfxDescTextsComparisons@19985` / `HText.hx` ~1602: when **`affixFactor !== 1`**, display magnitude is
   * **`max(1, floor(raw * factor))`** on the rolled value; factor **`1`** keeps normal rounding.
   */
  function presentationFlatForAffixFactor(raw, affixFactor) {
    const f =
      typeof affixFactor === "number" && Number.isFinite(affixFactor) ? affixFactor : 1;
    if (f === 1) {
      if (typeof raw === "number" && Number.isFinite(raw) && Math.abs(raw) < 1 && raw !== Math.round(raw)) {
        return raw;
      }
      return Math.round(raw);
    }
    if (raw <= 0) return Math.floor(raw * f + 1e-9);
    return Math.max(1, Math.floor(raw * f + 1e-9));
  }

  /**
   * **`getAffixFactor@9343`**: item types expose **`slot.affixFactor`** on slot defs (e.g. **`Slot_Weapon2`** arsenal = **0.4**).
   */
  function affixFactorForWeaponSlotDef(slotDef) {
    if (!slotDef || !slotDef.weaponSlot || slotDef.weaponRole !== "arsenal") return 1;
    const row = itemTypeRowsById && itemTypeRowsById.Slot_Weapon2;
    const slot = row && row.slot;
    if (slot && typeof slot.affixFactor === "number" && Number.isFinite(slot.affixFactor)) {
      return slot.affixFactor;
    }
    return scalingParams.arsenalStatMultiplier;
  }

  /**
   * Simulated flat totals: see `atbScalingRowDroppedInGenerateItemAffixesDump` + `collectAtbScalingRowsForItem` for what
   * is reproduced from `_asm_generateItemAffixes.txt`. Tooltip **`displayed`** / **`affixFactor`** are applied in **`affixPreviewLines`** (see `GEAR_STATS_PIPELINE.md`).
   *
   * Group by **`endAtb`**, one **`getAtbLevelScaling19714`** on averaged bounds, **× n** row factor, **× G** when any row is not
   * **`gearOnly`**, **÷ aptitudes**, **`math_round`**, rarity bucket ratio, **`flatScaleForGearLine`**. Weapon extras: **`mergeWeaponUpgradeSpecialFlats`**. Then **`applyGearStatPresentationStage`** (parity approach: **`tools/hlbc-latest/GEAR_STATS_PIPELINE.md`**).
   * @param {{ stars?: number, weaponSlot?: boolean, viewerClassId?: string, flawless?: boolean, rarityOverride?: string|null, omitWeaponUpgradeExtraFlats?: boolean }} [opts] — when **`omitWeaponUpgradeExtraFlats`**, skip **`mergeWeaponUpgradeSpecialFlats`** so **`weaponUpgradeBonusPreviewLines`** can show the bonus without duplicating the same stats (preview / tooltip only).
   */
  function simulateFlatTotals(baseItem, plannerTier, opts) {
    const out = {};
    const item = resolveSimulationItem(baseItem, opts);
    if (!item || !item.type) return out;

    const stars = opts && opts.stars ? clamp(Math.round(opts.stars), 0, 99) : 0;
    const flawless = !!(opts && opts.flawless);
    const weaponSlot = !!(opts && opts.weaponSlot);

    const ratios = mergedAtbRatioForItemAndRarity(item.type, item.rarity);
    const aptList = item.aptitudes || [];
    const aptN = Math.max(aptList.length, 1);
    const armorAux = avgArmorReduction(item);

    const rows = collectAtbScalingRowsForItem(item, opts);
    const byEnd = new Map();
    for (const row of rows) {
      const k = row.endAtb;
      if (!byEnd.has(k)) byEnd.set(k, []);
      byEnd.get(k).push(row);
    }

    const tCurve = lootCoordinateT(item, plannerTier, stars, flawless);
    const G = gearCurveGFromT(tCurve);

    for (const [, group] of byEnd) {
      if (!group.length) continue;
      const n = group.length;
      let sumS = 0;
      let sumE = 0;
      for (let i = 0; i < n; i++) {
        sumS += group[i].start;
        sumE += group[i].end;
      }
      const avgS = sumS / n;
      const avgE = sumE / n;
      const first = group[0];
      const endAtb = first.endAtb;

      const curveIdx = attributeIndexById[endAtb];
      if (curveIdx === undefined) continue;
      /* Dual refs in bytecode: Armor vs MagicArmor aux; planner uses merged `armorReduction` for both until item data exposes separate magic aux. */
      const core = getAtbLevelScaling19714(curveIdx, tCurve, avgS, avgE, armorAux, armorAux);

      let s = core;
      /**
       * **`generateItemAffixes`** (~368–371): **`reg54 *= reg32`** (`gearCurveGFromT`) when **`!gearOnly`** for that scaling row.
       * Grouping is by **`endAtb`** — use **`some(!gearOnly)`**: if the first row is **`gearOnly`** (e.g. ratings) but another row in the same
       * group is not, **`first.gearOnly`** would wrongly skip **× G**. (Duplicate **`gearOnly: false`** rows: literal asm multiplies **G**
       * per iteration; shipped tooltip totals for dual-aptitude vitality match **one** **× G** here — see **`GEAR_STATS_PIPELINE.md`**.)
       */
      if (group.some((r) => !r.gearOnly)) s *= G;
      /**
       * **`reg54 /= item.aptitudes.length`** (~397–284); map emission adds **`reg54`** per row → planner **`× n`** with averaged **`core`**.
       */
        s /= aptN;

      if (Math.round(s) <= 0) continue;

      const bucket = statGroupBucket(
        typeof first.statGroup === "number" && Number.isFinite(first.statGroup) ? first.statGroup : -1
      );
      const r = ratios[bucket];
      if (!(typeof r === "number" && r > 0)) continue;

      const rowDistMul = n;
      const rawMul = s * r * rowDistMul;
      const displayKey = first.sourceAtb || first.endAtb;
      const sc = flatScaleForGearLine(displayKey, endAtb);
      const shown = integerGearFlat(displayKey, rawMul / sc);

      if (shown !== 0) {
        out[displayKey] = (out[displayKey] || 0) + shown;
      }
    }

    if (!(opts && opts.omitWeaponUpgradeExtraFlats)) {
      mergeWeaponUpgradeSpecialFlats(out, item, stars, weaponSlot);
    }

    return applyGearStatPresentationStage(out, item, plannerTier, opts);
  }

  /**
   * Rarity **rank** for `{type}_Upgrade` **`affixes[].conds`** (`minRank` / `maxRank`).
   * Sheet brackets are **Common = 1 … Legendary = 5**, but **Rare/Epic/Legendary** map to **minRank 2 / 3 / 4**
   * (not 3 / 4 / 5): rank equals rarity index for Rare+, and **`index + 1`** for Common/Uncommon only — see **`Staff_Upgrade`**
   * in **`data.cdb`** (`minRank`/`maxRank` pairs **2–5** for extra ★★★ stats).
   */
  function weaponRarityRankForUpgradeConds(rarityId) {
    const i = RARITY_ORDER.indexOf(rarityId || "Common");
    if (i < 0) return 1;
    if (i <= 1) return i + 1;
    return i;
  }

  /** Whether **`conds`** matches this weapon rarity rank (sheet rules on `{type}_Upgrade` affixes). */
  function gearUpgradeAffixMatchesRank(conds, rank) {
    if (!conds || typeof conds !== "object") return true;
    const minR = conds.minRank != null ? conds.minRank : 1;
    const maxR =
      conds.maxRank != null ? conds.maxRank : conds.minRank != null ? conds.minRank : 5;
    return rank >= minR && rank <= maxR;
  }

  function matchingGearUpgradeAffixRows(skillRow, rank) {
    const list = skillRow && skillRow.affixes;
    if (!Array.isArray(list)) return [];
    return list.filter((ax) => gearUpgradeAffixMatchesRank(ax && ax.conds, rank));
  }

  /** Merge **`vars`** with the best matching **`props.rankOverride`** tier for this rarity rank. */
  function mergeGearUpgradeRankVars(skillRow, rank) {
    const out = { ...(skillRow.vars || {}) };
    const ov = skillRow.props && skillRow.props.rankOverride;
    if (!Array.isArray(ov)) return out;
    let best = null;
    let bestMin = -1;
    for (let i = 0; i < ov.length; i++) {
      const row = ov[i];
      if (!row || typeof row.minRank !== "number" || !row.vars) continue;
      if (rank >= row.minRank && row.minRank > bestMin) {
        bestMin = row.minRank;
        best = row.vars;
      }
    }
    if (best) Object.assign(out, best);
    return out;
  }

  /**
   * Resolve **`texts.desc`** on `{type}_Upgrade` skills: **`::val1%::`** from matching affix **`val`** (ordered),
   * other **`::name::`** / **`::name%::`** from merged **`vars`** (after rank override).
   */
  function resolveGearUpgradeSkillDesc(skillRow, rank) {
    let desc = skillRow.texts && skillRow.texts.desc;
    if (desc != null && typeof desc === "object" && desc.v != null) desc = String(desc.v);
    if (!desc || typeof desc !== "string") return "";
    desc = expandBracketLabelsInAffixDesc(desc);
    const mergedVars = mergeGearUpgradeRankVars(skillRow, rank);
    const matchedAff = matchingGearUpgradeAffixRows(skillRow, rank);
    const valByIndex = {};
    let vi = 1;
    for (let i = 0; i < matchedAff.length; i++) {
      const ax = matchedAff[i];
      if (typeof ax.val === "number" && Number.isFinite(ax.val)) valByIndex[vi++] = ax.val;
    }
    return desc.replace(/::([^:]+)::/g, (_, inner) => {
      const pct = inner.endsWith("%");
      const name = pct ? inner.slice(0, -1) : inner;
      let raw;
      if (/^val\d+$/.test(name)) raw = valByIndex[parseInt(name.slice(3), 10)];
      else raw = mergedVars[name];
      if (!Number.isFinite(raw)) return `::${inner}::`;
      if (pct) {
        const n = raw > 0 && raw <= 1 ? Math.round(raw * 100) : Math.round(raw);
        return `${n}%`;
      }
      if (raw > 0 && raw <= 1 && /^(chance|damage)$/i.test(name)) return `${Math.round(raw * 100)}%`;
      return String(raw);
    });
  }

  /**
   * Loads **`skill`** row **`{item.type}_Upgrade`** (`Staff_Upgrade`, …): **`affixes`** rows per rarity rank,
   * **`texts.desc`** tokens resolved from those vals + **`vars`** / **`rankOverride`**.
   */
  function weaponUpgradeTierFromSkillSheet(item, rarityId) {
    if (!item || !item.type || !skillById) return null;
    const sk = skillById[`${item.type}_Upgrade`];
    if (!sk) return null;
    const rank = weaponRarityRankForUpgradeConds(rarityId || item.rarity || "Common");
    const extraFlat = {};
    const matched = matchingGearUpgradeAffixRows(sk, rank);
    for (let i = 0; i < matched.length; i++) {
      const ax = matched[i];
      if (!ax || ax.ref !== "TAttribute_Flat") continue;
      const attr = ax.target && ax.target.attribute;
      if (!attr || typeof ax.val !== "number" || !Number.isFinite(ax.val)) continue;
      extraFlat[attr] = (extraFlat[attr] || 0) + ax.val;
    }
    const bonusTexts = [];
    const line = resolveGearUpgradeSkillDesc(sk, rank).trim();
    if (line) bonusTexts.push(line);
    if (!bonusTexts.length && !Object.keys(extraFlat).length) return null;
    return { minStars: 3, extraFlat, bonusTexts };
  }

  /**
   * ★★★+ weapon bonuses: primary source **`skill`** **`{type}_Upgrade`** in `data.cdb`; then **`WEAPON_UPGRADE_SPECIAL`**,
   * then family fallback **`WEAPON_UPGRADE_FAMILY`**.
   */
  function weaponUpgradeTierForItem(item, rarity) {
    if (!item) return null;
    const rare = rarity || item.rarity || "Common";
    const byId = WEAPON_UPGRADE_SPECIAL[item.id];
    if (byId && byId[rare]) return byId[rare];
    const fromSkill = weaponUpgradeTierFromSkillSheet(item, rare);
    if (fromSkill) return fromSkill;
    const famKey = WEAPON_TYPE_UPGRADE_FAMILY[item.type];
    const fam = famKey ? WEAPON_UPGRADE_FAMILY[famKey] : null;
    if (fam && fam[rare]) return fam[rare];
    return null;
  }

  /** Primary attribute rolled from each hero aptitude’s first **`statGroup` 0** scaling row. */
  const HERO_APTITUDE_PRIMARY_ATTR = {
    Fighter: "Strength",
    Assassin: "Dexterity",
    Wizard: "Intellect",
    Cleric: "Faith",
  };

  /** Planner **`#gp-class`** ids → CDB aptitude **`ref`** for that hero. */
  function heroAptitudeRefForViewerClassId(viewerClassId) {
    switch (viewerClassId) {
      case "Warrior":
        return "Fighter";
      case "Rogue":
        return "Assassin";
      case "Mage":
        return "Wizard";
      case "Priest":
        return "Cleric";
      default:
        return null;
    }
  }

  /** True when **`item.aptitudes`** lists at least two hero-class refs (`Fighter`, `Assassin`, `Wizard`, `Cleric`). */
  function itemHasDualHeroClassAptitudes(item) {
    const apts = item && item.aptitudes;
    if (!Array.isArray(apts) || apts.length < 2) return false;
    const heroRefs = new Set(["Fighter", "Assassin", "Wizard", "Cleric"]);
    let n = 0;
    for (let i = 0; i < apts.length; i++) {
      const r = apts[i] && apts[i].ref;
      if (r && heroRefs.has(r)) n++;
    }
    return n >= 2;
  }

  /**
   * **Stage 2 — presentation / tooltip pipeline** (HashLink runtime after numeric affix generation).
   *
   * Documented in **`tools/hlbc-latest/GEAR_STATS_PIPELINE.md`**. Shipping bytecode wraps rows in
   * **`st.Item.getItemAffixes@7543`** (`_asm_getItemAffixes7543.txt`): maps `generateItemAffixes` output into affix DTOs
   * (`ref`, `val`, `conds`, `displayed`, …). Tooltip scaling (**`affixFactor`**, **`makeAfxDescTextsComparisons`**) and the
   * **`displayed`** gate are applied in **`affixPreviewLines`** / **`presentationFlatForAffixFactor`** instead of here.
   *
   * **`generateItemAffixes@19789`** (`_asm_generateItemAffixes.txt`) uses **`item.faction`** only when an aptitude
   * **`atbScaling`** row has **`conds.factions`**: compare **`reg0.faction`** to those refs (~**172–205**); rows with no faction
   * **`conds`** skip that loop and are eligible. There is **no** bytecode branch that drops aggregated **Vitality** based on
   * dual aptitudes vs **`item.faction`** — that logic lives in **`collectAtbScalingRowsForItem`** / **`aptitudeRowPassesFilters`**.
   *
   * Primary-line hiding below is **presentation-only** (tooltip parity heuristics), not part of **`generateItemAffixes`**.
   *
   * @param {Record<string, number>} totals from stage 1 (+ weapon ★ tables)
   * @returns {Record<string, number>}
   */
  function applyGearStatPresentationStage(totals, item, plannerTier, opts) {
    const out = { ...totals };
    if (!item) return out;

    const neutralFaction = !(item.faction && String(item.faction).trim());
    const viewer = opts && opts.viewerClassId;
    const heroRef = viewer ? heroAptitudeRefForViewerClassId(viewer) : null;
    const apts = item.aptitudes || [];
    if (
      neutralFaction &&
      heroRef &&
      apts.length === 1 &&
      apts[0] &&
      apts[0].ref === heroRef
    ) {
      const attr = HERO_APTITUDE_PRIMARY_ATTR[heroRef];
      if (attr && Object.prototype.hasOwnProperty.call(out, attr)) {
        delete out[attr];
      }
    }

    /* Neutral + dual hero aptitudes: no **Vitality** row on Nomad-style templates; faction gear keeps **`item.faction`** filtering + vitality (see **`CASES`** / bee raid rares). */
    if (neutralFaction && itemHasDualHeroClassAptitudes(item)) {
      delete out.Vitality;
    }

    return out;
  }

  /** Constant tables only; not in dumped `generateItemAffixes`. */
  function mergeWeaponUpgradeSpecialFlats(out, item, stars, weaponSlot) {
    if (!weaponSlot || stars < 1 || !item || !item.id) return;
    const tier = weaponUpgradeTierForItem(item, item.rarity || "Common");
    if (!tier || stars < (tier.minStars || 3)) return;
    const xf = tier.extraFlat;
    if (!xf || typeof xf !== "object") return;
    for (const k of Object.keys(xf)) {
      const v = xf[k];
      if (typeof v === "number" && Number.isFinite(v))
        out[k] = (out[k] || 0) + integerGearFlat(k, v);
    }
  }

  /** Display-only lines for weapon upgrade bonus text (after minStars). */
  function weaponUpgradeBonusPreviewLines(item, rarity, stars) {
    const lines = [];
    if (!item || stars < 1) return lines;
    const tier = weaponUpgradeTierForItem(item, rarity || item.rarity || "Common");
    if (!tier || stars < (tier.minStars || 3)) return lines;
    const texts = tier.bonusTexts || [];
    for (let i = 0; i < texts.length; i++) {
      lines.push(`Upgrade: ${texts[i]}`);
    }
    return lines;
  }

  /** @returns {string[]} Lines formatted like `HText.affix` — same `affix.desc` templates as the client (`::s_atb_value::`, …). */
  function formatSimulatedStatLines(totals) {
    const keys = Object.keys(totals).filter((k) => totals[k] !== 0);
    keys.sort((a, b) => {
      const ia = PREVIEW_ATTR_ORDER.indexOf(a);
      const ib = PREVIEW_ATTR_ORDER.indexOf(b);
      if (ia >= 0 && ib >= 0) return ia - ib;
      if (ia >= 0) return -1;
      if (ib >= 0) return 1;
      return displayNameForAttr(a).localeCompare(displayNameForAttr(b));
    });
    return keys.map((k) => {
      const n = totals[k];
      const label = displayNameForAttr(k);
      let ref = "TAttribute_Flat";
      let v = n;
      if (attributeUsesPercentSheetFlag(k)) {
        ref = "TAttribute_ARatio";
        v = simulatedRatioForPercentAttribute(k, n);
      }
      const def = affixDefById[ref];
      const rawDesc = def ? normalizeAffixSheetDesc(def.desc) : "";
      if (rawDesc && rawDesc.indexOf("::") >= 0) {
        const pseudoAx = { target: { attribute: k }, ref };
        const tokens = buildGearAffixTokenMap(pseudoAx, ref, v, label);
        let out = expandGearAffixDescTemplate(rawDesc, tokens);
        if (/::[a-zA-Z0-9_]+::/.test(out)) {
          out = legacyAffixLineNumeric(ref, v, label);
        }
        return out;
      }
      return legacyAffixLineNumeric(ref, v, label);
    });
  }

  /** Wrap leading signed number in `.gp-stat-val` for tooltip / modal card styling. */
  function formatPlainStatLineHtml(line) {
    const s = String(line);
    if (s.startsWith(GP_PREVIEW_TRINKET_SKILL_PREFIX)) {
      const sid = s.slice(GP_PREVIEW_TRINKET_SKILL_PREFIX.length);
      const sk = skillById[sid];
      const timing = sk ? skillTimingMetaTextJoined(sk) : "";
      const timingHtml = timing
        ? `<span class="gp-trinket-skill-cd">${escapeHtml(timing)}</span> `
        : "";
      const bodyHtml = sk ? skillDescHtmlForPreview(sk) : "";
      return `<div class="gp-stat-line">Equipped: ${timingHtml}${bodyHtml}</div>`;
    }
    const m = s.match(/^([+\-]?\d+(?:\.\d+)?)\s+(.+)$/);
    if (!m) return `<div class="gp-stat-line">${escapeHtml(s)}</div>`;
    return `<div class="gp-stat-line"><span class="gp-stat-val">${escapeHtml(m[1])}</span> <span class="gp-stat-lbl">${escapeHtml(
      m[2]
    )}</span></div>`;
  }

  function previewPlainLinesAsHtml(lines) {
    if (!lines.length) return "";
    return lines.map(formatPlainStatLineHtml).join("");
  }

  function loadPlannerDerivedTables(cdb) {
    aptitudeById = {};
    attributeById = {};
    attributeIndexById = {};
    rarityById = {};

    const aptSheet = sheetByName(cdb, "aptitude");
    if (aptSheet && aptSheet.lines) {
      for (const r of aptSheet.lines) {
        if (r.id) aptitudeById[r.id] = r;
      }
    }

    const attrSheet = sheetByName(cdb, "attribute");
    if (attrSheet && attrSheet.lines) {
      attrSheet.lines.forEach((r, i) => {
        if (r.id) {
          attributeById[r.id] = r;
          attributeIndexById[r.id] = i;
        }
      });
    }

    const rarSheet = sheetByName(cdb, "rarity");
    if (rarSheet && rarSheet.lines) {
      for (const r of rarSheet.lines) {
        if (r.id) rarityById[r.id] = r;
      }
    }

    affinityParentById = {};
    const affSheet = sheetByName(cdb, "affinity");
    if (affSheet && affSheet.lines) {
      for (const r of affSheet.lines) {
        if (!r || !r.id) continue;
        const p = r.parent;
        affinityParentById[r.id] = typeof p === "string" && p ? p : null;
      }
    }

    jobById = {};
    const jobSheet = sheetByName(cdb, "job");
    if (jobSheet && jobSheet.lines) {
      for (const r of jobSheet.lines) {
        if (r && r.id) jobById[r.id] = r;
      }
    }

    craftRecipeByItemId = {};
    const craftSheet = sheetByName(cdb, "craft");
    if (craftSheet && craftSheet.lines) {
      for (let ci = 0; ci < craftSheet.lines.length; ci++) {
        const row = craftSheet.lines[ci];
        if (!row || typeof row.item !== "string" || !row.item.trim()) continue;
        const iid = row.item.trim();
        const jobId = typeof row.job === "string" && row.job.trim() ? row.job.trim() : "";
        const lv = row.level;
        if (!jobId || lv == null || !Number.isFinite(Number(lv))) continue;
        craftRecipeByItemId[iid] = { job: jobId, level: Math.round(Number(lv)) };
      }
    }
  }

  /**
   * Same data bootstrap as **`main()`** after JSON load — no DOM. Used by **`tests/gear-item-attribute-display.mjs`**
   * via **`globalThis.__GEAR_PLANNER_TEST__`**.
   */
  function hydratePlannerFromCdb(cdb) {
    const itemSheet = sheetByName(cdb, "item");
    const itemTypeSheet = sheetByName(cdb, "itemType");
    unitSheet = sheetByName(cdb, "unit");
    if (!itemSheet || !itemTypeSheet || !unitSheet) {
      throw new Error("Missing required sheets (item, itemType, unit) in CDB.");
    }
    unitRowById = {};
    const uLines = unitSheet.lines || [];
    for (let ui = 0; ui < uLines.length; ui++) {
      const ur = uLines[ui];
      if (ur && ur.id) unitRowById[ur.id] = ur;
    }
    applyGearScalingConstantsFromCdb(cdb);
    loadPlannerDerivedTables(cdb);
    weaponTypes = buildWeaponTypes(itemSheet, itemTypeSheet);
    itemTypeRowsById = {};
    for (const r of itemTypeSheet.lines) {
      itemTypeRowsById[r.id] = r;
    }
    itemIdsShopSection = collectItemIdsUnderSeparatorTitle(itemSheet, "Shop");
    itemLines = itemSheet.lines.filter(
      (r) =>
        !["CraftingComponent", "Recipe", "Package", "Consumable"].includes(r.type) &&
        !itemIdsShopSection.has(r.id) &&
        !PLANNER_ITEM_ID_BLOCKLIST.has(r.id) &&
        !PLANNER_EXCLUDE_ITEM_FACTIONS.has(String(r.faction || "").trim())
    );
    itemById = {};
    for (let i = 0; i < itemLines.length; i++) {
      const r = itemLines[i];
      if (r && r.id) itemById[r.id] = r;
    }
    buildConsumableBuffCatalog(itemSheet.lines || []);
    const skillSheet = sheetByName(cdb, "skill");
    skillLines = skillSheet && skillSheet.lines ? skillSheet.lines : [];
    skillById = {};
    for (let i = 0; i < skillLines.length; i++) {
      const s = skillLines[i];
      if (s && s.id) skillById[s.id] = s;
    }
    const gameTermSheet = sheetByName(cdb, "gameTerm");
    gameTermById = {};
    if (gameTermSheet && gameTermSheet.lines) {
      for (let i = 0; i < gameTermSheet.lines.length; i++) {
        const r = gameTermSheet.lines[i];
        if (r && r.id) gameTermById[r.id] = r;
      }
    }

    const affixSheet = sheetByName(cdb, "affix");
    affixDefById = {};
    if (affixSheet && affixSheet.lines) {
      for (let i = 0; i < affixSheet.lines.length; i++) {
        const r = affixSheet.lines[i];
        if (r && r.id) affixDefById[r.id] = r;
      }
    }
  }

  function escapeHtml(s) {
    if (s == null || s === "") return "";
    return String(s)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  /** Weapon ★★★+ bonus prose (`Upgrade: …`) — same row style as stats; numeric **`%`** segments use **`gp-stat-val`** (green). */
  function formatWeaponUpgradePreviewLineHtml(rawLine) {
    const s = String(rawLine);
    const body = s.startsWith("Upgrade:") ? s.slice("Upgrade:".length).trim() : s;
    const parts = body.split(/(\d+(?:\.\d+)?%)/g);
    let html = "";
    for (let i = 0; i < parts.length; i++) {
      const p = parts[i];
      if (/^\d+(?:\.\d+)?%$/.test(p)) {
        html += `<span class="gp-stat-val">${escapeHtml(p)}</span>`;
      } else {
        html += escapeHtml(p);
      }
    }
    return `<div class="gp-stat-line">${html}</div>`;
  }

  /**
   * Unit sheet `levelScaling` endpoints use the same geometric curve as `getAtbLevelScaling@19714`
   * (`LevelScalingFormula_EarlyMaxLevel`), not linear interpolation between `[lo, hi]`.
   */
  function interpolatePrimary(lo, hi, charLevel) {
    const em = scalingParams.earlyMaxLevel;
    const lv = clamp(Math.round(charLevel), 1, em);
    return getAtbLevelScalingDefault(lo, hi, lv);
  }

  function ratingDivisorL(charLevel) {
    const em = scalingParams.earlyMaxLevel;
    const lv = clamp(Math.round(charLevel), 1, em);
    return getAtbLevelScalingDefault(RATING_MIN, RATING_MAX, lv);
  }

  function sheetByName(cdb, name) {
    return cdb.sheets.find((s) => s.name === name);
  }

  /**
   * Rows belonging to a sheet **separator** block whose **`title`** matches (e.g. **Shop**).
   * Each separator’s **`id`** is the first **`item`** row id in that block; the block runs until the next separator.
   */
  function collectItemIdsUnderSeparatorTitle(itemSheet, sectionTitle) {
    const lines = itemSheet.lines || [];
    const idToIndex = new Map();
    for (let li = 0; li < lines.length; li++) {
      const row = lines[li];
      if (row && row.id) idToIndex.set(row.id, li);
    }
    const seps = itemSheet.separators || [];
    const markers = [];
    for (let si = 0; si < seps.length; si++) {
      const sep = seps[si];
      if (!sep || typeof sep.id !== "string") continue;
      const ix = idToIndex.get(sep.id);
      if (ix === undefined) continue;
      markers.push({
        start: ix,
        title: sep.title != null ? String(sep.title) : "",
      });
    }
    markers.sort((a, b) => a.start - b.start);
    const out = new Set();
    for (let mi = 0; mi < markers.length; mi++) {
      if (markers[mi].title !== sectionTitle) continue;
      const end = mi + 1 < markers.length ? markers[mi + 1].start : lines.length;
      for (let j = markers[mi].start; j < end; j++) {
        const row = lines[j];
        if (row && row.id) out.add(row.id);
      }
    }
    return out;
  }

  function buildWeaponTypes(itemSheet, itemTypeSheet) {
    const byId = {};
    for (const r of itemTypeSheet.lines) byId[r.id] = r;

    function chain(tid) {
      const out = [];
      let cur = tid;
      while (cur) {
        out.push(cur);
        const row = byId[cur];
        if (!row) break;
        const inh = row.inherit;
        cur =
          typeof inh === "string"
            ? inh
            : Array.isArray(inh) && inh[0] && inh[0].ref
              ? inh[0].ref
              : null;
      }
      return out;
    }

    const roots = new Set([
      "Weapon",
      "MainhandWeapon",
      "OHWeapon",
      "THWeapon",
      "DualWeapon",
      "LongWeapon",
      "OffhandWeapon",
    ]);
    const weaponish = new Set();
    for (const r of itemTypeSheet.lines) {
      const ch = chain(r.id);
      if (ch.some((x) => roots.has(x))) weaponish.add(r.id);
    }
    return weaponish;
  }

  function computeClassBaseStats(classId, charLevel) {
    const rows = unitSheet.lines;
    const baseHero = rows.find((r) => r.id === "BaseHero");
    const cls = rows.find((r) => r.id === classId);
    if (!baseHero || !cls) throw new Error("Missing BaseHero or class unit row");

    const stats = {};

    for (const e of baseHero.stats || []) {
      if (e.value != null && e.attribute) stats[e.attribute] = e.value;
    }

    for (const e of cls.stats || []) {
      const a = e.attribute;
      const ls = e.levelScaling;
      if (Array.isArray(ls) && ls.length >= 2 && ls[0].val != null && ls[1].val != null) {
        stats[a] = interpolatePrimary(ls[0].val, ls[1].val, charLevel);
      } else if (e.value != null) {
        stats[a] = e.value;
      }
    }

    for (const id of PRIMARY_ATTRIBUTE_IDS) {
      const v = stats[id];
      if (typeof v === "number" && !Number.isNaN(v)) stats[id] = Math.round(v);
    }

    return stats;
  }

  /** Aptitude refs from the class unit row (`props.aptitudes`), e.g. Mage → `Wizard`. */
  function classAptitudeRefs(classId) {
    const rows = unitSheet && unitSheet.lines;
    if (!rows) return new Set();
    const cls = rows.find((r) => r.id === classId);
    const refs = new Set();
    const apt = cls && cls.props && cls.props.aptitudes;
    if (!Array.isArray(apt)) return refs;
    for (let i = 0; i < apt.length; i++) {
      const a = apt[i];
      if (a && typeof a.ref === "string" && a.ref) refs.add(a.ref);
    }
    return refs;
  }

  /** Item `aptitudes` must overlap class aptitudes when both sides specify refs; empty item aptitudes = any class. */
  function itemMatchesClassAptitudes(item, classAptRefs) {
    if (!classAptRefs || classAptRefs.size === 0) return true;
    const ia = item.aptitudes;
    if (!Array.isArray(ia) || ia.length === 0) return true;
    for (let i = 0; i < ia.length; i++) {
      const r = ia[i] && ia[i].ref;
      if (typeof r === "string" && classAptRefs.has(r)) return true;
    }
    return false;
  }

  function itemFitsSlotType(slotDef, item) {
    if (!slotDef || !item) return false;
    if (slotDef.weaponSlot) {
      if (!weaponTypes.has(item.type)) return false;
      if (slotDef.weaponRole === "off") return canEquipOffSlot(item.type);
      if (slotDef.weaponRole === "main") return canEquipMainSlot(item.type);
      if (slotDef.weaponRole === "arsenal") {
        return canEquipMainSlot(item.type) || canEquipOffSlot(item.type);
      }
      return false;
    }
    if (!slotDef.types || !slotDef.types.length) return true;
    return slotDef.types.includes(item.type);
  }

  function itemMatchesSlotClass(slotDef, item, classId) {
    if (!slotDef || !item || !classId) return true;
    if (!slotDef.weaponSlot && SLOT_KEYS_NO_CLASS_APTITUDE_MODAL_FILTER.has(slotDef.key)) return true;
    return itemMatchesClassAptitudes(item, classAptitudeRefs(classId));
  }

  function weaponItemDuplicatesArsenalOrHand(slotDef, item, slotMap) {
    if (!slotDef || !slotDef.weaponSlot || !item || !item.id) return false;
    const map = slotMap || selection;
    const same = (key) => {
      const it = map && map[key] && map[key].item;
      return !!(it && it.id === item.id);
    };
    if (slotDef.weaponRole === "arsenal") return same("mainHand") || same("offHand");
    if (slotDef.weaponRole === "main" || slotDef.weaponRole === "off") return same("arsenal");
    return false;
  }

  function slotInactiveReason(slotDef, sel, classId, charLevel, slotMap) {
    const item = sel && sel.item;
    if (!slotDef || !item) return "";
    const lv = Number.isFinite(charLevel) ? Math.floor(charLevel) : CHAR_LEVEL_DEFAULT;
    if (slotDef.weaponRole === "arsenal" && lv < ARSENAL_UNLOCK_LEVEL) {
      return `Arsenal unlocks at level ${ARSENAL_UNLOCK_LEVEL}`;
    }
    if (slotDef.weaponRole === "off") {
      const map = slotMap || selection;
      const mh = map && map.mainHand && map.mainHand.item;
      if (mh && weaponOccupiesBothHands(mh.type)) return "Blocked by two-handed main hand";
    }
    if (slotDef.weaponRole === "arsenal" && weaponItemDuplicatesArsenalOrHand(slotDef, item, slotMap)) {
      return "Already equipped in main hand or off-hand";
    }
    if (!itemFitsSlotType(slotDef, item)) return "Item type no longer fits this slot";
    if (!itemMatchesSlotClass(slotDef, item, classId)) return `Cannot equip on ${classId || "this class"}`;
    return "";
  }

  function slotSelectionIsActive(slotDef, sel, classId, charLevel, slotMap) {
    return !slotInactiveReason(slotDef, sel, classId, charLevel, slotMap);
  }

  function itemDisplayName(it) {
    const n = it.texts && it.texts.name;
    let base;
    if (typeof n === "string") base = n;
    else if (n && typeof n === "object" && n.v != null) base = String(n.v);
    else base = it.id;
    return base;
  }

  function jobDisplayName(jobId) {
    if (!jobId || typeof jobId !== "string") return "";
    const row = jobById[jobId];
    if (!row || !row.texts) return jobId;
    const t = row.texts;
    if (typeof t.jobTitle === "string" && t.jobTitle.trim()) return t.jobTitle.trim();
    if (typeof t.name === "string" && t.name.trim()) return t.name.trim();
    if (t.name && typeof t.name === "object" && t.name.v != null) return String(t.name.v).trim();
    return jobId;
  }

  /** Craft row from **`craft`** sheet — e.g. **`Level 1 Outfitter craft`**. */
  function itemCraftRecipeSubtitle(item) {
    if (!item || typeof item.id !== "string" || !itemFactionIsCraft(item)) return "";
    const rec = craftRecipeByItemId[item.id];
    if (!rec || rec.level == null || !Number.isFinite(rec.level)) return "";
    const jn = jobDisplayName(rec.job);
    if (!jn) return "";
    return `Level ${Math.round(rec.level)} ${jn} craft`;
  }

  /** Item modal / grid: dungeon drop line **or** craft job line (mutually exclusive for craft vs non-craft). */
  function itemModalSecondarySubtitle(it) {
    if (!it) return "";
    return itemFactionIsCraft(it) ? itemCraftRecipeSubtitle(it) : itemDungeonBossDropSubtitle(it);
  }

  /** Hide planner rows that only have an internal id as label (e.g. `Halos_Demon`). */
  function itemHasDisplayName(it) {
    const n = it.texts && it.texts.name;
    if (typeof n === "string" && n.trim()) return true;
    if (n && typeof n === "object" && n.v != null && String(n.v).trim()) return true;
    return false;
  }

  function itemTypeInheritanceChain(typeId) {
    const out = [];
    const seen = new Set();
    let cur = typeId;
    while (cur && typeof cur === "string" && !seen.has(cur)) {
      seen.add(cur);
      out.push(cur);
      const row = itemTypeRowsById && itemTypeRowsById[cur];
      cur = row ? parseItemTypeInherit(row.inherit) : null;
    }
    return out;
  }

  /** **`scroll`** | **`elixir`** | **`food`** | **`potion`** | **`other`** — attribute buff consumable; else **`null`**. */
  function itemConsumableBuffKind(it) {
    if (!it || typeof it.type !== "string") return null;
    const chain = itemTypeInheritanceChain(it.type);
    if (!chain.includes("Consumable") && it.type !== "Elixir" && it.type !== "Scroll") return null;
    if (chain.some((t) => String(t).startsWith("Augment"))) return null;
    if (chain.includes("Scroll") || /^ScrollOf/i.test(it.id)) return "scroll";
    if (
      chain.includes("Elixir") ||
      /^Elixir/i.test(it.id) ||
      it.id === MINOR_ALCHEMIST_CAULDRON_ITEM_ID
    ) {
      return "elixir";
    }
    if (chain.includes("Food") || /^Cook_/i.test(it.id) || it.id === "Feast") return "food";
    if (chain.includes("Potion")) return "potion";
    return "other";
  }

  function itemStaticFlatAffixTotals(it) {
    const totals = {};
    if (!it || !Array.isArray(it.affixes)) return totals;
    for (let i = 0; i < it.affixes.length; i++) {
      const ax = it.affixes[i];
      if (!ax || ax.ref !== "TAttribute_Flat") continue;
      if (ax.mod && ax.mod.dynVal) continue;
      const attr = ax.target && ax.target.attribute;
      if (!attr || typeof ax.val !== "number" || !Number.isFinite(ax.val)) continue;
      totals[attr] = (totals[attr] || 0) + presentationFlatForAffixFactor(ax.val, 1);
    }
    return totals;
  }

  function buildConsumableBuffCatalog(itemSheetLines) {
    consumableBuffCatalog = { scroll: [], elixir: [], food: [], potion: [], other: [] };
    consumableBuffById = {};
    for (let i = 0; i < itemSheetLines.length; i++) {
      const it = itemSheetLines[i];
      if (!it || typeof it.id !== "string" || !it.id) continue;
      const kind = itemConsumableBuffKind(it);
      if (!kind || !consumableBuffCatalog[kind]) continue;
      if (!Object.keys(itemStaticFlatAffixTotals(it)).length) continue;
      consumableBuffById[it.id] = it;
      consumableBuffCatalog[kind].push(it);
    }
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const kind = CONSUMABLE_BUFF_KIND_DEFS[ki].kind;
      const list = consumableBuffCatalog[kind] || [];
      list.sort((a, b) => String(itemDisplayName(a)).localeCompare(String(itemDisplayName(b))));
    }
  }

  function sanitizeActiveConsumableIds() {
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const kind = CONSUMABLE_BUFF_KIND_DEFS[ki].kind;
      const id = activeConsumableByKind[kind];
      if (!id) continue;
      const it = consumableBuffById[id];
      if (!it || itemConsumableBuffKind(it) !== kind) activeConsumableByKind[kind] = null;
    }
  }

  function consumablesSnapshotFromActive() {
    const out = {};
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const def = CONSUMABLE_BUFF_KIND_DEFS[ki];
      out[def.snapshotKey] = activeConsumableByKind[def.kind] || null;
    }
    return out;
  }

  function applyConsumablesFromSnapshot(cons) {
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      activeConsumableByKind[CONSUMABLE_BUFF_KIND_DEFS[ki].kind] = null;
    }
    if (!cons || typeof cons !== "object") return;
    const consNorm = { ...cons };
    if (
      consNorm.potionId === MINOR_ALCHEMIST_CAULDRON_ITEM_ID &&
      !consNorm.elixirId
    ) {
      consNorm.elixirId = MINOR_ALCHEMIST_CAULDRON_ITEM_ID;
      consNorm.potionId = null;
    }
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const def = CONSUMABLE_BUFF_KIND_DEFS[ki];
      const raw = consNorm[def.snapshotKey];
      if (typeof raw === "string" && raw.trim()) activeConsumableByKind[def.kind] = raw.trim();
    }
    sanitizeActiveConsumableIds();
  }

  function sumConsumableBuffFlats() {
    const totals = {};
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const id = activeConsumableByKind[CONSUMABLE_BUFF_KIND_DEFS[ki].kind];
      if (!id) continue;
      const it = consumableBuffById[id];
      if (!it) continue;
      const row = itemStaticFlatAffixTotals(it);
      for (const k of Object.keys(row)) {
        totals[k] = (totals[k] || 0) + row[k];
      }
    }
    return totals;
  }

  function consumableAffixSummaryHtml(it) {
    const totals = itemStaticFlatAffixTotals(it);
    const attrs = Object.keys(totals).sort((a, b) => displayNameForAttr(a).localeCompare(displayNameForAttr(b)));
    if (!attrs.length) return "";
    const parts = [];
    for (let i = 0; i < attrs.length; i++) {
      const attr = attrs[i];
      const v = totals[attr];
      const row = attributeById[attr];
      const isPct = !!(row && row.flags && (row.flags & ATTR_FLAG_PERCENT));
      const valStr = isPct
        ? `${formatSignedTalentFlat(v)}%`
        : formatSignedTalentFlat(v);
      parts.push(
        `<span class="gp-consumable-card__affix"><span class="gp-consumable-card__affix-val">${escapeHtml(
          valStr
        )}</span> ${escapeHtml(displayNameForAttr(attr))}</span>`
      );
    }
    return parts.join("");
  }

  function itemFlavorText(it) {
    const t = it.texts || {};
    if (typeof t.flavorDesc === "string") return t.flavorDesc;
    if (t.desc && typeof t.desc === "object" && t.desc.v) return String(t.desc.v);
    if (typeof t.desc === "string") return t.desc;
    return "";
  }

  function normalizeGfxPath(file) {
    return String(file || "")
      .replace(/\\/g, "/")
      .replace(/^\/+/, "");
  }

  /**
   * `cdb_pngs/files` slice export (`Foo/Foo.png`) for a portrait path, or **`null`**.
   * @param {string} file normalized `UI/Portraits/…/*.png`
   */
  function gfxCdbSliceRelPath(file) {
    const f = normalizeGfxPath(file);
    if (!f || !/^UI\/Portraits\//i.test(f)) return null;
    const base = f.split("/").pop();
    if (!base || !/\.png$/i.test(base)) return null;
    const name = base.replace(/\.png$/i, "");
    if (/^UI\/Portraits\/Units\//i.test(f)) return `unit/${name}/${name}.png`;
    if (/^UI\/Portraits\/Items\//i.test(f)) return `item/${name}/${name}.png`;
    return null;
  }

  function appendGfxCdbSliceCandidates(out, seen, file) {
    const sliceRel = gfxCdbSliceRelPath(file);
    if (!sliceRel) return;
    pushGfxUrlCandidate(out, seen, GFX_CDB_SLICES_BASE, sliceRel);
  }

  /** Portraits / masteries: generated PNG first (pak often missing); atlases keep pak-first order. */
  function itemGfxBasesForFile(file) {
    const f = normalizeGfxPath(file);
    if (
      f &&
      (/(?:^|\/)UI\/Portraits\/Items\/Masteries\//i.test(f) ||
        /(?:^|\/)UI\/Portraits\/Items\//i.test(f) ||
        /(?:^|\/)UI\/Portraits\/Units\//i.test(f))
    ) {
      return [
        "game-data/generated/cdb_pngs/files/",
        "game-data/extracted/res/",
        "game-data/extracted/res.light/",
      ];
    }
    return ITEM_GFX_BASES;
  }

  function pushGfxUrlCandidate(out, seen, base, encodedPath) {
    let href = "";
    try {
      const baseUrl = new URL(base, window.location.href);
      href = new URL(encodedPath, baseUrl).href;
    } catch (_) {
      href = base + encodedPath;
    }
    if (seen.has(href)) return;
    seen.add(href);
    out.push(href);
  }

  /**
   * Absolute URLs for an asset path (encoded segments), mirroring map.js `lootItemIconAssetUrlPaths`.
   * @param {string} file
   * @returns {string[]}
   */
  function itemGfxUrlCandidates(file) {
    const f = normalizeGfxPath(file);
    if (!f) return [];
    const encodedPath = f
      .split("/")
      .filter(Boolean)
      .map(encodeURIComponent)
      .join("/");
    const bases = itemGfxBasesForFile(f);
    const out = [];
    const seen = new Set();
    for (let bi = 0; bi < bases.length; bi++) {
      pushGfxUrlCandidate(out, seen, bases[bi], encodedPath);
    }
    appendGfxCdbSliceCandidates(out, seen, f);
    return out;
  }

  /** Unit foe thumbs — same portrait base order as items, plus **`slices/unit/Name/Name.png`**. */
  function unitPortraitUrlCandidates(file) {
    return itemGfxUrlCandidates(file);
  }

  /**
   * Full-image portrait (`mountLootIcon–style) with extra **`unit`** slice paths.
   * @param {HTMLElement} container
   * @param {{ file?: string } | null | undefined} gfxMeta
   * @param {string} [imgClass]
   */
  function mountUnitPortrait(container, gfxMeta, imgClass) {
    container.textContent = "";
    const urls = gfxMeta && gfxMeta.file ? unitPortraitUrlCandidates(gfxMeta.file) : [];
    if (!urls.length) {
      const ph = document.createElement("span");
      ph.className = "gp-foe-thumb-placeholder";
      ph.setAttribute("aria-hidden", "true");
      ph.textContent = "◎";
      container.appendChild(ph);
      return;
    }
    const img = document.createElement("img");
    img.alt = "";
    img.loading = "lazy";
    img.decoding = "async";
    if (imgClass) img.className = imgClass;
    let idx = 0;
    img.onerror = () => {
      idx++;
      if (idx < urls.length) {
        img.src = urls[idx];
      } else {
        img.remove();
        const ph = document.createElement("span");
        ph.className = "gp-foe-thumb-placeholder";
        ph.textContent = "?";
        container.appendChild(ph);
      }
    };
    img.src = urls[0];
    container.appendChild(img);
  }

  function unitGfxForPlanner(unitId) {
    const row = unitRowById[unitId];
    return row && row.gfx ? row.gfx : null;
  }

  function unitDisplayNameFromRow(row) {
    if (!row || !row.texts) return "";
    const n = row.texts.name;
    if (typeof n === "string" && n.trim()) return n.trim();
    if (n && typeof n === "object" && n.v != null && String(n.v).trim()) return String(n.v).trim();
    return "";
  }

  /** Display name for foe picker + damage preview header (no internal ids). */
  function foePlannerDisplayLabel(foeId) {
    if (!foeId || foeId === "median") return "Typical foe";
    const ex = foeUnitById[foeId];
    if (ex && ex.name) return String(ex.name);
    const row = unitRowById[foeId];
    const dn = unitDisplayNameFromRow(row);
    return dn || String(foeId);
  }

  /** Foe panel label — dungeon bosses get `"Boss Name - Dungeon Name"` appended. */
  function foePlannerPanelLabel(foeId) {
    const base = foePlannerDisplayLabel(foeId);
    const du = foeId && dungeonBossByUnitId[String(foeId)];
    const dn = du && du.dungeonName ? String(du.dungeonName).trim() : "";
    return dn ? `${base} — ${dn}` : base;
  }

  /** Item modal boss line: **`dungeonName`** from **`dungeon_regions.json`** only (no boss name prefix). */
  function foePlannerItemBossDropLabel(foeId) {
    const du = foeId && dungeonBossByUnitId[String(foeId)];
    const dn = du && du.dungeonName ? String(du.dungeonName).trim() : "";
    return dn || foePlannerDisplayLabel(foeId);
  }

  /**
   * All **`item`** ids reachable from a loot table (**direct entries + nested **`lootTable`** refs**). **`stack`** breaks cycles.
   * Results are memoized in **`lootTableItemExpansionMemo`** while building the boss-drop index.
   */
  function allItemIdsInLootTable(tableId, lootTables, stack) {
    const tid = typeof tableId === "string" ? tableId.trim() : "";
    if (!tid || !lootTables || typeof lootTables !== "object") return [];
    const row = lootTables[tid];
    if (!row || typeof row !== "object") return [];
    if (lootTableItemExpansionMemo && lootTableItemExpansionMemo[tid]) {
      return lootTableItemExpansionMemo[tid];
    }
    if (!stack) stack = new Set();
    if (stack.has(tid)) return [];
    stack.add(tid);
    const out = new Set();
    const entries = row.entries;
    if (Array.isArray(entries)) {
      for (let ei = 0; ei < entries.length; ei++) {
        const ent = entries[ei];
        if (!ent || typeof ent !== "object") continue;
        const iid = ent.item;
        if (typeof iid === "string" && iid.trim()) out.add(iid.trim());
        const nlt = ent.lootTable;
        if (typeof nlt === "string" && nlt.trim()) {
          const sub = allItemIdsInLootTable(nlt.trim(), lootTables, stack);
          for (let si = 0; si < sub.length; si++) out.add(sub[si]);
        }
      }
    }
    stack.delete(tid);
    const arr = [...out];
    if (lootTableItemExpansionMemo) lootTableItemExpansionMemo[tid] = arr;
    return arr;
  }

  /**
   * Builds **`itemDungeonBossDropsByItemId`** from **`loot_tables.json`** + **`dungeonBossByUnitId`**.
   * Each entry is a dungeon **boss unit id** and **`dungeonName`** label for the item modal; **`itemDungeonBossDropSubtitle`** filters by the item’s CDB **`faction`**
   * vs **`dungeon_regions.json`** **`faction`** on that boss ( **`World`** / missing faction → no filter ).
   */
  function hydrateItemBossDropIndexFromLootTables(payload) {
    lootTableItemExpansionMemo = Object.create(null);
    itemDungeonBossDropsByItemId = null;
    if (!payload || typeof payload !== "object") return;
    const lootTables = payload.lootTables;
    const idx =
      payload.indexes &&
      payload.indexes.unitIdsByLootTableId &&
      typeof payload.indexes.unitIdsByLootTableId === "object"
        ? payload.indexes.unitIdsByLootTableId
        : null;
    if (!lootTables || typeof lootTables !== "object" || !idx) return;

    const byItem = Object.create(null);
    const roots = Object.keys(idx);
    for (let ri = 0; ri < roots.length; ri++) {
      const rootId = roots[ri];
      const unitList = idx[rootId];
      if (!Array.isArray(unitList) || !unitList.length) continue;
      const bossUnits = [];
      for (let ui = 0; ui < unitList.length; ui++) {
        const uid = unitList[ui];
        if (typeof uid === "string" && uid && dungeonBossByUnitId[uid]) bossUnits.push(uid);
      }
      if (!bossUnits.length) continue;
      const itemIds = allItemIdsInLootTable(rootId, lootTables, new Set());
      for (let ii = 0; ii < itemIds.length; ii++) {
        const iid = itemIds[ii];
        if (!byItem[iid]) byItem[iid] = new Map();
        const m = byItem[iid];
        for (let bi = 0; bi < bossUnits.length; bi++) {
          const bu = bossUnits[bi];
          m.set(bu, foePlannerItemBossDropLabel(bu));
        }
      }
    }
    const out = Object.create(null);
    const keys = Object.keys(byItem);
    for (let ki = 0; ki < keys.length; ki++) {
      const k = keys[ki];
      const m = byItem[k];
      const arr = [];
      for (const [unitId, label] of m.entries()) {
        arr.push({ unitId, label });
      }
      arr.sort((a, b) => a.label.localeCompare(b.label));
      out[k] = arr;
    }
    itemDungeonBossDropsByItemId = out;
  }

  /**
   * Comma-separated **dungeon names** (`dungeon_regions.dungeonName`) for drops: loot-table reachability when the item id
   * appears as **`item`** in exported tables, else **faction fallback** when the sheet has **`faction`** other than **`World`**.
   * Craft-faction items: no line.
   */
  function itemDungeonBossDropSubtitle(item) {
    if (!item || typeof item.id !== "string") {
      return "";
    }
    if (itemFactionIsCraft(item)) return "";
    const entries =
      itemDungeonBossDropsByItemId && itemDungeonBossDropsByItemId[item.id];
    const facRaw =
      typeof item.faction === "string" && item.faction.trim() ? item.faction.trim() : "";
    const filterByFaction = !!(facRaw && facRaw !== "World");
    const labels = [];
    if (Array.isArray(entries)) {
      for (let i = 0; i < entries.length; i++) {
        const e = entries[i];
        if (!e || typeof e.unitId !== "string" || typeof e.label !== "string") continue;
        if (filterByFaction) {
          const dm = dungeonBossByUnitId[e.unitId];
          const bf =
            dm && typeof dm.faction === "string" && dm.faction.trim()
              ? dm.faction.trim()
              : "";
          if (bf !== facRaw) continue;
        }
        labels.push(e.label);
      }
    }
    if (labels.length) {
      const uniq = [...new Set(labels)].sort((a, b) => a.localeCompare(b));
      return uniq.join(", ");
    }
    if (!facRaw || facRaw === "World") return "";
    const facFallback =
      dungeonBossLabelsByFactionId && dungeonBossLabelsByFactionId[facRaw];
    if (Array.isArray(facFallback) && facFallback.length) {
      return facFallback.join(", ");
    }
    return "";
  }

  /**
   * Integer levels this foe template can use for armor preview (`spawnLevelSpan` / `lvl`–`maxLvl` from **`foe_defenses.json`**).
   */
  function foeSpawnLevelsForPicker(u) {
    if (!u || typeof u !== "object") {
      const fb = [];
      for (let L = 1; L <= MONSTER_LEVEL_MAX; L++) fb.push(L);
      return fb;
    }
    /** Training dummy is always **level 1** in-game for this planner. */
    if (u.id === "Dummy") return [1];
    const span = u.spawnLevelSpan;
    let lo = 1;
    let hi = MONSTER_LEVEL_MAX;
    let got = false;
    if (Array.isArray(span) && span.length >= 2) {
      const a = Number(span[0]);
      const b = Number(span[1]);
      if (Number.isFinite(a) && Number.isFinite(b) && (a > 0 || b > 0)) {
        lo = Math.min(a, b);
        hi = Math.max(a, b);
        got = true;
      }
    }
    if (!got && u.lvl != null) {
      lo = Number(u.lvl);
      hi = u.maxLvl != null ? Number(u.maxLvl) : lo;
      got = Number.isFinite(lo);
    }
    if (!got) {
      const fb = [];
      for (let L = 1; L <= MONSTER_LEVEL_MAX; L++) fb.push(L);
      return fb;
    }
    lo = clamp(Math.ceil(lo), 1, MONSTER_LEVEL_MAX);
    hi = clamp(Math.floor(hi), 1, MONSTER_LEVEL_MAX);
    if (hi < lo) {
      const one = clamp(Math.round(Number(u.lvl)) || 1, 1, MONSTER_LEVEL_MAX);
      return [one];
    }
    const out = [];
    for (let L = lo; L <= hi; L++) out.push(L);
    return out.length ? out : [clamp(Math.round(Number(u.lvl)) || 1, 1, MONSTER_LEVEL_MAX)];
  }

  /**
   * Parse map **region** from template **`id`** segments like **`Bee_Z1W`** → region index **1**, sub **W**.
   * Boss-style ids without a **`Z*`** token use **`Other`** for sorting/filtering.
   */
  function foeZoneFromUnitId(unitId) {
    const parts = String(unitId || "").split("_");
    for (let i = 0; i < parts.length; i++) {
      const m = parts[i].match(/^Z(\d+)([A-Za-z]*)$/);
      if (m) {
        const zoneNum = parseInt(m[1], 10);
        const sub = (m[2] || "").toUpperCase();
        const named = FOE_ZONE_DISPLAY_NAME[zoneNum];
        const label = named
          ? sub
            ? `${named} · ${sub}`
            : named
          : sub
            ? `Region ${zoneNum} · ${sub}`
            : `Region ${zoneNum}`;
        const sortKey = `${String(zoneNum).padStart(2, "0")}_${sub || "_"}`;
        return { zoneNum, sub, label, sortKey };
      }
    }
    return {
      zoneNum: null,
      sub: "",
      label: "Other",
      sortKey: "99_~",
    };
  }

  function hydrateDungeonBossLookup(payload) {
    dungeonBossByUnitId = {};
    dungeonBossLabelsByFactionId = null;
    const h =
      payload && payload.hardFoeLevel != null ? Number(payload.hardFoeLevel) : NaN;
    dungeonRegionsHardLevel =
      Number.isFinite(h) && h > 0
        ? clamp(Math.round(h), 1, MONSTER_LEVEL_MAX)
        : DUNGEON_HARD_FOE_LEVEL_DEFAULT;
    const list =
      payload && Array.isArray(payload.dungeons) ? payload.dungeons : [];
    for (let i = 0; i < list.length; i++) {
      const d = list[i];
      const boss =
        d && typeof d.bossUnit === "string" && d.bossUnit.trim()
          ? d.bossUnit.trim()
          : "";
      if (!boss) continue;
      const zp = String(d.zonePrefix || "").trim();
      const zonePrefix = zp.startsWith("Z2") ? "Z2" : "Z1";
      const nl = d != null && d.normalFoeLevel != null ? Number(d.normalFoeLevel) : NaN;
      const normalFoeLevel =
        Number.isFinite(nl) && nl > 0
          ? clamp(Math.round(nl), 1, MONSTER_LEVEL_MAX)
          : null;
      const fac =
        d && typeof d.faction === "string" && d.faction.trim() ? d.faction.trim() : "";
      dungeonBossByUnitId[boss] = {
        activityId: String(d.activityId || ""),
        dungeonName: String(d.dungeonName || ""),
        zonePrefix,
        normalFoeLevel,
        ...(fac ? { faction: fac } : {}),
      };
    }
    const byFac = Object.create(null);
    for (let j = 0; j < list.length; j++) {
      const d = list[j];
      const fac =
        d && typeof d.faction === "string" && d.faction.trim() ? d.faction.trim() : "";
      const boss =
        d && typeof d.bossUnit === "string" && d.bossUnit.trim()
          ? d.bossUnit.trim()
          : "";
      if (!fac || !boss || !dungeonBossByUnitId[boss]) continue;
      if (!byFac[fac]) byFac[fac] = [];
      const lab = foePlannerItemBossDropLabel(boss);
      const arr = byFac[fac];
      if (arr.indexOf(lab) < 0) arr.push(lab);
    }
    const facKeys = Object.keys(byFac);
    if (facKeys.length) {
      dungeonBossLabelsByFactionId = Object.create(null);
      for (let fk = 0; fk < facKeys.length; fk++) {
        const k = facKeys[fk];
        dungeonBossLabelsByFactionId[k] = [...byFac[k]].sort((a, b) => a.localeCompare(b));
      }
    }
  }

  /** Normal dungeon foe level: activity **`props.level`** export, else foe template spawn span. */
  function resolveDungeonNormalFoeLevel(unitId) {
    const id = String(unitId || "");
    const dm = dungeonBossByUnitId[id];
    if (!dm) return MONSTER_LEVEL_DEFAULT;
    if (dm.normalFoeLevel != null && Number.isFinite(dm.normalFoeLevel)) {
      return clamp(dm.normalFoeLevel, 1, MONSTER_LEVEL_MAX);
    }
    const u = foeUnitById[id];
    if (u && typeof u === "object") {
      const b = foeSpawnSpanBounds(u);
      return clamp(b.lo, 1, MONSTER_LEVEL_MAX);
    }
    return clamp(12, 1, MONSTER_LEVEL_MAX);
  }

  /** Skover (**1**) vs Eternal Autumn (**2**) from foe template **`Z*`** segment or dungeon boss table. */
  function foeEffectiveZoneNum(unitId) {
    const du = dungeonBossByUnitId[String(unitId || "")];
    if (du) return du.zonePrefix === "Z2" ? 2 : 1;
    return foeZoneFromUnitId(unitId).zoneNum;
  }

  function foePlannerSortKey(unit) {
    if (unit && unit.id === "Dummy") return "00_dummy";
    const du = dungeonBossByUnitId[String(unit.id || "")];
    if (du) {
      const zn = du.zonePrefix === "Z2" ? 2 : 1;
      return `${String(zn).padStart(2, "0")}_dungeon_${du.activityId || unit.id}`;
    }
    return foeZoneFromUnitId(unit.id).sortKey;
  }

  function foeZoneAllowedInPlanner(zoneNum) {
    return zoneNum != null && FOE_ZONE_PLANNER_ALLOWED.has(zoneNum);
  }

  /** **`median`** or a unit id in **`FOE_ZONE_PLANNER_ALLOWED`** only. */
  function foeIdPickableInPlanner(foeId) {
    if (!foeId || foeId === "median") return true;
    if (foeId === "Dummy") return true;
    return foeZoneAllowedInPlanner(foeEffectiveZoneNum(foeId));
  }

  /** Integer spawn level bounds for sorting / filters (from **`spawnLevelSpan`** or **`lvl`** / **`maxLvl`**). */
  function foeSpawnSpanBounds(u) {
    if (!u || typeof u !== "object") return { lo: 1, hi: MONSTER_LEVEL_MAX };
    if (u.id === "Dummy") return { lo: 1, hi: 1 };
    const span = u.spawnLevelSpan;
    if (Array.isArray(span) && span.length >= 2) {
      let lo = Math.min(Number(span[0]), Number(span[1]));
      let hi = Math.max(Number(span[0]), Number(span[1]));
      if (Number.isFinite(lo) && Number.isFinite(hi) && (lo > 0 || hi > 0)) {
        lo = clamp(Math.ceil(lo), 1, MONSTER_LEVEL_MAX);
        hi = clamp(Math.floor(hi), 1, MONSTER_LEVEL_MAX);
        if (hi >= lo) return { lo, hi };
      }
    }
    if (u.lvl != null) {
      const lo = clamp(Math.round(Number(u.lvl)) || 1, 1, MONSTER_LEVEL_MAX);
      const hi =
        u.maxLvl != null ? clamp(Math.round(Number(u.maxLvl)), 1, MONSTER_LEVEL_MAX) : lo;
      return { lo: Math.min(lo, hi), hi: Math.max(lo, hi) };
    }
    return { lo: 1, hi: MONSTER_LEVEL_MAX };
  }

  function foeCompareForSort(a, b) {
    const cz = foePlannerSortKey(a).localeCompare(foePlannerSortKey(b));
    if (cz !== 0) return cz;
    const sa = foeSpawnSpanBounds(a);
    const sb = foeSpawnSpanBounds(b);
    if (sa.lo !== sb.lo) return sa.lo - sb.lo;
    return String(a.name || a.id).localeCompare(String(b.name || b.id));
  }

  /**
   * @param {HTMLElement} container
   * @param {{ file?: string } | null | undefined} gfxMeta
   * @param {string} [imgClass]
   */
  /**
   * @param {string} file
   * @param {(url: string | null) => void} cb
   */
  function probeFirstWorkingGfxUrl(file, cb) {
    const urls = itemGfxUrlCandidates(file);
    if (!urls.length) {
      cb(null);
      return;
    }
    const probe = new Image();
    let attempt = 0;
    const tryNext = () => {
      if (attempt >= urls.length) {
        cb(null);
        return;
      }
      const url = urls[attempt];
      attempt += 1;
      probe.onload = () => cb(url);
      probe.onerror = tryNext;
      probe.src = url;
    };
    tryNext();
  }

  /**
   * @param {(url: string | null) => void} cb
   */
  function resolveItemSlotsSheetUrl(cb) {
    if (itemSlotsSheetUrl) {
      cb(itemSlotsSheetUrl);
      return;
    }
    probeFirstWorkingGfxUrl("UI/Elements/item_slots.png", (url) => {
      if (url) itemSlotsSheetUrl = url;
      cb(url);
    });
  }

  /**
   * In-game rarity frame behind slot icons (`item_slots.png`).
   * @param {HTMLElement} iconWrap
   * @param {string | null | undefined} rarityId
   */
  function applySlotRarityFrame(iconWrap, rarityId) {
    if (!iconWrap) return;
    const tile = RARITY_SLOT_TILE[rarityId || "Common"] || RARITY_SLOT_TILE.Common;
    const cell = ITEM_SLOT_FRAME_CELL;
    iconWrap.classList.add("slot-card__icon-wrap--framed");
    resolveItemSlotsSheetUrl((url) => {
      if (!url) return;
      iconWrap.style.backgroundImage = `url("${String(url).replace(/"/g, "%22")}")`;
      iconWrap.style.backgroundSize = `${4 * cell}px ${2 * cell}px`;
      iconWrap.style.backgroundPosition = `-${tile[0] * cell}px -${tile[1] * cell}px`;
    });
  }

  /**
   * @param {HTMLElement} container
   * @param {string} file
   * @param {string} [alt]
   */
  /**
   * Class banner from `class_flag.png` (non-square 76×108 cells; X is pixel offset).
   * @param {HTMLElement} container
   * @param {string} classId
   * @param {number} [targetPx] — max height in CSS pixels
   */
  function mountClassFlagIcon(container, classId, targetPx) {
    if (!container) return;
    container.textContent = "";
    const xOff = CLASS_FLAG_X[classId];
    if (xOff == null) return;
    const urls = itemGfxUrlCandidates(CLASS_FLAG_FILE);
    if (!urls.length) return;
    const target = typeof targetPx === "number" && targetPx > 0 ? targetPx : 48;
    const scale = Math.min(1, target / CLASS_FLAG_CELL_H);
    const dispW = CLASS_FLAG_CELL_W * scale;
    const dispH = CLASS_FLAG_CELL_H * scale;

    const wrap = document.createElement("div");
    wrap.className = "gp-class-flag-wrap";
    wrap.style.width = `${dispW}px`;
    wrap.style.height = `${dispH}px`;
    wrap.style.overflow = "hidden";

    const inner = document.createElement("div");
    inner.className = "gp-class-flag-inner";
    inner.style.width = `${CLASS_FLAG_CELL_W}px`;
    inner.style.height = `${CLASS_FLAG_CELL_H}px`;
    inner.style.backgroundRepeat = "no-repeat";
    inner.style.backgroundPosition = `-${xOff}px 0px`;
    inner.style.transform = `scale(${scale})`;
    inner.style.transformOrigin = "top left";

    wrap.appendChild(inner);
    container.appendChild(wrap);

    const probe = new Image();
    let attempt = 0;
    const tryNextUrl = () => {
      if (attempt >= urls.length) {
        wrap.textContent = "";
        return;
      }
      const urlSafe = urls[attempt].replace(/\\/g, "/");
      attempt += 1;
      probe.onload = () => {
        inner.style.backgroundImage = "url(" + JSON.stringify(urlSafe) + ")";
      };
      probe.onerror = tryNextUrl;
      probe.src = urlSafe;
    };
    tryNextUrl();
  }

  function mountPlannerImage(container, file, alt) {
    if (!container) return;
    container.textContent = "";
    probeFirstWorkingGfxUrl(file, (url) => {
      if (!url) return;
      const img = document.createElement("img");
      img.alt = alt || "";
      img.loading = "lazy";
      img.decoding = "async";
      img.src = url;
      container.appendChild(img);
    });
  }

  function gfxMetaCacheKey(gfxMeta) {
    if (!gfxMeta || typeof gfxMeta.file !== "string" || !gfxMeta.file.trim()) return "";
    const cell =
      typeof gfxMeta.size === "number" && Number.isFinite(gfxMeta.size) && gfxMeta.size > 0
        ? Math.floor(gfxMeta.size)
        : 32;
    const cw =
      typeof gfxMeta.width === "number" && Number.isFinite(gfxMeta.width) && gfxMeta.width > 0
        ? Math.floor(gfxMeta.width)
        : 1;
    const ch =
      typeof gfxMeta.height === "number" && Number.isFinite(gfxMeta.height) && gfxMeta.height > 0
        ? Math.floor(gfxMeta.height)
        : 1;
    const tx = typeof gfxMeta.x === "number" && Number.isFinite(gfxMeta.x) ? Math.floor(gfxMeta.x) : 0;
    const ty = typeof gfxMeta.y === "number" && Number.isFinite(gfxMeta.y) ? Math.floor(gfxMeta.y) : 0;
    return `${gfxMeta.file.trim()}|${cell}|${tx}|${ty}|${cw}|${ch}`;
  }

  function mountLootIcon(container, gfxMeta, imgClass) {
    if (!container) return;
    const cacheKey = gfxMetaCacheKey(gfxMeta);
    if (
      cacheKey &&
      container.dataset.gpGfxKey === cacheKey &&
      container.querySelector("img[src]")
    ) {
      return;
    }
    delete container.dataset.gpGfxKey;
    container.textContent = "";
    const urls = gfxMeta && gfxMeta.file ? itemGfxUrlCandidates(gfxMeta.file) : [];
    if (!urls.length) {
      const ph = document.createElement("span");
      ph.className = "slot-card__placeholder-icon";
      ph.textContent = "◇";
      container.appendChild(ph);
      return;
    }
    const img = document.createElement("img");
    img.alt = "";
    img.loading = "lazy";
    img.decoding = "async";
    if (imgClass) img.className = imgClass;
    let idx = 0;
    img.onload = () => {
      if (cacheKey) container.dataset.gpGfxKey = cacheKey;
    };
    img.onerror = () => {
      idx++;
      if (idx < urls.length) {
        img.src = urls[idx];
      } else {
        img.remove();
        const ph = document.createElement("span");
        ph.className = "slot-card__placeholder-icon";
        ph.textContent = "◇";
        container.appendChild(ph);
      }
    };
    img.src = urls[0];
    container.appendChild(img);
  }

  /**
   * Sprite atlas icon (skill UI / loot atlases) — same math as `map.js` `appendFareverLootIconCell`.
   * Supports multi-cell sprites via optional `width` / `height` (tile counts).
   * @param {HTMLElement} container
   * @param {{ file?: string; size?: number; x?: number; y?: number; width?: number; height?: number } | null | undefined} gfxMeta
   * @param {number} [targetPx]
   */
  function mountAtlasIcon(container, gfxMeta, targetPx) {
    if (!container) return;
    const cacheKey = gfxMetaCacheKey(gfxMeta);
    const targetKey =
      typeof targetPx === "number" && targetPx > 0 ? String(Math.floor(targetPx)) : "36";
    const fullKey = cacheKey ? `${cacheKey}|${targetKey}` : "";
    const innerLoaded = container.querySelector(".gp-atlas-icon-inner");
    if (
      fullKey &&
      container.dataset.gpGfxKey === fullKey &&
      innerLoaded &&
      innerLoaded.style.backgroundImage
    ) {
      return;
    }
    delete container.dataset.gpGfxKey;
    container.textContent = "";
    if (!gfxMeta || typeof gfxMeta.file !== "string" || !gfxMeta.file.trim()) {
      const ph = document.createElement("span");
      ph.className = "slot-card__placeholder-icon";
      ph.textContent = "◇";
      container.appendChild(ph);
      return;
    }
    const urls = itemGfxUrlCandidates(gfxMeta.file.trim());
    if (!urls.length) {
      const ph = document.createElement("span");
      ph.className = "slot-card__placeholder-icon";
      ph.textContent = "◇";
      container.appendChild(ph);
      return;
    }
    const cell =
      typeof gfxMeta.size === "number" && Number.isFinite(gfxMeta.size) && gfxMeta.size > 0
        ? Math.floor(gfxMeta.size)
        : 32;
    const cw =
      typeof gfxMeta.width === "number" && Number.isFinite(gfxMeta.width) && gfxMeta.width > 0
        ? Math.floor(gfxMeta.width)
        : 1;
    const ch =
      typeof gfxMeta.height === "number" && Number.isFinite(gfxMeta.height) && gfxMeta.height > 0
        ? Math.floor(gfxMeta.height)
        : 1;
    const tx =
      typeof gfxMeta.x === "number" && Number.isFinite(gfxMeta.x) ? Math.floor(gfxMeta.x) : 0;
    const ty =
      typeof gfxMeta.y === "number" && Number.isFinite(gfxMeta.y) ? Math.floor(gfxMeta.y) : 0;
    const innerW = cell * cw;
    const innerH = cell * ch;
    const target = typeof targetPx === "number" && targetPx > 0 ? targetPx : 36;
    const maxDim = Math.max(innerW, innerH);
    const scale = Math.min(1, target / maxDim);

    const wrap = document.createElement("div");
    wrap.className = "gp-atlas-icon-wrap";
    wrap.style.width = `${innerW * scale}px`;
    wrap.style.height = `${innerH * scale}px`;
    wrap.style.overflow = "hidden";

    const inner = document.createElement("div");
    inner.className = "gp-atlas-icon-inner";
    inner.style.width = `${innerW}px`;
    inner.style.height = `${innerH}px`;
    inner.style.backgroundRepeat = "no-repeat";
    inner.style.backgroundPosition = `-${tx * cell}px -${ty * cell}px`;
    inner.style.transform = `scale(${scale})`;
    inner.style.transformOrigin = "top left";

    wrap.appendChild(inner);
    container.appendChild(wrap);

    const probe = new Image();
    let attempt = 0;
    const tryNextUrl = () => {
      if (attempt >= urls.length) {
        wrap.textContent = "";
        const ph = document.createElement("span");
        ph.className = "slot-card__placeholder-icon";
        ph.textContent = "?";
        wrap.appendChild(ph);
        return;
      }
      const urlSafe = urls[attempt].replace(/\\/g, "/");
      attempt += 1;
      probe.onload = () => {
        inner.style.backgroundImage = "url(" + JSON.stringify(urlSafe) + ")";
        if (fullKey) container.dataset.gpGfxKey = fullKey;
      };
      probe.onerror = tryNextUrl;
      probe.src = urlSafe;
    };
    tryNextUrl();
  }

  function parseItemTypeInherit(inh) {
    if (typeof inh === "string") return inh;
    if (Array.isArray(inh) && inh[0] && inh[0].ref) return inh[0].ref;
    return null;
  }

  /** Walk inherit chain from slot type (e.g. Head → Armor → Gear …). */
  function itemTypeChainRows(typeId) {
    if (!itemTypeRowsById || !typeId) return [];
    const rows = [];
    const seen = new Set();
    let cur = typeId;
    while (cur && !seen.has(cur)) {
      seen.add(cur);
      const row = itemTypeRowsById[cur];
      if (!row) break;
      rows.push(row);
      cur = parseItemTypeInherit(row.inherit);
    }
    return rows;
  }

  /** @param {string} typeId */
  function itemTypeAncestorIds(typeId) {
    return itemTypeChainRows(typeId).map((r) => r.id);
  }

  const MAIN_HAND_WEAPON_FAMILY_IDS = new Set(["OHWeapon", "DualWeapon", "THWeapon", "LongWeapon"]);
  const OFFHAND_BLOCKING_WEAPON_FAMILY_IDS = new Set(["DualWeapon", "THWeapon", "LongWeapon"]);

  /** Main-hand candidates: one-hand, dual, two-hand, and long weapon lineages. */
  function canEquipMainSlot(typeId) {
    const a = itemTypeAncestorIds(typeId);
    return a.some((id) => MAIN_HAND_WEAPON_FAMILY_IDS.has(id));
  }

  /** Off-hand candidates: dedicated off-hand weapon lineages only. */
  function canEquipOffSlot(typeId) {
    return itemTypeAncestorIds(typeId).includes("OffhandWeapon");
  }

  /** Dual, two-handed, and long weapons block the off-hand slot. */
  function weaponOccupiesBothHands(typeId) {
    const a = itemTypeAncestorIds(typeId);
    return a.some((id) => OFFHAND_BLOCKING_WEAPON_FAMILY_IDS.has(id));
  }

  /** Main-hand weapons whose family permits an off-hand item alongside them. */
  function weaponCanEquipWithOffhand(typeId) {
    return canEquipMainSlot(typeId) && !weaponOccupiesBothHands(typeId);
  }

  function skillRowType(sk) {
    if (!sk || sk.type == null) return -1;
    return typeof sk.type === "number" ? sk.type : -1;
  }

  /**
   * **Attack**-chain **`skill.type`** **0–4** (in-game **Attack** / **ComboAttack** — not authored **[WeaponSkill]** rows **7** / **24**).
   * Bonuses that target **[WeaponSkill]** must **exclude** these types.
   */
  function skillRowIsAttackChainType(sk) {
    const t = skillRowType(sk);
    return t >= SKILL_TYPE_ATTACK_CHAIN_MIN && t <= SKILL_TYPE_ATTACK_CHAIN_MAX;
  }

  /** **0–3** — matches **`isBaseAttack()`**-gated mage talents (**Chainstrike**, **Amplification**, …). */
  function skillRowIsMageBaseAttackType(sk) {
    const t = skillRowType(sk);
    return t >= SKILL_TYPE_ATTACK_CHAIN_MIN && t < SKILL_TYPE_ATTACK_CHAIN_MAX;
  }

  /** **4** — **`isFinalAttack()`** / combo finisher (**High Voltage**). */
  function skillRowIsMageComboAttackType(sk) {
    return skillRowType(sk) === SKILL_TYPE_ATTACK_CHAIN_MAX;
  }

  function mageTalentRank(talentSkillId) {
    const r = talentAllocations[talentSkillId];
    return typeof r === "number" && r >= 1 ? Math.floor(r) : 0;
  }

  function mageIsConduitSkillId(skillId) {
    if (typeof skillId !== "string" || !skillId) return false;
    if (skillId.indexOf("Mage_Conduit_") === 0) return true;
    const sk = skillById[skillId];
    return !!(sk && String(skillDisplayName(sk) || "").indexOf("Conduit:") === 0);
  }

  function mageConduitSlotCount(charLevel) {
    const lv = Number.isFinite(charLevel) ? Math.floor(charLevel) : CHAR_LEVEL_DEFAULT;
    return lv >= 4 ? 3 : 2;
  }

  function mageAvailableConduitSkillIds() {
    const out = [];
    function push(sid) {
      if (typeof sid !== "string" || !sid || out.includes(sid) || !skillById[sid]) return;
      out.push(sid);
    }
    for (let i = 0; i < MAGE_BASE_CONDUIT_IDS.length; i++) push(MAGE_BASE_CONDUIT_IDS[i]);
    for (const talentId of Object.keys(talentAllocations)) {
      if (mageTalentRank(talentId) <= 0) continue;
      const talent = skillById[talentId];
      const unlock =
        talent &&
        talent.props &&
        talent.props.talent &&
        typeof talent.props.talent.unlockConduit === "string"
          ? talent.props.talent.unlockConduit
          : "";
      push(unlock);
    }
    return out;
  }

  function mageSelectedConduitSkillIds(charLevel) {
    const src = Array.isArray(plannerDamagePreviewSettings.mageConduitSkillIds)
      ? plannerDamagePreviewSettings.mageConduitSkillIds
      : [];
    const available = new Set(mageAvailableConduitSkillIds());
    const max = mageConduitSlotCount(charLevel);
    const out = [];
    for (let i = 0; i < src.length && out.length < max; i++) {
      const sid = src[i];
      if (typeof sid === "string" && available.has(sid) && !out.includes(sid)) out.push(sid);
    }
    return out;
  }

  function sanitizeMageConduitSelection(charLevel) {
    plannerDamagePreviewSettings.mageConduitSkillIds = mageSelectedConduitSkillIds(charLevel);
  }

  function setMageConduitSelected(skillId, selected, charLevel) {
    const available = new Set(mageAvailableConduitSkillIds());
    const cur = mageSelectedConduitSkillIds(charLevel).filter((sid) => sid !== skillId);
    if (selected && typeof skillId === "string" && available.has(skillId)) {
      cur.push(skillId);
    }
    plannerDamagePreviewSettings.mageConduitSkillIds = cur.slice(0, mageConduitSlotCount(charLevel));
  }

  function priestIsPrayerSkillId(skillId) {
    if (typeof skillId !== "string" || !skillId) return false;
    const sk = skillById[skillId];
    return !!(sk && String(skillDisplayName(sk) || "").indexOf("Prayer:") === 0);
  }

  function priestAvailablePrayerSkillIds() {
    const out = [];
    const cls = unitSheet && unitSheet.lines ? unitSheet.lines.find((r) => r.id === "Priest") : null;
    const classRows = (cls && cls.skills) || [];
    for (let i = 0; i < classRows.length; i++) {
      const sid = classRows[i] && classRows[i].skill;
      if (typeof sid !== "string" || !sid || !priestIsPrayerSkillId(sid)) continue;
      if (!out.includes(sid)) out.push(sid);
    }
    return out;
  }

  function priestSelectedPrayerSkillIds() {
    const src = Array.isArray(plannerDamagePreviewSettings.priestPrayerSkillIds)
      ? plannerDamagePreviewSettings.priestPrayerSkillIds
      : [];
    const available = new Set(priestAvailablePrayerSkillIds());
    const out = [];
    for (let i = 0; i < src.length && out.length < PRIEST_PRAYER_SLOT_COUNT; i++) {
      const sid = src[i];
      if (typeof sid === "string" && available.has(sid) && !out.includes(sid)) out.push(sid);
    }
    return out;
  }

  function sanitizePriestPrayerSelection() {
    plannerDamagePreviewSettings.priestPrayerSkillIds = priestSelectedPrayerSkillIds();
  }

  function setPriestPrayerSelected(skillId, selected) {
    const available = new Set(priestAvailablePrayerSkillIds());
    const cur = priestSelectedPrayerSkillIds().filter((sid) => sid !== skillId);
    if (selected && typeof skillId === "string" && available.has(skillId)) {
      cur.push(skillId);
    }
    plannerDamagePreviewSettings.priestPrayerSkillIds = cur.slice(0, PRIEST_PRAYER_SLOT_COUNT);
  }

  /** Rounded-rect **active** vs **circular** passive icon: **`skill.type` 24** (weapon passive) or **`skill.nature` 5** (Passive). */
  function skillIconIsPassiveFrame(sk) {
    if (!sk) return false;
    if (skillRowType(sk) === SKILL_TYPE_WEAPON_PASSIVE) return true;
    return typeof sk.nature === "number" && sk.nature === SKILL_NATURE_PASSIVE;
  }

  /** CDB **`skill.mastery[]`** rune rows (active class skills only). */
  function skillMasteryEntries(sk) {
    if (!sk || !Array.isArray(sk.mastery) || !sk.mastery.length) return [];
    const out = [];
    for (let i = 0; i < sk.mastery.length; i++) {
      const m = sk.mastery[i];
      if (!m || typeof m.id !== "string" || !m.id.trim()) continue;
      out.push(m);
    }
    return out;
  }

  function skillMasteryDisplayName(entry) {
    if (!entry) return "";
    const t = entry.text || entry.texts;
    const nm = t && t.name != null ? normalizeSkillTextFragment(t.name) : "";
    return nm || entry.id || "";
  }

  function skillMasteryDescRaw(entry) {
    if (!entry) return "";
    const t = entry.text || entry.texts;
    return t && t.desc != null ? normalizeSkillTextFragment(t.desc) : "";
  }

  function selectedClassSkillMasteryId(skillId, sk) {
    const entries = skillMasteryEntries(sk);
    if (!entries.length) return null;
    const pick =
      plannerDamagePreviewSettings.classSkillMasteryBySkillId &&
      plannerDamagePreviewSettings.classSkillMasteryBySkillId[skillId];
    if (typeof pick === "string" && pick && entries.some((e) => e.id === pick)) return pick;
    return null;
  }

  function setClassSkillMasteryId(skillId, masteryId) {
    if (!plannerDamagePreviewSettings.classSkillMasteryBySkillId) {
      plannerDamagePreviewSettings.classSkillMasteryBySkillId = {};
    }
    if (!masteryId) delete plannerDamagePreviewSettings.classSkillMasteryBySkillId[skillId];
    else plannerDamagePreviewSettings.classSkillMasteryBySkillId[skillId] = masteryId;
  }

  /** Mystic Empowerment M2: **`"magic"`** (default) or **`"physical"`**. */
  function masteryBuffChoiceForSkill(skillId) {
    const root = plannerDamagePreviewSettings && plannerDamagePreviewSettings.masteryBuffChoiceBySkillId;
    if (!root || typeof root !== "object" || typeof skillId !== "string" || !skillId) return "magic";
    return root[skillId] === "physical" ? "physical" : "magic";
  }

  function setMasteryBuffChoice(skillId, choice) {
    if (typeof skillId !== "string" || !skillId) return;
    if (!plannerDamagePreviewSettings.masteryBuffChoiceBySkillId || typeof plannerDamagePreviewSettings.masteryBuffChoiceBySkillId !== "object") {
      plannerDamagePreviewSettings.masteryBuffChoiceBySkillId = {};
    }
    plannerDamagePreviewSettings.masteryBuffChoiceBySkillId[skillId] =
      choice === "physical" ? "physical" : "magic";
  }

  function mysticEmpowermentStatusIdForBuffChoice(choice) {
    return choice === "physical" ? MYSTIC_EMPOWERMENT_STATUS_PHYSICAL : MYSTIC_EMPOWERMENT_STATUS_MAGIC;
  }

  /** Host **`texts.refs`** aimed at the status row that matches the M2 buff pick (for **`::ref_val2%::`**). */
  function mysticEmpowermentRefsHostForM2(hostSk) {
    if (!hostSk || hostSk.id !== MYSTIC_EMPOWERMENT_HOST_ID) return hostSk;
    const stId = mysticEmpowermentStatusIdForBuffChoice(masteryBuffChoiceForSkill(hostSk.id));
    const texts = hostSk.texts && typeof hostSk.texts === "object" ? { ...hostSk.texts } : {};
    return { ...hostSk, texts: { ...texts, refs: { ref: stId } } };
  }

  function mysticEmpowermentM2MasteryFlatBonus(classId) {
    const out = {};
    if (classId !== "Mage") return out;
    const host = skillById[MYSTIC_EMPOWERMENT_HOST_ID];
    if (!host) return out;
    if (!passiveScriptGlobalMultApplies(MYSTIC_EMPOWERMENT_HOST_ID)) return out;
    if (selectedClassSkillMasteryId(MYSTIC_EMPOWERMENT_HOST_ID, host) !== MYSTIC_EMPOWERMENT_M2_ID) return out;
    const choice = masteryBuffChoiceForSkill(MYSTIC_EMPOWERMENT_HOST_ID);
    const st = skillById[mysticEmpowermentStatusIdForBuffChoice(choice)];
    if (!st || !Array.isArray(st.affixes)) return out;
    const attr = choice === "physical" ? "PhysicalMastery" : "MagicMastery";
    for (let i = 0; i < st.affixes.length; i++) {
      const ax = st.affixes[i];
      if (!ax || ax.ref !== "TAttribute_Flat") continue;
      if (ax.target && ax.target.attribute !== attr) continue;
      const c = ax.conds;
      if (!c || c.mastery !== MYSTIC_EMPOWERMENT_M2_ID) continue;
      if (typeof ax.val === "number" && Number.isFinite(ax.val)) {
        out[attr] = presentationFlatForAffixFactor(ax.val, 1);
      }
      break;
    }
    return out;
  }

  function masteryEntryById(sk, masteryId) {
    if (!masteryId) return null;
    const entries = skillMasteryEntries(sk);
    for (let i = 0; i < entries.length; i++) {
      if (entries[i].id === masteryId) return entries[i];
    }
    return null;
  }

  /** Host skill vars merged with the selected rune’s **`vars`** (for script / desc). */
  function mergedVarsForSkillWithSelectedMastery(sk) {
    const base = mergedVarsForSkillDesc(sk, skillDamageScalingCondsRank(sk));
    const mid = sk && sk.id ? selectedClassSkillMasteryId(sk.id, sk) : null;
    const entry = mid && sk ? masteryEntryById(sk, mid) : null;
    if (entry && entry.vars && typeof entry.vars === "object") {
      return { ...base, ...entry.vars };
    }
    return base;
  }

  /** Resolve a mastery **`text.desc`** using host **`texts.refs`**, host/mastery vars, and mastery props. */
  function masteryDescHtml(masteryEntry, hostSk, combatCtx) {
    let raw = skillMasteryDescRaw(masteryEntry);
    if (masteryEntry && masteryEntry.id && MASTERY_DESC_TEXT_OVERRIDE[masteryEntry.id]) {
      raw = MASTERY_DESC_TEXT_OVERRIDE[masteryEntry.id];
    }
    if (!raw || !hostSk) return "";
    const mergedVars = {
      ...(hostSk.vars && typeof hostSk.vars === "object" ? hostSk.vars : {}),
      ...(masteryEntry.vars && typeof masteryEntry.vars === "object" ? masteryEntry.vars : {}),
    };
    const faux = { ...hostSk, vars: mergedVars };
    const refsHost =
      masteryEntry && masteryEntry.id === MYSTIC_EMPOWERMENT_M2_ID
        ? mysticEmpowermentRefsHostForM2(hostSk)
        : hostSk;
    const marked = expandSkillDescPlaceholdersMarked(raw, faux, true, combatCtx, undefined, 1, {
      refsHost,
      masteryEntry,
    });
    const fin = finalizeUnresolvedSkillPlaceholders(marked);
    return skillDescMarkedStringToHtml(fin);
  }

  function mysticEmpowermentM2BuffChoiceLabel(choice) {
    const attr = choice === "physical" ? "PhysicalMastery" : "MagicMastery";
    const nm = displayNameForAttr(attr) || attr;
    return `${nm} +5%`;
  }

  /** M2 rune: pick Magic vs Physical Mastery buff (inside **`.gp-char-skill__mastery`**). */
  function syncMysticEmpowermentM2BuffChoice(masteryWrap, sid, sk, ctxForSkill) {
    if (!masteryWrap || sid !== MYSTIC_EMPOWERMENT_HOST_ID || !sk) return;
    const selectedMid = selectedClassSkillMasteryId(sid, sk);
    const show = selectedMid === MYSTIC_EMPOWERMENT_M2_ID;
    let choiceWrap = masteryWrap.querySelector(".gp-char-skill__mastery-choice");
    if (!show) {
      if (choiceWrap) choiceWrap.hidden = true;
      return;
    }
    const cur = masteryBuffChoiceForSkill(sid);
    const activeEntry = masteryEntryById(sk, MYSTIC_EMPOWERMENT_M2_ID);
    const refreshM2Desc = () => {
      const masteryDesc = masteryWrap.querySelector(".gp-char-skill__mastery-desc");
      if (masteryDesc && activeEntry) {
        masteryDesc.innerHTML = `<span class="gp-char-skill__mastery-desc-name">${escapeHtml(
          skillMasteryDisplayName(activeEntry)
        )}</span> ${masteryDescHtml(activeEntry, sk, ctxForSkill)}`;
      }
    };
    if (!choiceWrap) {
      choiceWrap = document.createElement("div");
      choiceWrap.className = "gp-char-skill__mastery-choice";
      const choiceHd = document.createElement("div");
      choiceHd.className = "gp-char-skill__mastery-choice-hd";
      choiceHd.textContent = "Mastery buff";
      choiceWrap.appendChild(choiceHd);
      const btnRow = document.createElement("div");
      btnRow.className = "gp-char-skill__mastery-choice-btns";
      btnRow.setAttribute("role", "group");
      btnRow.setAttribute("aria-label", "Cosmic Singularity mastery attribute");
      for (const ch of ["magic", "physical"]) {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "gp-char-skill__mastery-choice-btn";
        btn.dataset.mysticBuff = ch;
        btn.textContent = mysticEmpowermentM2BuffChoiceLabel(ch);
        btn.addEventListener("click", (ev) => {
          ev.preventDefault();
          setMasteryBuffChoice(sid, ch);
          syncMysticEmpowermentM2BuffChoice(masteryWrap, sid, sk, ctxForSkill);
          refreshM2Desc();
          if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
          else if (typeof plannerRefreshSkillsPanelsHook === "function") plannerRefreshSkillsPanelsHook();
        });
        btnRow.appendChild(btn);
      }
      choiceWrap.appendChild(btnRow);
      masteryWrap.appendChild(choiceWrap);
    }
    choiceWrap.hidden = false;
    choiceWrap.querySelectorAll(".gp-char-skill__mastery-choice-btn").forEach((btn) => {
      const ch = btn.dataset.mysticBuff;
      const on = ch === cur;
      btn.setAttribute("aria-pressed", on ? "true" : "false");
      btn.classList.toggle("gp-char-skill__mastery-choice-btn--active", on);
    });
  }

  /** Drop invalid rune picks when class changes. */
  function sanitizeClassSkillMasteriesForClass(classId) {
    const validSkill = new Set();
    const cls = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const classRows = (cls && cls.skills) || [];
    for (let ri = 0; ri < classRows.length; ri++) {
      const sid = classRows[ri] && classRows[ri].skill;
      if (typeof sid !== "string" || !sid || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      const sk = skillById[sid];
      if (!sk || skillIconIsPassiveFrame(sk)) continue;
      if (!skillMasteryEntries(sk).length) continue;
      validSkill.add(sid);
    }
    const map = plannerDamagePreviewSettings.classSkillMasteryBySkillId;
    if (!map || typeof map !== "object") return;
    for (const k of Object.keys(map)) {
      if (!validSkill.has(k)) delete map[k];
    }
  }

  /** Collapse any placeholders the expander did not fill — show the token id instead of an ellipsis. */
  function finalizeUnresolvedSkillPlaceholders(text) {
    return String(text || "")
      .replace(/::([\s\S]*?)::/g, (_, inner) => {
        const raw = String(inner).trim();
        return raw ? `[${raw}]` : "";
      })
      .replace(/\s+/g, " ")
      .trim();
  }

  /** Delimits resolved substitutions when building HTML (private-use chars; stripped before display). */
  const SKILL_DESC_MARK_S = "\uE000";
  const SKILL_DESC_MARK_E = "\uE001";
  /** Delimits **`::dmg::`**-style values expanded for **`gp-char-skill__dmg-tip`** (see **`skillDescMarkedStringToHtml`**). */
  const SKILL_DESC_MARK_DMG_S = "\uE002";
  const SKILL_DESC_MARK_DMG_E = "\uE003";

  function isSkillDescDamagePreviewKey(key) {
    const k = String(key || "").toLowerCase();
    return k === "dmg" || k === "dmgs" || k === "heal" || k === "shield" || k === "dmg2" || k === "dmg3";
  }

  /** Internal preview line marker + skill id (`formatPlainStatLineHtml` only). */
  const GP_PREVIEW_TRINKET_SKILL_PREFIX = "\uE020GP_TRSK\uE021";

  /** Narrative prose stays plain; resolved substitutions use `.gp-skill-desc-val` (accent); damage previews also get **`gp-char-skill__dmg-tip`**. */
  function skillDescMarkedStringToHtml(s) {
    const MS = SKILL_DESC_MARK_S;
    const ME = SKILL_DESC_MARK_E;
    const MDS = SKILL_DESC_MARK_DMG_S;
    const MDE = SKILL_DESC_MARK_DMG_E;
    let out = "";
    let i = 0;
    const str = String(s || "");
    function appendEscapedTextWithValTags(text) {
      let html = "";
      let pos = 0;
      const re = /<val>([\s\S]*?)<\/val>/gi;
      let m;
      while ((m = re.exec(text))) {
        if (m.index > pos) html += escapeHtml(text.slice(pos, m.index));
        html += `<span class="gp-skill-desc-val">${escapeHtml(m[1])}</span>`;
        pos = m.index + m[0].length;
      }
      if (pos < text.length) html += escapeHtml(text.slice(pos));
      return html;
    }
    while (i < str.length) {
      const nStart = str.indexOf(MS, i);
      const dStart = str.indexOf(MDS, i);
      let start = -1;
      let useDmg = false;
      if (nStart >= 0 && dStart >= 0) {
        if (dStart <= nStart) {
          start = dStart;
          useDmg = true;
        } else {
          start = nStart;
        }
      } else if (dStart >= 0) {
        start = dStart;
        useDmg = true;
      } else if (nStart >= 0) {
        start = nStart;
      } else {
        out += appendEscapedTextWithValTags(str.slice(i));
        break;
      }
      if (start > i) out += appendEscapedTextWithValTags(str.slice(i, start));
      const openLen = useDmg ? MDS.length : MS.length;
      const closeCh = useDmg ? MDE : ME;
      const end = str.indexOf(closeCh, start + openLen);
      if (end < 0) {
        out += appendEscapedTextWithValTags(str.slice(start));
        break;
      }
      const inner = str.slice(start + openLen, end);
      if (useDmg) {
        const parts = inner.split("\x1f");
        let rankStr = "1";
        let phKey = "dmg";
        let displayVal = inner;
        if (parts.length >= 3) {
          rankStr = parts[0];
          phKey = parts[1];
          displayVal = parts.slice(2).join("\x1f");
        }
        const rk = escapeHtml(String(rankStr));
        const pk = escapeHtml(String(phKey));
        const dv = escapeHtml(String(displayVal));
        out += `<span class="gp-skill-desc-val gp-char-skill__dmg-tip" data-gp-dmg-tip="desc" data-gp-dmg-rank="${rk}" data-gp-dmg-key="${pk}">${dv}</span>`;
      } else {
        out += `<span class="gp-skill-desc-val">${escapeHtml(inner)}</span>`;
      }
      i = end + closeCh.length;
    }
    return out;
  }

  /** Skill description with resolved tokens wrapped for styling (`skillDescText` stays plain). */
  function skillDescHtml(sk, combatCtx, weaponEffectiveRank) {
    if (!sk) return "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const raw = skillDescRaw(sk);
    let main = "";
    if (raw) {
      const marked = expandSkillDescPlaceholdersMarked(raw, sk, true, ctx, weaponEffectiveRank, 1);
      const fin = finalizeUnresolvedSkillPlaceholders(marked);
      main = skillDescMarkedStringToHtml(fin);
    }
    const ranks = skillRankDescsHtml(sk, combatCtx, weaponEffectiveRank);
    if (!main && !ranks) return "";
    if (!ranks) return main;
    if (!main) return `<div class="gp-skill-rank-descs">${ranks}</div>`;
    return `${main}<div class="gp-skill-rank-descs">${ranks}</div>`;
  }

  function skillDescHtmlForPreview(sk, combatCtx) {
    return skillDescHtml(sk, combatCtx);
  }

  function skillDescRaw(sk) {
    const t = sk && sk.texts;
    if (!t) return "";
    let d = t.desc;
    if (d && typeof d === "object" && d.v != null) d = String(d.v);
    return typeof d === "string" ? d : "";
  }

  function normalizeSkillTextFragment(v) {
    if (v == null) return "";
    if (typeof v === "string") return v;
    if (typeof v === "object" && v.v != null) return String(v.v);
    return "";
  }

  /** `texts.rankDescs[]` → `{ rank, desc }` sorted by rank (strings normalized like `texts.desc`). */
  function skillRankDescEntries(sk) {
    const t = sk && sk.texts;
    const arr = t && Array.isArray(t.rankDescs) ? t.rankDescs : [];
    const out = [];
    for (let i = 0; i < arr.length; i++) {
      const row = arr[i];
      if (!row || typeof row.rank !== "number") continue;
      const d = normalizeSkillTextFragment(row.desc);
      if (!d) continue;
      out.push({ rank: row.rank, desc: d });
    }
    out.sort((a, b) => a.rank - b.rank);
    return out;
  }

  /** Minimum weapon rank required for a step/effect to contribute to damage previews (defaults to **1**). */
  function skillEffectDamageMinRank(step, effect) {
    let m = 1;
    const c1 = effect && effect.cond && effect.cond.minRank;
    const c2 = step && step.cond && step.cond.minRank;
    if (typeof c1 === "number" && Number.isFinite(c1)) m = Math.max(m, Math.floor(c1));
    if (typeof c2 === "number" && Number.isFinite(c2)) m = Math.max(m, Math.floor(c2));
    return Math.max(1, m);
  }

  /** HTML for each `rankDescs` line (same placeholder rules as base `desc`). When **`weaponEffectiveRank`** is set (weapon
   * preview), lines whose **`rank`** is **greater** than that rank are still output but marked **`gp-skill-rank-desc--beyond-preview`**
   * (greyed / inert) so higher-rank effects stay visible without reading as active.
   */
  function skillRankDescsHtml(sk, combatCtx, weaponEffectiveRank) {
    const entries = skillRankDescEntries(sk);
    if (!entries.length || !sk) return "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const previewCap =
      weaponEffectiveRank != null && Number.isFinite(weaponEffectiveRank)
        ? clamp(Math.floor(weaponEffectiveRank), 1, 99)
        : null;
    let html = "";
    for (let i = 0; i < entries.length; i++) {
      const { rank, desc } = entries[i];
      const beyond = previewCap != null && rank > previewCap;
      const marked = expandSkillDescPlaceholdersMarked(desc, sk, true, ctx, weaponEffectiveRank, rank);
      const fin = finalizeUnresolvedSkillPlaceholders(marked);
      const inner = skillDescMarkedStringToHtml(fin);
      if (!inner) continue;
      html += `<div class="gp-skill-rank-desc${beyond ? " gp-skill-rank-desc--beyond-preview" : ""}"${
        beyond ? ` title="Requires rank ${rank} (previewing rank ${previewCap})"` : ""
      }><span class="gp-skill-rank-desc__label">Rank ${rank}</span> <span class="gp-skill-rank-desc__body">${inner}</span></div>`;
    }
    return html;
  }

  /**
   * When **`texts.refs.ref`** is absent from CDB but **`{skillId}_Status`** exists (common trinket pattern), the runtime still
   * links **`::ref_*::`** tokens to that row — mirror it so **`::ref_val1::`** reads **`affixes[0].val`** (e.g. Prismatic Pearl → **8**).
   */
  function inferPrimaryRefSkillRow(sk) {
    const bid = sk && sk.id;
    if (typeof bid !== "string" || !bid) return null;
    const row = skillById[`${bid}_Status`];
    return row || null;
  }

  /** Status ids from host **`steps[].props.status.ref`**, optionally filtered by **`cond.mastery`**. */
  function statusRefIdsFromHostSteps(hostSk, masteryEntryId) {
    const steps = hostSk && Array.isArray(hostSk.steps) ? hostSk.steps : [];
    const all = [];
    const masteryMatched = [];
    for (let i = 0; i < steps.length; i++) {
      const st = steps[i];
      const ref =
        st && st.props && st.props.status && typeof st.props.status.ref === "string"
          ? st.props.status.ref.trim()
          : "";
      if (!ref) continue;
      all.push(ref);
      const cm = st.cond && st.cond.mastery;
      if (masteryEntryId != null && cm != null && String(cm) === String(masteryEntryId)) {
        masteryMatched.push(ref);
      }
    }
    if (masteryMatched.length) return masteryMatched;
    return all;
  }

  /**
   * Resolve **`texts.refs`** id for a slot; when absent, infer from mastery-gated / status **`steps`**
   * (e.g. **`Warrior_Rage_Strike`** M1 → **`Slow`**).
   */
  function skillRefIdForSlot(hostSk, slot, refOpts) {
    if (!hostSk || (slot !== "ref" && slot !== "ref1" && slot !== "ref2" && slot !== "ref3")) return "";
    const t = hostSk.texts && hostSk.texts.refs;
    if (t && typeof t === "object") {
      if ((slot === "ref" || slot === "ref1") && typeof t.ref === "string" && t.ref.trim()) return t.ref.trim();
      if (slot === "ref2" && typeof t.ref2 === "string" && t.ref2.trim()) return t.ref2.trim();
      if (slot === "ref3" && typeof t.ref3 === "string" && t.ref3.trim()) return t.ref3.trim();
    }
    const masteryEntryId = refOpts && refOpts.masteryEntryId;
    const fromSteps = statusRefIdsFromHostSteps(hostSk, masteryEntryId);
    if (slot === "ref" || slot === "ref1") return fromSteps[0] || "";
    if (slot === "ref2") return fromSteps[1] || "";
    if (slot === "ref3") return fromSteps[2] || "";
    return "";
  }

  /** `texts.refs.ref` / `ref2` / `ref3` (and `ref1` → primary ref) → skill rows. */
  function skillRefTargetBySlot(sk, slot, refOpts) {
    if (!sk || (slot !== "ref" && slot !== "ref1" && slot !== "ref2" && slot !== "ref3")) return null;
    let id = skillRefIdForSlot(sk, slot, refOpts);
    if (!id && (slot === "ref" || slot === "ref1")) {
      const fb = inferPrimaryRefSkillRow(sk);
      if (fb) return fb;
    }
    return id ? skillById[id] || null : null;
  }

  function skillRefTargetFromTexts(sk) {
    return skillRefTargetBySlot(sk, "ref");
  }

  /**
   * **`texts.refs`** targets (`ref`, `ref2`, `ref3`) — weapon passives often leave **`steps`** empty and put damage on these rows
   * (**`Sword_Swarm_Passive`** → **`Sword_Swarm_Passive_Swarm`**).
   * @returns {object[]} unique **`skill`** sheet rows (same order: ref, ref2, ref3).
   */
  function referencedSkillsForMergedDamage(sk) {
    const out = [];
    const seen = new Set();
    function pushRow(row) {
      if (!row || typeof row.id !== "string" || !row.id || seen.has(row.id)) return;
      seen.add(row.id);
      out.push(row);
    }
    const t = sk && sk.texts && sk.texts.refs;
    if (!t || typeof t !== "object") return out;
    if (typeof t.ref === "string" && t.ref.trim()) pushRow(skillById[t.ref.trim()]);
    if (typeof t.ref2 === "string" && t.ref2.trim()) pushRow(skillById[t.ref2.trim()]);
    if (typeof t.ref3 === "string" && t.ref3.trim()) pushRow(skillById[t.ref3.trim()]);
    return out;
  }

  /** Merge **`refs`** damage into previews when the host is passive-authored or a known multi-hit host (e.g. Static Nova M2). */
  function skillAggregatesReferencedDamageRows(sk) {
    if (!sk) return false;
    if (sk.id === BOOK_WATER_ORBS_SKILL2_ID) return true;
    if (skillIconIsPassiveFrame(sk)) return true;
    if (sk.id === "Mage_StaticNova") {
      const mid = selectedClassSkillMasteryId(sk.id, sk);
      return mid === STATIC_NOVA_M2_MASTERY_ID;
    }
    return false;
  }

  function skillSkipsCombatDamagePreview(sk) {
    return !!(sk && typeof sk.id === "string" && SKILL_IDS_SKIP_COMBAT_DAMAGE_PREVIEW.has(sk.id));
  }

  /** **`steps[].cond.mastery` / `effects[].cond.mastery`** — include only when that rune is selected on **`hostSk`**. */
  function skillHostStepEffectMatchesMastery(hostSk, step, effect) {
    if (!hostSk) return true;
    const sel = selectedClassSkillMasteryId(hostSk.id, hostSk);
    return skillStepEffectMatchesMasteryId(step, effect, sel);
  }

  function skillStepEffectMatchesMasteryId(step, effect, masteryId) {
    const gates = [];
    if (step && step.cond && step.cond.mastery != null && step.cond.mastery !== "") {
      gates.push(String(step.cond.mastery));
    }
    if (effect && effect.cond && effect.cond.mastery != null && effect.cond.mastery !== "") {
      gates.push(String(effect.cond.mastery));
    }
    if (!gates.length) return true;
    if (!masteryId) return false;
    for (let gi = 0; gi < gates.length; gi++) {
      if (gates[gi] !== String(masteryId)) return false;
    }
    return true;
  }

  /** Sheet affix stack count for aura statuses (not × **`maxStacks`** prayer stacks). */
  function statusPreviewSheetAffixStacks(statusSk) {
    if (statusSk && statusSk.id === FISTS_SINK_TO_BOTTOM_CRIT_STATUS_ID) return 0;
    if (statusSk && statusSk.id === CRUSADER_STATUS_ID) return 1;
    const stacks = statusPreviewEffectiveStacks(statusSk);
    if (stacks <= 0) return 0;
    if (statusSk && STATUS_PREVIEW_AURA_STACK_OVERRIDES.has(statusSk.id)) return 1;
    return stacks;
  }

  /** Whether **`statusId`** from **`hostSk`** should apply sheet buffs for the selected host rune. */
  function statusBuffAppliesForHostMastery(hostSk, statusId, hostMid) {
    if (!hostSk || !statusId) return false;
    if (statusId === JUDGMENT_STATUS_ID && hostSk.id === JUDGMENT_HOST_ID) {
      return hostMid === JUDGMENT_M1_MASTERY_ID;
    }
    return true;
  }

  /** Separate merged-damage rows per mastery-gated step (e.g. **Radiant Verdict** M1 floor). */
  function previewDamageGroupKindLabel(p, consumerSk, step) {
    let kl = (p && p.kindLabel) || "Hit";
    if (!consumerSk || !step) return kl;
    const mid = step.cond && step.cond.mastery;
    if (mid) {
      const me = masteryEntryById(consumerSk, mid);
      const runeName = me ? skillMasteryDisplayName(me) : String(mid);
      return `${kl} (${runeName})`;
    }
    if (consumerSk.id === RADIANT_VERDICT_ID && step.id) {
      return `${kl} (${step.id})`;
    }
    return kl;
  }

  function globalBuffStatusARatioVal(hostId, statusId, attr, defaultRatio) {
    if (!globalBuffHostOnSkillBar(hostId) || !passiveScriptGlobalMultApplies(hostId)) return 0;
    const st = skillById[statusId];
    if (!st || !Array.isArray(st.affixes)) return defaultRatio;
    for (let i = 0; i < st.affixes.length; i++) {
      const ax = st.affixes[i];
      if (!ax || ax.ref !== "TAttribute_ARatio") continue;
      if ((ax.target && ax.target.attribute) !== attr) continue;
      if (typeof ax.val === "number" && Number.isFinite(ax.val)) return statusPreviewAffixVal(st, ax);
    }
    return defaultRatio;
  }

  /** Multiplier for future heal previews (**`1 + ratio`**). */
  function globalClassBuffHealMultiplier() {
    let m = 1;
    for (let i = 0; i < GLOBAL_BUFF_HEAL_SHIELD_FROM_STATUS.length; i++) {
      const rule = GLOBAL_BUFF_HEAL_SHIELD_FROM_STATUS[i];
      if (rule.attr !== "HealGivenMultiplier") continue;
      const r = globalBuffStatusARatioVal(rule.hostId, rule.statusId, rule.attr, rule.defaultRatio);
      if (r > 0) m *= 1 + r;
    }
    return m;
  }

  /** Multiplier for future shield previews (**`1 + ratio`**). */
  function globalClassBuffShieldMultiplier() {
    let m = 1;
    for (let i = 0; i < GLOBAL_BUFF_HEAL_SHIELD_FROM_STATUS.length; i++) {
      const rule = GLOBAL_BUFF_HEAL_SHIELD_FROM_STATUS[i];
      if (rule.attr !== "ShieldPowerMultiplier") continue;
      const r = globalBuffStatusARatioVal(rule.hostId, rule.statusId, rule.attr, rule.defaultRatio);
      if (r > 0) m *= 1 + r;
    }
    return m;
  }

  function finisherMaxComboPoints() {
    const sk = skillById[FINISHER_SKILL_ID];
    if (!sk) return 5;
    const mid = selectedClassSkillMasteryId(sk.id, sk);
    return mid === FINISHER_M2_MASTERY_ID ? 6 : 5;
  }

  function previewFinisherComboPointsUsed() {
    const raw = plannerDamagePreviewSettings.previewFinisherComboPoints;
    const maxCp = finisherMaxComboPoints();
    if (typeof raw === "number" && Number.isFinite(raw)) {
      return clamp(Math.floor(raw), 0, maxCp);
    }
    return maxCp;
  }

  function previewUrgeFinisherStreakCount() {
    const raw = plannerDamagePreviewSettings.previewUrgeFinisherStreak;
    if (typeof raw === "number" && Number.isFinite(raw)) {
      return clamp(Math.floor(raw), 0, 99);
    }
    return 0;
  }

  function skillIsWeaponSkillForPreview(sk) {
    if (!sk) return false;
    if (skillRowIsAttackChainType(sk)) return false;
    const ty = skillRowType(sk);
    return ty === SKILL_TYPE_WEAPON_ACTIVE || ty === SKILL_TYPE_WEAPON_PASSIVE;
  }

  function globalBuffHostOnSkillBar(hostId) {
    if (typeof hostId !== "string" || !hostId) return false;
    const hosts = collectCombatPanelSkillHostIds(plannerSelectedClassId(), selection);
    return hosts.has(hostId);
  }

  function globalBuffStatusDamageAdditive(hostId, statusId, varKey, defaultAdd) {
    if (!globalBuffHostOnSkillBar(hostId) || !passiveScriptGlobalMultApplies(hostId)) return 0;
    const st = skillById[statusId];
    if (!st) return defaultAdd;
    const v = skillVarLookupLoose(st, varKey, st.vars);
    return typeof v === "number" && Number.isFinite(v) ? v : defaultAdd;
  }

  function thrillOfTheHunterDamageAdditive(consumerSk) {
    if (!consumerSk || !skillIsAttackActionForBuffs(consumerSk)) return 0;
    if (!globalBuffHostOnSkillBar(BOW_THRILL_OF_THE_HUNTER_ID)) return 0;
    if (!passiveScriptGlobalMultApplies(BOW_THRILL_OF_THE_HUNTER_ID)) return 0;
    const host = skillById[BOW_THRILL_OF_THE_HUNTER_ID];
    const rank = host ? skillDamageScalingCondsRank(host) : 1;
    const bag = host ? mergedVarsForSkillDesc(host, rank) : null;
    const add = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : rank >= 2 ? 0.75 : 0.5;
    return add > 0 ? add : 0;
  }

  function pyroclasmMagicDamageMultiplier(consumerSk, previewHit) {
    if (!consumerSk) return 1;
    if (!previewHit || previewHit.affinityRoot !== "Magic") return 1;
    if (!globalBuffHostOnSkillBar(STAFF_PYROCLASM_ID)) return 1;
    if (!passiveScriptGlobalMultApplies(STAFF_PYROCLASM_ID)) return 1;
    const st = skillById[STAFF_PYROCLASM_STATUS_ID];
    const bag = st ? mergedVarsForSkillDesc(st, 1) : null;
    const add = bag && typeof bag.var1 === "number" && Number.isFinite(bag.var1) ? bag.var1 : 0.08;
    return add > 0 ? 1 + add : 1;
  }

  /** **Scorching Embers** — **`Staff_Craft_C_Status`** stacks add **`var1 × stacks`** to magic [WeaponSkill] damage (script **`onSkillProc`**). */
  function scorchingEmbersMagicWeaponSkillMultiplier(consumerSk) {
    if (!consumerSk || !skillIsWeaponSkillForPreview(consumerSk)) return 1;
    if (!globalBuffHostOnSkillBar(STAFF_SCORCHING_EMBERS_ID)) return 1;
    if (!passiveScriptGlobalMultApplies(STAFF_SCORCHING_EMBERS_ID)) return 1;
    const st = skillById[STAFF_SCORCHING_EMBERS_STATUS_ID];
    const stacks = st ? statusPreviewStackCount(st) : 0;
    if (stacks <= 0) return 1;
    const host = skillById[STAFF_SCORCHING_EMBERS_ID];
    const rank = host ? skillDamageScalingCondsRank(host) : 1;
    const bag = st ? mergedVarsForSkillDesc(st, rank) : null;
    const per = bag && typeof bag.var1 === "number" && Number.isFinite(bag.var1) ? bag.var1 : 0.03;
    return 1 + per * stacks;
  }

  /** Multiplicative bonus from class buff hosts (Berserk, Death Mark, Blink M3 weapon, Finisher CP, Urge streak). */
  function globalClassBuffDamageMultiplier(consumerSk) {
    let m = 1;
    for (let i = 0; i < GLOBAL_BUFF_DAMAGE_FROM_STATUS.length; i++) {
      const rule = GLOBAL_BUFF_DAMAGE_FROM_STATUS[i];
      const add = globalBuffStatusDamageAdditive(rule.hostId, rule.statusId, rule.varKey, rule.defaultAdd);
      if (add > 0) m *= 1 + add;
    }
    const blinkHost = skillById.Mage_Blink;
    if (
      blinkHost &&
      globalBuffHostOnSkillBar("Mage_Blink") &&
      passiveScriptGlobalMultApplies("Mage_Blink") &&
      selectedClassSkillMasteryId("Mage_Blink", blinkHost) === BLINK_M3_MASTERY_ID &&
      consumerSk &&
      skillIsWeaponSkillForPreview(consumerSk)
    ) {
      const add = globalBuffStatusDamageAdditive("Mage_Blink", "Mage_Blink_Mastery3", "damage", 0.15);
      if (add > 0) m *= 1 + add;
    }
    if (consumerSk && consumerSk.id === FINISHER_SKILL_ID) {
      const cp = previewFinisherComboPointsUsed();
      const finSk = skillById[FINISHER_SKILL_ID];
      const perCp = finSk && finSk.vars && typeof finSk.vars.var1 === "number" ? finSk.vars.var1 : 0.3;
      if (cp > 0 && perCp > 0) m *= 1 + cp * perCp;
      const urgeSk = skillById[URGE_TO_KILL_HOST_ID];
      const urgeM1Selected =
        urgeSk && selectedClassSkillMasteryId(URGE_TO_KILL_HOST_ID, urgeSk) === URGE_TO_KILL_M1_MASTERY_ID;
      if (urgeM1Selected && passiveScriptGlobalMultApplies(URGE_TO_KILL_HOST_ID)) {
        const streak = previewUrgeFinisherStreakCount();
        if (streak > 0) m *= 1 + streak * 0.1;
      }
    }
    if (globalBuffHostOnSkillBar(CRUSADER_HOST_ID) && passiveScriptGlobalMultApplies(CRUSADER_HOST_ID)) {
      const crusSt = skillById[CRUSADER_STATUS_ID];
      if (crusSt && statusPreviewSheetAffixStacks(crusSt) > 0) {
        m *=
          1 +
          globalBuffStatusARatioVal(
            CRUSADER_HOST_ID,
            CRUSADER_STATUS_ID,
            "DamageModifier",
            0.1
          );
      }
    }
    const thrillAdd = thrillOfTheHunterDamageAdditive(consumerSk);
    if (thrillAdd > 0) m *= 1 + thrillAdd;
    return m;
  }

  function plannerKnivesTempestFoeArmorShredActive() {
    const host = skillById.Rogue_KnivesTempest;
    if (
      !host ||
      !globalBuffHostOnSkillBar("Rogue_KnivesTempest") ||
      !passiveScriptGlobalMultApplies("Rogue_KnivesTempest")
    ) {
      return false;
    }
    return selectedClassSkillMasteryId("Rogue_KnivesTempest", host) === KNIVES_TEMPEST_M3_MASTERY_ID;
  }

  /** Extra damage multiplier when Knives Tempest M3 shreds foe armor (−20% armor rating). */
  function plannerKnivesTempestArmorShredDamageMult(combatCtx, affinityRoot) {
    if (!plannerKnivesTempestFoeArmorShredActive() || !combatCtx || !combatCtx.derived) return 1;
    if (affinityRoot !== "Physical" && affinityRoot !== "Magic") return 1;
    const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const ml =
      combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx.foeUnitId != null ? combatCtx.foeUnitId : "median";
    const am = plannerMonsterArmorMagicPts(ml, foeId);
    const basePts = affinityRoot === "Physical" ? am.armorPts : am.magicArmorPts;
    const baseMult = 1 - plannerAffinityMitigatedFraction(basePts, 0, cl);
    const shredPts = basePts * 0.8;
    const shredMult = 1 - plannerAffinityMitigatedFraction(shredPts, 0, cl);
    if (!(baseMult > 0)) return 1;
    return shredMult / baseMult;
  }

  function skillVarLookup(sk, key, mergedVars) {
    const varsObj = mergedVars !== undefined ? mergedVars : sk && sk.vars;
    const v = varsObj && varsObj[key];
    return typeof v === "number" && Number.isFinite(v) ? v : null;
  }

  function skillVarLookupLoose(sk, key, mergedVars) {
    if (!sk || !key) return null;
    let v = skillVarLookup(sk, key, mergedVars);
    if (v != null) return v;
    const pairs = [
      ["val1", "var1"],
      ["val2", "var2"],
      ["val3", "var3"],
      ["va1", "var1"],
      ["dmg", "damage"],
      ["damage", "dmg"],
    ];
    const k = String(key);
    for (let i = 0; i < pairs.length; i++) {
      const [a, b] = pairs[i];
      if (k === a) {
        v = skillVarLookup(sk, b, mergedVars);
        if (v != null) return v;
      }
      if (k === b) {
        v = skillVarLookup(sk, a, mergedVars);
        if (v != null) return v;
      }
    }
    return null;
  }

  /** Merge `sk.vars` with every `props.rankOverride.vars` whose `minRank <= targetRank` (later ranks win). */
  function effectiveSkillVarsForWeaponRank(sk, targetRank) {
    const base = sk.vars && typeof sk.vars === "object" ? { ...sk.vars } : {};
    const ro = sk.props && Array.isArray(sk.props.rankOverride) ? [...sk.props.rankOverride] : [];
    ro.sort((a, b) => (a.minRank || 0) - (b.minRank || 0));
    for (let i = 0; i < ro.length; i++) {
      const entry = ro[i];
      if (!entry || typeof entry.minRank !== "number") continue;
      if (entry.minRank > targetRank) continue;
      if (entry.vars && typeof entry.vars === "object") Object.assign(base, entry.vars);
    }
    return base;
  }

  /** Vars bag for description tokens; omit weapon rank for class / trinket / generic previews. */
  function mergedVarsForSkillDesc(sk, weaponEffectiveRank) {
    if (!sk) return {};
    if (weaponEffectiveRank == null || weaponEffectiveRank < 1) {
      return sk.vars && typeof sk.vars === "object" ? sk.vars : {};
    }
    return effectiveSkillVarsForWeaponRank(sk, weaponEffectiveRank);
  }

  /**
   * Nth **`affixes[]`** row with a finite **`val`** whose **`conds`** match **`descRank`** (sheet order), for **`::val1::`** /
   * **`::ref_val1%::`** tokens — mirrors talent **`conds`** gating (**`minRank`** / **`maxRank`**).
   */
  /** Affix rows gated by **`conds.mastery`** only apply when expanding that rune's description. */
  function skillAffixRowMatchesMasteryGate(ax, masteryEntryId) {
    const c = ax && ax.conds;
    if (!c || typeof c !== "object" || c.mastery == null || c.mastery === "") return true;
    if (!masteryEntryId) return false;
    return String(c.mastery) === String(masteryEntryId);
  }

  function skillAffixEntryForPlaceholderKey(sk, key, descRank, masteryEntryId) {
    if (!sk || !Array.isArray(sk.affixes) || !sk.affixes.length) return null;
    let ordinal = -1;
    if (key === "val" || key === "val1") ordinal = 0;
    else {
      const m = /^val([2-9]\d*)$/.exec(key);
      if (!m) return null;
      ordinal = parseInt(m[1], 10) - 1;
    }
    const rank =
      descRank != null && Number.isFinite(descRank) ? Math.max(1, Math.floor(descRank)) : 1;
    let matched = 0;
    for (let i = 0; i < sk.affixes.length; i++) {
      const ax = sk.affixes[i];
      if (!ax || typeof ax.val !== "number" || !Number.isFinite(ax.val)) continue;
      if (!talentAffixRowMatchesRank(ax.conds, rank)) continue;
      if (!skillAffixRowMatchesMasteryGate(ax, masteryEntryId)) continue;
      if (matched === ordinal) return ax;
      matched++;
    }
    return null;
  }

  /** `TAttribute_Flat` stores sheet percentage points (`0.5` → `0.5%`); `TAttribute_ARatio` stores a ratio (`0.3` → `30%`). */
  function affixRefIsFlatPercentDisplay(ax) {
    const ref = ax && typeof ax.ref === "string" ? ax.ref : "";
    return ref === "TAttribute_Flat" || (ref.includes("Flat") && !ref.includes("ARatio"));
  }

  function formatSkillPercentFromAffixFlatVal(v) {
    if (typeof v !== "number" || !Number.isFinite(v)) return "";
    const rounded = Math.round(v * 1e6) / 1e6;
    let s = String(rounded);
    if (s.includes(".")) s = s.replace(/\.?0+$/, "");
    return `${s}%`;
  }

  /**
   * Move-speed debuff affixes: **`TAttribute_MRatioMin`** stores remaining speed ratio (0.7 → **15%** slow in tooltips);
   * negative **`TAttribute_ARatio`** is slow magnitude directly (e.g. −0.3 → **30%**).
   */
  function affixSlowByPercentFromRow(ax) {
    if (!ax || typeof ax.val !== "number" || !Number.isFinite(ax.val)) return null;
    const attr = ax.target && ax.target.attribute;
    const ref = typeof ax.ref === "string" ? ax.ref : "";
    if (attr !== "MoveSpeedFactor" && attr !== "MoveSpeed") return null;
    if (ref === "TAttribute_MRatioMin" && ax.val > 0 && ax.val < 1) {
      return formatSkillPercentFromRatio((1 - ax.val) / 2);
    }
    if (ref === "TAttribute_ARatio" && ax.val < 0) {
      return formatSkillPercentFromRatio(Math.abs(ax.val));
    }
    return null;
  }

  function formatAffixValPercentForDesc(ax) {
    if (!ax || typeof ax.val !== "number" || !Number.isFinite(ax.val)) return null;
    const slowPct = affixSlowByPercentFromRow(ax);
    if (slowPct != null) return slowPct;
    if ((ax.target && ax.target.attribute) === "DamageTakenModifier" && ax.val < 0) {
      return formatSkillPercentFromRatio(Math.abs(ax.val));
    }
    if (affixRefIsFlatPercentDisplay(ax)) return formatSkillPercentFromAffixFlatVal(ax.val);
    return formatSkillPercentFromRatio(ax.val);
  }

  /**
   * Some two-tier **`TAttribute_Flat`** pairs use **`maxRank`** / **`minRank`** rows where the low-tier **`val`** is one
   * above **`floor(high/2)`** (e.g. **3** vs **4** → intended **2%** / **4%**); the sheet’s low **`val`** is still used for combat.
   * Only adjusts **description** magnitudes for **percent-flag** attributes.
   */
  function adjustPairedTierLowFlatPercentMagnitudeForDesc(ax, sk, condsRank) {
    if (!ax || !sk || typeof ax.val !== "number" || !Number.isFinite(ax.val)) return ax.val;
    if (!affixRefIsFlatPercentDisplay(ax) || ax.ref !== "TAttribute_Flat") return ax.val;
    const c = ax.conds;
    if (!c || typeof c.maxRank !== "number") return ax.val;
    if (!talentAffixRowMatchesRank(c, condsRank)) return ax.val;
    const attr = ax.target && ax.target.attribute;
    if (!attr || !attributeUsesPercentSheetFlag(attr)) return ax.val;
    const aff = sk.affixes;
    if (!Array.isArray(aff)) return ax.val;
    let vHi = null;
    for (let i = 0; i < aff.length; i++) {
      const b = aff[i];
      if (!b || b.ref !== "TAttribute_Flat") continue;
      if ((b.target && b.target.attribute) !== attr) continue;
      const bc = b.conds;
      if (!bc || typeof bc.minRank !== "number" || bc.minRank < 2) continue;
      if (typeof b.val !== "number" || !Number.isFinite(b.val)) continue;
      vHi = b.val;
      break;
    }
    if (vHi == null || !(vHi > 0) || vHi % 2 !== 0) return ax.val;
    const floorHalf = Math.floor(vHi / 2);
    if (vHi - ax.val === 1 && ax.val === floorHalf + 1) return floorHalf;
    return ax.val;
  }

  function formatAffixValPercentForSkillDesc(ax, sk, condsRank) {
    if (!ax || typeof ax.val !== "number" || !Number.isFinite(ax.val)) return null;
    const slowPct = affixSlowByPercentFromRow(ax);
    if (slowPct != null) return slowPct;
    const vAdj = adjustPairedTierLowFlatPercentMagnitudeForDesc(ax, sk, condsRank);
    if ((ax.target && ax.target.attribute) === "DamageTakenModifier" && vAdj < 0) {
      return formatSkillPercentFromRatio(Math.abs(vAdj));
    }
    if (affixRefIsFlatPercentDisplay(ax)) return formatSkillPercentFromAffixFlatVal(vAdj);
    return formatSkillPercentFromRatio(vAdj);
  }

  /** Top-level skill `duration` (seconds), e.g. status buff length on `Trinket_*_Status`. */
  function skillTopDurationSeconds(sk) {
    if (!sk || typeof sk.duration !== "number" || !Number.isFinite(sk.duration)) return null;
    if (sk.duration < 0) return null;
    return sk.duration;
  }

  function skillTopDurationSecondsAtRank(sk, rank) {
    let d = skillTopDurationSeconds(sk);
    const r = Number.isFinite(rank) ? Math.max(1, Math.floor(rank)) : 1;
    const ro = sk && sk.props && Array.isArray(sk.props.rankOverride) ? [...sk.props.rankOverride] : [];
    ro.sort((a, b) => (a.minRank || 0) - (b.minRank || 0));
    for (let i = 0; i < ro.length; i++) {
      const entry = ro[i];
      if (!entry || typeof entry.minRank !== "number" || entry.minRank > r) continue;
      const od = entry.props && entry.props.duration;
      if (typeof od === "number" && Number.isFinite(od) && od >= 0) d = od;
    }
    return d;
  }

  function skillPropNumberAtRank(sk, propKey, rank) {
    if (!sk || !propKey) return null;
    let v =
      sk.props && typeof sk.props[propKey] === "number" && Number.isFinite(sk.props[propKey])
        ? sk.props[propKey]
        : null;
    const r = Number.isFinite(rank) ? Math.max(1, Math.floor(rank)) : 1;
    const ro = sk.props && Array.isArray(sk.props.rankOverride) ? [...sk.props.rankOverride] : [];
    ro.sort((a, b) => (a.minRank || 0) - (b.minRank || 0));
    for (let i = 0; i < ro.length; i++) {
      const entry = ro[i];
      if (!entry || typeof entry.minRank !== "number" || entry.minRank > r) continue;
      const ov = entry.props && entry.props[propKey];
      if (typeof ov === "number" && Number.isFinite(ov)) v = ov;
    }
    return v;
  }

  function formatSkillPercentFromRatio(ratio) {
    const p = ratio * 100;
    if (Math.abs(p - Math.round(p)) < 1e-6) return `${Math.round(p)}%`;
    return `${p.toFixed(1).replace(/\.0$/, "")}%`;
  }

  function formatSkillDurationSeconds(sec) {
    if (typeof sec !== "number" || !Number.isFinite(sec) || sec < 0) return "";
    if (sec === (sec | 0)) return `${sec | 0}s`;
    return `${sec.toFixed(1).replace(/\.0$/, "")}s`;
  }

  /**
   * Resolves `[AttributeId]` and `::tokens::` in skill `texts.desc` (`vars`, `refs.ref` / `ref2` / `ref3`, durations,
   * `::atbgain::` from **Spark**-restore **MaxSpark**×ratio steps, and combat previews for `::dmg::` when `combatCtx` or `plannerSkillCombatCtx` is set.
   * @param {boolean} markResolved — wrap each successful substitution in `SKILL_DESC_MARK_S`…`E` for HTML preview.
   * @param {object} [combatCtx] `{ sheetTotals, derived }`
   * @param {number} [weaponEffectiveRank] when set (e.g. `WEAPON_SKILL_EFFECTIVE_RANK`), merge `props.rankOverride` into `vars` for token resolution.
   * @param {number} [damageStepMaxRank] only include damaging steps whose `cond.minRank` (step or effect) is at most this value.
   * Omit (or pass null or undefined) to include all ranks. Base `texts.desc` uses 1 so `::dmg::` matches rank-1 authoring; each `rankDescs` line passes that row `rank` (e.g. `::dmg2::` at rank 3).
   * **`::dmg::`** / **`::dmg2::`** / **`::dmg3::`** use the 1st / 2nd / 3rd damage preview in **`steps`** order; **`::dmgs::`** sums all previews from **`collectEffectDamagePreviewsOrdered`**.
   * When **`combatCtx`** has **`sheetTotals`** + **`derived`**, those tokens show **pre-crit vs current foe** (**`raw × mastery × Fervor × DamageModifier × extraMore × armor`** with **0% penetration**), **no crit**, as **`floor`–`ceil`** (**`331-332`**) when fractional.
   */
  /**
   * @param {{ refsHost?: object, masteryEntry?: object }} [expandOpts] — **`refsHost`**: row whose **`texts.refs`** resolve **`::ref*::`** (mastery lines use the class skill). **`masteryEntry`**: rune row for **`props`** / mastery-gated affixes.
   */
  function expandSkillDescPlaceholdersMarked(
    desc,
    sk,
    markResolved,
    combatCtx,
    weaponEffectiveRank,
    damageStepMaxRank,
    expandOpts
  ) {
    if (!desc || !sk) return typeof desc === "string" ? desc : "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const refsHost = (expandOpts && expandOpts.refsHost) || sk;
    const descPhOpts =
      expandOpts && expandOpts.masteryEntry
        ? {
            masteryEntry: expandOpts.masteryEntry,
            masteryEntryId: expandOpts.masteryEntry.id,
            refsHost: expandOpts.refsHost || sk,
          }
        : null;
    const refResolveOpts = descPhOpts || expandOpts || null;
    let s = String(desc);
    const ms = SKILL_DESC_MARK_S;
    const me = SKILL_DESC_MARK_E;
    const mds = SKILL_DESC_MARK_DMG_S;
    const mde = SKILL_DESC_MARK_DMG_E;
    const rankForMark =
      damageStepMaxRank != null && Number.isFinite(damageStepMaxRank)
        ? Math.max(1, Math.floor(damageStepMaxRank))
        : 1;
    const grantorRank = refGrantorRankForAffixConds(sk, weaponEffectiveRank, rankForMark);
    function wrapResolvedSegment(placeholderKey, displayedValue) {
      if (!markResolved) return displayedValue;
      const pk = placeholderKey != null ? String(placeholderKey) : "";
      if (pk && isSkillDescDamagePreviewKey(pk)) {
        return mds + String(rankForMark) + "\x1f" + pk + "\x1f" + displayedValue + mde;
      }
      return ms + displayedValue + me;
    }

    const previewCache = new Map();
    function previewsFor(rsk) {
      if (!rsk || !ctx) return [];
      const id = rsk.id || "__none__";
      const capKey =
        damageStepMaxRank != null && Number.isFinite(damageStepMaxRank)
          ? String(Math.max(1, Math.floor(damageStepMaxRank)))
          : "all";
      const cacheKey = `${id}\x1e${capKey}`;
      if (!previewCache.has(cacheKey)) {
        previewCache.set(
          cacheKey,
          collectEffectDamagePreviewsOrdered(rsk, ctx, damageStepMaxRank)
        );
      }
      return previewCache.get(cacheKey);
    }

    s = s.replace(/\[([A-Za-z][A-Za-z0-9_]*)\]/g, (_, id) =>
      wrapResolvedSegment(null, displayNameForSkillDescBracket(id))
    );

    const refPairs = [
      ["ref3_", "ref3"],
      ["ref2_", "ref2"],
      ["ref1_", "ref"],
      ["ref_", "ref"],
    ];
    for (let ri = 0; ri < refPairs.length; ri++) {
      const prefix = refPairs[ri][0];
      const slot = refPairs[ri][1];
      const esc = prefix.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
      s = s.replace(new RegExp(`::${esc}([a-zA-Z0-9_]+)%::`, "g"), (_, key) => {
        const rsk = skillRefTargetBySlot(refsHost, slot, refResolveOpts);
        const out = resolveSkillDescPlaceholderToken(
          rsk,
          sk,
          key,
          true,
          ctx,
          previewsFor(rsk),
          weaponEffectiveRank,
          grantorRank,
          descPhOpts
        );
        return out != null ? wrapResolvedSegment(key, out) : `::${prefix}${key}%::`;
      });
      s = s.replace(new RegExp(`::${esc}([a-zA-Z0-9_]+)::`, "g"), (_, key) => {
        const rsk = skillRefTargetBySlot(refsHost, slot, refResolveOpts);
        const out = resolveSkillDescPlaceholderToken(
          rsk,
          sk,
          key,
          false,
          ctx,
          previewsFor(rsk),
          weaponEffectiveRank,
          grantorRank,
          descPhOpts
        );
        return out != null ? wrapResolvedSegment(key, out) : `::${prefix}${key}::`;
      });
    }

    s = s.replace(/::([a-zA-Z_][a-zA-Z0-9_]*)%::/g, (_, key) => {
      const out = resolveSkillDescPlaceholderToken(
        sk,
        sk,
        key,
        true,
        ctx,
        previewsFor(sk),
        weaponEffectiveRank,
        grantorRank,
        descPhOpts
      );
      return out != null ? wrapResolvedSegment(key, out) : `::${key}%::`;
    });

    s = s.replace(/::([a-zA-Z_][a-zA-Z0-9_]*)::/g, (_, key) => {
      const out = resolveSkillDescPlaceholderToken(
        sk,
        sk,
        key,
        false,
        ctx,
        previewsFor(sk),
        weaponEffectiveRank,
        grantorRank,
        descPhOpts
      );
      return out != null ? wrapResolvedSegment(key, out) : `::${key}::`;
    });

    return s;
  }

  function skillDescText(sk, combatCtx, weaponEffectiveRank) {
    if (!sk) return "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const parts = [];
    const raw = skillDescRaw(sk);
    if (raw) {
      parts.push(
        finalizeUnresolvedSkillPlaceholders(
          expandSkillDescPlaceholdersMarked(raw, sk, false, ctx, weaponEffectiveRank, 1)
        )
      );
    }
    const entries = skillRankDescEntries(sk);
    for (let i = 0; i < entries.length; i++) {
      const { rank, desc } = entries[i];
      const line = finalizeUnresolvedSkillPlaceholders(
        expandSkillDescPlaceholdersMarked(desc, sk, false, ctx, weaponEffectiveRank, rank)
      );
      if (line) parts.push(`Rank ${rank}: ${line}`);
    }
    return parts.filter(Boolean).join("\n\n");
  }

  /** True for any weapon-granted Base Attack variant (e.g. *_Base_Attack, *_Base_Attack1–4). */
  function isWeaponBaseAttackSkillId(sid) {
    return typeof sid === "string" && /Base_Attack/i.test(sid);
  }

  /** True for weapon **Final Combo Attack** skill ids (**`_FinalCombo`**). */
  function skillIsFinalComboAttackId(sid) {
    return typeof sid === "string" && /_FinalCombo/i.test(sid);
  }

  /**
   * **Attack** actions vs generic **skills** for passive targeting (**`_Attack`** includes **`Base_Attack`**, **`_FinalCombo`**).
   */
  function skillIsAttackActionForBuffs(sk) {
    const sid = sk && sk.id;
    return (
      skillRowIsAttackChainType(sk) ||
      (typeof sid === "string" && (/_Attack/i.test(sid) || /_FinalCombo/i.test(sid)))
    );
  }

  function weaponSkillHiddenFromMainSkillLists(sid) {
    return sid === BOOK_WATER_ORBS_SKILL2_RECAST_ID;
  }

  /** First weapon-granted Base Attack variant in sheet order. */
  function weaponFirstBaseAttackSkillId(item) {
    const raw = item && Array.isArray(item.skills) ? item.skills : [];
    for (let i = 0; i < raw.length; i++) {
      const sid = raw[i] && raw[i].skill;
      if (isWeaponBaseAttackSkillId(sid)) return sid;
    }
    return null;
  }

  /**
   * Main-hand weapon skill strip: first Base Attack (when present), then **three** other actives
   * (excludes Block type 6), then passive (**`type` 24** or **`nature` 5**) when present — up to five icons.
   * Without a base-attack row, shows up to four non-passive skills then passive (same cap on strip width).
   * @returns {{ id: string, passive: boolean }[]}
   */
  function weaponSkillStripLayout(item) {
    const raw = item.skills || [];
    let baseAttackId = null;
    const passiveIds = [];
    const left = [];

    for (let i = 0; i < raw.length; i++) {
      const sid = raw[i] && raw[i].skill;
      if (typeof sid !== "string" || !sid) continue;
      if (weaponSkillHiddenFromMainSkillLists(sid)) continue;
      if (isWeaponBaseAttackSkillId(sid)) {
        if (!baseAttackId) baseAttackId = sid;
        continue;
      }

      const sk = skillById[sid];
      const ty = skillRowType(sk);
      if (ty === SKILL_TYPE_BLOCK || sid === "PhysicalBlock" || sid === "MagicBlock") continue;
      if (sk && skillIconIsPassiveFrame(sk)) {
        passiveIds.push(sid);
        continue;
      }
      left.push(sid);
    }

    const passiveId = passiveIds.length ? passiveIds[passiveIds.length - 1] : null;
    const out = [];
    if (baseAttackId) {
      out.push({ id: baseAttackId, passive: false });
    }
    const maxOtherActives = baseAttackId ? 3 : 4;
    const otherActives = left.slice(0, maxOtherActives);
    for (let i = 0; i < otherActives.length; i++) {
      out.push({ id: otherActives[i], passive: false });
    }
    if (passiveId) {
      out.push({ id: passiveId, passive: true });
    }
    return out;
  }

  /** Arsenal ability slots — actives only (no base attack, combo attacks, or blocks). */
  function weaponSkillSelectableForArsenalPick(sid) {
    if (typeof sid !== "string" || !sid) return false;
    if (weaponSkillHiddenFromMainSkillLists(sid)) return false;
    if (isWeaponBaseAttackSkillId(sid)) return false;
    if (skillIsFinalComboAttackId(sid)) return false;
    const sk = skillById[sid];
    if (skillIsAttackActionForBuffs(sk)) return false;
    const ty = skillRowType(sk);
    if (ty === SKILL_TYPE_BLOCK || sid === "PhysicalBlock" || sid === "MagicBlock") return false;
    return true;
  }

  /**
   * Weapon skill panel list: first **Base Attack** only (hides Attack 2 / 3 chain steps), all other actives, passive last.
   * @returns {string[]}
   */
  function weaponSkillIdsForPanel(item) {
    const raw = item.skills || [];
    let baseAttackId = null;
    const passiveIds = [];
    const left = [];
    for (let i = 0; i < raw.length; i++) {
      const sid = raw[i] && raw[i].skill;
      if (typeof sid !== "string" || !sid) continue;
      if (weaponSkillHiddenFromMainSkillLists(sid)) continue;
      if (isWeaponBaseAttackSkillId(sid)) {
        if (!baseAttackId) baseAttackId = sid;
        continue;
      }
      const sk = skillById[sid];
      const ty = skillRowType(sk);
      if (ty === SKILL_TYPE_BLOCK || sid === "PhysicalBlock" || sid === "MagicBlock") continue;
      if (sk && skillIconIsPassiveFrame(sk)) {
        passiveIds.push(sid);
        continue;
      }
      left.push(sid);
    }
    const passiveId = passiveIds.length ? passiveIds[passiveIds.length - 1] : null;
    const ordered = [];
    if (baseAttackId) ordered.push(baseAttackId);
    for (let i = 0; i < left.length; i++) ordered.push(left[i]);
    if (passiveId) ordered.push(passiveId);
    return ordered;
  }

  /**
   * All weapon-granted skills available for arsenal ability picks (no base-attack / block; passive last).
   * @returns {string[]}
   */
  function weaponSkillPickIds(item) {
    const raw = item.skills || [];
    const passiveIds = [];
    const left = [];
    for (let i = 0; i < raw.length; i++) {
      const sid = raw[i] && raw[i].skill;
      if (typeof sid !== "string" || !sid) continue;
      if (!weaponSkillSelectableForArsenalPick(sid)) continue;
      const sk = skillById[sid];
      if (sk && skillIconIsPassiveFrame(sk)) {
        passiveIds.push(sid);
        continue;
      }
      left.push(sid);
    }
    const passiveId = passiveIds.length ? passiveIds[passiveIds.length - 1] : null;
    const ordered = left.slice();
    if (passiveId) ordered.push(passiveId);
    return ordered;
  }

  function clearArsenalSlot(charLevel) {
    const cl = clamp(charLevel || CHAR_LEVEL_DEFAULT, 1, CHAR_LEVEL_MAX);
    const s = selection.arsenal;
    if (!s) return;
    s.item = null;
    s.ilvl = cl;
    s.rarityOverride = null;
    s.stars = 0;
    s.enchantId = null;
    s.augmentId = null;
    s.flawless = false;
    s.pickSkill1 = null;
    s.pickSkill2 = null;
  }

  /**
   * Assign one arsenal weapon skill slot (`pickSkill1` / `pickSkill2`). Clears the other slot if it used the same skill id.
   * @param {{ pickSkill1?: string|null, pickSkill2?: string|null }} arSel
   * @param {1|2} slotNum
   * @param {string|null|undefined} sid
   */
  function assignArsenalPickSlot(arSel, slotNum, sid) {
    if (!arSel) return;
    if (sid != null && sid !== "" && !weaponSkillSelectableForArsenalPick(sid)) return;
    if (sid == null || sid === "") {
      if (slotNum === 1) arSel.pickSkill1 = null;
      else arSel.pickSkill2 = null;
    } else if (slotNum === 1) {
      arSel.pickSkill1 = sid;
      if (arSel.pickSkill2 === sid) arSel.pickSkill2 = null;
    } else {
      arSel.pickSkill2 = sid;
      if (arSel.pickSkill1 === sid) arSel.pickSkill1 = null;
    }
    clampArsenalSkillPicks();
  }

  function clampArsenalSkillPicks() {
    const w = selection.arsenal && selection.arsenal.item;
    const s = selection.arsenal;
    if (!w || !s) {
      if (s) {
        s.pickSkill1 = null;
        s.pickSkill2 = null;
      }
      return;
    }
    const allowed = new Set(weaponSkillPickIds(w));
    for (const k of ["pickSkill1", "pickSkill2"]) {
      const pid = s[k];
      if (pid && !allowed.has(pid)) s[k] = null;
    }
  }

  /** Unique equipped weapons for the skills panel (main → off → arsenal), by item id. */
  function collectEquippedWeaponsForSkillPanel(classId, charLevel) {
    const out = [];
    const seen = new Set();
    const clsId = classId || plannerSelectedClassId();
    const cl =
      Number.isFinite(charLevel)
        ? charLevel
        : plannerSkillCombatCtx && Number.isFinite(plannerSkillCombatCtx.charLevel)
          ? plannerSkillCombatCtx.charLevel
          : CHAR_LEVEL_DEFAULT;

    function push(key, label) {
      const sel = selection[key];
      if (!sel || !sel.item) return;
      const sd = SLOT_DEFS.find((s) => s.key === key);
      if (sd && !slotSelectionIsActive(sd, sel, clsId, cl, selection)) return;
      const id = sel.item.id;
      if (seen.has(id)) return;
      seen.add(id);
      out.push({ key, label, item: sel.item });
    }

    push("mainHand", "Main hand");
    const mh = selection.mainHand && selection.mainHand.item;
    const mhSd = SLOT_DEFS.find((s) => s.key === "mainHand");
    const mhActive =
      mh && mhSd && slotSelectionIsActive(mhSd, selection.mainHand, clsId, cl, selection);
    if (!mhActive || !weaponOccupiesBothHands(mh.type)) {
      push("offHand", "Off-hand");
    }
    const aw = selection.arsenal && selection.arsenal.item;
    if (aw && !seen.has(aw.id)) {
      seen.add(aw.id);
      out.push({ key: "arsenal", label: "Arsenal", item: aw });
    }
    return out;
  }

  /**
   * Bodies of **`onDamageEval`** / **`onInflictDamageEval`** hooks (brace-balanced) for heuristic **`dmgMult`** parsing.
   */
  function skillDamageScriptEvalBodies(script) {
    if (typeof script !== "string" || !script.trim()) return [];
    const out = [];
    const re = /\bfunction\s+(onDamageEval|onInflictDamageEval)\s*\(\s*(\w+)\s*\)\s*\{/g;
    let m;
    while ((m = re.exec(script))) {
      const start = m.index + m[0].length;
      let depth = 1;
      let i = start;
      for (; i < script.length && depth > 0; i++) {
        const ch = script[i];
        if (ch === "{") depth++;
        else if (ch === "}") depth--;
      }
      out.push({ hook: m[1], param: m[2], body: script.slice(start, i - 1) });
    }
    return out;
  }

  /**
   * When **`hasMastery(Mastery.&lt;id&gt;)`** guards the same **`if`** as **`dmgMult +=`**, returns that mastery entry id.
   * Used to route bonus vars to the rune row and to skip user-toggle “conditionals”.
   * @param {string} pre — script slice immediately before the **`dmgMult +=`** line
   * @returns {string|null}
   */
  function dmgMultAddMasteryGateId(pre) {
    if (!pre) return null;
    const re = /hasMastery\s*\(\s*Mastery\.(\w+)\s*\)/g;
    let last = null;
    let m;
    while ((m = re.exec(pre))) last = m;
    if (!last) return null;
    const tail = pre.slice(last.index + last[0].length);
    if (tail.indexOf("}") >= 0) return null;
    return last[1];
  }

  /** Prefer **`mastery[].vars`** for script bonuses tied to a specific rune id. */
  function skillVarForMasteryScript(sk, masteryEntryId, varKey) {
    const entry = masteryEntryId && sk ? masteryEntryById(sk, masteryEntryId) : null;
    if (entry && entry.vars && typeof entry.vars === "object") {
      const ev = entry.vars[varKey];
      if (typeof ev === "number" && Number.isFinite(ev)) return ev;
    }
    const rank = sk ? skillDamageScalingCondsRank(sk) : 1;
    const bag = sk ? mergedVarsForSkillDesc(sk, rank) : {};
    return sk ? skillVarLookupLoose(sk, varKey, bag) : null;
  }

  /**
   * Synthetic Conditionals pill for **Mage** **Chaincast** (`hasStatus(..., Mage_Talent_Chaincast_Status)`).
   * Enables **`MAGE_CHAINCAST_ASSUMPTION_ID`** on this skill’s **`scriptAssumptionsBySkillId`** row (see **`mageChaincastAssumptionActive`**).
   * **`varKey`** is a sentinel — script additive parsing ignores it (**`skillScriptAdditiveFromEnabledClauses`**).
   */
  function skillMageChaincastConditionalClause(sk) {
    if (!sk || plannerSelectedClassId() !== "Mage") return null;
    if (typeof sk.id !== "string" || !sk.id) return null;
    if (skillIconIsPassiveFrame(sk)) return null;
    if (!skillRowHasCombatDamagePreview(sk)) return null;
    const chainRe = /hasStatus\s*\(\s*\w+\s*,\s*(?:Skill\.)?Mage_Talent_Chaincast_Status\s*\)/;
    const script = typeof sk.script === "string" ? sk.script : "";
    const scriptHit = chainRe.test(script);
    const previewConsumer =
      skillRowIsMageBaseAttackType(sk) ||
      skillRowIsMageComboAttackType(sk) ||
      skillIsWeaponSkillForPreview(sk);
    if (!scriptHit && !previewConsumer) return null;
    const rankUse = skillDamageScalingCondsRank(sk);
    return {
      id: MAGE_CHAINCAST_ASSUMPTION_ID,
      label:
        "Assume Chaincast status — Chainstrike, Kinetic Surge, Echoing Life, and High Voltage use this in damage previews.",
      pill: "Chaincast",
      varKey: "__mage_chaincast_assumpt__",
      minRank: null,
      amountLabel: null,
      previewRank: rankUse,
    };
  }

  function skillQueensDecreeRank3ConditionalClause(sk) {
    if (!sk || sk.id !== BLADELEAF_QUEENS_DECREE_ID) return null;
    const rankUse = skillDamageScalingCondsRank(sk);
    return {
      id: BLADELEAF_QUEENS_DECREE_R3_ASSUMPTION_ID,
      label:
        "Assume Queen's Decree is on cooldown — rank 3 critical strikes add the Queen's Decree damage step after the triggering skill's damage.",
      pill: "Cooldown crit add",
      varKey: "__queens_decree_rank3_cooldown__",
      minRank: 3,
      amountLabel: null,
      previewRank: rankUse,
    };
  }

  function skillSparkShotHealthConditionalClause(sk) {
    if (!sk || sk.id !== BOW_SPARK_SHOT_ID) return null;
    const rankUse = skillDamageScalingCondsRank(sk);
    return {
      id: BOW_SPARK_SHOT_HEALTH_ASSUMPTION_ID,
      label:
        rankUse >= 3
          ? "Assume the enemy is below 35% or above 80% health — includes Spark Shot's additional damage step."
          : "Assume the enemy is below 35% health — includes Spark Shot's additional damage step.",
      pill: rankUse >= 3 ? "Below 35% or above 80% health" : "Below 35% health",
      varKey: "__spark_shot_health_window__",
      minRank: null,
      amountLabel: null,
      previewRank: rankUse,
    };
  }

  /**
   * Inferred **`dmg.dmgMult += vars.X`** / **`hit.dmgMult += vars.X`** clauses from skill **`script`** (additive multipliers).
   * Branches already guarded by **`hasMastery(...)`** are omitted — those follow the rune picker instead.
   * **`amountLabel`** / **`pill`** / **`label`** include the sheet value for **`vars.X`** at **`previewRank`** when present
   * (ratio magnitudes as a percent, e.g. **`0.12` → `12%`**; uses **`mergedVarsForSkillDesc`** so **`rankOverride`** applies).
   * @returns {Array<{ id: string, label: string, pill: string, varKey: string, minRank: number|null, amountLabel: string|null, previewRank: number }>}
   */
  function skillDamageScriptConditionalsFromSkill(sk) {
    const script = sk && typeof sk.script === "string" ? sk.script : "";
    const bodies = skillDamageScriptEvalBodies(script);
    const seen = new Map();
    const rankUse = sk ? skillDamageScalingCondsRank(sk) : 1;
    const bag = sk ? mergedVarsForSkillDesc(sk, rankUse) : {};
    const addRe = /\b(\w+)\.dmgMult\s*\+=\s*vars\.(\w+)/g;
    for (let bi = 0; bi < bodies.length; bi++) {
      const body = bodies[bi].body;
      addRe.lastIndex = 0;
      let m;
      while ((m = addRe.exec(body))) {
        const varKey = m[2];
        const idx = m.index;
        const pre = body.slice(Math.max(0, idx - 700), idx);
        if (skillIconIsPassiveFrame(sk) && /Mage_Talent_Chaincast_Status/.test(pre)) continue;
        if (dmgMultAddMasteryGateId(pre)) continue;
        const minRanks = [];
        const rre = /rank\s*>=\s*(\d+)/g;
        let rm;
        while ((rm = rre.exec(pre))) {
          const n = parseInt(rm[1], 10);
          if (Number.isFinite(n)) minRanks.push(n);
        }
        const minRank = minRanks.length ? Math.max.apply(null, minRanks) : null;
        const ccImm = /\bisCCImmune\s*\(\s*\)/.test(pre);
        const statuses = [];
        const stRe = /hasStatusType\s*\(\s*StatusType\.(\w+)\s*\)/g;
        let st;
        while ((st = stRe.exec(pre))) {
          if (statuses.indexOf(st[1]) < 0) statuses.push(st[1]);
        }
        statuses.sort();
        let id;
        let label;
        let pill;
        if (ccImm && statuses.length) {
          id = `assumpt_cc_soft_${varKey}_${statuses.join("_")}`;
          label = `+${varKey}: CC-immune or ${statuses.join("/")} on target`;
          pill = statuses.length <= 2 ? `CC / ${statuses.join("/")}` : "CC / soft CC";
        } else if (ccImm) {
          id = `assumpt_cc_immune_${varKey}`;
          label = `+${varKey}: CC-immune target`;
          pill = "CC-immune";
        } else if (statuses.length) {
          id = `assumpt_status_${statuses.join("_")}_${varKey}`;
          label = `+${varKey}: Target has ${statuses.join(" / ")}`;
          pill = statuses.join(" · ");
        } else {
          id = `assumpt_script_${varKey}_${bi}_${idx}`;
          label = `+${varKey}: Script damage bonus`;
          pill = varKey;
        }
        if (minRank != null) label += ` (rank ≥ ${minRank})`;
        let amountLabel = null;
        const rawV = sk ? skillVarLookupLoose(sk, varKey, bag) : null;
        if (typeof rawV === "number" && Number.isFinite(rawV)) {
          amountLabel = Math.abs(rawV) <= 2.25 ? formatSkillPercentFromRatio(rawV) : String(rawV);
          label += ` — ${varKey} ${amountLabel} (sheet @ rank ${rankUse})`;
          if (minRank != null && rankUse < minRank) {
            label += `; preview rank ${rankUse} is below ${minRank} for this branch`;
          }
          const shortAmt = amountLabel.length <= 12 ? amountLabel : amountLabel.replace(/\s/g, "");
          if (pill.indexOf(shortAmt) < 0) {
            pill = pill.length + shortAmt.length + 3 <= 30 ? `${pill} · ${shortAmt}` : `${pill} (${shortAmt})`;
          }
        }
        if (!seen.has(id)) seen.set(id, { id, label, pill, varKey, minRank, amountLabel, previewRank: rankUse });
      }
    }
    const mcc = skillMageChaincastConditionalClause(sk);
    if (mcc && !seen.has(mcc.id)) seen.set(mcc.id, mcc);
    const qd3 = skillQueensDecreeRank3ConditionalClause(sk);
    if (qd3 && !seen.has(qd3.id)) seen.set(qd3.id, qd3);
    const spark = skillSparkShotHealthConditionalClause(sk);
    if (spark && !seen.has(spark.id)) seen.set(spark.id, spark);
    return [...seen.values()];
  }

  function skillScriptAssumptionRowForSkillId(skillId) {
    const root = plannerDamagePreviewSettings && plannerDamagePreviewSettings.scriptAssumptionsBySkillId;
    if (!root || typeof root !== "object" || typeof skillId !== "string" || !skillId) return null;
    const row = root[skillId];
    return row && typeof row === "object" ? row : null;
  }

  function skillScriptAssumptionIsEnabled(skillId, clauseId) {
    const row = skillScriptAssumptionRowForSkillId(skillId);
    return !!(row && clauseId && row[clauseId]);
  }

  function skillScriptAssumptionSet(skillId, clauseId, on) {
    if (typeof skillId !== "string" || !skillId || typeof clauseId !== "string" || !clauseId) return;
    if (!plannerDamagePreviewSettings.scriptAssumptionsBySkillId || typeof plannerDamagePreviewSettings.scriptAssumptionsBySkillId !== "object") {
      plannerDamagePreviewSettings.scriptAssumptionsBySkillId = {};
    }
    if (!plannerDamagePreviewSettings.scriptAssumptionsBySkillId[skillId]) {
      plannerDamagePreviewSettings.scriptAssumptionsBySkillId[skillId] = {};
    }
    plannerDamagePreviewSettings.scriptAssumptionsBySkillId[skillId][clauseId] = !!on;
  }

  function skillScriptAdditiveFromEnabledClauses(sk) {
    const clauses = skillDamageScriptConditionalsFromSkill(sk);
    if (!clauses.length || !sk || typeof sk.id !== "string" || !sk.id) return 0;
    const bag = mergedVarsForSkillDesc(sk, skillDamageScalingCondsRank(sk));
    const rank = skillDamageScalingCondsRank(sk);
    const assRow = skillScriptAssumptionRowForSkillId(sk.id);
    let sum = 0;
    for (let i = 0; i < clauses.length; i++) {
      const c = clauses[i];
      if (!assRow || !assRow[c.id]) continue;
      if (c.minRank != null && rank < c.minRank) continue;
      const v = bag[c.varKey];
      if (typeof v === "number" && Number.isFinite(v)) sum += v;
    }
    return sum;
  }

  /** Multiplier from enabled script **`dmgMult +=`** clauses (**`1 + Σ vars`**) for this skill only (**`scriptAssumptionsBySkillId`**). */
  function skillScriptConditionalDamageMultiplier(sk) {
    if (!sk) return 1;
    const a = skillScriptAdditiveFromEnabledClauses(sk);
    return Math.max(0, 1 + a);
  }

  function mageChaincastAssumptionActive(consumerSk) {
    return (
      plannerSelectedClassId() === "Mage" &&
      consumerSk &&
      typeof consumerSk.id === "string" &&
      skillScriptAssumptionIsEnabled(consumerSk.id, MAGE_CHAINCAST_ASSUMPTION_ID)
    );
  }

  function mageChainstrikeDamageMultiplier(consumerSk) {
    if (!consumerSk || !mageChaincastAssumptionActive(consumerSk)) return 1;
    const r = mageTalentRank(MAGE_TALENT_CHAINSTRIKE_ID);
    if (r < 1) return 1;
    if (!skillRowIsMageBaseAttackType(consumerSk)) return 1;
    const sk = skillById[MAGE_TALENT_CHAINSTRIKE_ID];
    const bag = sk ? mergedVarsForSkillDesc(sk, r) : {};
    const d = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : 0.15;
    return Math.max(0, 1 + d);
  }

  function mageKineticSurgePhysicalMultiplier(consumerSk, previewHit) {
    if (!consumerSk || !mageChaincastAssumptionActive(consumerSk)) return 1;
    if (mageTalentRank(MAGE_TALENT_KINETIC_SURGE_ID) < 1) return 1;
    if (!skillIsWeaponSkillForPreview(consumerSk)) return 1;
    if (!previewHit || previewHit.affinityRoot !== "Physical") return 1;
    const sk = skillById[MAGE_TALENT_KINETIC_SURGE_ID];
    const bag = sk ? mergedVarsForSkillDesc(sk, 1) : {};
    const d = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : 0.5;
    return Math.max(0, 1 + d);
  }

  function mageEchoingLifeHealMultiplier(consumerSk) {
    if (!consumerSk || !mageChaincastAssumptionActive(consumerSk)) return 1;
    if (mageTalentRank(MAGE_TALENT_ECHOING_LIFE_ID) < 1) return 1;
    if (!skillIsWeaponSkillForPreview(consumerSk)) return 1;
    const sk = skillById[MAGE_TALENT_ECHOING_LIFE_ID];
    const bag = sk ? mergedVarsForSkillDesc(sk, 1) : {};
    const d = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : 0.3;
    return Math.max(0, 1 + d);
  }

  /**
   * Additive **`dmgMult`** from **`onDamageEval` / `onInflictDamageEval`** branches guarded by
   * **`hasMastery(Mastery.&lt;id&gt;)`** when that rune is selected (no rune → **0**).
   */
  function skillMasteryScriptDamageAdditive(sk) {
    if (!sk || typeof sk.id !== "string" || !sk.id) return 0;
    const sel = selectedClassSkillMasteryId(sk.id, sk);
    if (!sel) return 0;
    const script = typeof sk.script === "string" ? sk.script : "";
    const bodies = skillDamageScriptEvalBodies(script);
    if (!bodies.length) return 0;
    const masteryRe = /hasMastery\s*\(\s*Mastery\.(\w+)\s*\)/g;
    const dmgRe = /\b\w+\.dmgMult\s*\+=\s*vars\.(\w+)/g;
    let sum = 0;
    const seen = new Set();
    for (let bi = 0; bi < bodies.length; bi++) {
      const body = bodies[bi].body;
      masteryRe.lastIndex = 0;
      let mm;
      while ((mm = masteryRe.exec(body))) {
        const masteryId = mm[1];
        if (masteryId !== sel) continue;
        const idx = mm.index;
        const chunk = body.slice(idx, Math.min(body.length, idx + 600));
        const pre = body.slice(Math.max(0, idx - 400), idx);
        dmgRe.lastIndex = 0;
        let dm;
        while ((dm = dmgRe.exec(chunk))) {
          const varKey = dm[1];
          const keyId = `${masteryId}:${varKey}:${dm.index}`;
          if (seen.has(keyId)) continue;
          if (/healthRatio\s*<=/.test(pre + chunk.slice(0, dm.index + 80))) {
            /* Execution-style: assume foe below threshold for preview when rune is on. */
          }
          if (/totalHits\s*==\s*1/.test(pre + chunk.slice(0, dm.index + 80))) {
            /* First-hit-only bonus: include in preview. */
          }
          const v = skillVarForMasteryScript(sk, masteryId, varKey);
          if (typeof v === "number" && Number.isFinite(v)) {
            sum += v;
            seen.add(keyId);
          }
        }
      }
    }
    return sum;
  }

  /** **`1 + Σ`** mastery-gated script **`dmgMult`** (only when a rune is selected). */
  function skillMasteryDamageMultiplier(sk) {
    if (!sk) return 1;
    return Math.max(0, 1 + skillMasteryScriptDamageAdditive(sk));
  }

  /** Whether this host skill’s selected rune may modify **`consumerSk`** damage previews (default: same skill only). */
  function skillMasteryScriptAppliesToConsumer(hostSk, consumerSk) {
    if (!hostSk || typeof hostSk.id !== "string" || !hostSk.id) return false;
    if (!consumerSk || typeof consumerSk.id !== "string" || !consumerSk.id) return true;
    if (hostSk.id === consumerSk.id) return true;
    const sel = selectedClassSkillMasteryId(hostSk.id, hostSk);
    if (!sel) return false;
    return MASTERY_SCRIPT_GLOBAL_BY_ENTRY_ID.has(sel);
  }

  /** True when the skill row (or **`refs`** damage rows on passives) has combat **`effect.effect === 0`** scaling. */
  function skillRowHasCombatDamagePreview(sk) {
    if (skillSkipsCombatDamagePreview(sk)) return false;
    if (!sk) return false;
    function rowHasDamage(row) {
      if (!row || !Array.isArray(row.steps)) return false;
      for (let si = 0; si < row.steps.length; si++) {
        const step = row.steps[si];
        const effs = step.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!effectScalingIsCombatDamagePreview(e)) continue;
          if (!skillHostStepEffectMatchesMastery(row, step, e)) continue;
          return true;
        }
      }
      return false;
    }
    if (rowHasDamage(sk)) return true;
    if (skillAggregatesReferencedDamageRows(sk)) {
      const refs = referencedSkillsForMergedDamage(sk);
      for (let ri = 0; ri < refs.length; ri++) {
        if (rowHasDamage(refs[ri])) return true;
      }
    }
    return false;
  }

  /** Status ids from **`steps`** and **`texts.refs`** on a host skill. */
  function collectStatusRefIdsFromHostSkill(hostSk, outSet) {
    if (!hostSk || !outSet) return;
    collectReferencedStatusSkillRefsIntoSet(hostSk, outSet);
    const t = hostSk.texts && hostSk.texts.refs;
    if (!t || typeof t !== "object") return;
    if (typeof t.ref === "string" && t.ref.trim()) outSet.add(t.ref.trim());
    if (typeof t.ref2 === "string" && t.ref2.trim()) outSet.add(t.ref2.trim());
    if (typeof t.ref3 === "string" && t.ref3.trim()) outSet.add(t.ref3.trim());
  }

  function statusSkillGrantsPreviewFlats(stId) {
    if (stId === FISTS_SINK_TO_BOTTOM_CRIT_STATUS_ID) return false;
    const st = skillById[stId];
    if (!st) return false;
    return skillIsPreviewableStackingStatusBuff(st) || skillIsPreviewableFlatStatusBuff(st);
  }

  /** Host applies sheet flats via its own status row or a referenced / **`refs`** status skill. */
  function hostSkillGrantsStatusPreviewFlats(hostSk) {
    if (!hostSk) return false;
    if (skillIsPreviewableStackingStatusBuff(hostSk)) return true;
    const refs = new Set();
    collectStatusRefIdsFromHostSkill(hostSk, refs);
    for (const stId of refs) {
      if (statusSkillGrantsPreviewFlats(stId)) return true;
    }
    return false;
  }

  /**
   * Class **active** (non-passive-frame) skill with **no** combat damage that still buffs other skills
   * (status flats, script conditionals, self affix flats, or globally scoped rune script).
   */
  function classSkillIsNonDamageBuffContributor(sk) {
    if (!sk || typeof sk.id !== "string" || !sk.id) return false;
    if (skillIconIsPassiveFrame(sk)) return false;
    if (CLASS_SKILL_GLOBAL_BUFF_HOST_IDS.has(sk.id)) return true;
    if (skillRowHasCombatDamagePreview(sk)) return false;
    if (skillDamageScriptConditionalsFromSkill(sk).length) return true;
    if (hostSkillGrantsStatusPreviewFlats(sk)) return true;
    if (collectTalentFlatAffixAttributeOrder(sk).length) return true;
    const mid = selectedClassSkillMasteryId(sk.id, sk);
    if (mid && MASTERY_SCRIPT_GLOBAL_BY_ENTRY_ID.has(mid)) return true;
    return false;
  }

  let passiveScriptEquipmentMemoSig = "";
  /** @type {object[]|null} */
  let equippedPassivesWithScriptMemoList = null;

  /**
   * Passives with script **`dmgMult`** toggles plus **non-damage** class actives that grant buffs to other skills.
   */
  function globalBuffContributorsFromLoadout() {
    const out = [];
    const seen = new Set();
    function push(ps) {
      if (!ps || typeof ps.id !== "string" || !ps.id || seen.has(ps.id)) return;
      seen.add(ps.id);
      out.push(ps);
    }
    function considerPassive(ps) {
      if (!ps || !skillIconIsPassiveFrame(ps)) return;
      if (!skillDamageScriptConditionalsFromSkill(ps).length) return;
      push(ps);
    }
    const clsId = plannerSelectedClassId();
    const cl =
      plannerSkillCombatCtx && Number.isFinite(plannerSkillCombatCtx.charLevel)
        ? plannerSkillCombatCtx.charLevel
        : CHAR_LEVEL_DEFAULT;
    const weapons = collectEquippedWeaponsForSkillPanel(clsId, cl);
    for (let wi = 0; wi < weapons.length; wi++) {
      const it = weapons[wi].item;
      if (!it || !Array.isArray(it.skills)) continue;
      for (let si = 0; si < it.skills.length; si++) {
        const sid = it.skills[si] && it.skills[si].skill;
        if (typeof sid !== "string") continue;
        if (
          sid === BLADELEAF_SWARMSTRIKE_HOST_ID ||
          sid === BOW_THRILL_OF_THE_HUNTER_ID ||
          sid === STAFF_PYROCLASM_ID ||
          sid === STAFF_SCORCHING_EMBERS_ID
        ) {
          push(skillById[sid]);
        }
        else considerPassive(skillById[sid]);
      }
    }
    const cls = unitSheet && unitSheet.lines && clsId ? unitSheet.lines.find((r) => r.id === clsId) : null;
    const classRows = (cls && cls.skills) || [];
    for (let ci = 0; ci < classRows.length; ci++) {
      const sid = classRows[ci] && classRows[ci].skill;
      if (typeof sid !== "string" || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      const sk = skillById[sid];
      if (!sk) continue;
      if (skillIconIsPassiveFrame(sk)) considerPassive(sk);
      else if (classSkillIsNonDamageBuffContributor(sk)) push(sk);
    }
    if (clsId === "Mage") {
      const conduits = mageSelectedConduitSkillIds();
      for (let mi = 0; mi < conduits.length; mi++) {
        const sk = skillById[conduits[mi]];
        if (!sk) continue;
        if (skillIconIsPassiveFrame(sk)) considerPassive(sk);
        else if (classSkillIsNonDamageBuffContributor(sk)) push(sk);
      }
    }
    if (clsId === "Priest") {
      const prayers = priestSelectedPrayerSkillIds();
      for (let pi = 0; pi < prayers.length; pi++) {
        const sk = skillById[prayers[pi]];
        if (!sk) continue;
        if (skillIconIsPassiveFrame(sk)) considerPassive(sk);
        else if (classSkillIsNonDamageBuffContributor(sk)) push(sk);
      }
    }
    return out;
  }

  /** @deprecated alias — use **`globalBuffContributorsFromLoadout`**. */
  function equippedPassivesWithScriptDamageFromLoadout() {
    return globalBuffContributorsFromLoadout().filter(
      (ps) => skillIconIsPassiveFrame(ps) && skillDamageScriptConditionalsFromSkill(ps).length
    );
  }

  function equippedPassivesWithScriptDamageMemo() {
    const cl =
      plannerSkillCombatCtx && Number.isFinite(plannerSkillCombatCtx.charLevel)
        ? plannerSkillCombatCtx.charLevel
        : CHAR_LEVEL_DEFAULT;
    const weapons = collectEquippedWeaponsForSkillPanel(plannerSelectedClassId(), cl);
    const wids = weapons.map((w) => (w.item && w.item.id) || "").join("\x1e");
    const clsId = plannerSelectedClassId();
    const sig = `${clsId}\x1e${cl}\x1e${wids}`;
    if (sig !== passiveScriptEquipmentMemoSig || !equippedPassivesWithScriptMemoList) {
      passiveScriptEquipmentMemoSig = sig;
      equippedPassivesWithScriptMemoList = globalBuffContributorsFromLoadout();
    }
    return equippedPassivesWithScriptMemoList || [];
  }

  /** Buff toggles live in the **Buffs** tab — all contributors use the disabled map (default on). */
  function passiveScriptGlobalMultApplies(passiveSkillId) {
    const root = plannerDamagePreviewSettings && plannerDamagePreviewSettings.passiveScriptGlobalDisabledByPassiveId;
    return !(root && passiveSkillId && root[passiveSkillId]);
  }

  function passiveScriptGlobalMultSet(passiveSkillId, wantApplyToOthers) {
    if (typeof passiveSkillId !== "string" || !passiveSkillId) return;
    if (
      !plannerDamagePreviewSettings.passiveScriptGlobalDisabledByPassiveId ||
      typeof plannerDamagePreviewSettings.passiveScriptGlobalDisabledByPassiveId !== "object"
    ) {
      plannerDamagePreviewSettings.passiveScriptGlobalDisabledByPassiveId = {};
    }
    const root = plannerDamagePreviewSettings.passiveScriptGlobalDisabledByPassiveId;
    if (wantApplyToOthers) delete root[passiveSkillId];
    else root[passiveSkillId] = true;
  }

  function passiveScriptBoostRowForConsumer(consumerSkillId) {
    const root = plannerDamagePreviewSettings && plannerDamagePreviewSettings.passiveScriptBoostDisabledBySkillId;
    if (!root || typeof root !== "object" || typeof consumerSkillId !== "string" || !consumerSkillId) return null;
    const row = root[consumerSkillId];
    return row && typeof row === "object" ? row : null;
  }

  /** @returns {boolean} whether this passive’s script multiplier is applied to **`consumerSkillId`** previews (default **true**). */
  function passiveScriptBoostApplies(consumerSkillId, passiveSkillId) {
    const row = passiveScriptBoostRowForConsumer(consumerSkillId);
    return !(row && passiveSkillId && row[passiveSkillId]);
  }

  function passiveScriptBoostSet(consumerSkillId, passiveSkillId, on) {
    if (typeof consumerSkillId !== "string" || !consumerSkillId || typeof passiveSkillId !== "string" || !passiveSkillId)
      return;
    if (!plannerDamagePreviewSettings.passiveScriptBoostDisabledBySkillId || typeof plannerDamagePreviewSettings.passiveScriptBoostDisabledBySkillId !== "object") {
      plannerDamagePreviewSettings.passiveScriptBoostDisabledBySkillId = {};
    }
    const root = plannerDamagePreviewSettings.passiveScriptBoostDisabledBySkillId;
    if (on) {
      if (root[consumerSkillId]) {
        delete root[consumerSkillId][passiveSkillId];
        if (!Object.keys(root[consumerSkillId]).length) delete root[consumerSkillId];
      }
    } else {
      if (!root[consumerSkillId]) root[consumerSkillId] = {};
      root[consumerSkillId][passiveSkillId] = true;
    }
  }

  /**
   * Script multiplier for one preview hit: host row (**`p.scriptHostSkill`**) plus **equipped passive** script multipliers
   * (weapon / class passives with **`dmgMult +=`** heuristics) when the preview is for a **non-passive** skill card.
   * Passives apply **globally** unless turned off on the passive card (**`passiveScriptGlobalDisabledByPassiveId`**) — weapon-granted passives only — or
   * class corner-toggle buff skills (**`passiveScriptGlobalEnabledByPassiveId`**, default **off**) or
   * for one skill (**`passiveScriptBoostDisabledBySkillId`**).
   */
  function skillScriptMultiplierForPreviewHit(p, hostSkFallback, consumerSk) {
    const host = (p && p.scriptHostSkill) || hostSkFallback;
    let m = 1;
    if (host) {
      m *= skillScriptConditionalDamageMultiplier(host);
      if (skillMasteryScriptAppliesToConsumer(host, consumerSk)) {
        m *= skillMasteryDamageMultiplier(host);
      }
      m *= tideRisingStackDamageMultiplier(host);
    }
    if (!consumerSk || typeof consumerSk.id !== "string" || !consumerSk.id) return m;
    if (skillAggregatesReferencedDamageRows(consumerSk)) {
      m *= globalClassBuffDamageMultiplier(consumerSk);
      m *= mageChainstrikeDamageMultiplier(consumerSk);
      m *= mageKineticSurgePhysicalMultiplier(consumerSk, p);
      m *= pyroclasmMagicDamageMultiplier(consumerSk, p);
      m *= scorchingEmbersMagicWeaponSkillMultiplier(consumerSk);
      return m;
    }
    const contributors = equippedPassivesWithScriptDamageMemo();
    for (let li = 0; li < contributors.length; li++) {
      const ps = contributors[li];
      if (!ps || ps.id === consumerSk.id) continue;
      if (!passiveScriptGlobalMultApplies(ps.id)) continue;
      if (!passiveScriptBoostApplies(consumerSk.id, ps.id)) continue;
      const clauses = skillDamageScriptConditionalsFromSkill(ps);
      if (clauses.length || skillIconIsPassiveFrame(ps)) {
        m *= skillScriptConditionalDamageMultiplier(ps);
      }
    }
    m *= globalClassBuffDamageMultiplier(consumerSk);
    m *= mageChainstrikeDamageMultiplier(consumerSk);
    m *= mageKineticSurgePhysicalMultiplier(consumerSk, p);
    m *= pyroclasmMagicDamageMultiplier(consumerSk, p);
    m *= scorchingEmbersMagicWeaponSkillMultiplier(consumerSk);
    return m;
  }

  /** Lines describing what an enchant-granted skill does (for previews / tooltips). */
  function appendEnchantSkillPreviewLines(lines, sk) {
    if (!sk) return;
    const name = skillDisplayName(sk);
    lines.push(`Enchant — ${name}`);
    const desc = skillDescText(sk);
    if (desc) lines.push(desc);
    const merged = collectMergedDamageDisplayLines(sk, null);
    for (let mi = 0; mi < merged.length; mi++) lines.push(merged[mi]);
  }

  /** Effect-level damage scaling lines for skill cards (affinities + ratio × attribute). */
  function skillDamageLines(sk) {
    const out = [];
    if (!sk) return out;
    const raw = [];
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let srcIdx = 0; srcIdx < sources.length; srcIdx++) {
      const src = sources[srcIdx];
      if (!src || !Array.isArray(src.steps)) continue;
      for (const st of src.steps) {
        const effs = st.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!effectScalingIsCombatDamagePreview(e)) continue;
          if (!skillHostStepEffectMatchesMastery(src, st, e)) continue;
          const sc = e.scaling;
          const hasScaling = Array.isArray(sc) && sc.length > 0;
          const baseVal = typeof e.baseVal === "number" && Number.isFinite(e.baseVal) ? e.baseVal : 0;
          if (!hasScaling && !(baseVal > 0)) continue;
          const affShort = e.affinity ? String(e.affinity) : "Hit";
          const parts = [];
          const condRank = skillDamageScalingCondsRank(src);
          if (hasScaling) {
            for (let si = 0; si < sc.length; si++) {
              const row = sc[si];
              if (!talentAffixRowMatchesRank(row.conds, condRank)) continue;
              const atb = row.atb;
              const ratio = row.ratio;
              if (typeof atb === "string" && typeof ratio === "number") parts.push(`${atb} ×${ratio}`);
            }
          } else if (baseVal > 0) {
            parts.push(`${formatDmgAmount(baseVal)} flat damage`);
          }
          if (!parts.length) continue;
          raw.push({
            mergeKey: skillDamageMergeKey(e.affinity),
            affShort,
            text: parts.join(" + "),
          });
        }
      }
    }
    const order = [];
    const groups = new Map();
    for (let ri = 0; ri < raw.length; ri++) {
      const row = raw[ri];
      const k = row.mergeKey;
      if (!groups.has(k)) {
        order.push(k);
        groups.set(k, []);
      }
      groups.get(k).push(row);
    }
    for (let oi = 0; oi < order.length; oi++) {
      const k = order[oi];
      const rows = groups.get(k);
      const combinedText = rows.map((r) => r.text).join(" + ");
      const aff = skillDamageAffLabel(k, rows[0].affShort);
      out.push({ mergeKey: k, aff, text: combinedText });
    }
    return out;
  }

  /** `"Magic damage"` → **`Magic`** (matches **`skillDamageLines`** `mergeKey`). */
  function mergeKeyFromDamageKindLabel(kindLabel) {
    if (!kindLabel || typeof kindLabel !== "string") return "";
    return kindLabel.endsWith(" damage") ? kindLabel.slice(0, -" damage".length) : kindLabel;
  }

  /** Inverse for leftover scaling rows when there is no numeric preview. */
  function damageKindLabelFromMergeKey(mk) {
    if (mk === "Magic") return "Magic damage";
    if (mk === "Physical") return "Physical damage";
    return `${mk} damage`;
  }

  function skillPreviewShouldSkipProcDamageStep(hostSk, srcSk, step) {
    const hostId = hostSk && hostSk.id;
    const srcId = srcSk && srcSk.id;
    const stepId = step && step.id;
    if (
      hostId === BOW_SPARK_SHOT_ID &&
      srcId === BOW_SPARK_SHOT_ID &&
      stepId === "AdditionalDamage" &&
      !skillScriptAssumptionIsEnabled(BOW_SPARK_SHOT_ID, BOW_SPARK_SHOT_HEALTH_ASSUMPTION_ID)
    ) {
      return true;
    }
    return hostId === FISTS_SINK_TO_BOTTOM_ID && srcId === FISTS_SINK_TO_BOTTOM_ID && stepId === "HitProc";
  }

  function skillDescriptionShouldSkipProcDamageStep(hostSk, srcSk, step) {
    const hostId = hostSk && hostSk.id;
    const srcId = srcSk && srcSk.id;
    const stepId = step && step.id;
    return hostId === FISTS_SINK_TO_BOTTOM_ID && srcId === FISTS_SINK_TO_BOTTOM_ID && stepId === "HitProc";
  }

  function sinkToBottomRank3ExpectedMultiplier(sk) {
    if (!sk || sk.id !== FISTS_SINK_TO_BOTTOM_ID) return 1;
    if (skillDamageScalingCondsRank(sk) < 3) return 1;
    const chance = sk.vars && typeof sk.vars.chance === "number" && Number.isFinite(sk.vars.chance) ? sk.vars.chance : 0.25;
    return 1 + clamp(chance, 0, 1);
  }

  function tideRisingStackDamageMultiplier(sk) {
    if (!sk || sk.id !== FISTS_TIDE_RISING_UPPERCUT_ID) return 1;
    const st = skillById[FISTS_TIDE_RISING_STATUS_ID];
    const stacks = st ? statusPreviewStackCount(st) : 0;
    const per = sk.vars && typeof sk.vars.var2 === "number" && Number.isFinite(sk.vars.var2) ? sk.vars.var2 : 0.5;
    return 1 + Math.max(0, stacks) * per;
  }

  function blazingBeamDamageHitCount(hostSk, srcSk, step) {
    const hostId = hostSk && hostSk.id;
    const srcId = srcSk && srcSk.id;
    const stepId = step && step.id;
    return hostId === STAFF_BLAZING_BEAM_ID && srcId === STAFF_BLAZING_BEAM_ID && stepId === "Loop" ? 12 : 1;
  }

  function applyDamagePreviewHitCount(p, hitCount) {
    if (!p || !(hitCount > 1)) return p;
    const mult = Math.max(1, Math.floor(hitCount));
    if (typeof p.raw === "number" && Number.isFinite(p.raw)) p.raw *= mult;
    if (typeof p.rounded === "number" && Number.isFinite(p.rounded)) p.rounded = hlMathRound(p.rounded * mult);
    if (typeof p.uiBaseValPart === "string" && p.uiBaseValPart.trim() !== "") {
      const n = Number(p.uiBaseValPart);
      if (Number.isFinite(n)) p.uiBaseValPart = String(hlMathRound(n * mult));
    }
    if (Array.isArray(p.sheetLines)) {
      p.sheetLines = p.sheetLines.map((sl) =>
        sl && typeof sl.part === "number" && Number.isFinite(sl.part) ? { ...sl, part: sl.part * mult } : sl
      );
    }
    if (typeof p.scalingDetail === "string" && p.scalingDetail.trim()) {
      p.scalingDetail = `${p.scalingDetail} · ${mult} ticks`;
    } else {
      p.scalingDetail = `${mult} ticks`;
    }
    return p;
  }

  /**
   * One row per damage family — **`valPart`** is **UI base** damage (**`gp-char-skill__computed-dmg-*`**): CDB hit × mastery only,
   * no Fervor / crit / armor / conditionals; merged integers use **`hlMathRound`** (HashLink **`math_round`**). When **`combatCtx`** is present,
   * **`finalExpectedSum`** is the **expected average** for that row (**`gp-char-skill__final-dmg-*`**): per hit,
   * the full non-jitter damage chain is flattened with the Hero-owned **`ceil`** path observed after **`computeDamage`**;
   * weapon jitter rows still use the existing jitter EV path. Hit EVs are summed for the row.
   * **`damagePreviewHits`** holds the **`computeEffectDamagePreview`** objects merged into that row (for breakdown tooltips).
   * Hold / charge skills (**`props.casting.holdSteps`**) with per-tier **`castHoldStep`** damage use **only the full-charge tier**
   * (and any damage without **`castHoldStep`**) so mutually exclusive steps are not summed.
   */
  function collectMergedDamageRows(sk, combatCtx) {
    const dmgRows = skillDamageLines(sk);
    const detailByMerge = new Map();
    for (let i = 0; i < dmgRows.length; i++) {
      const r = dmgRows[i];
      detailByMerge.set(r.mergeKey, r.text);
    }

    const previews = [];
    const healPreviews = [];
    const shieldPreviews = [];
    if (sk && combatCtx && combatCtx.sheetTotals && combatCtx.derived) {
      const sheetTotals = combatCtx.sheetTotals;
      const derived = combatCtx.derived;
      const previewSources = skillAggregatesReferencedDamageRows(sk)
        ? [sk].concat(referencedSkillsForMergedDamage(sk))
        : [sk];
      for (let ci = 0; ci < previewSources.length; ci++) {
        const src = previewSources[ci];
        if (!src || !src.steps) continue;
        const condRank = skillDamageScalingCondsRank(src);
        const holdTier = skillHoldMergedDamageTierTarget(src);
        for (let si = 0; si < src.steps.length; si++) {
          const step = src.steps[si];
          if (skillPreviewShouldSkipProcDamageStep(sk, src, step)) continue;
          const effs = step.effects || [];
          for (let ei = 0; ei < effs.length; ei++) {
            const e = effs[ei];
            if (!skillHostStepEffectMatchesMastery(sk, step, e)) continue;
            if (!skillHoldMergedDamageEffectIncluded(step, e, holdTier)) continue;
            const p = computeEffectDamagePreview(e, sheetTotals, derived, combatCtx, condRank);
            if (p) {
              applyDamagePreviewHitCount(p, blazingBeamDamageHitCount(sk, src, step));
              p.scriptHostSkill = src;
              p.previewMergeStep = step;
              previews.push(p);
            }
            const ph = computeEffectHealPreview(e, sheetTotals, derived, combatCtx, condRank);
            if (ph) {
              ph.scriptHostSkill = src;
              ph.previewMergeStep = step;
              healPreviews.push(ph);
            }
            const ps = computeEffectShieldPreview(e, sheetTotals, derived, combatCtx, condRank);
            if (ps) {
              ps.scriptHostSkill = src;
              ps.previewMergeStep = step;
              shieldPreviews.push(ps);
            }
          }
        }
      }
    }

    const rows = [];
    if (previews.length) {
      const kindOrder = [];
      const byKind = new Map();
      for (let pi = 0; pi < previews.length; pi++) {
        const p = previews[pi];
        const kl = previewDamageGroupKindLabel(p, sk, p.previewMergeStep);
        if (!byKind.has(kl)) {
          kindOrder.push(kl);
          byKind.set(kl, []);
        }
        byKind.get(kl).push(p);
      }
      for (let ki = 0; ki < kindOrder.length; ki++) {
        const kl = kindOrder[ki];
        const group = byKind.get(kl);
        const nums = group.map((p) => (p.uiBaseValPart != null ? p.uiBaseValPart : String(p.rounded)));
        const valPart = nums.length > 1 ? nums.join(" + ") : nums[0];
        const mk = mergeKeyFromDamageKindLabel(kl);
        const mergedScalingDetail = group
          .map((p) => p.scalingDetail)
          .filter((s) => typeof s === "string" && s.trim());
        const computedDetail =
          mergedScalingDetail.length > 0 ? mergedScalingDetail.join(" · ") : null;
        const lineDetail = detailByMerge.has(mk) ? detailByMerge.get(mk) : undefined;
        const detail = computedDetail != null ? computedDetail : lineDetail !== undefined ? lineDetail : null;
        if (computedDetail != null || lineDetail !== undefined) {
          if (detailByMerge.has(mk)) detailByMerge.delete(mk);
        }
        const root = plannerDamageAffinityRootFromKindLabel(kl);
        let finalExpectedSum = null;
        if (combatCtx && combatCtx.derived) {
          const der = combatCtx.derived;
          const baseMult = plannerBaseUiHitDamageMultiplier(der, root);
          const preCritFlat = plannerPreCritFlatDamageMultiplier(der);
          const armorMult = plannerAverageDamageMultiplier(combatCtx, root);
          let fs = 0;
          for (let gi = 0; gi < group.length; gi++) {
            const p = group[gi];
            const derSkill = applySkillPreviewCritDerived(der, sk, p);
            const rawHit = typeof p.raw === "number" && Number.isFinite(p.raw) ? p.raw : 0;
            const sc = skillScriptMultiplierForPreviewHit(p, sk, sk);
            const preCritExact = rawHit * baseMult * preCritFlat * armorMult * sc;
            const jitSk = p.scriptHostSkill || sk;
            let hitEv = skillRowHasWeaponDamageJitter(jitSk)
              ? plannerExpectedWeaponJitterEvAfterCritRound(preCritExact, derSkill)
              : plannerExpectedHeroDamageAfterFlatten(preCritExact, derSkill);
            const hitCountM = sinkToBottomRank3ExpectedMultiplier(sk);
            hitEv *= hitCountM;
            hitEv += skillPostCalculationExtraDamagePerHit(sk, combatCtx, derSkill) * hitCountM;
            fs += hitEv;
          }
          finalExpectedSum = fs;
        }
        rows.push({
          valPart,
          kindLabel: kl,
          detail: detail != null ? detail : null,
          finalExpectedSum,
          damagePreviewHits: group,
        });
      }
    }
    if (sk && combatCtx && combatCtx.sheetTotals && combatCtx.derived && healPreviews.length) {
      const derived = combatCtx.derived;
      const supportM = plannerHealPreviewMultiplier(derived, sk);
      const echoM = mageEchoingLifeHealMultiplier(sk);
      let sumHeal = 0;
      const valParts = [];
      const detParts = [];
      for (let hi = 0; hi < healPreviews.length; hi++) {
        const h = healPreviews[hi];
        const rawHit = typeof h.raw === "number" && Number.isFinite(h.raw) ? h.raw : 0;
        const preCritHeal = Math.max(0, rawHit * supportM * echoM);
        const roundedH = hlMathRound(preCritHeal);
        sumHeal += plannerExpectedDamageEvAfterCritRound(preCritHeal, derived);
        valParts.push(String(roundedH));
        if (h.scalingDetail) detParts.push(h.scalingDetail);
      }
      rows.push({
        valPart: valParts.length > 1 ? valParts.join(" + ") : valParts[0],
        kindLabel: "Healing",
        detail: detParts.length ? detParts.join(" · ") : null,
        finalExpectedSum: sumHeal,
        damagePreviewHits: healPreviews,
      });
    }
    if (sk && combatCtx && combatCtx.sheetTotals && combatCtx.derived && shieldPreviews.length) {
      const derived = combatCtx.derived;
      const supportM = plannerShieldPreviewMultiplier(derived);
      let sumShield = 0;
      const valParts = [];
      const detParts = [];
      for (let si = 0; si < shieldPreviews.length; si++) {
        const h = shieldPreviews[si];
        const rawHit = typeof h.raw === "number" && Number.isFinite(h.raw) ? h.raw : 0;
        const roundedS = hlMathRound(Math.max(0, rawHit * supportM));
        sumShield += roundedS;
        valParts.push(String(roundedS));
        if (h.scalingDetail) detParts.push(h.scalingDetail);
      }
      rows.push({
        valPart: valParts.length > 1 ? valParts.join(" + ") : valParts[0],
        kindLabel: "Shield",
        detail: detParts.length ? detParts.join(" · ") : null,
        finalExpectedSum: sumShield,
        damagePreviewHits: shieldPreviews,
      });
    }
    for (const [mk, text] of detailByMerge) {
      rows.push({
        valPart: null,
        kindLabel: damageKindLabelFromMergeKey(mk),
        detail: text,
      });
    }
    appendWarriorBleedRelatedPreviewRows(sk, combatCtx, rows);
    appendSparkBeamM2SplashRows(sk, combatCtx, rows);
    return rows;
  }

  /** **Spark Beam** M2: nearby splash = **`var3`** (35%) of main beam expected damage. */
  function appendSparkBeamM2SplashRows(sk, combatCtx, rows) {
    if (!sk || sk.id !== "Mage_RayOfSpark" || !rows || !combatCtx || !combatCtx.derived) return;
    if (selectedClassSkillMasteryId(sk.id, sk) !== RAY_OF_SPARK_M2_MASTERY_ID) return;
    const m2 = masteryEntryById(sk, RAY_OF_SPARK_M2_MASTERY_ID);
    const ratio =
      m2 && m2.vars && typeof m2.vars.var3 === "number" && Number.isFinite(m2.vars.var3)
        ? m2.vars.var3
        : 0.35;
    let mainSum = null;
    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      if (row.finalExpectedSum == null || !Number.isFinite(row.finalExpectedSum)) continue;
      const root = plannerDamageAffinityRootFromKindLabel(row.kindLabel);
      if (root !== "Magic") continue;
      mainSum = (mainSum || 0) + row.finalExpectedSum;
    }
    if (mainSum == null || !(mainSum > 0)) return;
    const splash = mainSum * ratio;
    const pctLab = formatSkillPercentFromRatio(ratio);
    rows.push({
      valPart: formatDmgAmount(Math.max(0, hlMathRound(splash))),
      kindLabel: "Magic damage (M2 splash)",
      detail: `${pctLab} of main beam to nearby enemies`,
      finalExpectedSum: splash,
      damagePreviewHits: [],
    });
  }

  function mergedDamagePlainLine(row) {
    const v = row.valPart;
    const k = row.kindLabel;
    const d = row.detail;
    const hasV = v != null && String(v).trim() !== "";
    const hasD = d != null && String(d).trim() !== "";
    if (hasV && hasD) return `${v} ${k} (${d})`;
    if (hasV) return `${v} ${k}`;
    if (hasD) return `${k} (${d})`;
    return k;
  }

  /** Plain-text lines for enchant previews / plain lists. */
  function collectMergedDamageDisplayLines(sk, combatCtx) {
    const rows = collectMergedDamageRows(sk, combatCtx);
    const lines = [];
    for (let i = 0; i < rows.length; i++) lines.push(mergedDamagePlainLine(rows[i]));
    return lines;
  }

  function damagePreviewRowsExist(sk, combatCtx) {
    if (skillSkipsCombatDamagePreview(sk)) return false;
    if (!sk || !combatCtx || !combatCtx.sheetTotals || !combatCtx.derived) return false;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < sources.length; ci++) {
      const row = sources[ci];
      if (!row || !row.steps) continue;
      const condRank = skillDamageScalingCondsRank(row);
      const holdTier = skillHoldMergedDamageTierTarget(row);
      for (let si = 0; si < row.steps.length; si++) {
        const step = row.steps[si];
        const effs = step.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!skillHostStepEffectMatchesMastery(sk, step, e)) continue;
          if (!skillHoldMergedDamageEffectIncluded(step, e, holdTier)) continue;
          if (computeEffectDamagePreview(e, sheetTotals, derived, combatCtx, condRank)) return true;
          if (computeEffectHealPreview(e, sheetTotals, derived, combatCtx, condRank)) return true;
          if (computeEffectShieldPreview(e, sheetTotals, derived, combatCtx, condRank)) return true;
        }
      }
    }
    return false;
  }

  /** Base + gear attribute totals for `ratio × attribute` skill scaling (matches sheet values fed into `Unit.atb`). */
  function mergeCombatSheetTotals(baseStats, gearFlat) {
    const out = {};
    function add(o) {
      if (!o || typeof o !== "object") return;
      for (const k of Object.keys(o)) {
        const v = o[k];
        if (typeof v !== "number" || Number.isNaN(v)) continue;
        out[k] = (out[k] || 0) + v;
      }
    }
    add(baseStats);
    add(gearFlat);
    return out;
  }

  /**
   * Only **`effect.effect === 0`** rows are combat damage in CDB (**heal** = **1**, **resource** = **3**, …).
   * Omits **`target.atb: Spark`** restores (**`Mage_RayOfSpark`**, **`Mage_ChronoReset`**) and heals like **`Mage_ChronoReset`** M1 (**MaxHealth**).
   */
  function effectScalingIsCombatDamagePreview(effect) {
    if (!effect) return false;
    const tgt = effect.target && effect.target.atb != null ? String(effect.target.atb) : "";
    if (tgt === "Spark") return false;
    const ek = effect.effect;
    if (typeof ek === "number" && ek !== 0) return false;
    return true;
  }

  /** **effect 1** heal scaling (e.g. **Lifebolt**) — omits **Spark** resource rows like damage preview. */
  function effectScalingIsCombatHealPreview(effect) {
    if (!effect) return false;
    const tgt = effect.target && effect.target.atb != null ? String(effect.target.atb) : "";
    if (tgt === "Spark") return false;
    const ek = effect.effect;
    return ek === 1;
  }

  /** **effect 2** shield scaling — applies ShieldPower/Fervor, not damage crit/armor/mastery. */
  function effectScalingIsCombatShieldPreview(effect) {
    if (!effect) return false;
    const tgt = effect.target && effect.target.atb != null ? String(effect.target.atb) : "";
    if (tgt === "Spark") return false;
    const ek = effect.effect;
    return ek === 2;
  }

  /** True when **`steps`** contain a combat heal preview row (**`effect` 1** + scaling). */
  function skillRowHasHealCombatPreview(sk) {
    if (!sk || !Array.isArray(sk.steps)) return false;
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < sources.length; ci++) {
      const src = sources[ci];
      if (!src || !Array.isArray(src.steps)) continue;
      for (let si = 0; si < src.steps.length; si++) {
        const st = src.steps[si];
        const effs = st.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!skillHostStepEffectMatchesMastery(sk, st, e)) continue;
          if (!effectScalingIsCombatHealPreview(e)) continue;
          const sc = e.scaling;
          if (Array.isArray(sc) && sc.length) return true;
        }
      }
    }
    return false;
  }

  /** Max **`holdSteps`** from **`steps[].props.casting.holdSteps`** (hold-to-release / charge casts). */
  function skillCastHoldStepsCap(sk) {
    if (!sk || !Array.isArray(sk.steps)) return null;
    let mx = null;
    for (let i = 0; i < sk.steps.length; i++) {
      const casting = sk.steps[i] && sk.steps[i].props && sk.steps[i].props.casting;
      const hs = casting && typeof casting.holdSteps === "number" && Number.isFinite(casting.holdSteps);
      if (hs) {
        const n = Math.max(1, Math.floor(casting.holdSteps));
        mx = mx == null ? n : Math.max(mx, n);
      }
    }
    return mx;
  }

  /** `castHoldStep` on the effect **`cond`** wins over the step **`cond`** (same field name in CDB). */
  function skillStepOrEffectCastHoldStep(step, effect) {
    const ec = effect && effect.cond && effect.cond.castHoldStep;
    const sc = step && step.cond && step.cond.castHoldStep;
    if (typeof ec === "number" && Number.isFinite(ec)) return Math.floor(ec);
    if (typeof sc === "number" && Number.isFinite(sc)) return Math.floor(sc);
    return null;
  }

  /**
   * For hold-charge skills, merged **expected** / UI-base previews should use **one** release tier (full charge), not the sum
   * of every mutually exclusive **`castHoldStep`** hit. Returns the tier index to keep, or **`null`** when no filter applies.
   */
  function skillHoldMergedDamageTierTarget(sk) {
    const cap = skillCastHoldStepsCap(sk);
    if (cap == null) return null;
    let presentMax = null;
    const steps = sk.steps;
    for (let si = 0; si < steps.length; si++) {
      const step = steps[si];
      const effs = step && step.effects;
      if (!effs) continue;
      for (let ei = 0; ei < effs.length; ei++) {
        const e = effs[ei];
        if (!effectScalingIsCombatDamagePreview(e)) continue;
        const ch = skillStepOrEffectCastHoldStep(step, e);
        if (ch != null) presentMax = presentMax == null ? ch : Math.max(presentMax, ch);
      }
    }
    if (presentMax == null) return null;
    return Math.min(cap, presentMax);
  }

  function skillHoldMergedDamageEffectIncluded(step, effect, tierTarget) {
    if (tierTarget == null) return true;
    const ch = skillStepOrEffectCastHoldStep(step, effect);
    if (ch == null) return true;
    return ch === tierTarget;
  }

  /** Ratio **`r`** from **`scaling[].atb === "MaxSpark"`** on effects whose **`target.atb`** is **`Spark`** — used for **`::atbgain::`** (% of max Spark pool when pool equals **`MaxSpark`** sheet total). */
  function sparkRestoreRatioFromSkill(sk) {
    if (!sk || !Array.isArray(sk.steps)) return null;
    for (let si = 0; si < sk.steps.length; si++) {
      const effs = sk.steps[si].effects || [];
      for (let ei = 0; ei < effs.length; ei++) {
        const e = effs[ei];
        const tgt = e.target && e.target.atb != null ? String(e.target.atb) : "";
        if (tgt !== "Spark") continue;
        const sc = e.scaling;
        if (!Array.isArray(sc)) continue;
        for (let ri = 0; ri < sc.length; ri++) {
          const row = sc[ri];
          if (row.atb === "MaxSpark" && typeof row.ratio === "number" && Number.isFinite(row.ratio)) {
            return row.ratio;
          }
        }
      }
    }
    return null;
  }

  /** Resolve Physical / Magic root from `affinity` sheet parent chain (`Spark` → Magic, etc.). */
  function affinityDamageRoot(affinityId) {
    let id = affinityId != null ? String(affinityId) : "";
    const seen = new Set();
    while (id && !seen.has(id)) {
      seen.add(id);
      if (id === "Physical") return "Physical";
      if (id === "Magic") return "Magic";
      const next = affinityParentById[id];
      id = typeof next === "string" && next ? next : "";
    }
    return null;
  }

  /** Group hits that share the same tooltip damage family (Physical vs Magic lineage, else exact affinity). */
  function skillDamageMergeKey(affinityId) {
    const root = affinityDamageRoot(affinityId);
    if (root === "Physical" || root === "Magic") return root;
    return affinityId != null ? String(affinityId) : "Hit";
  }

  /** Short label for merged scaling rows (collapse Spark/Fire/… into Physical or Magic when grouped). */
  function skillDamageAffLabel(mergeKey, firstAffinityShort) {
    if (mergeKey === "Physical" || mergeKey === "Magic") return mergeKey;
    return firstAffinityShort;
  }

  /** In-game tooltips use "Magic damage" for all Magic-line affinities (Spark, Fire, …). */
  function affinityDamageKindLabel(affinityId) {
    const root = affinityDamageRoot(affinityId);
    if (root === "Physical") return "Physical damage";
    if (root === "Magic") return "Magic damage";
    const aff = affinityId != null ? String(affinityId) : "Hit";
    return `${aff} damage`;
  }

  /** Stat scaling slice in **`gp-char-skill__computed-dmg-detail`**: **`ratio × 100`** with trimmed decimals + **`%`**. */
  function fmtScalingDetailStatPercent(ratio) {
    if (!Number.isFinite(ratio)) return "?%";
    const pct = ratio * 100;
    const abs = Math.abs(pct);
    if (abs >= 100) return `${Math.round(pct)}%`;
    if (abs >= 10) return `${pct.toFixed(1).replace(/\.0$/, "")}%`;
    return `${pct.toFixed(2).replace(/\.?0+$/, "")}%`;
  }

  /**
   * HashLink **`math_round@18131`** (`tools/hashlink/src/std/math.c`): **`(int)floor(x + 0.5)`**.
   * Matches HashLink **`Math.round`** semantics, unlike raw
   * **`Math.round`** when float noise sits on a half boundary.
   * @param {number} x
   * @returns {number}
   */
  function hlMathRound(x) {
    if (!Number.isFinite(x)) return 0;
    return Math.floor(x + 0.5);
  }

  /**
   * In-game **`WeaponAttack_RandomRange`** gate on CDB **`type`** 0–3: combined pre-crit damage is multiplied by **`1 + r·U`**
   * with **U ~ Uniform[-1, 1]** before **`hlMathRound`**. **`r`** is **0.1** in exported constants.
   */
  const WEAPON_ATTACK_RANDOM_RANGE = 0.1;

  /** CDB attack-chain families (**`Attack`** … **`Attack4`**, types **0–4**) that receive weapon damage jitter. */
  function skillRowHasWeaponDamageJitter(sk) {
    if (!sk || typeof sk.type !== "number" || !Number.isFinite(sk.type)) return false;
    const t = sk.type;
    return t >= SKILL_TYPE_ATTACK_CHAIN_MIN && t <= SKILL_TYPE_ATTACK_CHAIN_MAX;
  }

  /**
   * Probability masses **P(hlMathRound(X) = k)** when **X ~ Uniform[a, b]** on a **closed** segment; masses sum to **1** and cover every
   * integer **k** that **`hlMathRound`** can yield on **[a, b]** (used for weapon jitter → description range + expected row).
   */
  function hlMathRoundMassesUniformInterval(a, b) {
    if (!Number.isFinite(a) || !Number.isFinite(b)) return [];
    const lo = Math.min(a, b);
    const hi = Math.max(a, b);
    const span = hi - lo;
    if (!(span > 0)) {
      const k = hlMathRound(lo);
      return [{ k, p: 1 }];
    }
    const out = [];
    const k0 = Math.floor(lo - 0.5);
    const k1 = Math.ceil(hi + 0.5);
    for (let k = k0; k <= k1; k++) {
      const segLo = Math.max(lo, k - 0.5);
      const segHi = Math.min(hi, k + 0.5);
      const len = segHi > segLo ? segHi - segLo : 0;
      if (len > 0) out.push({ k, p: len / span });
    }
    return out;
  }

  function hlMathRoundMassesUniformSymmetricBand(mid, r) {
    if (!Number.isFinite(mid) || !Number.isFinite(r) || !(r >= 0)) return [];
    return hlMathRoundMassesUniformInterval(mid * (1 - r), mid * (1 + r));
  }

  /** UI base string for skill cards: same integer rule as in-game hit rounding (**`hlMathRound`**). */
  function formatUiBaseDamageValPart(exact) {
    if (!Number.isFinite(exact)) return "?";
    return String(hlMathRound(exact));
  }

  /**
   * Shared **`scaling[]`** → **`raw`** / **`sheetLines`** for combat **`effect` 0** (damage), **`effect` 1** (heal),
   * or **`effect` 2** (shield). Heals/shields reuse weapon-split aptitude logic but skip damage-only mastery.
   * @param {boolean|string} previewKind **false** / `"damage"`, **true** / `"heal"`, or `"shield"`.
   * @param {number} [scalingCondsRank]
   */
  function computeEffectCombatScalingPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank, previewKind) {
    const healPreview = previewKind === true || previewKind === "heal";
    const shieldPreview = previewKind === "shield";
    if (shieldPreview) {
      if (!effectScalingIsCombatShieldPreview(effect)) return null;
    } else if (healPreview) {
      if (!effectScalingIsCombatHealPreview(effect)) return null;
    } else if (!effectScalingIsCombatDamagePreview(effect)) return null;
    const sc = effect && effect.scaling;
    const hasScaling = Array.isArray(sc) && sc.length > 0;
    const baseVal = effect && typeof effect.baseVal === "number" && Number.isFinite(effect.baseVal) ? effect.baseVal : 0;
    if ((!hasScaling && !(baseVal > 0)) || !sheetTotals || !derived) return null;
    const condRank =
      scalingCondsRank != null && Number.isFinite(scalingCondsRank)
        ? clamp(Math.floor(scalingCondsRank), 1, 99)
        : null;
    const wp = combatCtx && combatCtx.weaponPowerPreview;
    const wItem = wp && wp.item;
    let W = wp && typeof wp.weaponPowerRatio === "number" ? wp.weaponPowerRatio : null;
    if (W != null) {
      W = Math.min(1, Math.max(0, W));
      if (W <= 0) W = null;
    }

    let raw = baseVal > 0 ? baseVal : 0;
    let weaponFlatTotal = 0;
    const statRatioAcc = new Map();
    /** @type {Array<{ type: string, atb: string, name: string, ratio: number, ratioEffective?: number, sheet?: number|null, w?: number|null, aptitudeCurveLevel?: number|null, part: number }>} */
    const sheetLines = [];
    if (baseVal > 0) {
      sheetLines.push({
        type: "aggregate",
        atb: "",
        name: "Base value",
        ratio: 0,
        part: baseVal,
      });
    }
    for (let i = 0; i < (hasScaling ? sc.length : 0); i++) {
      const row = sc[i];
      const atb = row.atb;
      const ratio = row.ratio;
      if (typeof atb !== "string" || typeof ratio !== "number") continue;
      if (condRank != null && !talentAffixRowMatchesRank(row.conds, condRank)) continue;
      const attrRow = attributeById[atb];
      const useWeaponSplit =
        W != null &&
        wItem &&
        attrRow &&
        typeof attrRow.flags === "number" &&
        (attrRow.flags & ATTR_FLAG_WEAPON_POWER_SPLIT) !== 0;
      const sv = sheetTotals[atb];
      const hasSv = typeof sv === "number" && Number.isFinite(sv);

      let statPart = 0;
      let rStat = ratio;
      if (hasSv) {
        rStat = useWeaponSplit ? ratio * (1 - W) : ratio;
        statPart = rStat * sv;
      }

      let flatPart = 0;
      let curveLCombat = null;
      if (useWeaponSplit) {
        curveLCombat =
          wp && typeof wp.aptitudeCurveLevel === "number" && Number.isFinite(wp.aptitudeCurveLevel)
            ? wp.aptitudeCurveLevel
            : null;
        const expCombat = expectedAttributeForWeaponSkillFlat(wItem, atb, curveLCombat);
        flatPart = expCombat * ratio * W;

        const curveLTip =
          wp && typeof wp.aptitudeCurveLevelTooltip === "number" && Number.isFinite(wp.aptitudeCurveLevelTooltip)
            ? wp.aptitudeCurveLevelTooltip
            : curveLCombat;
        const expTip = expectedAttributeForWeaponSkillFlat(wItem, atb, curveLTip);
        weaponFlatTotal += expTip * ratio * W;
      }

      raw += statPart + flatPart;

      const nm = displayNameForAttr(atb);
      if (hasSv) {
        sheetLines.push({
          type: "stat",
          atb,
          name: nm,
          ratio,
          ratioEffective: rStat,
          sheet: sv,
          part: statPart,
        });
      }
      if (useWeaponSplit && Math.abs(flatPart) >= 1e-8) {
        sheetLines.push({
          type: "flat",
          atb,
          name: nm,
          ratio,
          w: W,
          aptitudeCurveLevel: curveLCombat,
          part: flatPart,
        });
      }

      if (useWeaponSplit) {
        const rShow = ratio * (1 - W);
        statRatioAcc.set(atb, (statRatioAcc.get(atb) || 0) + rShow);
      } else {
        statRatioAcc.set(atb, (statRatioAcc.get(atb) || 0) + ratio);
      }
    }
    if (!sheetLines.length && Math.abs(raw) > 1e-6) {
      sheetLines.push({ type: "aggregate", atb: "", name: "Raw (aggregated)", ratio: 0, part: raw });
    }
    const aff = effect.affinity != null ? String(effect.affinity) : "Hit";
    const root = affinityDamageRoot(aff);
    const isSupportPreview = healPreview || shieldPreview;
    const mult = isSupportPreview ? 1 : plannerBaseUiHitDamageMultiplier(derived, root);
    const exactUiBase = raw * mult;
    const rounded = hlMathRound(exactUiBase);
    const uiBaseValPart = formatUiBaseDamageValPart(exactUiBase);

    const detailBits = [];
    if (weaponFlatTotal >= 0.005) {
      const noun = shieldPreview ? "shield" : healPreview ? "heal" : "damage";
      detailBits.push(`${hlMathRound(weaponFlatTotal)} flat ${noun}`);
    }
    const statKeys = [...statRatioAcc.keys()].sort((a, b) =>
      displayNameForAttr(a).localeCompare(displayNameForAttr(b))
    );
    for (let di = 0; di < statKeys.length; di++) {
      const k = statKeys[di];
      const acc = statRatioAcc.get(k);
      if (!Number.isFinite(acc) || Math.abs(acc) < 1e-10) continue;
      detailBits.push(`${displayNameForAttr(k)} ${fmtScalingDetailStatPercent(acc)}`);
    }
    const scalingDetail = detailBits.length ? detailBits.join(" + ") : null;

    const out = {
      rounded,
      uiBaseValPart,
      kindLabel: affinityDamageKindLabel(aff),
      raw,
      mult,
      scalingDetail,
      sheetLines,
      affinityRoot: root,
    };
    if (healPreview) out.isHealPreview = true;
    if (shieldPreview) out.isShieldPreview = true;
    return out;
  }

  /**
   * Tooltip / merged-line damage: matches **`getStepEffectScaling@19819`** for weapon skills when **`combatCtx.weaponPowerPreview`**
   * is set — aptitude **flat** uses **`Item.level`**-style **`L`** (**`lootScaleTier(ilvl)`**, same as **`getStepEffectItemScaling@19821`** → **`19718`**),
   * not **`lootCoordinateT`** (affix / raw-ilvl coordinate). Stat slice uses **full CDB `ratio`** × sheet ATB × **`(1 − W)`** when split.
   * **UI base** (**`uiBaseValPart`** / **`rounded`**): **× (1+mastery)** only — `rounded` is for **`::dmg::`** tokens; integers use
   * **`hlMathRound`** (HashLink **`math_round`**).
   * **Expected vs foe** (see **`collectMergedDamageRows` → `finalExpectedSum`**): one float chain
   * **raw × mastery × Fervor × DamageModifier × extraMore × armor**, then Hero-owned damage flattening uses **`ceil`**.
   * **crit** is resolved as a separate ceiled outcome, not as a linear multiplier inside the same rounding step.
   * @param {number} [scalingCondsRank] Rank for **`scaling[].conds`** (`minRank` / `maxRank`); defaults applied at call sites.
   */
  function computeEffectDamagePreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank) {
    return computeEffectCombatScalingPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank, false);
  }

  /**
   * **`effect.effect === 1`** heal scaling — same **`scaling[]`** rules as damage (**no armor / crit** in **`collectMergedDamageRows`** EV).
   * @param {number} [scalingCondsRank]
   */
  function computeEffectHealPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank) {
    return computeEffectCombatScalingPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank, true);
  }

  /**
   * **`effect.effect === 2`** shield scaling — in game this goes through **`getShieldPowerMultiplier`** and does not crit.
   * @param {number} [scalingCondsRank]
   */
  function computeEffectShieldPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank) {
    return computeEffectCombatScalingPreview(effect, sheetTotals, derived, combatCtx, scalingCondsRank, "shield");
  }

  /**
   * Fallback when **`foe_defenses.json`** is missing — linear heuristic armor / magic armor points.
   */
  function plannerMonsterArmorMagicHeuristic(monsterLevel) {
    const ml = clamp(Math.round(monsterLevel), 1, MONSTER_LEVEL_MAX);
    const pts = 28 + ml * 15;
    return { armorPts: pts, magicArmorPts: pts };
  }

  /**
   * Same resolution as {@link plannerMonsterArmorMagicPts} plus **`source`** for UI copy / tooltips.
   * @returns {{ armorPts: number, magicArmorPts: number, source: "unit" | "median" | "heuristic" }}
   */
  function plannerMonsterArmorMagicPtsResolved(monsterLevel, foeUnitId) {
    const ml = clamp(Math.round(monsterLevel), 1, MONSTER_LEVEL_MAX);
    const sk = String(ml);
    const fid = foeUnitId != null ? String(foeUnitId) : "median";
    const fb = foeDefensesPayload;
    if (fb && fid !== "median") {
      const u = foeUnitById[fid];
      const row = u && u.resolvedByLevel && u.resolvedByLevel[sk];
      if (row && typeof row.armorPts === "number" && Number.isFinite(row.armorPts)) {
        return {
          armorPts: row.armorPts,
          magicArmorPts:
            typeof row.magicArmorPts === "number" && Number.isFinite(row.magicArmorPts)
              ? row.magicArmorPts
              : row.armorPts,
          source: "unit",
        };
      }
    }
    if (fb && fb.summaryByMonsterLevel && fb.summaryByMonsterLevel[sk]) {
      const s = fb.summaryByMonsterLevel[sk];
      if (s && typeof s.medianArmorPts === "number" && Number.isFinite(s.medianArmorPts)) {
        return {
          armorPts: s.medianArmorPts,
          magicArmorPts:
            typeof s.medianMagicArmorPts === "number" && Number.isFinite(s.medianMagicArmorPts)
              ? s.medianMagicArmorPts
              : s.medianArmorPts,
          source: "median",
        };
      }
    }
    const h = plannerMonsterArmorMagicHeuristic(ml);
    return { armorPts: h.armorPts, magicArmorPts: h.magicArmorPts, source: "heuristic" };
  }

  /**
   * Target **Armor** / **MagicArmor** rating points (same space as `defender.atb` in `getAffinityDamageReduction`).
   * Uses exported CDB-derived values when **`foeDefensesPayload`** is set; otherwise {@link plannerMonsterArmorMagicHeuristic}.
   * For **`"median"`**, uses **`summaryByMonsterLevel[L]`**: median of each template’s armor resolved **at monster level L**,
   * including only enemy units whose spawn level span contains **L** (see export script).
   * @param {string} [foeUnitId] — **`"median"`** or a **`unit`** id from **`foe_defenses.json`**.
   */
  function plannerMonsterArmorMagicPts(monsterLevel, foeUnitId) {
    const r = plannerMonsterArmorMagicPtsResolved(monsterLevel, foeUnitId);
    return { armorPts: r.armorPts, magicArmorPts: r.magicArmorPts };
  }

  /**
   * Returns **R** with **0 ≤ R ≤ 1** where the game does **`damageMult *= (1 - R)`** (`computeDamage@5459` × `getAffinityDamageReduction@5150`).
   * `rawResistPts` = stacked resist; `penPercentPts` = sheet pen (e.g. **5** = 5 / 100 of resist ignored).
   */
  function plannerAffinityMitigatedFraction(rawResistPts, penPercentPts, attackerLevel) {
    const a = RESIST_SCALABLE_A;
    const b = RESIST_SCALABLE_B;
    const lv = clamp(Math.floor(attackerLevel || 1), 1, CHAR_LEVEL_MAX);
    let pen = typeof penPercentPts === "number" && Number.isFinite(penPercentPts) ? penPercentPts : 0;
    pen = clamp(pen, 0, 100);
    const raw = Math.max(0, rawResistPts || 0);
    const eff = raw * (1 - pen * 0.01);
    const denom = eff + a + b * lv;
    if (!(denom > 0)) return 0;
    return eff / denom;
  }

  /** Physical / **`Magic`** lineage from merged **`kindLabel`** (`"Magic damage"` → **`Magic`**); **`null`** if no armor DR bucket. */
  function plannerDamageAffinityRootFromKindLabel(kindLabel) {
    const mk = mergeKeyFromDamageKindLabel(kindLabel);
    const r = affinityDamageRoot(mk);
    return r === "Physical" || r === "Magic" ? r : null;
  }

  function plannerDamagePreviewExtraMoreMult() {
    const m = plannerDamagePreviewSettings && plannerDamagePreviewSettings.extraMoreDamageMult;
    if (typeof m !== "number" || !Number.isFinite(m) || m <= 0) return 1;
    return clamp(m, 0.05, 50);
  }

  /** Sum of additive **%**-style stats on **`derived`** → one **(1 + Σ/100)** multiplier. */
  function plannerDerivedAdditivePctMult(derived, keys) {
    if (!derived || !keys || !keys.length) return 1;
    let s = 0;
    for (let i = 0; i < keys.length; i++) {
      const v = derived[keys[i]];
      if (typeof v === "number" && Number.isFinite(v)) s += v;
    }
    return s ? 1 + s / 100 : 1;
  }

  /**
   * **White / UI skill line**: **Physical/Magic mastery** only (no **Fervor**, no crit, no **`DamageModifier`**, no
   * **`extraMoreDamageMult`**, no armor).
   */
  function plannerBaseUiHitDamageMultiplier(derived, affinityRoot) {
    if (!derived || typeof derived !== "object") return 1;
    let m = 1;
    if (affinityRoot === "Physical") m *= 1 + (derived.PhysicalMastery_pct || 0) / 100;
    else if (affinityRoot === "Magic") m *= 1 + (derived.MagicMastery_pct || 0) / 100;
    return m;
  }

  /**
   * **Fervor**, sheet **`DamageModifier`**, and **`extraMoreDamageMult`** only — **no crit**. Crit is mixed in **after**
   * the Hero-owned damage flattening step via **`plannerExpectedHeroDamageAfterFlatten`**.
   */
  function plannerPreCritFlatDamageMultiplier(derived) {
    if (!derived || typeof derived !== "object") return 1;
    let m = 1;
    m *= 1 + (derived.Fervor_pct || 0) / 100;
    m *= plannerDerivedAdditivePctMult(derived, ["DamageModifier_pct"]);
    m *= plannerDamagePreviewExtraMoreMult();
    return m;
  }

  function plannerSupportFervorMultiplier(derived) {
    if (!derived || typeof derived !== "object") return 1;
    return 1 + (derived.Fervor_pct || 0) / 100;
  }

  function plannerHealPreviewMultiplier(derived) {
    return plannerSupportFervorMultiplier(derived) * globalClassBuffHealMultiplier();
  }

  function plannerShieldPreviewMultiplier(derived) {
    return plannerSupportFervorMultiplier(derived) * globalClassBuffShieldMultiplier();
  }

  /**
   * Linear product **Fervor × crit EV × DamageModifier × extraMore** (no mastery, no armor). Rough scaling only — the
   * **green expected line** uses **`plannerPreCritFlatDamageMultiplier`** + **`plannerExpectedDamageEvAfterCritRound`**.
   */
  function plannerFinalDamageAfterBaseMultiplier(derived) {
    if (!derived || typeof derived !== "object") return 1;
    return plannerPreCritFlatDamageMultiplier(derived) * plannerCritDamageMultiplier(derived);
  }

  function plannerAverageDamageMultiplier(combatCtx, affinityRoot) {
    if (!combatCtx || !combatCtx.derived) return 1;
    const der = combatCtx.derived;
    const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const ml =
      combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx.foeUnitId != null ? combatCtx.foeUnitId : "median";
    const am = plannerMonsterArmorMagicPts(ml, foeId);
    let mult = 1;
    if (affinityRoot === "Physical") {
      const pen = der.ArmorPenetration_pct || 0;
      mult *= 1 - plannerAffinityMitigatedFraction(am.armorPts, pen, cl);
    } else if (affinityRoot === "Magic") {
      const pen = der.SpellPenetration_pct || 0;
      const magPts = plannerEffectiveMagicArmorMitigationPts(combatCtx);
      mult *= 1 - plannerAffinityMitigatedFraction(magPts, pen, cl);
    }
    mult *= plannerKnivesTempestArmorShredDamageMult(combatCtx, affinityRoot);
    return mult;
  }

  /** Same as {@link plannerAverageDamageMultiplier} but **0% penetration** — used for skill **`::dmg::`** prose (no pen, no crit). */
  function plannerAverageDamageMultiplierNoPenetration(combatCtx, affinityRoot) {
    if (!combatCtx || !combatCtx.derived) return 1;
    const der = combatCtx.derived;
    const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const ml =
      combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx.foeUnitId != null ? combatCtx.foeUnitId : "median";
    const am = plannerMonsterArmorMagicPts(ml, foeId);
    let mult = 1;
    if (affinityRoot === "Physical") {
      mult *= 1 - plannerAffinityMitigatedFraction(am.armorPts, 0, cl);
    } else if (affinityRoot === "Magic") {
      const magPts = plannerEffectiveMagicArmorMitigationPts(combatCtx);
      mult *= 1 - plannerAffinityMitigatedFraction(magPts, 0, cl);
    }
    mult *= plannerKnivesTempestArmorShredDamageMult(combatCtx, affinityRoot);
    return mult;
  }

  /** Sheet **CritDamage** is the crit-hit multiplier itself: **150%** means **1.5×**, not **+150%**. */
  function plannerCritDamageStatMultiplier(derived) {
    if (!derived || typeof derived !== "object") return 1;
    const pct = derived.CritDamage_pct;
    if (typeof pct !== "number" || !Number.isFinite(pct)) return 1;
    return Math.max(0, pct / 100);
  }

  function plannerSheetPenetrationPct(pct) {
    if (typeof pct !== "number" || !Number.isFinite(pct)) return 0;
    return clamp(hlMathRound(pct * 10) / 10, 0, 100);
  }

  function formatPlannerSheetPenetrationPct(pct) {
    if (typeof pct !== "number" || !Number.isFinite(pct)) return "—";
    return `${plannerSheetPenetrationPct(pct).toFixed(1).replace(/\.0$/, "")}%`;
  }

  function plannerHeroFlattenDamageAmount(x) {
    if (!Number.isFinite(x)) return 0;
    return Math.max(0, Math.ceil(x - 1e-9));
  }

  /** Crit contribution to average hit multiplier: **`expected`** uses sheet chance × crit multiplier; **`never`** / **`always`** force outcome. */
  function plannerCritDamageMultiplier(derived) {
    if (!derived || typeof derived !== "object") return 1;
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    const pSheet = clamp((derived.CritChance_pct || 0) / 100, 0, 1);
    const onCrit = plannerCritDamageStatMultiplier(derived);
    let p = pSheet;
    if (mode === "never") p = 0;
    else if (mode === "always") p = 1;
    return (1 - p) + p * onCrit;
  }

  function plannerDamagePreviewKickerLabel() {
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    if (mode === "never") return "Non-crit";
    if (mode === "always") return "All crit";
    return "Expected";
  }

  /**
   * Expected damage **after** pre-crit damage has already been reduced to integer **`D`** (**`hlMathRound`** of jittered or exact chain).
   * **Never**: **`D`**. **Always**: **`hlMathRound(D × (CritDamage_pct/100))`**. **Expected**:
   * **`(1−p)×D + p×hlMathRound(D × (CritDamage_pct/100))`** with effective **p** from preview crit mode.
   * @param {number} D **Post-`hlMathRound`** pre-crit damage (integer or near-integer)
   */
  function plannerExpectedDamageEvAfterCritRoundFromD(D, derived) {
    if (!Number.isFinite(D)) return 0;
    const D0 = hlMathRound(D);
    if (!derived || typeof derived !== "object") return Math.max(0, D0);
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    const pSheet = clamp((derived.CritChance_pct || 0) / 100, 0, 1);
    const onCrit = plannerCritDamageStatMultiplier(derived);
    let p = pSheet;
    if (mode === "never") p = 0;
    else if (mode === "always") p = 1;
    if (p <= 0) return Math.max(0, D0);
    if (p >= 1) return Math.max(0, hlMathRound(D0 * onCrit));
    return Math.max(0, (1 - p) * D0 + p * hlMathRound(D0 * onCrit));
  }

  /**
   * Expected damage **after** **`D = hlMathRound(preCritExact)`** (full pre-crit chain including armor). **Never**: **`D`**.
   * **Always**: **`hlMathRound(D × (CritDamage_pct/100))`**. **Expected**: **`(1−p)×D + p×hlMathRound(D × (CritDamage_pct/100))`**
   * with effective **p** from preview crit mode.
   * @param {number} preCritExact `raw × mastery × Fervor × DamageModifier × extraMore × armor`
   */
  function plannerExpectedDamageEvAfterCritRound(preCritExact, derived) {
    if (!Number.isFinite(preCritExact)) return 0;
    return plannerExpectedDamageEvAfterCritRoundFromD(hlMathRound(preCritExact), derived);
  }

  function plannerExpectedHeroDamageAfterFlatten(preCritExact, derived) {
    if (!Number.isFinite(preCritExact)) return 0;
    const nonCrit = plannerHeroFlattenDamageAmount(preCritExact);
    if (!derived || typeof derived !== "object") return nonCrit;
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    const pSheet = clamp((derived.CritChance_pct || 0) / 100, 0, 1);
    const onCrit = plannerCritDamageStatMultiplier(derived);
    let p = pSheet;
    if (mode === "never") p = 0;
    else if (mode === "always") p = 1;
    if (p <= 0) return nonCrit;
    const crit = plannerHeroFlattenDamageAmount(preCritExact * onCrit);
    if (p >= 1) return crit;
    return Math.max(0, (1 - p) * nonCrit + p * crit);
  }

  /**
   * **Weapon jitter then pre-crit round:** **X = μ(1 + r·U)**, **U ~ Uniform[-1, 1]**, **D = hlMathRound(X)**. For each integer
   * **k** with **P(D = k) > 0**, mix **`plannerExpectedDamageEvAfterCritRoundFromD(k, derived)`** (**crit** is applied **after** that
   * rounded pre-crit damage). Matches **Σ_k P(D = k) × EV(hit | D = k)**.
   * @param {number} preCritExact **μ** — same chain as **`plannerExpectedDamageEvAfterCritRound`** (**no** jitter in this float).
   */
  function plannerExpectedWeaponJitterEvAfterCritRound(preCritExact, derived) {
    if (!Number.isFinite(preCritExact)) return 0;
    const masses = hlMathRoundMassesUniformSymmetricBand(preCritExact, WEAPON_ATTACK_RANDOM_RANGE);
    if (!masses.length) return plannerExpectedDamageEvAfterCritRound(preCritExact, derived);
    let ev = 0;
    for (let i = 0; i < masses.length; i++) {
      const { k, p } = masses[i];
      ev += p * plannerExpectedDamageEvAfterCritRoundFromD(k, derived);
    }
    return ev;
  }

  function plannerCritProbabilityForPreview(derived) {
    if (!derived || typeof derived !== "object") return 0;
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    if (mode === "never") return 0;
    if (mode === "always") return 1;
    return clamp((derived.CritChance_pct || 0) / 100, 0, 1);
  }

  function plannerNonCritRoundedDamage(preCritExact, jitter) {
    if (!Number.isFinite(preCritExact)) return 0;
    if (!jitter) return plannerHeroFlattenDamageAmount(preCritExact);
    const masses = hlMathRoundMassesUniformSymmetricBand(preCritExact, WEAPON_ATTACK_RANDOM_RANGE);
    if (!masses.length) return Math.max(0, hlMathRound(preCritExact));
    let ev = 0;
    for (let i = 0; i < masses.length; i++) ev += masses[i].p * Math.max(0, masses[i].k);
    return ev;
  }

  function plannerIndependentNonCritDamageFromSkill(skillId, combatCtx) {
    const sk = skillById[skillId];
    if (!sk || !combatCtx || !combatCtx.sheetTotals || !combatCtx.derived || !Array.isArray(sk.steps)) return 0;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    const rank = skillDamageScalingCondsRank(sk);
    let sum = 0;
    for (let si = 0; si < sk.steps.length; si++) {
      const step = sk.steps[si];
      const effs = step && step.effects ? step.effects : [];
      for (let ei = 0; ei < effs.length; ei++) {
        const p = computeEffectDamagePreview(effs[ei], sheetTotals, derived, combatCtx, rank);
        if (!p) continue;
        const root = plannerSkillDescAffinityRootFromPreview(p);
        const rawHit = typeof p.raw === "number" && Number.isFinite(p.raw) ? p.raw : 0;
        const preCrit =
          rawHit *
          plannerBaseUiHitDamageMultiplier(derived, root) *
          plannerPreCritFlatDamageMultiplier(derived) *
          plannerAverageDamageMultiplier(combatCtx, root);
        sum += plannerNonCritRoundedDamage(preCrit, false);
      }
    }
    return sum;
  }

  function swarmstrikeAccordExtraDamagePerHit(combatCtx) {
    if (!globalBuffHostOnSkillBar(BLADELEAF_SWARMSTRIKE_HOST_ID)) return 0;
    if (!passiveScriptGlobalMultApplies(BLADELEAF_SWARMSTRIKE_HOST_ID)) return 0;
    const preCrit = plannerIndependentNonCritDamageFromSkill(BLADELEAF_SWARMSTRIKE_STATUS_ID, combatCtx);
    if (!(preCrit > 0)) return 0;
    const der = combatCtx && combatCtx.derived;
    return plannerExpectedDamageEvAfterCritRound(preCrit, der);
  }

  function queensDecreeCritExtraDamagePerHit(combatCtx, derivedForCrit) {
    const host = skillById[BLADELEAF_QUEENS_DECREE_ID];
    if (!host || skillDamageScalingCondsRank(host) < 3) return 0;
    if (!globalBuffHostOnSkillBar(BLADELEAF_QUEENS_DECREE_ID)) return 0;
    if (!passiveScriptGlobalMultApplies(BLADELEAF_QUEENS_DECREE_ID)) return 0;
    if (!skillScriptAssumptionIsEnabled(BLADELEAF_QUEENS_DECREE_ID, BLADELEAF_QUEENS_DECREE_R3_ASSUMPTION_ID)) {
      return 0;
    }
    const triggerChance = plannerCritProbabilityForPreview(derivedForCrit || (combatCtx && combatCtx.derived));
    if (!(triggerChance > 0)) return 0;
    const preCrit = plannerIndependentNonCritDamageFromSkill(BLADELEAF_QUEENS_DECREE_ID, combatCtx);
    if (!(preCrit > 0)) return 0;
    const der = derivedForCrit || (combatCtx && combatCtx.derived);
    return plannerExpectedDamageEvAfterCritRound(preCrit, der) * triggerChance;
  }

  function skillPostCalculationExtraDamagePerHit(consumerSk, combatCtx, derivedForCrit) {
    if (!consumerSk || !combatCtx) return 0;
    let add = 0;
    if (skillIsAttackActionForBuffs(consumerSk)) add += swarmstrikeAccordExtraDamagePerHit(combatCtx);
    if (skillRowHasCombatDamagePreview(consumerSk)) add += queensDecreeCritExtraDamagePerHit(combatCtx, derivedForCrit);
    return add;
  }

  /** Tooltip sublabel for the crit-after-round row. */
  function plannerCritAfterRoundTooltipDetail(derived) {
    if (!derived || typeof derived !== "object") return "";
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    const pSheet = clamp((derived.CritChance_pct || 0) / 100, 0, 1);
    const critMult = plannerCritDamageStatMultiplier(derived);
    let pEff = pSheet;
    if (mode === "never") pEff = 0;
    else if (mode === "always") pEff = 1;
    return `${plannerDamagePreviewKickerLabel()} · sheet chance ${formatMultiplierLabel(
      pEff * 100
    )}% · crit hit ×${formatMultiplierLabel(critMult)} · after Hero ceil(pre-crit damage)`;
  }

  /**
   * One line per **pre-crit** multiplier (**Fervor**, **`DamageModifier`**, **`extraMoreDamageMult`**). Crit is **not** included
   * (see **`plannerExpectedDamageEvAfterCritRound`**).
   * @returns {Array<{ id: string, label: string, detail: string, mult: number }>}
   */
  function plannerPostBaseDamageMultiplierLines(derived) {
    if (!derived || typeof derived !== "object") return [];
    const out = [];
    const fervPct = derived.Fervor_pct || 0;
    const ferv = 1 + fervPct / 100;
    out.push({
      id: "fervor",
      label: "Fervor",
      detail: `${fervPct >= 0 ? "+" : ""}${formatMultiplierLabel(fervPct)}% on sheet`,
      mult: ferv,
    });
    const dmRaw = derived.DamageModifier_pct || 0;
    const dm = plannerDerivedAdditivePctMult(derived, ["DamageModifier_pct"]);
    out.push({
      id: "dmod",
      label: "Damage modifier",
      detail: `${dmRaw >= 0 ? "+" : ""}${formatMultiplierLabel(dmRaw)}% on sheet`,
      mult: dm,
    });
    const xm = plannerDamagePreviewExtraMoreMult();
    const xmRaw = plannerDamagePreviewSettings && plannerDamagePreviewSettings.extraMoreDamageMult;
    const xmNote =
      typeof xmRaw === "number" && Number.isFinite(xmRaw)
        ? `preview setting ×${formatMultiplierLabel(xmRaw)}`
        : "default ×1";
    out.push({
      id: "extramore",
      label: "Extra more damage",
      detail: xmNote,
      mult: xm,
    });
    return out;
  }

  function plannerSupportPreviewMultiplierLines(derived, kind) {
    if (!derived || typeof derived !== "object") return [];
    const out = [];
    const fervPct = derived.Fervor_pct || 0;
    out.push({
      id: "fervor",
      label: "Fervor",
      detail: `${fervPct >= 0 ? "+" : ""}${formatMultiplierLabel(fervPct)}% on sheet`,
      mult: plannerSupportFervorMultiplier(derived),
    });
    const supportM = kind === "shield" ? globalClassBuffShieldMultiplier() : globalClassBuffHealMultiplier();
    if (Math.abs(supportM - 1) > 1e-6) {
      out.push({
        id: kind === "shield" ? "shieldpower" : "healgiven",
        label: kind === "shield" ? "Shield power" : "Healing bonus",
        detail: "active support status buffs",
        mult: supportM,
      });
    }
    return out;
  }

  /**
   * Single armor/pen damage multiplier line (same product as {@link plannerAverageDamageMultiplier}).
   */
  function plannerArmorMultiplierTooltipLine(combatCtx, affinityRoot, derived) {
    const mult = plannerAverageDamageMultiplier(combatCtx, affinityRoot);
    if (!derived || typeof derived !== "object") {
      return { label: "Armor / pen", detail: "", mult };
    }
    if (affinityRoot !== "Physical" && affinityRoot !== "Magic") {
      return {
        label: "Armor / pen",
        detail: "No physical/magic armor bucket for this affinity.",
        mult,
      };
    }
    const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const ml = combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx.foeUnitId != null ? String(combatCtx.foeUnitId) : "median";
    const am = plannerMonsterArmorMagicPtsResolved(ml, foeId);
    const pen =
      affinityRoot === "Physical" ? derived.ArmorPenetration_pct || 0 : derived.SpellPenetration_pct || 0;
    const effectivePen = clamp(pen, 0, 100);
    const pts = affinityRoot === "Physical" ? am.armorPts : am.magicArmorPts;
    const mit = plannerAffinityMitigatedFraction(pts, pen, cl);
    const resistLabel = affinityRoot === "Physical" ? "Armor" : "Magic armor";
    const detail = `foe L${Math.round(ml)} · ${resistLabel} ${formatMultiplierLabel(pts)} · pen ${formatMultiplierLabel(
      effectivePen
    )}% · mitigation ${formatMultiplierLabel(mit * 100)}%`;
    return { label: "Armor / pen", detail, mult };
  }

  /** Armor multiplier line with **0% pen** (description damage prose). */
  function plannerArmorMultiplierTooltipLineNoPenetration(combatCtx, affinityRoot, derived) {
    const mult = plannerAverageDamageMultiplierNoPenetration(combatCtx, affinityRoot);
    if (!derived || typeof derived !== "object") {
      return { label: "Armor (no pen)", detail: "", mult };
    }
    if (affinityRoot !== "Physical" && affinityRoot !== "Magic") {
      return {
        label: "Armor (no pen)",
        detail: "No physical/magic armor bucket for this affinity.",
        mult,
      };
    }
    const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    const ml = combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx.foeUnitId != null ? String(combatCtx.foeUnitId) : "median";
    const am = plannerMonsterArmorMagicPtsResolved(ml, foeId);
    const pts = affinityRoot === "Physical" ? am.armorPts : am.magicArmorPts;
    const mit = plannerAffinityMitigatedFraction(pts, 0, cl);
    const resistLabel = affinityRoot === "Physical" ? "Armor" : "Magic armor";
    const detail = `foe L${Math.round(ml)} · ${resistLabel} ${formatMultiplierLabel(pts)} · 0% pen · mitigation ${formatMultiplierLabel(
      mit * 100
    )}%`;
    return { label: "Armor (no pen)", detail, mult };
  }

  function plannerSkillDescAffinityRootFromPreview(p) {
    if (!p) return null;
    if (p.affinityRoot === "Physical" || p.affinityRoot === "Magic") return p.affinityRoot;
    return plannerDamageAffinityRootFromKindLabel(p.kindLabel);
  }

  /**
   * Pre-crit damage for skill-description **`::dmg::`** tokens: **`raw × mastery × Fervor × DamageModifier × extraMore × armor`**
   * with **0% penetration** on the armor term — same float fed to **`hlMathRound`** before crit on the expected line, minus pen.
   * Optional **`scriptHostSkill`** on **`p`** (or **`hostSkFallback`**) applies per-skill enabled **`scriptAssumptionsBySkillId`** (**`1 + Σ vars`** from **`dmgMult +=`** hooks).
   * When **`consumerSkForPassiveBoost`** is set (or defaults to **`hostSkFallback`**), also multiplies by **equipped passive**
   * script multipliers (weapon / class) unless opted out (**`passiveScriptGlobalDisabledByPassiveId`** / **`passiveScriptGlobalEnabledByPassiveId`** / **`passiveScriptBoostDisabledBySkillId`**).
   */
  function plannerPreCritExactFromPreview(p, combatCtx, hostSkFallback, consumerSkForPassiveBoost, usePen) {
    if (!p || !combatCtx || !combatCtx.derived) return null;
    const der = combatCtx.derived;
    const root = plannerSkillDescAffinityRootFromPreview(p);
    const rawHit = typeof p.raw === "number" && Number.isFinite(p.raw) ? p.raw : 0;
    const baseM = plannerBaseUiHitDamageMultiplier(der, root);
    const preCritFlat = plannerPreCritFlatDamageMultiplier(der);
    const armorMult = usePen
      ? plannerAverageDamageMultiplier(combatCtx, root)
      : plannerAverageDamageMultiplierNoPenetration(combatCtx, root);
    const consumer = consumerSkForPassiveBoost !== undefined ? consumerSkForPassiveBoost : hostSkFallback;
    const sc = skillScriptMultiplierForPreviewHit(p, hostSkFallback, consumer);
    return Math.max(0, rawHit * baseM * preCritFlat * armorMult * sc);
  }

  /** Pre-crit float for **`::dmg::`** / description tooltip (**0% pen**). */
  function plannerSkillDescPreCritExactFromPreview(p, combatCtx, hostSkFallback, consumerSkForPassiveBoost) {
    return plannerPreCritExactFromPreview(p, combatCtx, hostSkFallback, consumerSkForPassiveBoost, false);
  }

  /** Pre-crit float for **green expected** line (**foe pen** on armor). */
  function plannerExpectedPreCritExactFromPreview(p, combatCtx, hostSkFallback, consumerSkForPassiveBoost) {
    return plannerPreCritExactFromPreview(p, combatCtx, hostSkFallback, consumerSkForPassiveBoost, true);
  }

  /**
   * Tooltip rows: **D = ceil(pre-crit)** for Hero-owned non-jitter damage (or **mean D** over weapon jitter),
   * then crit EV on **D**.
   * @param {{ weaponJitter?: boolean }} [opts]
   */
  function dmgTipRoundedAndCritRowsHtml(preCritExact, derived, opts) {
    if (!Number.isFinite(preCritExact) || !derived) return "";
    const jitter = opts && opts.weaponJitter;
    let h = "";
    if (jitter) {
      const masses = hlMathRoundMassesUniformSymmetricBand(preCritExact, WEAPON_ATTACK_RANDOM_RANGE);
      let meanK = 0;
      for (let i = 0; i < masses.length; i++) meanK += masses[i].p * masses[i].k;
      h += dmgTipTripleRowHtml(
        `Mean rounded <span class="gp-muted gp-dmg-tip-row__sub">E[hlMathRound(X)] · X uniform on ±${formatMultiplierLabel(
          WEAPON_ATTACK_RANDOM_RANGE * 100
        )}% pre-crit band</span>`,
        escapeHtml(formatDmgAmount(meanK)),
        "="
      );
    } else {
      const D = plannerHeroFlattenDamageAmount(preCritExact);
      h += dmgTipTripleRowHtml(
        `Flattened <span class="gp-muted gp-dmg-tip-row__sub">D = ceil(pre-crit chain)</span>`,
        escapeHtml(String(D)),
        "="
      );
    }
    const ev = jitter
      ? plannerExpectedWeaponJitterEvAfterCritRound(preCritExact, derived)
      : plannerExpectedHeroDamageAfterFlatten(preCritExact, derived);
    h += dmgTipTripleRowHtml(
      `Crit <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(plannerCritAfterRoundTooltipDetail(derived))}</span>`,
      escapeHtml(formatDmgAmount(ev)),
      "—"
    );
    return h;
  }

  /** Integer range for fractional pre-crit damage (**331.87** → **`331-332`**). */
  function formatSkillDescDamagePreCritRange(exact) {
    if (!Number.isFinite(exact)) return "0";
    const lo = Math.floor(exact);
    const hi = Math.ceil(exact);
    if (lo === hi) return String(lo);
    return `${lo}-${hi}`;
  }

  /**
   * **WeaponAttack** jitter (**`X ~ U[mid(1−r), mid(1+r)]`**) then **`hlMathRound`** — min/max integers with positive mass
   * (same style as **`formatSkillDescDamagePreCritRange`**: **`k`** or **`lo-hi`**).
   */
  function formatSkillDescWeaponJitterRoundedRangeFromMid(mid, r) {
    if (!Number.isFinite(mid) || !Number.isFinite(r)) return "—";
    const masses = hlMathRoundMassesUniformSymmetricBand(mid, r);
    if (!masses.length) return formatSkillDescDamagePreCritRange(mid);
    const kLo = masses[0].k;
    const kHi = masses[masses.length - 1].k;
    if (kLo === kHi) return String(kLo);
    return `${kLo}-${kHi}`;
  }

  /**
   * **`::dmgs::`** with independent jitter per preview hit: sum of min / max **`hlMathRound`** supports (**extreme** totals,
   * consistent with independent rolls).
   */
  function formatSkillDescWeaponJitterDmgsRoundedRange(previews, combatCtx, ts, r) {
    if (!previews || !previews.length || !combatCtx || !ts) return "—";
    let lo = 0;
    let hi = 0;
    let n = 0;
    for (let i = 0; i < previews.length; i++) {
      const ex = plannerSkillDescPreCritExactFromPreview(previews[i], combatCtx, ts);
      if (ex == null || !Number.isFinite(ex)) continue;
      const masses = hlMathRoundMassesUniformSymmetricBand(ex, r);
      if (!masses.length) continue;
      lo += masses[0].k;
      hi += masses[masses.length - 1].k;
      n++;
    }
    if (!n) return "—";
    if (lo === hi) return String(lo);
    return `${lo}-${hi}`;
  }

  function plannerParseMergedValPartSum(valPart) {
    if (valPart == null) return null;
    const s = String(valPart).replace(/\s+/g, " ").trim();
    if (!s) return null;
    const parts = s.split("+");
    let sum = 0;
    for (let i = 0; i < parts.length; i++) {
      const n = parseFloat(parts[i].trim());
      if (!Number.isFinite(n)) return null;
      sum += n;
    }
    return sum;
  }

  /**
   * Rows whose **UI base** + **expected** totals appear in **`skillVsMonsterAverageDamageHtml`** — merged strip omits these
   * so scaling **`gp-char-skill__computed-dmg-detail`** is not duplicated (it follows **`gp-char-skill__final-dmg-kind`** there).
   */
  function skillDamageRowShownInFinalBlock(row) {
    return (
      row &&
      row.valPart != null &&
      String(row.valPart).trim() !== "" &&
      row.finalExpectedSum != null &&
      Number.isFinite(row.finalExpectedSum)
    );
  }

  function skillPreviewRowIsShieldOnly(row) {
    if (!row) return false;
    const kl = String(row.kindLabel || "").toLowerCase();
    if (kl.includes("shield")) return true;
    if (kl.includes("healing")) return false;
    const hits = row.damagePreviewHits || [];
    return hits.length > 0 && hits.every((h) => h && h.isShieldPreview);
  }

  /**
   * Second block under base tooltip — **expected average** per damage family (**`gp-char-skill__final-dmg`**): **Fervor**,
   * **`DamageModifier`**, **`extraMoreDamageMult`**, foe **armor / pen**, then **`hlMathRound`**, then **crit** EV
   * (**`plannerExpectedDamageEvAfterCritRound`**). **`gp-char-skill__computed-dmg-detail`** follows **`gp-char-skill__final-dmg-kind`**.
   */
  function skillVsMonsterAverageDamageHtml(sk, combatCtx) {
    if (!sk || !damagePreviewRowsExist(sk, combatCtx)) return "";
    const ml =
      combatCtx && combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeRaw = combatCtx && combatCtx.foeUnitId != null ? String(combatCtx.foeUnitId) : "median";
    const foeHd = foePlannerDisplayLabel(foeRaw);
    const rows = collectMergedDamageRows(sk, combatCtx);
    let inner = "";
    let hasDamagePreviewRow = false;
    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      if (row.valPart == null || row.finalExpectedSum == null || !Number.isFinite(row.finalExpectedSum)) continue;
      if (!skillPreviewRowIsShieldOnly(row)) hasDamagePreviewRow = true;
      const fin = formatDmgAmount(Math.max(0, row.finalExpectedSum));
      const hasDet = row.detail != null && String(row.detail).trim() !== "";
      inner += `<div class="gp-char-skill__final-dmg-row gp-char-skill__final-dmg-row--merged">`;
      inner += `<span class="gp-char-skill__final-dmg-val gp-char-skill__dmg-tip" data-gp-dmg-tip="expected" data-gp-dmg-row="${escapeHtml(
        String(i)
      )}">${escapeHtml(fin)}</span> `;
      inner += `<span class="gp-char-skill__final-dmg-kind">${escapeHtml(row.kindLabel)}</span>`;
      if (hasDet) {
        inner += ` <span class="gp-char-skill__computed-dmg-detail">(${escapeHtml(String(row.detail))})</span>`;
      }
      inner += `</div>`;
    }
    if (!inner) return "";
    const kick = hasDamagePreviewRow ? plannerDamagePreviewKickerLabel() : "Preview";
    const meta = hasDamagePreviewRow ? `L${String(ml)} · ${foeHd}` : "Your stats";
    return (
      `<div class="gp-char-skill__final-dmg">` +
      `<div class="gp-char-skill__final-dmg-hd">` +
      `<span class="gp-char-skill__final-dmg-kicker">${escapeHtml(kick)}</span>` +
      `<span class="gp-char-skill__final-dmg-meta">${escapeHtml(meta)}</span>` +
      `</div>` +
      inner +
      `</div>`
    );
  }

  /** Sum of **expected** per-hit rows (same math as **`skillVsMonsterAverageDamageHtml`**): **`finalExpectedSum`** per family. */
  function skillTotalExpectedDamageSum(sk, combatCtx) {
    if (!sk || !damagePreviewRowsExist(sk, combatCtx)) return null;
    const rows = collectMergedDamageRows(sk, combatCtx);
    let sum = 0;
    let any = false;
    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      if (row.valPart == null || row.finalExpectedSum == null || !Number.isFinite(row.finalExpectedSum)) continue;
      sum += Math.max(0, row.finalExpectedSum);
      any = true;
    }
    return any ? sum : null;
  }

  /**
   * Compact HTML listing skills whose **expected** total damage changes between two combat snapshots.
   * @param {number} [maxRows]
   */
  function skillDamageDeltaPreviewHtml(beforeCtx, afterCtx, classId, maxRows) {
    if (!beforeCtx || !afterCtx) return "";
    const cap = maxRows != null && Number.isFinite(maxRows) ? Math.max(1, Math.floor(maxRows)) : 8;
    const snapEq = beforeCtx.selectionSnapshot || selection;
    const snapPv = afterCtx.selectionSnapshot || selection;
    const ids = collectDamagingSkillIdsForModal(classId, snapEq, snapPv, beforeCtx, afterCtx);
    const lines = [];
    for (let ii = 0; ii < ids.length && lines.length < cap; ii++) {
      const sid = ids[ii];
      const sk = skillById[sid];
      if (!sk) continue;
      const te = skillTotalExpectedDamageSum(sk, beforeCtx);
      const tp = skillTotalExpectedDamageSum(sk, afterCtx);
      if (te == null && tp == null) continue;
      let d = 0;
      if (te != null && tp != null) d = tp - te;
      else if (tp != null) d = tp;
      else d = -te;
      if (Math.abs(d) < 1e-9) continue;
      const nm = skillDisplayName(sk) || sid;
      const deltaStr =
        Math.abs(d) < 1e-9 ? "0" : (d > 0 ? "+" : "") + formatDmgAmount(d);
      lines.push(
        `<div class="gp-damage-delta-preview__row"><span class="gp-damage-delta-preview__name">${escapeHtml(
          nm
        )}</span> <span class="gp-damage-delta-preview__delta">${escapeHtml(deltaStr)}</span></div>`
      );
    }
    if (!lines.length) return "";
    return `<div class="gp-damage-delta-preview">${lines.join("")}</div>`;
  }

  function combatSnapshotAfterTalentRankDelta(sid, charLevel, classId, baseCtx) {
    const rank = talentAllocations[sid] || 0;
    const sk = skillById[sid];
    const max = talentMaxPointsForSkill(sk);
    if (rank >= max) return null;
    const had = Object.prototype.hasOwnProperty.call(talentAllocations, sid);
    const prev = talentAllocations[sid];
    talentAllocations[sid] = rank + 1;
    const cl = charLevel != null ? charLevel : CHAR_LEVEL_DEFAULT;
    const baseStats = computeClassBaseStats(classId, cl);
    const gearFlat = mergeGearTalentFlats(cl, classId);
    const derived = deriveCombatPreview(baseStats, gearFlat, cl);
    const sheetTotals = mergeCombatSheetTotals(baseStats, gearFlat);
    const out = {
      sheetTotals,
      derived,
      charLevel: cl,
      classId,
      selectionSnapshot: selection,
      monsterLevel: baseCtx && baseCtx.monsterLevel != null ? baseCtx.monsterLevel : MONSTER_LEVEL_DEFAULT,
      foeUnitId: baseCtx && baseCtx.foeUnitId != null ? baseCtx.foeUnitId : "median",
    };
    if (had) talentAllocations[sid] = prev;
    else delete talentAllocations[sid];
    return out;
  }

  function combatSnapshotAfterConsumable(kind, itemId, charLevel, classId, baseCtx) {
    if (!kind || !itemId) return null;
    const prev = activeConsumableByKind[kind];
    activeConsumableByKind[kind] = itemId;
    const cl = charLevel != null ? charLevel : CHAR_LEVEL_DEFAULT;
    const baseStats = computeClassBaseStats(classId, cl);
    const gearFlat = mergeGearTalentFlats(cl, classId);
    const derived = deriveCombatPreview(baseStats, gearFlat, cl);
    const sheetTotals = mergeCombatSheetTotals(baseStats, gearFlat);
    const out = {
      sheetTotals,
      derived,
      charLevel: cl,
      classId,
      selectionSnapshot: selection,
      monsterLevel: baseCtx && baseCtx.monsterLevel != null ? baseCtx.monsterLevel : MONSTER_LEVEL_DEFAULT,
      foeUnitId: baseCtx && baseCtx.foeUnitId != null ? baseCtx.foeUnitId : "median",
    };
    if (prev) activeConsumableByKind[kind] = prev;
    else activeConsumableByKind[kind] = null;
    return out;
  }

  function previewsSubsetForDescPlaceholderKey(previews, key) {
    const k = String(key || "").toLowerCase();
    if (!previews || !previews.length) return [];
    if (k === "heal" || k === "shield") return previews.slice();
    if (k === "dmg") return previews[0] ? [previews[0]] : [];
    if (k === "dmg2") {
      const p = descNumberedDamagePreview(previews, 1);
      return p ? [p] : [];
    }
    if (k === "dmg3") {
      const p = descNumberedDamagePreview(previews, 2);
      return p ? [p] : [];
    }
    if (k === "dmgs") return previews.slice();
    return previews;
  }

  function descNumberedDamagePreview(previews, index) {
    if (!previews || !previews.length) return null;
    if (previews[index]) return previews[index];
    const masteryGated = [];
    for (let i = 0; i < previews.length; i++) {
      const p = previews[i];
      const st = p && p.previewMergeStep;
      if (st && st.cond && st.cond.mastery != null && st.cond.mastery !== "") masteryGated.push(p);
    }
    return masteryGated.length === 1 ? masteryGated[0] : null;
  }

  function formatMultiplierLabel(n) {
    if (typeof n !== "number" || !Number.isFinite(n)) return "—";
    const t = Math.round(n * 10000) / 10000;
    let s = String(t);
    if (s.includes(".")) s = s.replace(/\.?0+$/, "");
    return s;
  }

  function formatDmgAmount(n) {
    if (typeof n !== "number" || !Number.isFinite(n)) return "—";
    const t = Math.round(n * 1000) / 1000;
    let s = String(t);
    if (s.includes(".")) s = s.replace(/\.?0+$/, "");
    return s;
  }

  /** One row: label (HTML inner) | value inner | mult inner (e.g. ×1.05 or —). */
  function dmgTipTripleRowHtml(labelInnerHtml, valueInnerHtml, multInnerHtml) {
    const v =
      valueInnerHtml != null && String(valueInnerHtml).trim() !== ""
        ? `<span class="gp-dmg-tip-row__v">${valueInnerHtml}</span>`
        : `<span class="gp-dmg-tip-row__v gp-dmg-tip-row__empty"></span>`;
    const mRaw = multInnerHtml != null ? String(multInnerHtml).trim() : "";
    const m =
      mRaw !== "" && mRaw !== "—"
        ? `<span class="gp-dmg-tip-row__m">${multInnerHtml}</span>`
        : `<span class="gp-dmg-tip-row__m gp-dmg-tip-row__muted">—</span>`;
    return (
      `<div class="gp-dmg-tip-row" role="row">` +
      `<span class="gp-dmg-tip-row__k">${labelInnerHtml}</span>` +
      v +
      m +
      `</div>`
    );
  }

  function formatSheetLineEntryHtml(sl) {
    if (!sl) return "";
    if (sl.type === "aggregate") {
      return dmgTipTripleRowHtml(
        escapeHtml(sl.name || "Raw"),
        escapeHtml(formatDmgAmount(sl.part)),
        "—"
      );
    }
    if (sl.type === "stat") {
      const sheetStr =
        sl.sheet != null && Number.isFinite(sl.sheet) ? formatDmgAmount(sl.sheet) : "—";
      const re = sl.ratioEffective != null ? sl.ratioEffective : sl.ratio;
      const sub = `${formatMultiplierLabel(re)} × ${sheetStr}`;
      const lab = `${escapeHtml(sl.name)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(sub)}</span>`;
      const sign = sl.part >= 0 ? "+" : "";
      return dmgTipTripleRowHtml(lab, escapeHtml(sign + formatDmgAmount(sl.part)), "—");
    }
    if (sl.type === "flat") {
      const wStr = sl.w != null ? formatMultiplierLabel(sl.w) : "?";
      const apt =
        sl.aptitudeCurveLevel != null && Number.isFinite(sl.aptitudeCurveLevel)
          ? `curve L${Math.round(sl.aptitudeCurveLevel)}`
          : "curve —";
      const sub = `W=${escapeHtml(wStr)} · ${escapeHtml(apt)}`;
      const lab = `${escapeHtml(sl.name)} <span class="gp-muted gp-dmg-tip-row__sub">weapon flat · ${sub}</span>`;
      const sign = sl.part >= 0 ? "+" : "";
      return dmgTipTripleRowHtml(lab, escapeHtml(sign + formatDmgAmount(sl.part)), "—");
    }
    return "";
  }

  function formatDamagePreviewHitSectionHtml(p, combatCtx, hitIdx, hitMode, hostSkForScript) {
    if (!p) return "";
    if (p.isHealPreview || p.isShieldPreview) {
      const supportKind = p.isShieldPreview ? "shield" : "heal";
      const supportLabel = p.isShieldPreview ? "Shield" : "Healing";
      const der = combatCtx && combatCtx.derived;
      const mode = hitMode === "desc" ? "desc" : "expected";
      let h = "";
      const lines = Array.isArray(p.sheetLines) ? p.sheetLines : [];
      for (let li = 0; li < lines.length; li++) h += formatSheetLineEntryHtml(lines[li]);
      const raw = typeof p.raw === "number" && Number.isFinite(p.raw) ? p.raw : 0;
      h += dmgTipTripleRowHtml(`Raw (${supportKind} subtotal)`, escapeHtml(formatDmgAmount(raw)), "—");
      if (der && combatCtx && hostSkForScript) {
        const postLines = plannerSupportPreviewMultiplierLines(der, supportKind);
        for (let pi = 0; pi < postLines.length; pi++) {
          const L = postLines[pi];
          const lab = `${escapeHtml(L.label)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(L.detail)}</span>`;
          h += dmgTipTripleRowHtml(lab, "", `×${escapeHtml(formatMultiplierLabel(L.mult))}`);
        }
        const echoM = p.isHealPreview ? mageEchoingLifeHealMultiplier(hostSkForScript) : 1;
        if (Math.abs(echoM - 1) > 1e-6) {
          h += dmgTipTripleRowHtml(
            `${escapeHtml("Echoing Life (Chaincast)")} <span class="gp-muted gp-dmg-tip-row__sub">weapon heal</span>`,
            "",
            `×${escapeHtml(formatMultiplierLabel(echoM))}`
          );
        }
        const supportM = p.isShieldPreview ? plannerShieldPreviewMultiplier(der) : plannerHealPreviewMultiplier(der);
        const preCritSupport = Math.max(0, raw * supportM * echoM);
        h += dmgTipTripleRowHtml(
          `<strong>${supportLabel} (${p.isShieldPreview ? "no mastery / armor / crit" : "no mastery / armor"})</strong>`,
          escapeHtml(formatDmgAmount(hlMathRound(preCritSupport))),
          "="
        );
        if (p.isHealPreview) {
          h += dmgTipTripleRowHtml(
            `Crit <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(plannerCritAfterRoundTooltipDetail(der))}</span>`,
            escapeHtml(formatDmgAmount(plannerExpectedDamageEvAfterCritRound(preCritSupport, der))),
            "="
          );
        }
      }
      return h;
    }
    const mode = hitMode === "desc" ? "desc" : "expected";
    const der = combatCtx && combatCtx.derived;
    let h = "";
    const lines = Array.isArray(p.sheetLines) ? p.sheetLines : [];
    if (lines.length) {
      for (let li = 0; li < lines.length; li++) h += formatSheetLineEntryHtml(lines[li]);
    } else if (p.scalingDetail) {
      h += dmgTipTripleRowHtml(
        `<span class="gp-muted">Sheet (summary)</span>`,
        escapeHtml(String(p.scalingDetail)),
        "—"
      );
    }
    const raw = typeof p.raw === "number" && Number.isFinite(p.raw) ? p.raw : 0;
    h += dmgTipTripleRowHtml("Raw (CDB subtotal)", escapeHtml(formatDmgAmount(raw)), "—");
    const root = p.affinityRoot != null ? p.affinityRoot : null;
    let masName = "Mastery";
    let masPct = 0;
    if (root === "Physical") {
      masName = "Physical mastery";
      masPct = der ? der.PhysicalMastery_pct || 0 : 0;
    } else if (root === "Magic") {
      masName = "Magic mastery";
      masPct = der ? der.MagicMastery_pct || 0 : 0;
    }
    const mult = typeof p.mult === "number" && Number.isFinite(p.mult) ? p.mult : 1;
    const masLab = `${escapeHtml(masName)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(
      formatMultiplierLabel(masPct)
    )}% on sheet</span>`;
    const rnd = hlMathRound(raw * mult);
    const valCol = mode === "desc" ? escapeHtml(String(rnd)) : "";
    h += dmgTipTripleRowHtml(masLab, valCol, `×${escapeHtml(formatMultiplierLabel(mult))}`);
    if (der && combatCtx) {
      const affRoot = plannerSkillDescAffinityRootFromPreview(p);
      const postLines = plannerPostBaseDamageMultiplierLines(der);
      for (let pi = 0; pi < postLines.length; pi++) {
        const L = postLines[pi];
        const lab = `${escapeHtml(L.label)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(L.detail)}</span>`;
        h += dmgTipTripleRowHtml(lab, "", `×${escapeHtml(formatMultiplierLabel(L.mult))}`);
      }
      const arm =
        mode === "desc"
          ? plannerArmorMultiplierTooltipLineNoPenetration(combatCtx, affRoot, der)
          : plannerArmorMultiplierTooltipLine(combatCtx, affRoot, der);
      h += dmgTipTripleRowHtml(
        `${escapeHtml(arm.label)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(arm.detail)}</span>`,
        "",
        `×${escapeHtml(formatMultiplierLabel(arm.mult))}`
      );
      const scScr = skillScriptMultiplierForPreviewHit(p, hostSkForScript, hostSkForScript);
      if (Math.abs(scScr - 1) > 1e-6) {
        h += dmgTipTripleRowHtml(
          `Conditionals <span class="gp-muted gp-dmg-tip-row__sub">this skill + passive scripts (when on)</span>`,
          "",
          `×${escapeHtml(formatMultiplierLabel(scScr))}`
        );
      }
      if (mode === "expected") {
        const preCritExact = plannerExpectedPreCritExactFromPreview(p, combatCtx, hostSkForScript, hostSkForScript);
        if (preCritExact != null) {
          const jit = skillRowHasWeaponDamageJitter(p.scriptHostSkill || hostSkForScript);
          const derSkill = applySkillPreviewCritDerived(der, hostSkForScript, p);
          h += dmgTipRoundedAndCritRowsHtml(preCritExact, derSkill, jit ? { weaponJitter: true } : null);
          const swarmAdd = skillIsAttackActionForBuffs(hostSkForScript)
            ? swarmstrikeAccordExtraDamagePerHit(combatCtx)
            : 0;
          if (swarmAdd > 0) {
            const swarmVal = `<span class="gp-char-skill__dmg-tip" data-gp-dmg-tip="expected" data-gp-dmg-row="0" data-gp-dmg-skill-id="${escapeHtml(
              BLADELEAF_SWARMSTRIKE_STATUS_ID
            )}">${escapeHtml(formatDmgAmount(swarmAdd))}</span>`;
            h += dmgTipTripleRowHtml(
              `Swarmstrike Accord <span class="gp-muted gp-dmg-tip-row__sub">post-hit bonus when active</span>`,
              swarmVal,
              "+"
            );
          }
          const queenAdd = skillRowHasCombatDamagePreview(hostSkForScript)
            ? queensDecreeCritExtraDamagePerHit(combatCtx, derSkill)
            : 0;
          if (queenAdd > 0) {
            h += dmgTipTripleRowHtml(
              `Queen's Decree <span class="gp-muted gp-dmg-tip-row__sub">post-hit crit bonus when active</span>`,
              escapeHtml(formatDmgAmount(queenAdd)),
              "+"
            );
          }
        }
      }
    }
    if (mode === "desc" && der && combatCtx) {
      const ex = plannerSkillDescPreCritExactFromPreview(p, combatCtx, hostSkForScript);
      const jitSk = p.scriptHostSkill || hostSkForScript;
      const rangeStr =
        ex != null
          ? skillRowHasWeaponDamageJitter(jitSk)
            ? formatSkillDescWeaponJitterRoundedRangeFromMid(ex, WEAPON_ATTACK_RANDOM_RANGE)
            : formatSkillDescDamagePreCritRange(ex)
          : "—";
      h += dmgTipTripleRowHtml(
        `<strong>In description</strong> <span class="gp-muted gp-dmg-tip-row__sub">vs foe · no pen · no crit</span>`,
        escapeHtml(rangeStr),
        "="
      );
    }
    return h;
  }

  /**
   * One section per **`computeEffectDamagePreview`** hit — sheet lines, raw, mastery.
   * Multiple hits (repeats / multi-part skills) are wrapped in **`gp-dmg-tip-hit`** for clearer structure.
   * @param {"desc"|"expected"} [hitMode] **`desc`**: UI integer on the mastery row. **`expected`**: multiplier only (no extra UI-base row).
   * @param {object} [hostSkForScript] skill row for script toggles when **`p.scriptHostSkill`** is absent.
   */
  function formatDamagePreviewHitsBreakdownHtml(hits, combatCtx, hitMode, hostSkForScript) {
    if (!hits || !hits.length || !combatCtx) return "";
    const hm = hitMode === "desc" ? "desc" : "expected";
    const multi = hits.length > 1;
    let h = "";
    for (let i = 0; i < hits.length; i++) {
      const inner = formatDamagePreviewHitSectionHtml(hits[i], combatCtx, multi ? i : -1, hm, hostSkForScript);
      if (!inner) continue;
      if (multi) {
        const n = i + 1;
        h +=
          `<div class="gp-dmg-tip-hit" role="group" aria-label="Damage part ${n} of ${hits.length}">` +
          `<div class="gp-dmg-tip-hit__hd">Part ${n}<span class="gp-dmg-tip-hit__of"> / ${hits.length}</span></div>` +
          `<div class="gp-dmg-tip-hit__body">${inner}</div>` +
          `</div>`;
      } else {
        h += inner;
      }
    }
    return h;
  }

  /**
   * Rich tooltip matching **`gp-slot-tooltip--weapon-skill`** layout — explains hovered damage on class / weapon skill cards.
   * @param {{ kind: string, rank?: number, key?: string, row?: number }} spec
   */
  function buildSkillDamageBreakdownTooltipHtml(sk, sid, combatCtx, spec) {
    const sp = spec || {};
    const kind = sp.kind;
    if (!sk || (kind !== "desc" && kind !== "expected")) return "";
    const name = escapeHtml(skillDisplayName(sk) || sid || "Skill");
    const passive = skillIconIsPassiveFrame(sk);
    const iconFrame = passive ? "gp-skill-icon--passive" : "gp-skill-icon--active";
    let breakdownKind = "damage";
    if (kind === "desc") {
      const keyForMeta = String(sp.key || "dmg").toLowerCase();
      if (keyForMeta === "heal") breakdownKind = "heal";
      else if (keyForMeta === "shield") breakdownKind = "shield";
    } else if (kind === "expected") {
      const riMeta =
        typeof sp.row === "number" && Number.isFinite(sp.row)
          ? Math.max(0, Math.floor(sp.row))
          : parseInt(String(sp.row != null ? sp.row : "0"), 10) || 0;
      const rowsMeta = combatCtx ? collectMergedDamageRows(sk, combatCtx) : [];
      const rowMeta = rowsMeta[riMeta];
      if (rowMeta && String(rowMeta.kindLabel || "").toLowerCase().includes("healing")) breakdownKind = "heal";
      else if (rowMeta && String(rowMeta.kindLabel || "").toLowerCase().includes("shield")) breakdownKind = "shield";
    }
    const breakdownTitle =
      breakdownKind === "heal" ? "Heal breakdown" : breakdownKind === "shield" ? "Shield breakdown" : "Damage breakdown";
    const meta = escapeHtml(passive ? `${breakdownTitle} · Passive` : breakdownTitle);

    let bodyInner = "";
    if (kind === "desc") {
      const rank = clamp(parseInt(String(sp.rank != null ? sp.rank : 1), 10) || 1, 1, 99);
      const key = String(sp.key || "dmg").toLowerCase();
      if (!combatCtx || !combatCtx.sheetTotals || !combatCtx.derived) {
        bodyInner = `<p class="gp-muted gp-dmg-tip-empty">Equip gear and set foe / level so description damage previews can resolve.</p>`;
      } else {
        const prevAll =
          key === "heal"
            ? collectEffectHealPreviewsOrdered(sk, combatCtx, rank)
            : key === "shield"
              ? collectEffectShieldPreviewsOrdered(sk, combatCtx, rank)
              : collectEffectDamagePreviewsOrdered(sk, combatCtx, rank);
        const prev = previewsSubsetForDescPlaceholderKey(prevAll, key);
        if (!prev.length) {
          bodyInner = `<p class="gp-muted gp-dmg-tip-empty">No matching ${escapeHtml(breakdownKind)} preview for <code>::${escapeHtml(
            key
          )}::</code> at rank ≤${escapeHtml(String(rank))}.</p>`;
        } else {
          bodyInner = formatDamagePreviewHitsBreakdownHtml(prev, combatCtx, "desc", sk);
        }
      }
    } else if (kind === "expected") {
      const ri =
        typeof sp.row === "number" && Number.isFinite(sp.row)
          ? Math.max(0, Math.floor(sp.row))
          : parseInt(String(sp.row != null ? sp.row : "0"), 10) || 0;
      if (!combatCtx || !combatCtx.derived || !damagePreviewRowsExist(sk, combatCtx)) {
        bodyInner = `<p class="gp-muted gp-dmg-tip-empty">No expected damage preview for this skill with current stats.</p>`;
      } else {
        const mrows = collectMergedDamageRows(sk, combatCtx);
        const row = mrows[ri];
        if (!row || row.finalExpectedSum == null || !Number.isFinite(row.finalExpectedSum)) {
          bodyInner = `<p class="gp-muted gp-dmg-tip-empty">No merged ${escapeHtml(breakdownKind)} row for this line.</p>`;
        } else {
          const der = combatCtx.derived;
          const root = plannerDamageAffinityRootFromKindLabel(row.kindLabel);
          const fin = formatDmgAmount(Math.max(0, row.finalExpectedSum));

          const hits = row.damagePreviewHits || [];
          const sheetHits = hits.length
            ? formatDamagePreviewHitsBreakdownHtml(hits, combatCtx, "expected", sk)
            : row.detail != null && String(row.detail).trim()
              ? dmgTipTripleRowHtml(
                  `<span class="gp-muted">CDB lines</span>`,
                  escapeHtml(String(row.detail).trim()),
                  "—"
                ) +
                `<p class="gp-muted gp-dmg-tip-sheetexplain">No numeric preview slice attached.</p>`
              : "";

          let chainHtml = "";
          if (!hits.length) {
            const postLines = plannerPostBaseDamageMultiplierLines(der);
            for (let pi = 0; pi < postLines.length; pi++) {
              const L = postLines[pi];
              const lab = `${escapeHtml(L.label)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(
                L.detail
              )}</span>`;
              chainHtml += dmgTipTripleRowHtml(lab, "", `×${escapeHtml(formatMultiplierLabel(L.mult))}`);
            }
            const arm = plannerArmorMultiplierTooltipLine(combatCtx, root, der);
            chainHtml += dmgTipTripleRowHtml(
              `${escapeHtml(arm.label)} <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(arm.detail)}</span>`,
              "",
              `×${escapeHtml(formatMultiplierLabel(arm.mult))}`
            );
            chainHtml += dmgTipTripleRowHtml(
              `Crit <span class="gp-muted gp-dmg-tip-row__sub">${escapeHtml(plannerCritAfterRoundTooltipDetail(der))}</span>`,
              "",
              "—"
            );
          }

          const resultHtml = dmgTipTripleRowHtml(
            `<strong>${escapeHtml(row.kindLabel || "Damage")}</strong> <span class="gp-muted gp-dmg-tip-row__sub">${
              skillPreviewRowIsShieldOnly(row) ? "preview" : "expected average"
            }</span>`,
            escapeHtml(fin),
            "="
          );

          bodyInner =
            sheetHits +
            chainHtml +
            (hits.length > 1 ? `<div class="gp-dmg-tip-final-wrap">${resultHtml}</div>` : resultHtml);
        }
      }
    }

    if (!bodyInner) return "";

    return (
      `<div class="gp-tooltip__header gp-tooltip__header--skill-tip">` +
      `<div class="gp-tooltip__icon ${iconFrame}"></div>` +
      `<div class="gp-tooltip__headtext">` +
      `<div class="gp-tooltip__name">${name}</div>` +
      `<div class="gp-tooltip__meta">${meta}</div>` +
      `</div></div>` +
      `<div class="gp-tooltip-skill-body">` +
      bodyInner +
      `</div>`
    );
  }

  /**
   * Wire **description** / **expected** damage spans (**`.gp-char-skill__dmg-tip`**) so hover opens the damage breakdown tooltip.
   * Used on **`gp-char-skill`** cards and inside rich skill tooltips (weapon strip, talents, item modal skill diff).
   */
  /**
   * @param {{ omitAnchorLeaveHide?: boolean }} [opts] — **`omitAnchorLeaveHide`**: dmg anchors live inside the floating
   * **`gp-slot-tooltip`**; replacing **`innerHTML`** detaches them and fires **`mouseleave`**, which would schedule hide instantly.
   */
  function wireNestedSkillDamageBreakdownTooltips(container, sk, sid, combatCtx, opts) {
    if (!container || !sk) return;
    const omitLeaveHide = !!(opts && opts.omitAnchorLeaveHide);
    const anchors = container.querySelectorAll(".gp-char-skill__dmg-tip");
    for (let ai = 0; ai < anchors.length; ai++) {
      const el = anchors[ai];
      if (el.dataset.gpDmgWired === "1") continue;
      el.dataset.gpDmgWired = "1";
      const show = () => {
        const kind = el.dataset.gpDmgTip || "";
        const spec = {
          kind,
          rank: parseInt(String(el.dataset.gpDmgRank || "1"), 10) || 1,
          key: el.dataset.gpDmgKey || "dmg",
          row: parseInt(String(el.dataset.gpDmgRow || "0"), 10) || 0,
          skillId: el.dataset.gpDmgSkillId || "",
        };
        const tipSk = spec.skillId && skillById[spec.skillId] ? skillById[spec.skillId] : sk;
        const tipSid = tipSk && tipSk.id ? tipSk.id : sid;
        const html = buildSkillDamageBreakdownTooltipHtml(tipSk, tipSid, combatCtx, spec);
        if (!html) return;
        const gfx = tipSk.gfx || null;
        showGearPlannerTooltip(el, html, {
          className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill gp-slot-tooltip--skill-dmg-breakdown",
          decorate: (tip) => {
            const iw = tip.querySelector(".gp-tooltip__icon");
            if (iw && gfx) mountAtlasIcon(iw, gfx, 44);
          },
        });
      };
      el.addEventListener("mouseenter", show);
      el.addEventListener("focus", show);
      if (!omitLeaveHide) {
        el.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
        el.addEventListener("blur", scheduleHideGearPlannerTooltip);
      }
    }
  }

  function wireCharSkillCardDamageTooltips(card, sk, sid, combatCtx) {
    wireNestedSkillDamageBreakdownTooltips(card, sk, sid, combatCtx);
  }

  /**
   * After injecting skill tooltip HTML into the fixed overlay: header icon + breakdown wiring for underlined damage values.
   * @param {object|null} [gfx] — atlas ref for header icon; falls back to **`sk.gfx`**
   */
  function decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, sk, sid, combatCtx, gfx) {
    if (!tip) return;
    const iw = tip.querySelector(".gp-tooltip__icon");
    const g = gfx || (sk && sk.gfx) || null;
    if (iw && g) mountAtlasIcon(iw, g, 44);
    wireNestedSkillDamageBreakdownTooltips(tip, sk, sid, combatCtx, { omitAnchorLeaveHide: true });
  }

  function collectDamagingSkillIdsForModal(classId, snapEq, snapPv, ctxEq, ctxPv) {
    const ids = new Set();
    function addFromSnap(snap) {
      for (const wkey of ["mainHand", "offHand", "arsenal"]) {
        const s = snap[wkey];
        if (!s || !s.item) continue;
        const sd = SLOT_DEFS.find((x) => x.key === wkey);
        const cl =
          (ctxPv && Number.isFinite(ctxPv.charLevel) && ctxPv.charLevel) ||
          (ctxEq && Number.isFinite(ctxEq.charLevel) && ctxEq.charLevel) ||
          CHAR_LEVEL_DEFAULT;
        if (sd && !slotSelectionIsActive(sd, s, classId, cl, snap)) continue;
        if (wkey === "mainHand") {
          const ba = weaponFirstBaseAttackSkillId(s.item);
          if (ba) {
            const skBa = skillById[ba];
            if (skBa && (damagePreviewRowsExist(skBa, ctxEq) || damagePreviewRowsExist(skBa, ctxPv))) ids.add(ba);
          }
        }
        if (wkey === "arsenal") {
          for (const sid of weaponSkillPickIds(s.item)) {
            const sk = skillById[sid];
            if (!sk) continue;
            if (damagePreviewRowsExist(sk, ctxEq) || damagePreviewRowsExist(sk, ctxPv)) ids.add(sid);
          }
          continue;
        }
        for (const sid of weaponSkillPickIds(s.item)) {
          const sk = skillById[sid];
          if (!sk) continue;
          if (damagePreviewRowsExist(sk, ctxEq) || damagePreviewRowsExist(sk, ctxPv)) ids.add(sid);
        }
      }
    }
    addFromSnap(snapEq);
    addFromSnap(snapPv);
    const cls = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const classRows = (cls && cls.skills) || [];
    for (const row of classRows) {
      const sid = row.skill;
      if (typeof sid !== "string" || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      const sk = skillById[sid];
      if (!sk) continue;
      if (damagePreviewRowsExist(sk, ctxEq) || damagePreviewRowsExist(sk, ctxPv)) ids.add(sid);
    }
    if (classId === "Mage") {
      const conduits = mageSelectedConduitSkillIds();
      for (let mi = 0; mi < conduits.length; mi++) {
        const sid = conduits[mi];
        const sk = skillById[sid];
        if (sk && (damagePreviewRowsExist(sk, ctxEq) || damagePreviewRowsExist(sk, ctxPv))) ids.add(sid);
      }
    }
    if (classId === "Priest") {
      const prayers = priestSelectedPrayerSkillIds();
      for (let pi = 0; pi < prayers.length; pi++) {
        const sid = prayers[pi];
        const sk = skillById[sid];
        if (sk && (damagePreviewRowsExist(sk, ctxEq) || damagePreviewRowsExist(sk, ctxPv))) ids.add(sid);
      }
    }
    return [...ids];
  }

  /** Damaging skills for the **Buffs** tab damage table (includes weapon attacks not in arsenal picks). */
  function collectDamagingSkillIdsForBuffPanel(classId, combatCtx) {
    const snap = (combatCtx && combatCtx.selectionSnapshot) || selection;
    const cl =
      (combatCtx && Number.isFinite(combatCtx.charLevel) && combatCtx.charLevel) || CHAR_LEVEL_DEFAULT;
    const ids = [];
    const seen = new Set();
    function add(sid) {
      if (typeof sid !== "string" || !sid || seen.has(sid)) return;
      const sk = skillById[sid];
      if (!sk || !damagePreviewRowsExist(sk, combatCtx)) return;
      seen.add(sid);
      ids.push(sid);
    }
    for (const wkey of ["mainHand", "offHand", "arsenal"]) {
      const s = snap[wkey];
      if (!s || !s.item) continue;
      const sd = SLOT_DEFS.find((x) => x.key === wkey);
      if (sd && !slotSelectionIsActive(sd, s, classId, cl, snap)) continue;
      if (wkey === "arsenal") {
        if (s.pickSkill1) add(s.pickSkill1);
        if (s.pickSkill2) add(s.pickSkill2);
        continue;
      }
      for (const sid of weaponSkillIdsForPanel(s.item)) add(sid);
    }
    const cls = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const classRows = (cls && cls.skills) || [];
    for (const row of classRows) {
      const sid = row.skill;
      if (typeof sid !== "string" || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      add(sid);
    }
    if (classId === "Mage") {
      for (const sid of mageSelectedConduitSkillIds()) add(sid);
    }
    if (classId === "Priest") {
      for (const sid of priestSelectedPrayerSkillIds()) add(sid);
    }
    return ids;
  }

  function buffContributorWeaponLabel(sid) {
    const cl =
      plannerSkillCombatCtx && Number.isFinite(plannerSkillCombatCtx.charLevel)
        ? plannerSkillCombatCtx.charLevel
        : CHAR_LEVEL_DEFAULT;
    const weapons = collectEquippedWeaponsForSkillPanel(plannerSelectedClassId(), cl);
    for (let i = 0; i < weapons.length; i++) {
      const it = weapons[i].item;
      if (!it || !Array.isArray(it.skills)) continue;
      for (let j = 0; j < it.skills.length; j++) {
        if (it.skills[j] && it.skills[j].skill === sid) return weapons[i].label;
      }
    }
    return null;
  }

  function orderedModalWeaponSkillIdsForItem(idSet, item, includeBaseAttack) {
    const out = [];
    if (!item) return out;
    if (includeBaseAttack) {
      const ba = weaponFirstBaseAttackSkillId(item);
      if (ba && idSet.has(ba)) out.push(ba);
    }
    for (const sid of weaponSkillPickIds(item)) {
      if (!idSet.has(sid)) continue;
      if (out.indexOf(sid) >= 0) continue;
      out.push(sid);
    }
    return out;
  }

  /** Main-hand weapon skills (optional base attack first). */
  function orderedModalMainHandSkillIds(idSet, snapEq, snapPv) {
    const mhItem =
      (snapPv.mainHand && snapPv.mainHand.item) || (snapEq.mainHand && snapEq.mainHand.item);
    return orderedModalWeaponSkillIdsForItem(idSet, mhItem, true);
  }

  /** Off-hand weapon skills when main hand is not two-handed. */
  function orderedModalOffHandSkillIds(idSet, snapEq, snapPv) {
    const mhItem =
      (snapPv.mainHand && snapPv.mainHand.item) || (snapEq.mainHand && snapEq.mainHand.item);
    if (mhItem && weaponOccupiesBothHands(mhItem.type)) return [];
    const ohItem =
      (snapPv.offHand && snapPv.offHand.item) || (snapEq.offHand && snapEq.offHand.item);
    return orderedModalWeaponSkillIdsForItem(idSet, ohItem, false);
  }

  /** All selectable arsenal-weapon skills (**`weaponSkillPickIds`** order). */
  function orderedModalArsenalWeaponSkillIds(idSet, snapEq, snapPv) {
    const arPv = snapPv.arsenal;
    const arEq = snapEq.arsenal;
    const src = arPv && arPv.item ? arPv : arEq && arEq.item ? arEq : null;
    if (!src || !src.item) return [];
    return orderedModalWeaponSkillIdsForItem(idSet, src.item, false);
  }

  /** Skills whose post-hit bonus lines change between equipped vs preview snapshots. */
  function orderedModalBuffDamageSkillIds(idSet, classId, snapEq, snapPv, ctxEq, ctxPv) {
    const out = [];
    const seen = new Set();
    const candidates = collectDamagingSkillIdsForModal(classId, snapEq, snapPv, ctxEq, ctxPv);
    for (let ci = 0; ci < candidates.length; ci++) {
      const sid = candidates[ci];
      const sk = skillById[sid];
      if (!sk || !idSet.has(sid) || seen.has(sid)) continue;
      const te = skillTotalExpectedDamageSum(sk, ctxEq);
      const tp = skillTotalExpectedDamageSum(sk, ctxPv);
      if (te == null && tp == null) continue;
      const postEq =
        te != null ? skillPostCalculationExtraDamagePerHit(sk, ctxEq, ctxEq && ctxEq.derived) : 0;
      const postPv =
        tp != null ? skillPostCalculationExtraDamagePerHit(sk, ctxPv, ctxPv && ctxPv.derived) : 0;
      if (Math.abs(postPv - postEq) < 1e-9) continue;
      seen.add(sid);
      out.push(sid);
    }
    return out;
  }

  /** Class skill ids in **`unit.skills`** sheet order (matches Class skill panel). */
  function orderedModalClassSkillIds(idSet, classId) {
    const out = [];
    const seen = new Set();
    const cls = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const classRows = (cls && cls.skills) || [];
    for (const row of classRows) {
      const sid = row.skill;
      if (typeof sid !== "string" || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      if (!idSet.has(sid) || seen.has(sid)) continue;
      seen.add(sid);
      out.push(sid);
    }
    if (classId === "Mage") {
      const conduits = mageSelectedConduitSkillIds();
      for (let mi = 0; mi < conduits.length; mi++) {
        const sid = conduits[mi];
        if (!idSet.has(sid) || seen.has(sid)) continue;
        seen.add(sid);
        out.push(sid);
      }
    }
    if (classId === "Priest") {
      const prayers = priestSelectedPrayerSkillIds();
      for (let pi = 0; pi < prayers.length; pi++) {
        const sid = prayers[pi];
        if (!idSet.has(sid) || seen.has(sid)) continue;
        seen.add(sid);
        out.push(sid);
      }
    }
    return out;
  }

  /**
   * Preview snapshot (**`snapPv`**) slot that grants **`sid`** for weapon-strip parity (**main hand** before **off-hand** when not 2H).
   * @returns {"" | "mainHand" | "offHand"}
   */
  function modalPreviewWeaponSlotForSkillId(sid, snapPv) {
    if (!sid || !snapPv) return "";
    const mhItem = snapPv.mainHand && snapPv.mainHand.item;
    if (mhItem && weaponSkillPickIds(mhItem).includes(sid)) return "mainHand";
    const mh2h = mhItem && weaponOccupiesBothHands(mhItem.type);
    if (!mh2h) {
      const ohItem = snapPv.offHand && snapPv.offHand.item;
      if (ohItem && weaponSkillPickIds(ohItem).includes(sid)) return "offHand";
    }
    return "";
  }

  /** Item modal — compare **expected** skill damage vs snapshot with gear currently in the slot when the modal opened. */
  function formatModalSkillDamageDiffSection(ctxEq, ctxPv, classId, snapEq, snapPv) {
    const idArr = collectDamagingSkillIdsForModal(classId, snapEq, snapPv, ctxEq, ctxPv);
    if (!idArr.length) return "";
    const idSet = new Set(idArr);

    const mainIds = orderedModalMainHandSkillIds(idSet, snapEq, snapPv);
    const offIds = orderedModalOffHandSkillIds(idSet, snapEq, snapPv);
    const arsenalIds = orderedModalArsenalWeaponSkillIds(idSet, snapEq, snapPv);
    const classIds = orderedModalClassSkillIds(idSet, classId);
    const buffIds = orderedModalBuffDamageSkillIds(idSet, classId, snapEq, snapPv, ctxEq, ctxPv);
    const placed = new Set([].concat(mainIds, offIds, arsenalIds, classIds, buffIds));
    const orphanIds = idArr
      .filter((sid) => !placed.has(sid))
      .sort((a, b) =>
        String(skillDisplayName(skillById[a]) || a).localeCompare(
          String(skillDisplayName(skillById[b]) || b)
        )
      );

    const sections = [
      { label: "Main hand", ids: mainIds, tipKind: "weapon", weaponSlot: "mainHand" },
      { label: "Off-hand", ids: offIds, tipKind: "weapon", weaponSlot: "offHand" },
      { label: "Arsenal", ids: arsenalIds, tipKind: "arsenal", weaponSlot: "arsenal" },
      { label: "Class skills", ids: classIds, tipKind: "class", weaponSlot: "" },
      { label: "Buffs (extra damage)", ids: buffIds, tipKind: "buff", weaponSlot: "" },
    ];
    if (orphanIds.length) {
      sections.push({ label: "Other", ids: orphanIds });
    }

    let body = "";
    for (let si = 0; si < sections.length; si++) {
      const sec = sections[si];
      const secRows = [];
      for (let ii = 0; ii < sec.ids.length; ii++) {
        const sid = sec.ids[ii];
        const sk = skillById[sid];
        if (!sk) continue;
        const te = skillTotalExpectedDamageSum(sk, ctxEq);
        const tp = skillTotalExpectedDamageSum(sk, ctxPv);
        if (te == null && tp == null) continue;
        let d = 0;
        if (te != null && tp != null) d = tp - te;
        else if (tp != null) d = tp;
        else d = -te;
        secRows.push({ sid, sk, te, tp, d });
      }
      if (!secRows.length) continue;
      body += `<tr class="gp-modal-skill-diff__sec-row"><td class="gp-modal-skill-diff__sec-label" colspan="4">${escapeHtml(
        sec.label
      )}</td></tr>`;
      for (let ri = 0; ri < secRows.length; ri++) {
      const { sk, te, tp, d } = secRows[ri];
      const sid = secRows[ri].sid;
      const nm = escapeHtml(skillDisplayName(sk) || sid);
      let deltaStr = "";
      let badgeClass = "gp-modal-skill-diff__delta-badge--same";
      if (te != null && tp != null) {
        if (Math.abs(d) < 1e-9) {
          deltaStr = "0";
        } else {
          deltaStr = (d > 0 ? "+" : "") + formatDmgAmount(d);
          badgeClass =
            d > 0 ? "gp-modal-skill-diff__delta-badge--up" : "gp-modal-skill-diff__delta-badge--down";
        }
      } else if (tp != null) {
        deltaStr = "+" + formatDmgAmount(tp);
        badgeClass = "gp-modal-skill-diff__delta-badge--up";
      } else {
        deltaStr = formatDmgAmount(-te);
        badgeClass = "gp-modal-skill-diff__delta-badge--down";
      }

      let tipKind = sec.tipKind || "other";
      let weaponSlot = sec.weaponSlot || "";
      if (tipKind === "weapon" && !weaponSlot) {
        weaponSlot = modalPreviewWeaponSlotForSkillId(sid, snapPv) || "";
      }

      let tip = "";
      if (te != null && tp != null) {
        tip = `Equipped ${te} → selected ${tp}`;
        if (te !== 0) {
          const pct = (100 * (tp - te)) / te;
          if (Number.isFinite(pct)) {
            tip += ` (${pct >= 0 ? "+" : ""}${pct.toFixed(pct % 1 === 0 ? 0 : 1)}%)`;
          }
        }
      } else if (tp != null) {
        tip = `Empty slot → ${tp} with this item`;
      } else {
        tip = `Equipped ${te}; preview has no comparable damage line`;
      }

      const deltaInner =
        d === 0 && te != null && tp != null
          ? `<span class="gp-modal-skill-diff__delta-plain">${escapeHtml(deltaStr)}</span>`
          : `<span class="gp-modal-skill-diff__delta-badge ${badgeClass}">${escapeHtml(deltaStr)}</span>`;

      body +=
        `<tr class="gp-modal-skill-diff__data-row" data-gp-skill-tip="1" data-skill-id="${escapeHtml(
          sid
        )}" data-tip-kind="${escapeHtml(tipKind)}" data-weapon-slot="${escapeHtml(
          weaponSlot
        )}" data-delta-tip="${escapeHtml(tip)}">` +
        `<td class="gp-modal-skill-diff__name">${nm}</td>` +
        `<td class="gp-modal-skill-diff__num">${te != null ? escapeHtml(formatDmgAmount(te)) : "—"}</td>` +
        `<td class="gp-modal-skill-diff__num">${tp != null ? escapeHtml(formatDmgAmount(tp)) : "—"}</td>` +
        `<td class="gp-modal-skill-diff__delta">${deltaInner}</td></tr>`;
      }
    }
    if (!body) return "";
    const ml =
      ctxPv && ctxPv.monsterLevel != null ? ctxPv.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeRaw = ctxPv && ctxPv.foeUnitId != null ? String(ctxPv.foeUnitId) : "median";
    const foeLabel = foePlannerDisplayLabel(foeRaw);
    const foeHd = escapeHtml(foeLabel);
    const sectionAria = escapeHtml(
      `Skill damage: equipped slot versus this preview, using monster level ${ml} and foe ${foeLabel}.`
    );
    return (
      `<section class="gp-modal-skill-diff" aria-label="${sectionAria}">` +
      `<div class="gp-modal-skill-diff__head">` +
      `<div class="gp-modal-skill-diff__head-text">` +
      `<span class="gp-modal-skill-diff__title">Skill damage</span>` +
      `</div>` +
      `<div class="gp-modal-skill-diff__chips">` +
      `<span class="gp-modal-skill-diff__chip">L${escapeHtml(String(ml))}</span>` +
      `<span class="gp-modal-skill-diff__chip">${foeHd}</span>` +
      `</div>` +
      `</div>` +
      `<table class="gp-modal-skill-diff__table">` +
      `<thead><tr>` +
      `<th scope="col">Skill</th>` +
      `<th scope="col" class="gp-modal-skill-diff__th-col-head">Equipped</th>` +
      `<th scope="col" class="gp-modal-skill-diff__th-col-head">Selected</th>` +
      `<th scope="col" class="gp-modal-skill-diff__th-col-head">Result</th>` +
      `</tr></thead>` +
      `<tbody>${body}</tbody></table></section>`
    );
  }

  /** Ordered hit previews (one entry per damaging/healing scaling effect, in **`steps`** order) for `::dmg::` (first), `::dmg2::`, `::dmg3::`, and **`::dmgs::`** (sum of all). */
  function collectEffectDamagePreviewsOrdered(sk, combatCtx, damageStepMaxRank) {
    const out = [];
    if (!sk || !combatCtx) return out;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    if (!sheetTotals || !derived) return out;
    const cap =
      damageStepMaxRank != null && Number.isFinite(damageStepMaxRank)
        ? Math.max(1, Math.floor(damageStepMaxRank))
        : null;
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < sources.length; ci++) {
      const src = sources[ci];
      if (!src || !src.steps) continue;
      const rankForScaling = cap != null ? cap : skillDamageScalingCondsRank(src);
      for (let si = 0; si < src.steps.length; si++) {
        const st = src.steps[si];
        if (skillDescriptionShouldSkipProcDamageStep(sk, src, st)) continue;
        const effs = st.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!skillHostStepEffectMatchesMastery(sk, st, e)) continue;
          if (cap != null && skillEffectDamageMinRank(st, e) > cap) continue;
          const p = computeEffectDamagePreview(e, sheetTotals, derived, combatCtx, rankForScaling);
          if (p) {
            applyDamagePreviewHitCount(p, blazingBeamDamageHitCount(sk, src, st));
            p.scriptHostSkill = src;
            p.previewMergeStep = st;
            out.push(p);
          }
        }
      }
    }
    return out;
  }

  /** Ordered heal previews (**`effect` 1** + **`scaling[]`**) — mirrors **`collectEffectDamagePreviewsOrdered`**. */
  function collectEffectHealPreviewsOrdered(sk, combatCtx, damageStepMaxRank) {
    const out = [];
    if (!sk || !combatCtx) return out;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    if (!sheetTotals || !derived) return out;
    const cap =
      damageStepMaxRank != null && Number.isFinite(damageStepMaxRank)
        ? Math.max(1, Math.floor(damageStepMaxRank))
        : null;
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < sources.length; ci++) {
      const src = sources[ci];
      if (!src || !src.steps) continue;
      const rankForScaling = cap != null ? cap : skillDamageScalingCondsRank(src);
      for (let si = 0; si < src.steps.length; si++) {
        const st = src.steps[si];
        const effs = st.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!skillHostStepEffectMatchesMastery(sk, st, e)) continue;
          if (cap != null && skillEffectDamageMinRank(st, e) > cap) continue;
          const p = computeEffectHealPreview(e, sheetTotals, derived, combatCtx, rankForScaling);
          if (p) {
            p.scriptHostSkill = src;
            p.previewMergeStep = st;
            out.push(p);
          }
        }
      }
    }
    return out;
  }

  /** Ordered shield previews (**`effect` 2** + **`scaling[]`**) — mirrors heal/damage preview ordering. */
  function collectEffectShieldPreviewsOrdered(sk, combatCtx, damageStepMaxRank, masteryEntryId) {
    const out = [];
    if (!sk || !combatCtx) return out;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    if (!sheetTotals || !derived) return out;
    const cap =
      damageStepMaxRank != null && Number.isFinite(damageStepMaxRank)
        ? Math.max(1, Math.floor(damageStepMaxRank))
        : null;
    const sources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < sources.length; ci++) {
      const src = sources[ci];
      if (!src || !src.steps) continue;
      const rankForScaling = cap != null ? cap : skillDamageScalingCondsRank(src);
      for (let si = 0; si < src.steps.length; si++) {
        const st = src.steps[si];
        const effs = st.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (masteryEntryId != null && masteryEntryId !== "") {
            if (!skillStepEffectMatchesMasteryId(st, e, masteryEntryId)) continue;
          } else if (!skillHostStepEffectMatchesMastery(sk, st, e)) continue;
          if (cap != null && skillEffectDamageMinRank(st, e) > cap) continue;
          const p = computeEffectShieldPreview(e, sheetTotals, derived, combatCtx, rankForScaling);
          if (p) {
            p.scriptHostSkill = src;
            p.previewMergeStep = st;
            out.push(p);
          }
        }
      }
    }
    return out;
  }

  /**
   * Resolve a single `::token::` / `::token%::` value for skill description prose.
   * @param {object|null} targetSk skill row providing vars/refs output (ref skill or self)
   * @param {object} hostSk row whose description is being expanded
   */
  function resolveSkillDescPlaceholderToken(
    targetSk,
    hostSk,
    key,
    wantPct,
    combatCtx,
    previews,
    weaponEffectiveRank,
    descAffixRank,
    descPhOpts
  ) {
    const ts = targetSk || hostSk;
    if (!ts || !key) return null;
    const affixRank =
      descAffixRank != null && Number.isFinite(descAffixRank) ? Math.max(1, Math.floor(descAffixRank)) : 1;
    const masteryEntryId = descPhOpts && descPhOpts.masteryEntryId;
    const varsBag = mergedVarsForSkillDesc(ts, affixRank);

    if (key === "charges") {
      const me = descPhOpts && descPhOpts.masteryEntry;
      if (me && me.props && typeof me.props.charges === "number" && Number.isFinite(me.props.charges)) {
        return String(Math.round(me.props.charges));
      }
      const charges = skillPropNumberAtRank(ts, "charges", affixRank);
      if (charges != null) return String(Math.round(charges));
      return null;
    }

    if (key === "name") {
      const nameRow = targetSk || hostSk;
      const nm = nameRow ? skillDisplayName(nameRow) || nameRow.id : null;
      return nm || null;
    }

    if (key === "atbgain") {
      const ratio = sparkRestoreRatioFromSkill(ts);
      if (ratio != null && Number.isFinite(ratio)) {
        return formatSkillPercentFromRatio(ratio);
      }
      return null;
    }

    if (wantPct) {
      if (/^val\d*$/.test(key)) {
        const ax = skillAffixEntryForPlaceholderKey(ts, key, affixRank, masteryEntryId);
        if (ax) return formatAffixValPercentForSkillDesc(ax, ts, affixRank);
      }
      let v = skillVarLookupLoose(ts, key, varsBag);
      if (v == null && (key === "damage" || key === "dmg")) {
        v = skillVarLookupLoose(ts, "damage", varsBag);
        if (v == null) v = skillVarLookupLoose(ts, "dmg", varsBag);
      }
      if (v != null) {
        const av = Math.abs(v);
        if (av > 0 && av <= 1) return formatSkillPercentFromRatio(v);
        return formatSkillPercentFromAffixFlatVal(v);
      }
      return null;
    }

    if (key === "cooldown") {
      const cd = typeof ts.cooldown === "number" && Number.isFinite(ts.cooldown) ? ts.cooldown : null;
      return cd != null ? formatSkillDurationSeconds(cd) : null;
    }

    if (key === "duration" || key === "dur") {
      let d = skillTopDurationSecondsAtRank(ts, affixRank);
      if (d == null && ts && typeof ts.dur === "number" && Number.isFinite(ts.dur) && ts.dur >= 0) d = ts.dur;
      if (d != null) return formatSkillDurationSeconds(d);
      let v = skillVarLookupLoose(ts, key === "dur" ? "dur" : "duration", varsBag);
      if (v != null) return formatSkillDurationSeconds(v);
      return null;
    }

    if (key === "dur1" || key === "dur2" || key === "time" || key === "time2") {
      const v = skillVarLookupLoose(ts, key, varsBag);
      return v != null ? formatSkillDurationSeconds(v) : null;
    }

    if (key === "range") {
      const v = skillVarLookupLoose(ts, "range", varsBag);
      return v != null ? String(Math.round(v * 100) / 100) : null;
    }

    if (key === "stacks") {
      let v = skillVarLookupLoose(ts, key, varsBag);
      if (v != null) return String(Math.round(v));
      const mx = ts && ts.props && ts.props.status && typeof ts.props.status.maxStacks === "number" ? ts.props.status.maxStacks : null;
      if (mx != null && Number.isFinite(mx)) return String(Math.round(mx));
      return null;
    }

    if (key === "dmg") {
      if (combatCtx && previews && previews.length) {
        const p0 = previews[0];
        if (combatCtx.sheetTotals && combatCtx.derived) {
          const ex = plannerSkillDescPreCritExactFromPreview(p0, combatCtx, ts);
          if (ex != null) {
            return skillRowHasWeaponDamageJitter(ts)
              ? formatSkillDescWeaponJitterRoundedRangeFromMid(ex, WEAPON_ATTACK_RANDOM_RANGE)
              : formatSkillDescDamagePreCritRange(ex);
          }
        }
        return String(p0.rounded);
      }
      return null;
    }

    if (key === "dmgs") {
      if (combatCtx && previews && previews.length) {
        if (combatCtx.sheetTotals && combatCtx.derived) {
          if (skillRowHasWeaponDamageJitter(ts)) {
            return formatSkillDescWeaponJitterDmgsRoundedRange(previews, combatCtx, ts, WEAPON_ATTACK_RANDOM_RANGE);
          }
          let sum = 0;
          for (let i = 0; i < previews.length; i++) {
            const ex = plannerSkillDescPreCritExactFromPreview(previews[i], combatCtx, ts);
            if (ex != null) sum += ex;
          }
          return formatSkillDescDamagePreCritRange(sum);
        }
        const sumR = previews.reduce((a, p) => a + p.rounded, 0);
        return String(sumR);
      }
      return null;
    }

    if (key === "dmg2") {
      const p1 = descNumberedDamagePreview(previews, 1);
      if (!p1) return null;
      if (combatCtx && combatCtx.sheetTotals && combatCtx.derived) {
        const ex = plannerSkillDescPreCritExactFromPreview(p1, combatCtx, ts);
        if (ex != null) {
          return skillRowHasWeaponDamageJitter(ts)
            ? formatSkillDescWeaponJitterRoundedRangeFromMid(ex, WEAPON_ATTACK_RANDOM_RANGE)
            : formatSkillDescDamagePreCritRange(ex);
        }
      }
      return String(p1.rounded);
    }

    if (key === "dmg3") {
      const p2 = descNumberedDamagePreview(previews, 2);
      if (!p2) return null;
      if (combatCtx && combatCtx.sheetTotals && combatCtx.derived) {
        const ex = plannerSkillDescPreCritExactFromPreview(p2, combatCtx, ts);
        if (ex != null) {
          return skillRowHasWeaponDamageJitter(ts)
            ? formatSkillDescWeaponJitterRoundedRangeFromMid(ex, WEAPON_ATTACK_RANDOM_RANGE)
            : formatSkillDescDamagePreCritRange(ex);
        }
      }
      return String(p2.rounded);
    }

    if (key === "heal") {
      if (wantPct) return null;
      if (!combatCtx || !combatCtx.sheetTotals || !combatCtx.derived) return null;
      const heals = collectEffectHealPreviewsOrdered(ts, combatCtx, affixRank);
      if (!heals.length) return null;
      const derived = combatCtx.derived;
      const supportM = plannerHealPreviewMultiplier(derived);
      const echoM = mageEchoingLifeHealMultiplier(hostSk);
      let sum = 0;
      for (let i = 0; i < heals.length; i++) {
        const h = heals[i];
        const rawHit = typeof h.raw === "number" && Number.isFinite(h.raw) ? h.raw : 0;
        sum += rawHit * supportM * echoM;
      }
      return formatSkillDescDamagePreCritRange(sum);
    }

    if (key === "shield") {
      if (wantPct) return null;
      if (combatCtx && combatCtx.sheetTotals && combatCtx.derived) {
        const shields = collectEffectShieldPreviewsOrdered(ts, combatCtx, affixRank, masteryEntryId);
        if (shields.length) {
          const supportM = plannerShieldPreviewMultiplier(combatCtx.derived);
          let sum = 0;
          for (let i = 0; i < shields.length; i++) {
            const h = shields[i];
            const rawHit = typeof h.raw === "number" && Number.isFinite(h.raw) ? h.raw : 0;
            sum += rawHit * supportM;
          }
          return formatSkillDescDamagePreCritRange(sum);
        }
      }
      const v = skillVarLookupLoose(ts, "shield", varsBag);
      return v != null ? String(Math.round(v * 100) / 100) : null;
    }

    let v = null;
    if (/^val\d*$/.test(key)) {
      const ax = skillAffixEntryForPlaceholderKey(ts, key, affixRank, masteryEntryId);
      if (ax) v = adjustPairedTierLowFlatPercentMagnitudeForDesc(ax, ts, affixRank);
    }
    if (v == null) v = skillVarLookupLoose(ts, key, varsBag);
    if (v == null && key === "va1") v = skillVarLookupLoose(ts, "var1", varsBag);

    if (v != null) {
      const lk = key.toLowerCase();
      if (lk === "chance" && v > 0 && v <= 1) return formatSkillPercentFromRatio(v);
      if (Math.abs(v - Math.round(v)) < 1e-6 && Math.abs(v) < 1e9) return String(Math.round(v));
      const s = String(Math.round(v * 1000) / 1000);
      return s.replace(/\.0+$/, "");
    }

    return null;
  }

  /**
   * Extra damage lines not mirrored in **`skillVsMonsterAverageDamageHtml`** (e.g. sheet-only tails): **`kind`** +
   * optional **`gp-char-skill__computed-dmg-detail`**. Rows that already appear in the final **expected** block are omitted
   * (no UI base **`gp-char-skill__computed-dmg-val`** — scaling detail is shown there after **`gp-char-skill__final-dmg-kind`**).
   */
  function skillMergedCombatDamageHtml(sk, combatCtx) {
    const rowsData = collectMergedDamageRows(sk, combatCtx || null);
    if (!rowsData.length) return "";
    let rows = "";
    for (let li = 0; li < rowsData.length; li++) {
      const row = rowsData[li];
      if (skillDamageRowShownInFinalBlock(row)) continue;
      const hasD = row.detail != null && String(row.detail).trim() !== "";
      rows += `<div class="gp-char-skill__computed-dmg-row gp-char-skill__computed-dmg-row--merged">`;
      rows += `<span class="gp-char-skill__computed-dmg-kind">${escapeHtml(row.kindLabel)}</span>`;
      if (hasD) {
        rows += ` <span class="gp-char-skill__computed-dmg-detail">(${escapeHtml(String(row.detail))})</span>`;
      }
      rows += `</div>`;
    }
    if (!rows) return "";
    return `<div class="gp-char-skill__computed-dmg">${rows}</div>`;
  }

  /** Appends extra merged lines (sheet-only tails) plus the **expected vs foe** block when present. */
  function appendComputedSkillDamageToCard(textCol, sk, combatCtx) {
    if (!textCol || skillSkipsCombatDamagePreview(sk)) return;
    const ctx = combatCtx || null;
    const html = skillMergedCombatDamageHtml(sk, ctx);
    const vs = skillVsMonsterAverageDamageHtml(sk, ctx);
    if (!html && !vs) return;
    if (html) textCol.insertAdjacentHTML("beforeend", html);
    if (vs) textCol.insertAdjacentHTML("beforeend", vs);
  }

  /**
   * Refresh description / mastery / damage on an existing skill card without remounting icons.
   * @param {HTMLElement} card `.gp-char-skill` with **`data-skill-id`**
   */
  function refreshSkillCardDynamic(card, combatCtx) {
    if (!card) return;
    const sid = card.getAttribute("data-skill-id");
    if (!sid) return;
    const sk = skillById[sid];
    if (!sk) return;
    const weaponSlotKey = card.getAttribute("data-weapon-slot") || "";
    const ctxForSkill =
      weaponSlotKey && combatCtx
        ? combatCtxWithWeaponSlotPower(combatCtx, weaponSlotKey)
        : combatCtx;
    const textCol = card.querySelector(".gp-char-skill__text");
    if (!textCol) return;
    const effWeaponRank = weaponSlotKey ? weaponSkillDisplayRank(sid) : undefined;

    if (weaponSlotKey) {
      textCol.querySelectorAll(".gp-char-skill__rank-btn").forEach((rb) => {
        const rv = parseInt(rb.textContent, 10);
        if (!Number.isFinite(rv)) return;
        const on = rv === effWeaponRank;
        rb.setAttribute("aria-pressed", on ? "true" : "false");
        rb.classList.toggle("gp-char-skill__rank-btn--active", on);
      });
      const desc = textCol.querySelector(".gp-char-skill__desc");
      if (desc) desc.innerHTML = skillDescHtml(sk, ctxForSkill, effWeaponRank);
    }

    const masteryWrap = textCol.querySelector(".gp-char-skill__mastery");
    if (masteryWrap && !weaponSlotKey && !skillIconIsPassiveFrame(sk)) {
      const selectedMid = selectedClassSkillMasteryId(sid, sk);
      masteryWrap.querySelectorAll(".gp-char-skill__mastery-rune").forEach((rb) => {
        const mid = rb.dataset.masteryId;
        const on = mid === selectedMid;
        rb.setAttribute("aria-pressed", on ? "true" : "false");
        rb.classList.toggle("gp-char-skill__mastery-rune--active", on);
      });
      const masteryDesc = masteryWrap.querySelector(".gp-char-skill__mastery-desc");
      if (masteryDesc) {
        const activeEntry = selectedMid ? masteryEntryById(sk, selectedMid) : null;
        if (activeEntry) {
          masteryDesc.innerHTML = `<span class="gp-char-skill__mastery-desc-name">${escapeHtml(
            skillMasteryDisplayName(activeEntry)
          )}</span> ${masteryDescHtml(activeEntry, sk, ctxForSkill)}`;
        } else {
          masteryDesc.innerHTML =
            `<span class="gp-muted">No rune selected — click a rune to apply its effect to damage previews.</span>`;
        }
      }
      syncMysticEmpowermentM2BuffChoice(masteryWrap, sid, sk, ctxForSkill);
    }

    textCol.querySelectorAll(".gp-char-skill__computed-dmg, .gp-char-skill__final-dmg").forEach((el) => el.remove());
    textCol.querySelectorAll(".gp-char-skill__surge-row").forEach((el) => el.remove());
    textCol.querySelectorAll(".gp-char-skill__urge-row").forEach((el) => el.remove());
    textCol.querySelectorAll(".gp-char-skill__stack-row").forEach((el) => el.remove());
    appendSurgeViolenceFinalComboRow(textCol, sid);
    appendComputedSkillDamageToCard(textCol, sk, ctxForSkill);
    const hostStatusBuffs = previewableStatusBuffsForHostSkill(sk);
    if (hostStatusBuffs.length) {
      for (let hsi = 0; hsi < hostStatusBuffs.length; hsi++) {
        appendStatusBuffStackRowsToSkillCard(textCol, hostStatusBuffs[hsi], sk);
      }
    } else if (skillIsPreviewableStackingStatusBuff(sk)) {
      appendStatusBuffStackRowsToSkillCard(textCol, sk, sk);
    }
    appendTideRisingUppercutStackRow(textCol, sid);
    if (sid === FINISHER_SKILL_ID) {
      /** Rebuild — **max CP** changes with **Rogue_Finisher_M2** (5 → 6); syncing in place left the wrong number of buttons. */
      textCol.querySelectorAll(".gp-char-skill__combo-row").forEach((el) => el.remove());
      appendFinisherComboPointRow(textCol);
    }
    if (sid === URGE_TO_KILL_HOST_ID) appendUrgeFinisherStreakRow(textCol, sk);
    wireCharSkillCardDamageTooltips(card, sk, sid, ctxForSkill);
  }

  /** In-place refresh for rune picks, script toggles, rank buttons, foe level, etc. */
  function refreshAllSkillCardsDynamic(combatCtx, classBodyEl, weaponBodyEl) {
    plannerSkillCombatCtx = combatCtx;
    const roots = [classBodyEl, weaponBodyEl].filter(Boolean);
    for (let ri = 0; ri < roots.length; ri++) {
      const cards = roots[ri].querySelectorAll(".gp-char-skill[data-skill-id]");
      for (let ci = 0; ci < cards.length; ci++) refreshSkillCardDynamic(cards[ci], combatCtx);
    }
  }

  /**
   * Rich HTML for the fixed `gp-slot-tooltip` (weapon-strip skill cells, item modal skill diff, etc.).
   * @param {{ passive?: boolean, weaponSlotKeyForPower?: string, category?: "weapon"|"arsenal"|"class"|"other", footerPlain?: string }} opts
   */
  function buildWeaponSkillTooltipHtml(sk, sid, combatCtx, opts) {
    const o = opts || {};
    const name = skillDisplayName(sk) || sid || "Skill";
    const passive = !!o.passive;
    const wSlot = o.weaponSlotKeyForPower;
    const category = o.category || (wSlot ? "weapon" : "class");
    const tipCtx =
      wSlot && combatCtx ? combatCtxWithWeaponSlotPower(combatCtx, wSlot) : combatCtx;

    let meta;
    if (category === "class") {
      meta = passive ? "Class skill · Passive" : "Class skill";
    } else if (category === "arsenal") {
      meta = passive ? "Arsenal · Passive" : "Arsenal skill";
    } else if (category === "other") {
      meta = passive ? "Skill · Passive" : "Skill";
    } else {
      meta = passive ? "Weapon skill · Passive" : "Weapon skill · Active";
    }
    const timing = sk ? skillTimingMetaTextJoined(sk) : "";
    const metaLine = timing ? `${meta} · ${timing}` : meta;

    const iconFrame = passive ? "gp-skill-icon--passive" : "gp-skill-icon--active";
    let html = `
      <div class="gp-tooltip__header gp-tooltip__header--skill-tip">
        <div class="gp-tooltip__icon ${iconFrame}"></div>
        <div class="gp-tooltip__headtext">
          <div class="gp-tooltip__name">${escapeHtml(name)}</div>
          <div class="gp-tooltip__meta">${escapeHtml(metaLine)}</div>
        </div>
      </div>`;

    const weaponEffRank = wSlot ? weaponSkillDisplayRank(sid) : undefined;
    let body = "";
    const descHtml = sk ? skillDescHtml(sk, tipCtx, weaponEffRank) : "";
    if (descHtml) {
      body += `<div class="gp-tooltip-skill-desc">${descHtml}</div>`;
    }

    const mergedDmg = skillMergedCombatDamageHtml(sk, tipCtx || null);
    const vsMon = skillVsMonsterAverageDamageHtml(sk, tipCtx || null);
    if (mergedDmg || vsMon) {
      const hd = damagePreviewRowsExist(sk, tipCtx)
        ? `<div class="gp-tooltip-skill-preview-hd">With your stats</div>`
        : "";
      body += hd + mergedDmg + vsMon;
    }

    const foot = o.footerPlain != null ? String(o.footerPlain).trim() : "";
    if (foot) {
      body += `<div class="gp-tooltip-skill-delta-note gp-muted">${escapeHtml(foot)}</div>`;
    }

    if (body) html += `<div class="gp-tooltip-skill-body">${body}</div>`;
    return html;
  }

  /** Hover on item modal **Skill damage** table — same rich tooltip as weapon strip (uses **preview** combat ctx). */
  function wireModalSkillDiffSkillTooltips(previewEl, combatCtx) {
    if (!previewEl || !combatCtx) return;
    const sec = previewEl.querySelector(".gp-modal-skill-diff");
    if (!sec) return;
    const rows = sec.querySelectorAll("tr.gp-modal-skill-diff__data-row[data-gp-skill-tip]");
    for (let i = 0; i < rows.length; i++) {
      const tr = rows[i];
      tr.addEventListener("mouseenter", () => {
        const sid = tr.getAttribute("data-skill-id");
        const kindRaw = tr.getAttribute("data-tip-kind") || "other";
        const ws = tr.getAttribute("data-weapon-slot") || "";
        const deltaTip = tr.getAttribute("data-delta-tip") || "";
        const sk = sid ? skillById[sid] : null;
        if (!sk) return;
        const passive = skillIconIsPassiveFrame(sk);
        const kind =
          kindRaw === "weapon" || kindRaw === "arsenal" || kindRaw === "class" || kindRaw === "other"
            ? kindRaw
            : "other";
        const tip = buildWeaponSkillTooltipHtml(sk, sid, combatCtx, {
          passive,
          weaponSlotKeyForPower: ws || undefined,
          category: kind,
          footerPlain: deltaTip || undefined,
        });
        const gfx = sk && sk.gfx ? sk.gfx : null;
        const tipCtx = ws ? combatCtxWithWeaponSlotPower(combatCtx, ws) : combatCtx;
        showGearPlannerTooltip(tr, tip, {
          className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill gp-slot-tooltip--modal-skill-diff",
          decorate: (tipEl) => {
            decorateGearPlannerSkillTooltipWithDamageBreakdown(tipEl, sk, sid, tipCtx, gfx);
          },
        });
      });
      tr.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
    }
  }

  function talentPointsBudget(charLevel) {
    if (charLevel < TALENT_FIRST_POINT_LEVEL) return 0;
    return charLevel - (TALENT_FIRST_POINT_LEVEL - 1);
  }

  function talentPointsSpent(alloc) {
    let n = 0;
    for (const k of Object.keys(alloc)) n += alloc[k] || 0;
    return n;
  }

  function talentMaxPointsForSkill(sk) {
    const m = sk && sk.props && sk.props.talent && sk.props.talent.maxPoints;
    return typeof m === "number" && m >= 1 ? Math.floor(m) : 1;
  }

  function talentTreesForClass(classId) {
    const row = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const t = row && row.talentTrees;
    return Array.isArray(t) ? t : [];
  }

  function collectTalentSkillIdsForClass(classId) {
    const set = new Set();
    const trees = talentTreesForClass(classId);
    for (let ti = 0; ti < trees.length; ti++) {
      const list = trees[ti] && trees[ti].talents;
      if (!Array.isArray(list)) continue;
      for (let i = 0; i < list.length; i++) {
        const e = list[i];
        if (e && typeof e.skill === "string") set.add(e.skill);
      }
    }
    return set;
  }

  /**
   * Skill ids whose **`skillDescHtml`** / **`skillDescText`** can appear in the gear planner UI: granted by **`itemLines`** gear,
   * class panel (**`unit.skills`** per **`CLASS_IDS`**), or talent trees (same classes). Excludes hidden class skills (**`CLASS_SKILLS_HIDDEN_IDS`**).
   */
  function collectPlannerSurfaceSkillIds() {
    const ids = new Set();

    for (let ii = 0; ii < itemLines.length; ii++) {
      const it = itemLines[ii];
      if (!it) continue;
      for (const row of it.skills || []) {
        if (row && typeof row.skill === "string" && row.skill) ids.add(row.skill);
      }
    }

    for (let ci = 0; ci < CLASS_IDS.length; ci++) {
      const classId = CLASS_IDS[ci];
      const cls = unitRowById[classId];
      const classRows = (cls && cls.skills) || [];
      for (let ri = 0; ri < classRows.length; ri++) {
        const row = classRows[ri];
        const sid = row && row.skill;
        if (typeof sid !== "string" || !sid || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
        ids.add(sid);
      }
      const tal = collectTalentSkillIdsForClass(classId);
      for (const sid of tal) ids.add(sid);
    }

    return ids;
  }

  function sanitizeTalentAllocationsForClass(classId) {
    const valid = collectTalentSkillIdsForClass(classId);
    for (const k of Object.keys(talentAllocations)) {
      if (!valid.has(k)) {
        delete talentAllocations[k];
        continue;
      }
      const sk = skillById[k];
      const mx = talentMaxPointsForSkill(sk);
      let v = talentAllocations[k] || 0;
      v = clamp(v, 0, mx);
      if (v <= 0) delete talentAllocations[k];
      else talentAllocations[k] = v;
    }
  }

  function talentSpentOverBudget(charLevel) {
    const budget = talentPointsBudget(charLevel);
    return talentPointsSpent(talentAllocations) > budget;
  }

  /** Legacy name — no longer removes points when level drops (tree locks until you respec). */
  function clampTalentAllocationsToBudget(classId, charLevel) {
    sanitizeTalentAllocationsForClass(classId);
  }

  function talentApexSkillId(tree) {
    const list = tree && tree.talents;
    if (Array.isArray(list)) {
      for (let i = 0; i < list.length; i++) {
        const e = list[i];
        if (e && e.tier === 0 && typeof e.skill === "string") return e.skill;
      }
    }
    return typeof tree.root === "string" ? tree.root : "";
  }

  function talentApexMaxRank(tree) {
    const aid = talentApexSkillId(tree);
    const sk = skillById[aid];
    return talentMaxPointsForSkill(sk);
  }

  function talentEntryForSkill(tree, skillId) {
    const list = tree && tree.talents;
    if (!Array.isArray(list)) return null;
    for (let i = 0; i < list.length; i++) {
      const e = list[i];
      if (e && e.skill === skillId) return e;
    }
    return null;
  }

  /** Total points allocated across every talent in **`tree`** (apex + all tiers). */
  function talentTotalPointsInTree(tree, alloc) {
    let n = 0;
    const list = tree && tree.talents;
    if (!Array.isArray(list)) return 0;
    for (let i = 0; i < list.length; i++) {
      const sid = list[i] && list[i].skill;
      if (!sid) continue;
      const r = alloc[sid];
      if (typeof r === "number" && r > 0) n += r;
    }
    return n;
  }

  /** Points spent in **`branch`** on tiers ≥ 1 (column depth). */
  function talentColumnPoints(tree, branch, alloc) {
    let n = 0;
    const list = tree && tree.talents;
    if (!Array.isArray(list)) return 0;
    for (let i = 0; i < list.length; i++) {
      const e = list[i];
      if (!e || typeof e.tier !== "number" || e.tier < 1) continue;
      if ((e.branch || 0) !== branch) continue;
      const sid = e.skill;
      n += alloc[sid] || 0;
    }
    return n;
  }

  /** Talent **`skill.affixes[]`** row applies to current allocated rank when **`conds`** match (**`minRank`** / **`maxRank`**). */
  function talentAffixRowMatchesRank(conds, allocatedRank) {
    if (!conds || typeof conds !== "object") return true;
    if (typeof conds.minRank === "number" && allocatedRank < conds.minRank) return false;
    if (typeof conds.maxRank === "number" && allocatedRank > conds.maxRank) return false;
    return true;
  }

  /**
   * Passive attribute lines from allocated talents (**`TAttribute_Flat`** on **`skill.affixes`**) — same presentation as gear flats.
   * @param {{ skipDynAffixes?: boolean }} [opts] — when true, skip rows with **`mod.dynVal`** (runtime-filled; see **`sumTalentDynamicMasteryFlats`**).
   */
  function sumTalentAffixFlats(classId, opts) {
    const skipDyn = !!(opts && opts.skipDynAffixes);
    const totals = {};
    const valid = collectTalentSkillIdsForClass(classId);
    for (const sid of Object.keys(talentAllocations)) {
      const allocatedRank = talentAllocations[sid];
      if (!valid.has(sid) || !allocatedRank || allocatedRank < 1) continue;
      const sk = skillById[sid];
      if (!sk || !Array.isArray(sk.affixes)) continue;
      for (let ai = 0; ai < sk.affixes.length; ai++) {
        const ax = sk.affixes[ai];
        if (!ax || ax.ref !== "TAttribute_Flat") continue;
        if (skipDyn && ax.mod && ax.mod.dynVal) continue;
        if (!talentAffixRowMatchesRank(ax.conds, allocatedRank)) continue;
        const attr = ax.target && ax.target.attribute;
        if (!attr || typeof ax.val !== "number") continue;
        totals[attr] = (totals[attr] || 0) + presentationFlatForAffixFactor(ax.val, 1);
      }
    }
    return totals;
  }

  /**
   * Talent affix values driven by **`setDynVal`** at runtime (e.g. **`Mage_Talent_Discipline`**: Physical = **`var2 ×`** sheet [MagicMastery] %).
   * Requires **`totalMagicMasterySheetPct`** = class base + gear + **static** talent MagicMastery (includes Discipline’s flat +5).
   */
  function sumTalentDynamicMasteryFlats(classId, totalMagicMasterySheetPct) {
    const out = {};
    const magicPct =
      typeof totalMagicMasterySheetPct === "number" && Number.isFinite(totalMagicMasterySheetPct)
        ? totalMagicMasterySheetPct
        : 0;

    const sid = "Mage_Talent_Discipline";
    const rank = talentAllocations[sid] || 0;
    if (rank < 1 || classId !== "Mage") return out;
    const valid = collectTalentSkillIdsForClass(classId);
    if (!valid.has(sid)) return out;
    const sk = skillById[sid];
    const ratio = sk && sk.vars && typeof sk.vars.var2 === "number" ? sk.vars.var2 : 0;
    if (ratio <= 0 || magicPct <= 0) return out;

    // Matches CDB script `setDynVal(1, vars.var2 * magicm * 100)` with sheet MagicMastery as %-points (e.g. 5 → 2.5 physical).
    out.PhysicalMastery = ratio * magicPct;
    return out;
  }

  /** Shallow copy of a slot **`selection[slot]`** entry for hypothetical snapshots (item modal compare). */
  function cloneSlotSel(sel) {
    if (!sel || typeof sel !== "object") {
      return {
        item: null,
        ilvl: null,
        stars: 0,
        rarityOverride: null,
        enchantId: null,
        augmentId: null,
        flawless: false,
        pickSkill1: null,
        pickSkill2: null,
      };
    }
    return {
      item: sel.item || null,
      ilvl: sel.ilvl != null ? sel.ilvl : null,
      stars: sel.stars != null ? sel.stars : 0,
      rarityOverride: sel.rarityOverride || null,
      enchantId: sel.enchantId || null,
      augmentId: sel.augmentId || null,
      flawless: !!sel.flawless,
      pickSkill1: sel.pickSkill1 != null ? sel.pickSkill1 : null,
      pickSkill2: sel.pickSkill2 != null ? sel.pickSkill2 : null,
    };
  }

  /** Full planner **`selection`** clone with one slot replaced — feeds **`sumGearAffixes`** override. */
  function buildFullSelectionSnapshot(overrideSlotKey, overrideSel) {
    const snap = {};
    for (let i = 0; i < SLOT_DEFS.length; i++) {
      const k = SLOT_DEFS[i].key;
      snap[k] = k === overrideSlotKey ? cloneSlotSel(overrideSel) : cloneSlotSel(selection[k]);
    }
    return snap;
  }

  function collectReferencedStatusSkillRefsIntoSet(hostSk, outSet) {
    if (!hostSk || !outSet || !Array.isArray(hostSk.steps)) return;
    for (let si = 0; si < hostSk.steps.length; si++) {
      const step = hostSk.steps[si];
      if (!step) continue;
      const ps = step.props && step.props.status;
      if (ps && typeof ps.ref === "string" && ps.ref.trim()) outSet.add(ps.ref.trim());
      const effs = step.effects || [];
      for (let ei = 0; ei < effs.length; ei++) {
        const e = effs[ei];
        const st = e && e.props && e.props.status;
        if (st && typeof st.ref === "string" && st.ref.trim()) outSet.add(st.ref.trim());
      }
    }
  }

  function collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel) {
    const hosts = new Set();
    const cls = unitSheet && unitSheet.lines && unitSheet.lines.find((r) => r.id === classId);
    const classRows = (cls && cls.skills) || [];
    for (let i = 0; i < classRows.length; i++) {
      const sid = classRows[i] && classRows[i].skill;
      if (typeof sid !== "string" || CLASS_SKILLS_HIDDEN_IDS.has(sid)) continue;
      if (mageIsConduitSkillId(sid)) continue;
      if (priestIsPrayerSkillId(sid)) continue;
      hosts.add(sid);
    }
    if (classId === "Mage") {
      const conduits = mageSelectedConduitSkillIds();
      for (let mi = 0; mi < conduits.length; mi++) hosts.add(conduits[mi]);
    }
    if (classId === "Priest") {
      const prayers = priestSelectedPrayerSkillIds();
      for (let pi = 0; pi < prayers.length; pi++) hosts.add(prayers[pi]);
    }
    const slotMap = selectionSnapshot || selection;
    const cl =
      Number.isFinite(charLevel)
        ? charLevel
        : plannerSkillCombatCtx && Number.isFinite(plannerSkillCombatCtx.charLevel)
          ? plannerSkillCombatCtx.charLevel
          : CHAR_LEVEL_DEFAULT;
    for (let wi = 0; wi < SLOT_DEFS.length; wi++) {
      const sd = SLOT_DEFS[wi];
      const sel = slotMap[sd.key];
      if (!sel || !sel.item) continue;
      if (!slotSelectionIsActive(sd, sel, classId, cl, slotMap)) continue;
      const ench = sel.enchantId ? enchantItemById(sel.enchantId) : null;
      if (ench && Array.isArray(ench.skills)) {
        for (let ei = 0; ei < ench.skills.length; ei++) {
          const sid = ench.skills[ei] && ench.skills[ei].skill;
          if (typeof sid === "string" && sid) hosts.add(sid);
        }
      }
      /** Same rule as **`equippedWeaponGrantedSkillIds`**: arsenal hosts are only **pickSkill1/2**, not every row on the weapon. */
      if (sd.weaponRole === "arsenal") {
        if (typeof sel.pickSkill1 === "string" && sel.pickSkill1 && !weaponSkillHiddenFromMainSkillLists(sel.pickSkill1)) hosts.add(sel.pickSkill1);
        if (typeof sel.pickSkill2 === "string" && sel.pickSkill2 && !weaponSkillHiddenFromMainSkillLists(sel.pickSkill2)) hosts.add(sel.pickSkill2);
        continue;
      }
      if (!Array.isArray(sel.item.skills)) continue;
      for (let si = 0; si < sel.item.skills.length; si++) {
        const ent = sel.item.skills[si];
        const sid = ent && ent.skill;
        if (weaponSkillHiddenFromMainSkillLists(sid)) continue;
        if (typeof sid === "string") hosts.add(sid);
      }
    }
    return hosts;
  }

  /** Max **`skillDamageScalingCondsRank`** among hosts that apply this **`props.status.ref`** (for gated **`affixes[].conds`**). */
  function statusGrantorMaxRankByStatusId(classId, selectionSnapshot, charLevel) {
    const map = new Map();
    const hostIds = collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel);
    for (const hid of hostIds) {
      if (!passiveScriptGlobalMultApplies(hid)) continue;
      const h = skillById[hid];
      if (!h) continue;
      const r = skillDamageScalingCondsRank(h, selectionSnapshot);
      const seen = new Set();
      collectStatusRefIdsFromHostSkill(h, seen);
      for (const stId of seen) {
        const prev = map.get(stId) || 0;
        if (r > prev) map.set(stId, r);
      }
    }
    return map;
  }

  function skillStatusMaxStacksFromProps(sk) {
    const mx = sk && sk.props && sk.props.status && sk.props.status.maxStacks;
    if (typeof mx !== "number" || !Number.isFinite(mx) || mx < 1) return 0;
    if (sk && sk.id === CRUSADER_STATUS_ID) return Math.floor(mx);
    return Math.min(99, Math.floor(mx));
  }

  function statusPreviewStackCount(statusSk) {
    const maxS = skillStatusMaxStacksFromProps(statusSk);
    if (maxS < 1) return 0;
    const sid = statusSk.id;
    const bag = plannerDamagePreviewSettings.previewStatusStacksBySkillId;
    if (bag && typeof bag === "object" && Object.prototype.hasOwnProperty.call(bag, sid)) {
      const raw = bag[sid];
      if (typeof raw === "number" && Number.isFinite(raw)) return clamp(Math.floor(raw), 0, maxS);
    }
    if (sid === CRUSADER_STATUS_ID) return 0;
    return maxS;
  }

  function skillIsPreviewableStackingStatusBuff(sk) {
    if (sk && sk.id === FISTS_SINK_TO_BOTTOM_CRIT_STATUS_ID) return false;
    return !!(sk && skillStatusMaxStacksFromProps(sk) >= 1 && statusSkillHasPreviewableAffixes(sk));
  }

  function statusSkillHasPreviewableAffixes(sk) {
    if (!sk || !Array.isArray(sk.affixes)) return false;
    for (let i = 0; i < sk.affixes.length; i++) {
      const ax = sk.affixes[i];
      if (!ax || (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(sk, ax))) continue;
      const ref = typeof ax.ref === "string" ? ax.ref : "";
      if (ref === "TAttribute_Flat" || ref === "TAttribute_ARatio") return true;
    }
    return false;
  }

  function statusPreviewControlRequiredMasteryId(statusSk) {
    if (!statusSk || !Array.isArray(statusSk.affixes)) return null;
    let required = null;
    let sawPreviewable = false;
    for (let i = 0; i < statusSk.affixes.length; i++) {
      const ax = statusSk.affixes[i];
      if (!ax || (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(statusSk, ax))) continue;
      const ref = typeof ax.ref === "string" ? ax.ref : "";
      if (ref !== "TAttribute_Flat" && ref !== "TAttribute_ARatio") continue;
      sawPreviewable = true;
      const mid = ax.conds && ax.conds.mastery != null && ax.conds.mastery !== "" ? String(ax.conds.mastery) : "";
      if (!mid) return null;
      if (required == null) required = mid;
      else if (required !== mid) return null;
    }
    return sawPreviewable ? required : null;
  }

  /** Non-stacking status with static **`TAttribute_Flat`** / **`TAttribute_ARatio`** rows. */
  function skillIsPreviewableFlatStatusBuff(sk) {
    if (!sk || !(sk.props && sk.props.status)) return false;
    if (skillStatusMaxStacksFromProps(sk) >= 1) return false;
    return statusSkillHasPreviewableAffixes(sk);
  }

  function statusPreviewEffectiveStacks(statusSk) {
    const maxS = skillStatusMaxStacksFromProps(statusSk);
    if (maxS >= 1) return statusPreviewStackCount(statusSk);
    if (skillIsPreviewableFlatStatusBuff(statusSk)) return 1;
    return 0;
  }

  /** Stacking status rows applied by a host (e.g. **Brutal Frenzy** → **`GA_Craft_FinalCombo_Status`**). */
  function previewableStatusBuffsForHostSkill(hostSk) {
    const out = [];
    if (!hostSk) return out;
    if (skillIsPreviewableStackingStatusBuff(hostSk)) {
      out.push(hostSk);
      return out;
    }
    const refs = new Set();
    collectStatusRefIdsFromHostSkill(hostSk, refs);
    for (const stId of refs) {
      const st = skillById[stId];
      if (skillIsPreviewableStackingStatusBuff(st)) out.push(st);
    }
    return out;
  }

  /**
   * Flat per stack for a status at the **grantor host** rank (`affixes[].conds` + status **`rankOverride`** on **`var1`**).
   */
  function statusPreviewFlatPerStackAtGrantorRank(statusSk, attrId, grantorRank, hostMasteryId) {
    if (!statusSk || !attrId) return 0;
    if (MYSTIC_EMPOWERMENT_STATUS_SHEET_IDS.has(statusSk.id)) {
      return 0;
    }
    const r = grantorRank != null && Number.isFinite(grantorRank) ? Math.max(1, Math.floor(grantorRank)) : 1;
    const fromAffix = talentAffixFlatSumAtRank(statusSk, attrId, r, hostMasteryId);
    if (fromAffix > 0) return statusPreviewFlatMultiplier(statusSk) * fromAffix;
    return 0;
  }

  function crusaderPreviewStackEffectMultiplier() {
    const host = skillById[CRUSADER_HOST_ID];
    if (!host || selectedClassSkillMasteryId(CRUSADER_HOST_ID, host) !== CRUSADER_M2_MASTERY_ID) return 1;
    const st = skillById[CRUSADER_STATUS_ID];
    const vars = st ? mergedVarsForSkillDesc(st, 1) : {};
    const perStack =
      vars && typeof vars.var1 === "number" && Number.isFinite(vars.var1) ? vars.var1 : 0.01;
    return 1 + Math.max(0, statusPreviewStackCount(st)) * perStack;
  }

  function statusPreviewFlatMultiplier(statusSk) {
    return statusSk && statusSk.id === CRUSADER_STATUS_ID ? crusaderPreviewStackEffectMultiplier() : 1;
  }

  function statusPreviewAffixVal(statusSk, ax) {
    const base = ax && typeof ax.val === "number" && Number.isFinite(ax.val) ? ax.val : 0;
    return statusSk && statusSk.id === CRUSADER_STATUS_ID ? base * crusaderPreviewStackEffectMultiplier() : base;
  }

  /** Flat **`TAttribute_*`** totals from equipped-host-applied statuses (scaled by preview stack count). */
  function sumPreviewStatusBuffFlats(classId, selectionSnapshot, charLevel) {
    const totals = {};
    const hostIds = collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel);
    for (const hid of hostIds) {
      if (!passiveScriptGlobalMultApplies(hid)) continue;
      const host = skillById[hid];
      if (!host) continue;
      const hostMid = selectedClassSkillMasteryId(hid, host);
      const rank = skillDamageScalingCondsRank(host, selectionSnapshot);
      const refs = new Set();
      collectStatusRefIdsFromHostSkill(host, refs);
      if (skillIsPreviewableStackingStatusBuff(host)) refs.add(hid);
      for (const stId of refs) {
        if (!statusBuffAppliesForHostMastery(host, stId, hostMid)) continue;
        const statusSk = skillById[stId];
        if (!statusSk) continue;
        const stacks = statusPreviewSheetAffixStacks(statusSk);
        if (stacks <= 0) continue;
        const attrs = collectTalentFlatAffixAttributeOrder(statusSk);
        if (!attrs.length) continue;
        for (let ai = 0; ai < attrs.length; ai++) {
          const attr = attrs[ai];
          const per = statusPreviewFlatPerStackAtGrantorRank(statusSk, attr, rank, hostMid);
          if (!per) continue;
          totals[attr] = (totals[attr] || 0) + per * stacks;
        }
      }
    }
    return totals;
  }

  /**
   * Additive **`TAttribute_ARatio`** on active **self** status buffs (Armor on **Battle Shout** M3, **Spark Shield** M3, …).
   * Excludes foe-only debuff rows (e.g. Knives Tempest **Shred**), which would wrongly reduce the player’s armor on the summary.
   * Values are ratios (0.3 → +30% armor); applied in **`renderSummary`** as **`(1 + Σ)`** on base armor.
   */
  function sumPreviewStatusBuffARatios(classId, selectionSnapshot, charLevel) {
    const totals = {};
    const hostIds = collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel);
    for (const hid of hostIds) {
      if (!passiveScriptGlobalMultApplies(hid)) continue;
      const host = skillById[hid];
      if (!host) continue;
      const hostMid = selectedClassSkillMasteryId(hid, host);
      const rank = skillDamageScalingCondsRank(host, selectionSnapshot);
      const refs = new Set();
      collectStatusRefIdsFromHostSkill(host, refs);
      if (skillIsPreviewableStackingStatusBuff(host)) refs.add(hid);
      for (const stId of refs) {
        if (!statusBuffAppliesForHostMastery(host, stId, hostMid)) continue;
        if (STATUS_PREVIEW_SKIP_HOST_SHEET_ARATIO_IDS.has(stId)) continue;
        const st = skillById[stId];
        if (!st || !Array.isArray(st.affixes)) continue;
        const stacks = statusPreviewSheetAffixStacks(st);
        if (stacks <= 0) continue;
        if (
          stId === "Warrior_BattleShout_Buff" &&
          host.id === "Warrior_BattleShout" &&
          hostMid !== BATTLE_SHOUT_M3_MASTERY_ID
        ) {
          continue;
        }
        for (let ai = 0; ai < st.affixes.length; ai++) {
          const ax = st.affixes[ai];
          if (!ax || ax.ref !== "TAttribute_ARatio") continue;
          if (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(st, ax)) continue;
          const attr = ax.target && ax.target.attribute;
          if (!attr || typeof ax.val !== "number") continue;
          if (!talentAffixRowMatchesRank(ax.conds, rank)) continue;
          if (!skillAffixRowMatchesMasteryGate(ax, hostMid)) continue;
          totals[attr] = (totals[attr] || 0) + statusPreviewAffixVal(st, ax) * stacks;
        }
      }
    }
    return totals;
  }

  /**
   * Sheet MagicMastery % used by **Discipline** (`var2 ×` magic) — class base + gear + talents + status flats/ratios,
   * before dynamic Physical from Discipline is applied.
   */
  function sheetMagicMasteryPctBeforeDiscipline(classId, charLevel, selectionSnapshot) {
    const baseStats = computeClassBaseStats(classId, charLevel);
    const gear = sumGearAffixes(charLevel, classId, selectionSnapshot);
    const talStatic = sumTalentAffixFlats(classId, { skipDynAffixes: true });
    const combined = { ...gear };
    for (const k of Object.keys(talStatic)) {
      combined[k] = (combined[k] || 0) + talStatic[k];
    }
    const stFlat = sumPreviewStatusBuffFlats(classId, selectionSnapshot, charLevel);
    const stRatio = sumPreviewStatusBuffARatios(classId, selectionSnapshot, charLevel);
    const out = { ...combined };
    for (const k of Object.keys(stFlat)) {
      out[k] = (out[k] || 0) + stFlat[k];
    }
    const ratio = stRatio.MagicMastery;
    if (typeof ratio === "number" && Number.isFinite(ratio) && ratio !== 0) {
      const baseVal = (baseStats.MagicMastery || 0) + (out.MagicMastery || 0);
      out.MagicMastery = (out.MagicMastery || 0) + baseVal * ratio;
    }
    return (baseStats.MagicMastery || 0) + (out.MagicMastery || 0);
  }

  /** Gear simulator flats plus talent **`affixes`** contributions for sheet / combat preview. */
  function mergeGearTalentFlats(charLevel, classId, selectionSnapshot) {
    const baseStats = computeClassBaseStats(classId, charLevel);
    const gear = sumGearAffixes(charLevel, classId, selectionSnapshot);
    const talStatic = sumTalentAffixFlats(classId, { skipDynAffixes: true });
    const combined = { ...gear };
    for (const k of Object.keys(talStatic)) {
      combined[k] = (combined[k] || 0) + talStatic[k];
    }

    const stFlat = sumPreviewStatusBuffFlats(classId, selectionSnapshot, charLevel);
    const stRatio = sumPreviewStatusBuffARatios(classId, selectionSnapshot, charLevel);

    const out = { ...combined };
    for (const k of Object.keys(stFlat)) {
      out[k] = (out[k] || 0) + stFlat[k];
    }
    for (let pi = 0; pi < PRIMARY_ATTRIBUTE_IDS.length; pi++) {
      const attr = PRIMARY_ATTRIBUTE_IDS[pi];
      const ratio = stRatio[attr];
      if (typeof ratio !== "number" || !Number.isFinite(ratio) || ratio === 0) continue;
      const baseVal = (baseStats[attr] || 0) + (out[attr] || 0);
      out[attr] = (out[attr] || 0) + baseVal * ratio;
    }
    const magicForDiscipline = (baseStats.MagicMastery || 0) + (out.MagicMastery || 0);
    const dyn = sumTalentDynamicMasteryFlats(classId, magicForDiscipline);
    for (const k of Object.keys(dyn)) {
      out[k] = (out[k] || 0) + dyn[k];
    }
    const mysticM2 = mysticEmpowermentM2MasteryFlatBonus(classId);
    for (const k of Object.keys(mysticM2)) {
      out[k] = (out[k] || 0) + mysticM2[k];
    }
    const consFlat = sumConsumableBuffFlats();
    for (const k of Object.keys(consFlat)) {
      out[k] = (out[k] || 0) + consFlat[k];
    }
    return out;
  }

  /** Column points required in this branch before nodes on **`tier`** accept ranks (gates **1 / 3 / 7** for tier **2 / 3 / 4**). */
  function talentColumnThresholdForTier(tier) {
    if (tier <= 1) return 0;
    if (tier === 2) return 1;
    if (tier === 3) return 3;
    return 7;
  }

  /** UI meter **`shown/need`** — **`shown`** never exceeds **`need`** (met tiers show **need/need**, not **4/1**). */
  function talentTierGateMeterText(colPts, need) {
    const n = typeof need === "number" && Number.isFinite(need) ? Math.max(0, need) : 0;
    const raw = typeof colPts === "number" && Number.isFinite(colPts) ? Math.max(0, colPts) : 0;
    return `${Math.min(raw, n)}/${n}`;
  }

  function talentIncrementAllowed(tree, entry, alloc, charLevel) {
    if (talentSpentOverBudget(charLevel)) return false;
    const sid = entry.skill;
    const sk = skillById[sid];
    const rank = alloc[sid] || 0;
    const max = talentMaxPointsForSkill(sk);
    const budget = talentPointsBudget(charLevel);
    const spent = talentPointsSpent(alloc);
    if (spent >= budget) return false;
    if (rank >= max) return false;

    const tier = typeof entry.tier === "number" ? entry.tier : 0;
    if (tier === 0) return true;

    const apexId = talentApexSkillId(tree);
    const apexRank = alloc[apexId] || 0;
    const apexMax = talentApexMaxRank(tree);
    if (apexRank < apexMax) return false;

    const branch = typeof entry.branch === "number" ? entry.branch : 0;
    const need = talentColumnThresholdForTier(tier);
    const colPts = talentColumnPoints(tree, branch, alloc);
    if (colPts < need) return false;

    return true;
  }

  function talentLockReason(tree, entry, alloc, charLevel) {
    const budget = talentPointsBudget(charLevel);
    if (charLevel < TALENT_FIRST_POINT_LEVEL) {
      return `Talents unlock at level ${TALENT_FIRST_POINT_LEVEL}.`;
    }
    if (talentSpentOverBudget(charLevel)) {
      const over = talentPointsSpent(alloc) - budget;
      return `Over budget by ${over} point${over === 1 ? "" : "s"} — remove points before adding more.`;
    }
    if (talentPointsSpent(alloc) >= budget) {
      return "No talent points left — level up for more.";
    }

    const sid = entry.skill;
    const sk = skillById[sid];
    const rank = alloc[sid] || 0;
    const max = talentMaxPointsForSkill(sk);
    if (rank >= max) return "";

    const tier = typeof entry.tier === "number" ? entry.tier : 0;
    if (tier === 0) return "";

    const apexId = talentApexSkillId(tree);
    const apexRank = alloc[apexId] || 0;
    const apexMax = talentApexMaxRank(tree);
    if (apexRank < apexMax) {
      return `Spend all apex ranks first (${apexRank}/${apexMax}).`;
    }

    const branch = typeof entry.branch === "number" ? entry.branch : 0;
    const need = talentColumnThresholdForTier(tier);
    const colPts = talentColumnPoints(tree, branch, alloc);
    if (colPts < need) {
      return `Need ${need} talent point(s) in this branch below the apex for tier ${tier} (have ${colPts}).`;
    }
    return "";
  }

  /** Ordered unique **`attribute`** ids from static **`TAttribute_Flat`** talent rows (stable sheet order). */
  function collectTalentFlatAffixAttributeOrder(sk) {
    const order = [];
    const seen = new Set();
    if (!sk || !Array.isArray(sk.affixes)) return order;
    for (let i = 0; i < sk.affixes.length; i++) {
      const ax = sk.affixes[i];
      if (!ax || ax.ref !== "TAttribute_Flat") continue;
      if (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(sk, ax)) continue;
      const attr = ax.target && ax.target.attribute;
      if (!attr || seen.has(attr)) continue;
      seen.add(attr);
      order.push(attr);
    }
    return order;
  }

  function statusPreviewUsesDynamicBaseAffix(sk, ax) {
    if (!sk || sk.id !== CRUSADER_STATUS_ID || !ax) return false;
    const attr = ax.target && ax.target.attribute;
    return (
      attr === "CritChance" ||
      attr === "CooldownReduction" ||
      attr === "DamageModifier" ||
      attr === "HealGivenMultiplier" ||
      attr === "ShieldPowerMultiplier"
    );
  }

  /** Sum of presentation flats for **`attrId`** from **`sk.affixes`** when **`conds`** match **`rank`**. */
  function talentAffixFlatSumAtRank(sk, attrId, rank, masteryEntryId) {
    if (!sk || !Array.isArray(sk.affixes)) return 0;
    let sum = 0;
    for (let i = 0; i < sk.affixes.length; i++) {
      const ax = sk.affixes[i];
      if (!ax || ax.ref !== "TAttribute_Flat") continue;
      if (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(sk, ax)) continue;
      const a = ax.target && ax.target.attribute;
      if (a !== attrId || typeof ax.val !== "number") continue;
      if (!talentAffixRowMatchesRank(ax.conds, rank)) continue;
      if (!skillAffixRowMatchesMasteryGate(ax, masteryEntryId)) continue;
      sum += presentationFlatForAffixFactor(ax.val, 1);
    }
    return sum;
  }

  function formatSignedTalentFlat(v) {
    const vs = Math.abs(v) >= 10 ? v.toFixed(0) : v.toFixed(1).replace(/\.0$/, "");
    return `${v >= 0 ? "+" : ""}${vs}`;
  }

  /**
   * Rank **1** and **max** values side-by-side (plus a middle term when needed); **`gp-skill-desc-val`** marks the total at **`curRank`**.
   */
  function talentAffixScalingNumsHtml(n1s, nrs, nmaxs, curRank, maxPoints, v1, vr, vmax) {
    const sep = `<span class="gp-talent-tip-val-sep">/</span>`;
    const hl = (s) => `<span class="gp-skill-desc-val">${escapeHtml(s)}</span>`;
    const plain = (s) => escapeHtml(s);
    const eps = 1e-9;
    if (maxPoints <= 1) return hl(nrs);
    if (Math.abs(v1 - vmax) < eps) return hl(nrs);
    if (curRank <= 1) return hl(n1s) + sep + plain(nmaxs);
    if (curRank >= maxPoints) return plain(n1s) + sep + hl(nmaxs);
    if (Math.abs(vr - v1) < eps && Math.abs(vr - vmax) < eps) return hl(nrs);
    if (Math.abs(vr - v1) < eps) return hl(n1s) + sep + plain(nmaxs);
    if (Math.abs(vr - vmax) < eps) return plain(n1s) + sep + hl(nmaxs);
    return plain(n1s) + sep + hl(nrs) + sep + plain(nmaxs);
  }

  /** Static talent **`TAttribute_Flat`** rows — compact scaling with tooltip value styling (**`gp-skill-desc-val`**). */
  function talentAffixBonusesHtmlCompact(sk, maxPoints, curRank) {
    if (!sk) return "";
    const attrs = collectTalentFlatAffixAttributeOrder(sk);
    if (!attrs.length) return "";
    const mx = Math.max(1, maxPoints);
    const rankClamped = clamp(Math.floor(curRank), 1, mx);
    const parts = [];
    for (let i = 0; i < attrs.length; i++) {
      const attrId = attrs[i];
      const v1 = talentAffixFlatSumAtRank(sk, attrId, 1);
      const vmax = talentAffixFlatSumAtRank(sk, attrId, mx);
      const vr = talentAffixFlatSumAtRank(sk, attrId, rankClamped);
      const label = displayNameForAttr(attrId);
      const n1 = formatSignedTalentFlat(v1);
      const nmax = formatSignedTalentFlat(vmax);
      const nr = formatSignedTalentFlat(vr);
      const numsHtml = talentAffixScalingNumsHtml(n1, nr, nmax, rankClamped, mx, v1, vr, vmax);
      parts.push(
        `<div class="gp-talent-tip-affix-line"><span class="gp-talent-tip-affix-nums">${numsHtml}</span> <span class="gp-talent-tip-affix-lbl">${escapeHtml(label)}</span></div>`
      );
    }
    return parts.join("");
  }

  /** Split **`expandSkillDescPlaceholdersMarked`** output into alternating plain / resolved (**`\uE000…\uE001`**) segments. */
  function splitMarkedSkillDescParts(str) {
    const MS = SKILL_DESC_MARK_S;
    const ME = SKILL_DESC_MARK_E;
    const parts = [];
    let i = 0;
    const s = String(str || "");
    while (i < s.length) {
      const start = s.indexOf(MS, i);
      if (start < 0) {
        if (i < s.length) parts.push({ t: "text", s: s.slice(i) });
        break;
      }
      if (start > i) parts.push({ t: "text", s: s.slice(i, start) });
      const end = s.indexOf(ME, start + MS.length);
      if (end < 0) {
        parts.push({ t: "text", s: s.slice(start) });
        break;
      }
      parts.push({ t: "val", s: s.slice(start + MS.length, end) });
      i = end + ME.length;
    }
    return parts;
  }

  /** Merge three resolved placeholder strings (**rank low / current / high**) with **`gp-skill-desc-val`** on the active rank (talent allocation preview). */
  function mergeSkillDescThreeValsHtml(vLo, vMid, vHi, rankLo, rankMid, rankHi) {
    const sep = `<span class="gp-talent-tip-val-sep">/</span>`;
    const hl = (v) => `<span class="gp-skill-desc-val">${escapeHtml(v)}</span>`;
    const pl = (v) => escapeHtml(v);
    if (vLo === vMid && vMid === vHi) return hl(vLo);
    if (vLo === vHi) return hl(vLo);
    const er = rankMid;
    if (er <= rankLo) return hl(vLo) + sep + pl(vHi);
    if (er >= rankHi) return pl(vLo) + sep + hl(vHi);
    if (vMid === vLo) return hl(vLo) + sep + pl(vHi);
    if (vMid === vHi) return pl(vLo) + sep + hl(vHi);
    return pl(vLo) + sep + hl(vMid) + sep + pl(vHi);
  }

  /** Merge marked segment lists from expansions at **rankLo**, **rankMid**, **rankHi** — one sentence; differing slots become **`a/b`** (or **`a/b/c`** when needed). */
  function mergeThreeMarkedSkillPartsHtml(partsLo, partsMid, partsHi, rankLo, rankMid, rankHi) {
    if (!partsLo.length && !partsMid.length && !partsHi.length) return "";
    if (partsLo.length !== partsMid.length || partsLo.length !== partsHi.length) return null;
    let html = "";
    for (let i = 0; i < partsLo.length; i++) {
      const a = partsLo[i];
      const b = partsMid[i];
      const c = partsHi[i];
      if (!a || !b || !c || a.t !== b.t || a.t !== c.t) return null;
      if (a.t === "text") {
        const t = a.s || "";
        if ((b.s || "") !== t || (c.s || "") !== t) return null;
        html += escapeHtml(t);
      } else {
        html += mergeSkillDescThreeValsHtml(a.s, b.s, c.s, rankLo, rankMid, rankHi);
      }
    }
    return html;
  }

  /**
   * One merged line for **`template`** (**`texts.desc`** or a **`rankDescs`** fragment): compare placeholders at **rankLo**, **rankMid**, **rankHi**.
   * Falls back to **rankMid** only when structure diverges.
   */
  function skillDescMergedEndpointsHtml(template, sk, combatCtx, rankLo, rankHi, rankMid) {
    if (!template || !sk) return "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const hi = Math.max(1, Math.floor(rankHi));
    const lo = clamp(Math.floor(rankLo), 1, hi);
    const er = clamp(Math.floor(rankMid != null ? rankMid : lo), lo, hi);
    const mLo = finalizeUnresolvedSkillPlaceholders(
      expandSkillDescPlaceholdersMarked(template, sk, true, ctx, lo, lo)
    );
    const mHi = finalizeUnresolvedSkillPlaceholders(
      expandSkillDescPlaceholdersMarked(template, sk, true, ctx, hi, hi)
    );
    const mEr = finalizeUnresolvedSkillPlaceholders(
      expandSkillDescPlaceholdersMarked(template, sk, true, ctx, er, er)
    );
    const merged = mergeThreeMarkedSkillPartsHtml(
      splitMarkedSkillDescParts(mLo),
      splitMarkedSkillDescParts(mEr),
      splitMarkedSkillDescParts(mHi),
      lo,
      er,
      hi
    );
    if (merged != null) return merged;
    return skillDescMarkedStringToHtml(mEr);
  }

  /** **`rankDescs`** rows for ranks **1**, **max**, and current (**middle** only) — expanded at preview rank (extra lines; main **`desc`** handles merged scaling). */
  function skillRankDescAppendixTalentHtml(sk, combatCtx, maxPoints, effectiveRank) {
    const entries = skillRankDescEntries(sk);
    if (!entries.length || !sk) return "";
    const mx = Math.max(1, maxPoints);
    const er = clamp(Math.floor(effectiveRank || 1), 1, mx);
    const want = new Set([1, mx]);
    if (mx > 2 && er > 1 && er < mx) want.add(er);
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    let inner = "";
    for (let i = 0; i < entries.length; i++) {
      const row = entries[i];
      if (!want.has(row.rank)) continue;
      const marked = finalizeUnresolvedSkillPlaceholders(
        expandSkillDescPlaceholdersMarked(row.desc, sk, true, ctx, er, row.rank)
      );
      const body = skillDescMarkedStringToHtml(marked);
      if (!body) continue;
      inner += `<div class="gp-skill-rank-desc"><span class="gp-skill-rank-desc__label">Rank ${row.rank}</span> <span class="gp-skill-rank-desc__body">${body}</span></div>`;
    }
    return inner ? `<div class="gp-skill-rank-descs gp-skill-rank-descs--talent-appendix">${inner}</div>` : "";
  }

  /** Single merged narrative for multi-point talents (**main `desc`** + compact **`rankDescs`** appendix). */
  function skillTalentMergedStoryHtml(sk, combatCtx, maxPoints, effectiveRank) {
    if (!sk || maxPoints <= 1) return "";
    const mx = Math.max(1, maxPoints);
    const er = clamp(Math.floor(effectiveRank || 1), 1, mx);
    const raw = skillDescRaw(sk);
    let mainHtml = "";
    if (raw) {
      mainHtml = skillDescMergedEndpointsHtml(raw, sk, combatCtx, 1, mx, er);
    }
    const appendix = skillRankDescAppendixTalentHtml(sk, combatCtx, mx, er);
    if (!mainHtml && !appendix) return "";
    return (
      `<div class="gp-talent-tip-desc-merged">` +
      (mainHtml ? `<div class="gp-tooltip-skill-desc gp-tooltip-skill-desc--talent-merged">${mainHtml}</div>` : "") +
      appendix +
      `</div>`
    );
  }

  /** Preview line for **`Mage_Talent_Discipline`** dynamic Physical mastery (uses current sheet Magic from **`combatCtx`**). */
  function talentDisciplineDynamicHintHtml(sk, combatCtx) {
    if (!sk || sk.id !== "Mage_Talent_Discipline") return "";
    const ctx = combatCtx != null ? combatCtx : plannerSkillCombatCtx;
    const totals = ctx && ctx.sheetTotals;
    if (!totals || typeof totals.MagicMastery !== "number") return "";
    const ratio = sk.vars && typeof sk.vars.var2 === "number" ? sk.vars.var2 : 0;
    if (!(ratio > 0)) return "";
    const mag = totals.MagicMastery;
    const phy = ratio * mag;
    const magS = Math.abs(mag - Math.round(mag)) < 1e-6 ? String(Math.round(mag)) : String(Math.round(mag * 10) / 10).replace(/\.0$/, "");
    const phyS = Math.abs(phy - Math.round(phy)) < 1e-6 ? String(Math.round(phy)) : String(Math.round(phy * 10) / 10).replace(/\.0$/, "");
    const pct = Math.round(ratio * 100);
    return `<div class="gp-talent-tip-affix-line gp-talent-tip-affix-line--dyn">${escapeHtml("Physical Mastery: ")}<span class="gp-skill-desc-val">${escapeHtml(
      `+${phyS}%`
    )}</span>${escapeHtml(` (${pct}% of ${magS}% Magic Mastery on sheet)`)}</div>`;
  }

  /**
   * Rich tooltip for a talent node (**merged** styling with weapon / skill tips).
   * @param {object} tree — one **`talentTrees[]`** entry
   * @param {{ skill: string, tier?: number, branch?: number }} entry
   */
  function buildTalentTooltipHtml(tree, entry, alloc, charLevel, combatCtx) {
    const sid = entry.skill;
    const sk = skillById[sid];
    const name = skillDisplayName(sk) || sid || "Talent";
    const passive = sk && skillIconIsPassiveFrame(sk);
    const iconFrame = passive ? "gp-skill-icon--passive" : "gp-skill-icon--active";

    const rank = alloc[sid] || 0;
    const max = sk ? talentMaxPointsForSkill(sk) : 1;
    const effectiveRank = rank > 0 ? rank : 1;

    const talentTiming = sk ? skillTimingMetaTextJoined(sk) : "";

    let html = `
      <div class="gp-tooltip__header gp-tooltip__header--skill-tip">
        <div class="gp-tooltip__icon ${iconFrame}"></div>
        <div class="gp-tooltip__headtext">
          <div class="gp-tooltip__name">${escapeHtml(name)}</div>
          ${talentTiming ? `<div class="gp-tooltip__meta">${escapeHtml(talentTiming)}</div>` : ""}
        </div>
      </div>`;

    let body = "";

    const rawEmpty = !sk || !skillDescRaw(sk);
    const affHtml = sk ? talentAffixBonusesHtmlCompact(sk, max, effectiveRank) : "";
    const discDyn = sk && sk.id === "Mage_Talent_Discipline" ? talentDisciplineDynamicHintHtml(sk, combatCtx) : "";
    const rageShieldDyn =
      sid === WARRIOR_TALENT_RAGE_SHIELD_ID ? warriorRageShieldTalentTooltipHtml(combatCtx) : "";
    const bonusBlock =
      affHtml || discDyn || rageShieldDyn
        ? `<div class="gp-talent-tip-affixes">${affHtml}${discDyn}${rageShieldDyn}</div>`
        : "";

    if (max > 1 && sk) {
      const rankStoryBlock = skillTalentMergedStoryHtml(sk, combatCtx, max, effectiveRank);
      if (rawEmpty && bonusBlock && rankStoryBlock) {
        body += bonusBlock + rankStoryBlock;
      } else {
        if (rankStoryBlock) body += rankStoryBlock;
        if (bonusBlock) body += bonusBlock;
      }
      if (!rankStoryBlock && !bonusBlock && sk) {
        body += `<p class="gp-muted gp-talent-tip-empty">No description or attribute preview.</p>`;
      }
    } else {
      const descHtml = sk ? skillDescHtml(sk, combatCtx, effectiveRank) : "";
      if (rawEmpty && bonusBlock && descHtml) {
        body += bonusBlock + `<div class="gp-tooltip-skill-desc">${descHtml}</div>`;
      } else {
        if (descHtml) body += `<div class="gp-tooltip-skill-desc">${descHtml}</div>`;
        if (bonusBlock) body += bonusBlock;
      }
      if (!descHtml && !bonusBlock && sk) {
        body += `<p class="gp-muted gp-talent-tip-empty">No description or attribute preview.</p>`;
      }
    }

    const mergedDmg = sk ? skillMergedCombatDamageHtml(sk, combatCtx || null) : "";
    const vsMon = sk ? skillVsMonsterAverageDamageHtml(sk, combatCtx || null) : "";
    if (mergedDmg || vsMon) {
      const hd = damagePreviewRowsExist(sk, combatCtx)
        ? `<div class="gp-tooltip-skill-preview-hd">With your stats</div>`
        : "";
      body += hd + mergedDmg + vsMon;
    }

    if (body) html += `<div class="gp-tooltip-skill-body">${body}</div>`;
    return html;
  }

  /**
   * @param {HTMLElement} mountEl
   * @param {string} classId
   * @param {number} charLevel
   * @param {object} combatCtx
   * @param {() => void} onChange — persist + parent refresh
   */
  function setActiveConsumableBuff(kind, itemId) {
    if (!kind || !activeConsumableByKind || !Object.prototype.hasOwnProperty.call(activeConsumableByKind, kind)) return;
    const id = typeof itemId === "string" && itemId.trim() ? itemId.trim() : null;
    if (!id) {
      activeConsumableByKind[kind] = null;
      return;
    }
    if (id === activeConsumableByKind[kind]) {
      activeConsumableByKind[kind] = null;
      return;
    }
    const it = consumableBuffById[id];
    if (it && itemConsumableBuffKind(it) === kind) activeConsumableByKind[kind] = id;
  }

  /**
   * @param {HTMLElement} mountEl
   * @param {() => void} onChange
   */
  function renderConsumablesPanel(mountEl, onChange) {
    if (!mountEl) return;
    mountEl.textContent = "";
    sanitizeActiveConsumableIds();

    const hint = document.createElement("p");
    hint.className = "gp-consumables-hint gp-muted";
    hint.textContent =
      "Pick at most one item per section. Bonuses apply to the character sheet and damage previews. Click an active choice again to clear it.";
    mountEl.appendChild(hint);

    function mountSection(title, kind, activeId, items) {
      const sec = document.createElement("section");
      sec.className = "gp-consumables-section";
      const hd = document.createElement("h3");
      hd.className = "gp-consumables-section__title";
      hd.textContent = title;
      sec.appendChild(hd);

      const noneBtn = document.createElement("button");
      noneBtn.type = "button";
      noneBtn.className =
        "gp-consumable-card gp-consumable-card--none" + (!activeId ? " gp-consumable-card--active" : "");
      noneBtn.setAttribute("aria-pressed", !activeId ? "true" : "false");
      noneBtn.innerHTML = `<span class="gp-consumable-card__name">None</span>`;
      noneBtn.addEventListener("click", (ev) => {
        ev.preventDefault();
        setActiveConsumableBuff(kind, null);
        if (typeof onChange === "function") onChange();
      });
      sec.appendChild(noneBtn);

      const grid = document.createElement('div');
      grid.className = "gp-consumables-grid";
      if (items.length) {
        for (let i = 0; i < items.length; i++) {
          const it = items[i];
          const on = activeId === it.id;
          const btn = document.createElement("button");
          btn.type = "button";
          btn.className = "gp-consumable-card" + (on ? " gp-consumable-card--active" : "");
          btn.setAttribute("aria-pressed", on ? "true" : "false");
          btn.dataset.itemId = it.id;

          const icon = document.createElement("span");
          icon.className = "gp-consumable-card__icon";
          if (it.gfx) mountLootIcon(icon, it.gfx);

          const text = document.createElement("span");
          text.className = "gp-consumable-card__text";
          const nameEl = document.createElement("span");
          nameEl.className = "gp-consumable-card__name";
          nameEl.textContent = itemDisplayName(it) || it.id;
          text.appendChild(nameEl);
          const affHtml = consumableAffixSummaryHtml(it);
          if (affHtml) {
            const aff = document.createElement("span");
            aff.className = "gp-consumable-card__affixes";
            aff.innerHTML = affHtml;
            text.appendChild(aff);
          }
          btn.appendChild(icon);
          btn.appendChild(text);
          btn.addEventListener("mouseenter", () => {
            const ctx = plannerSkillCombatCtx;
            if (!ctx) return;
            const cl = ctx.charLevel != null ? ctx.charLevel : CHAR_LEVEL_DEFAULT;
            const cid = ctx.classId || "";
            const afterCtx = combatSnapshotAfterConsumable(kind, it.id, cl, cid, ctx);
            if (!afterCtx) return;
            const html = skillDamageDeltaPreviewHtml(ctx, afterCtx, cid, 6);
            if (!html) return;
            showGearPlannerTooltip(btn, html, {
              className: "gp-slot-tooltip gp-slot-tooltip--damage-delta",
            });
          });
          btn.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
          btn.addEventListener("click", (ev) => {
            ev.preventDefault();
            setActiveConsumableBuff(kind, it.id);
            if (typeof onChange === "function") onChange();
          });
          grid.appendChild(btn);
        }
      } else {
        const empty = document.createElement("p");
        empty.className = "gp-muted gp-consumables-empty";
        empty.textContent = "No matching items in data.";
        grid.appendChild(empty);
      }
      sec.appendChild(grid);
      mountEl.appendChild(sec);
    }

    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const def = CONSUMABLE_BUFF_KIND_DEFS[ki];
      const items = consumableBuffCatalog[def.kind] || [];
      if (!items.length) continue;
      mountSection(def.title, def.kind, activeConsumableByKind[def.kind], items);
    }
    const anyListed = CONSUMABLE_BUFF_KIND_DEFS.some(
      (def) => (consumableBuffCatalog[def.kind] || []).length > 0
    );
    if (!anyListed) {
      const empty = document.createElement("p");
      empty.className = "gp-muted";
      empty.textContent = "No attribute buff consumables found in data.";
      mountEl.appendChild(empty);
    }
  }

  function renderTalentTreesPanel(mountEl, classId, charLevel, combatCtx, onChange) {
    if (!mountEl) return;
    mountEl.textContent = "";
    const trees = talentTreesForClass(classId);
    if (!trees.length) {
      mountEl.innerHTML = `<p class="gp-muted">No talent tree data for this class.</p>`;
      return;
    }

    sanitizeTalentAllocationsForClass(classId);
    const budget = talentPointsBudget(charLevel);
    const spent = talentPointsSpent(talentAllocations);
    const overBudget = spent > budget;
    const sum = document.createElement("div");
    sum.className = "gp-talent-summary" + (overBudget ? " gp-talent-summary--over-budget" : "");
    sum.innerHTML =
      `<span class="gp-talent-summary__label">Talent points</span> ` +
      `<span class="gp-talent-summary__val">${spent} / ${budget}</span>` +
      (charLevel < TALENT_FIRST_POINT_LEVEL
        ? `<span class="gp-talent-summary__hint"> · First point at level ${TALENT_FIRST_POINT_LEVEL}</span>`
        : "") +
      (overBudget
        ? `<span class="gp-talent-summary__warn"> · Remove ${spent - budget} point${
            spent - budget === 1 ? "" : "s"
          } to match this level</span>`
        : "");
    mountEl.appendChild(sum);

    for (let ti = 0; ti < trees.length; ti++) {
      mountEl.appendChild(renderSingleTalentTree(trees[ti], classId, charLevel, combatCtx, onChange));
    }
  }

  /**
   * Updates talent UI state without rebuilding nodes (avoids icon/tooltip flicker when ranks change).
   * Expects DOM from **`renderTalentTreesPanel`** (`data-gp-talent-skill` / **`data-gp-talent-tier`**).
   */
  function refreshTalentTreeVisuals(mountEl, classId, charLevel) {
    if (!mountEl || mountEl.querySelector(".gp-muted")) return;

    const budget = talentPointsBudget(charLevel);
    const spent = talentPointsSpent(talentAllocations);
    const overBudget = spent > budget;
    const sumEl = mountEl.querySelector(".gp-talent-summary");
    if (sumEl) sumEl.classList.toggle("gp-talent-summary--over-budget", overBudget);
    const valEl = mountEl.querySelector(".gp-talent-summary__val");
    if (valEl) valEl.textContent = `${spent} / ${budget}`;
    let warnEl = mountEl.querySelector(".gp-talent-summary__warn");
    if (overBudget) {
      if (!warnEl && sumEl) {
        warnEl = document.createElement("span");
        warnEl.className = "gp-talent-summary__warn";
        sumEl.appendChild(warnEl);
      }
      if (warnEl) {
        warnEl.textContent = ` · Remove ${spent - budget} point${spent - budget === 1 ? "" : "s"} to match this level`;
      }
    } else if (warnEl) {
      warnEl.remove();
    }

    const trees = talentTreesForClass(classId);
    const sections = mountEl.querySelectorAll(":scope > section.gp-talent-tree");

    for (let ti = 0; ti < sections.length; ti++) {
      const treeEl = sections[ti];
      const tree = trees[ti];
      if (!tree) continue;

      const totalEl = treeEl.querySelector(".gp-talent-tree__head [data-gp-tree-total]");
      if (totalEl) {
        const treeTotal = talentTotalPointsInTree(tree, talentAllocations);
        totalEl.textContent = `${treeTotal} pt${treeTotal === 1 ? "" : "s"}`;
        totalEl.classList.toggle("gp-talent-tree__head-total--has", treeTotal > 0);
      }

      treeEl.querySelectorAll(".gp-talent-tree__tier-block[data-gp-talent-tier]").forEach((block) => {
        const tierNum = parseInt(block.getAttribute("data-gp-talent-tier"), 10);
        if (!Number.isFinite(tierNum) || tierNum < 2) return;
        const need = talentColumnThresholdForTier(tierNum);
        const row = block.querySelector(":scope > .gp-talent-tree__row--cols");
        if (!row) return;
        const branches = row.querySelectorAll(":scope > .gp-talent-tree__branch");
        branches.forEach((branchEl, bi) => {
          const br = bi + 1;
          const meter = branchEl.querySelector(".gp-talent-tree__branch-meter");
          if (meter) {
            const colPts = talentColumnPoints(tree, br, talentAllocations);
            meter.textContent = talentTierGateMeterText(colPts, need);
            meter.classList.toggle("gp-talent-tree__branch-meter--ok", colPts >= need);
          }
        });
      });

      treeEl.querySelectorAll(".gp-talent-node[data-gp-talent-skill]").forEach((nodeEl) => {
        const sid = nodeEl.getAttribute("data-gp-talent-skill");
        if (!sid) return;
        const entry = talentEntryForSkill(tree, sid);
        if (!entry) return;
        const sk = skillById[sid];
        const rank = talentAllocations[sid] || 0;
        const max = talentMaxPointsForSkill(sk);
        const canInc = talentIncrementAllowed(tree, entry, talentAllocations, charLevel);
        const dimmed = rank === 0 && !canInc;
        const lockAll = talentSpentOverBudget(charLevel);
        nodeEl.classList.toggle("gp-talent-node--locked", dimmed || lockAll);
        nodeEl.classList.toggle("gp-talent-node--invested", rank > 0);
        nodeEl.classList.toggle("gp-talent-node--maxed", rank > 0 && rank >= max);

        const iconBtn = nodeEl.querySelector(".gp-talent-node__icon-btn");
        if (iconBtn) {
          iconBtn.setAttribute("aria-label", `${skillDisplayName(sk) || sid}, ${rank} of ${max}`);
        }

        const lbl = nodeEl.querySelector(".gp-talent-node__rank");
        if (lbl) lbl.textContent = `${rank}/${max}`;

        const btnDec = nodeEl.querySelector(".gp-talent-node__btn--dec");
        if (btnDec) btnDec.disabled = rank <= 0;

        const btnInc = nodeEl.querySelector(".gp-talent-node__btn--inc");
        if (btnInc) btnInc.disabled = !canInc || rank >= max || talentSpentOverBudget(charLevel);
      });
    }
  }

  function renderSingleTalentTree(tree, classId, charLevel, combatCtx, onChange) {
    const treeRootEl = document.createElement("section");
    treeRootEl.className = "gp-talent-tree";

    const apexId = talentApexSkillId(tree);
    const apexSk = skillById[apexId];
    const titleText =
      (apexSk && skillDisplayName(apexSk)) ||
      (typeof tree.root === "string" ? tree.root : "") ||
      "Talent tree";
    const head = document.createElement("header");
    head.className = "gp-talent-tree__head";
    const treeTotal = talentTotalPointsInTree(tree, talentAllocations);
    head.innerHTML =
      `<h3 class="gp-talent-tree__title">${escapeHtml(titleText)}</h3>` +
      `<span class="gp-talent-tree__head-total${treeTotal > 0 ? " gp-talent-tree__head-total--has" : ""}" data-gp-tree-total title="Points invested in this tree">${treeTotal} pt${treeTotal === 1 ? "" : "s"}</span>` +
      (tree.desc ? `<p class="gp-talent-tree__desc">${escapeHtml(String(tree.desc))}</p>` : "");
    treeRootEl.appendChild(head);

    const list = tree.talents;
    if (!Array.isArray(list) || !list.length) return treeRootEl;

    const byTier = new Map();
    let maxT = 0;
    for (let i = 0; i < list.length; i++) {
      const e = list[i];
      const t = typeof e.tier === "number" ? e.tier : 0;
      maxT = Math.max(maxT, t);
      if (!byTier.has(t)) byTier.set(t, []);
      byTier.get(t).push(e);
    }

    const body = document.createElement("div");
    body.className = "gp-talent-tree__body";

    if (byTier.has(0)) {
      const apexRow = document.createElement("div");
      apexRow.className = "gp-talent-tree__row gp-talent-tree__row--apex";
      const tier0 = byTier.get(0).slice().sort((a, b) => (a.branch || 0) - (b.branch || 0));
      for (let i = 0; i < tier0.length; i++) {
        apexRow.appendChild(createTalentNodeEl(tree, tier0[i], classId, charLevel, combatCtx, onChange));
      }
      body.appendChild(apexRow);
    }

    for (let tier = 1; tier <= maxT; tier++) {
      if (!byTier.has(tier)) continue;

      const tierBlock = document.createElement("div");
      tierBlock.className = "gp-talent-tree__tier-block";
      tierBlock.setAttribute("data-gp-talent-tier", String(tier));

      const row = document.createElement("div");
      row.className = "gp-talent-tree__row gp-talent-tree__row--cols";
      const byBranch = new Map();
      const tierEntries = byTier.get(tier);
      for (let i = 0; i < tierEntries.length; i++) {
        const e = tierEntries[i];
        const b = typeof e.branch === "number" ? e.branch : 0;
        if (!byBranch.has(b)) byBranch.set(b, []);
        byBranch.get(b).push(e);
      }
      const needForTierGate = tier >= 2 ? talentColumnThresholdForTier(tier) : null;
      for (const br of [1, 2, 3]) {
        const cell = document.createElement("div");
        cell.className = "gp-talent-tree__branch";

        const branchHead = document.createElement("div");
        branchHead.className = "gp-talent-tree__branch-head";
        const tierLabel = document.createElement("span");
        tierLabel.className = "gp-talent-tree__branch-tier-label";
        tierLabel.textContent = `Tier ${tier}`;
        branchHead.appendChild(tierLabel);
        if (tier >= 2 && needForTierGate != null) {
          const colPts = talentColumnPoints(tree, br, talentAllocations);
          const meter = document.createElement("span");
          meter.className =
            "gp-talent-tree__branch-meter" +
            (colPts >= needForTierGate ? " gp-talent-tree__branch-meter--ok" : "");
          meter.textContent = talentTierGateMeterText(colPts, needForTierGate);
          meter.title = `Column ${br} · points toward tier ${tier} gate`;
          branchHead.appendChild(meter);
        }
        cell.appendChild(branchHead);

        const nodesWrap = document.createElement("div");
        nodesWrap.className = "gp-talent-tree__branch-nodes";
        const entries = (byBranch.get(br) || []).slice().sort((a, b) => String(a.skill).localeCompare(String(b.skill)));
        if (!entries.length) {
          const empty = document.createElement("span");
          empty.className = "gp-talent-tree__branch-empty";
          empty.setAttribute("aria-hidden", "true");
          empty.textContent = " ";
          nodesWrap.appendChild(empty);
        } else if (tier === 3 && entries.length === 3) {
          /** Top row: 2nd & 3rd talents grouped (same gap as default); bottom row: 1st centered — avoids stretching pair across the branch. */
          nodesWrap.classList.add("gp-talent-tree__branch-nodes--tier3-triple");
          const rowTop = document.createElement("div");
          rowTop.className = "gp-talent-tree__branch-nodes__pair-row";
          rowTop.appendChild(createTalentNodeEl(tree, entries[1], classId, charLevel, combatCtx, onChange));
          rowTop.appendChild(createTalentNodeEl(tree, entries[2], classId, charLevel, combatCtx, onChange));
          nodesWrap.appendChild(rowTop);
          const rowBot = document.createElement("div");
          rowBot.className = "gp-talent-tree__branch-nodes__single-row";
          rowBot.appendChild(createTalentNodeEl(tree, entries[0], classId, charLevel, combatCtx, onChange));
          nodesWrap.appendChild(rowBot);
        } else {
          for (let j = 0; j < entries.length; j++) {
            nodesWrap.appendChild(createTalentNodeEl(tree, entries[j], classId, charLevel, combatCtx, onChange));
          }
        }
        cell.appendChild(nodesWrap);

        row.appendChild(cell);
      }
      tierBlock.appendChild(row);
      body.appendChild(tierBlock);
    }

    treeRootEl.appendChild(body);
    return treeRootEl;
  }

  function createTalentNodeEl(tree, entry, classId, charLevel, combatCtx, onChange) {
    const sid = entry.skill;
    const sk = skillById[sid];
    const wrap = document.createElement("div");
    wrap.className = "gp-talent-node";
    wrap.setAttribute("data-gp-talent-skill", sid);

    const rank = talentAllocations[sid] || 0;
    const max = talentMaxPointsForSkill(sk);
    const canInc = talentIncrementAllowed(tree, entry, talentAllocations, charLevel);
    const dimmed = rank === 0 && !canInc;
    const lockAll = talentSpentOverBudget(charLevel);
    if (dimmed || lockAll) wrap.classList.add("gp-talent-node--locked");
    if (rank > 0) wrap.classList.add("gp-talent-node--invested");
    if (rank > 0 && rank >= max) wrap.classList.add("gp-talent-node--maxed");

    const iconBtn = document.createElement("button");
    iconBtn.type = "button";
    iconBtn.className =
      "gp-talent-node__icon-btn " +
      (sk && skillIconIsPassiveFrame(sk) ? "gp-skill-icon--passive" : "gp-skill-icon--active");
    iconBtn.setAttribute("aria-label", (skillDisplayName(sk) || sid) + `, ${rank} of ${max}`);
    if (sk && sk.gfx) mountAtlasIcon(iconBtn, sk.gfx, 40);
    else iconBtn.textContent = "?";

    iconBtn.addEventListener("mouseenter", () => {
      const ctx = plannerSkillCombatCtx || combatCtx;
      const html = buildTalentTooltipHtml(tree, entry, talentAllocations, charLevel, ctx);
      showGearPlannerTooltip(iconBtn, html, {
        className: "gp-slot-tooltip gp-slot-tooltip--talent",
        decorate: (tip) => {
          decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, sk, sid, ctx, sk && sk.gfx);
        },
      });
    });
    iconBtn.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);

    const controls = document.createElement("div");
    controls.className = "gp-talent-node__controls";

    const btnDec = document.createElement("button");
    btnDec.type = "button";
    btnDec.className = "gp-talent-node__btn gp-talent-node__btn--dec";
    btnDec.textContent = "−";
    btnDec.setAttribute("aria-label", "Remove talent point");
    btnDec.disabled = rank <= 0;

    const lbl = document.createElement("span");
    lbl.className = "gp-talent-node__rank";
    lbl.textContent = `${rank}/${max}`;

    const btnInc = document.createElement("button");
    btnInc.type = "button";
    btnInc.className = "gp-talent-node__btn gp-talent-node__btn--inc";
    btnInc.textContent = "+";
    btnInc.setAttribute("aria-label", "Add talent point");
    btnInc.disabled = !canInc || rank >= max || lockAll;

    btnInc.addEventListener("mouseenter", () => {
      const ctx = plannerSkillCombatCtx || combatCtx;
      if (!ctx || lockAll) return;
      const afterCtx = combatSnapshotAfterTalentRankDelta(sid, charLevel, classId, ctx);
      if (!afterCtx) return;
      const html = skillDamageDeltaPreviewHtml(ctx, afterCtx, classId, 6);
      if (!html) return;
      showGearPlannerTooltip(btnInc, html, {
        className: "gp-slot-tooltip gp-slot-tooltip--damage-delta",
      });
    });
    btnInc.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);

    function refresh() {
      if (typeof onChange === "function") onChange();
    }

    btnDec.addEventListener("click", (ev) => {
      ev.preventDefault();
      ev.stopPropagation();
      const r = talentAllocations[sid] || 0;
      if (r <= 0) return;
      if (r <= 1) delete talentAllocations[sid];
      else talentAllocations[sid] = r - 1;
      sanitizeTalentAllocationsForClass(classId);
      refresh();
    });

    btnInc.addEventListener("click", (ev) => {
      ev.preventDefault();
      ev.stopPropagation();
      if (!talentIncrementAllowed(tree, entry, talentAllocations, charLevel)) return;
      const r = talentAllocations[sid] || 0;
      if (r >= max) return;
      talentAllocations[sid] = r + 1;
      refresh();
    });

    controls.appendChild(btnDec);
    controls.appendChild(lbl);
    controls.appendChild(btnInc);

    wrap.appendChild(iconBtn);
    wrap.appendChild(controls);
    return wrap;
  }

  function skillDisplayName(sk) {
    if (sk && typeof sk.id === "string" && isWeaponBaseAttackSkillId(sk.id)) return "Attack";
    const t = sk && sk.texts;
    if (!t) return sk && sk.id ? String(sk.id) : "";
    if (typeof t.name === "string") return t.name;
    if (t.name && typeof t.name === "object" && t.name.v != null) return String(t.name.v);
    return sk.id || "";
  }

  /** `skill.cooldown` from CDB — seconds (may be fractional). */
  function formatSkillCooldownForUi(seconds) {
    if (!Number.isFinite(seconds) || seconds < 0) return "";
    if (seconds !== 0 && seconds < 1) {
      const t = Math.round(seconds * 10) / 10;
      return String(t).replace(/\.0$/, "");
    }
    if (seconds % 1 === 0) return String(Math.round(seconds));
    const t = Math.round(seconds * 10) / 10;
    return String(t).replace(/\.0$/, "");
  }

  /** Display fragment **`cd: 4s`** — empty when no **`cooldown`** on sheet or **`0`** (passive / no CD). */
  function skillCooldownMetaText(sk) {
    if (!sk || typeof sk.cooldown !== "number" || !Number.isFinite(sk.cooldown) || sk.cooldown <= 0) return "";
    const u = formatSkillCooldownForUi(sk.cooldown);
    if (!u) return "";
    return `cd: ${u}s`;
  }

  /** `skill.duration` from CDB — authored skill window (often overrides moveSet); seconds. */
  function skillDurationMetaText(sk) {
    if (!sk || typeof sk.duration !== "number" || !Number.isFinite(sk.duration) || sk.duration <= 0) return "";
    const u = formatSkillCooldownForUi(sk.duration);
    if (!u) return "";
    return `dur: ${u}s`;
  }

  /** Both **`cd`** / **`dur`** fragments when present — **`cd: 4s · dur: 0.25s`**. */
  function skillTimingMetaTextJoined(sk) {
    const parts = [skillCooldownMetaText(sk), skillDurationMetaText(sk)].filter(Boolean);
    return parts.join(" · ");
  }

  /** Prefix for inline meta (**` · cd: …`** / **` · dur: …`**). */
  function skillCooldownMetaInline(sk) {
    const t = skillCooldownMetaText(sk);
    return t ? ` · ${t}` : "";
  }

  function skillDurationMetaInline(sk) {
    const t = skillDurationMetaText(sk);
    return t ? ` · ${t}` : "";
  }

  /** **` · cd: … · dur: …`** combined for skill cards / compact rows. */
  function skillTimingMetaInline(sk) {
    let out = skillCooldownMetaInline(sk);
    out += skillDurationMetaInline(sk);
    return out;
  }

  function formatAffixLine(ax, curveRatio, affixFactor) {
    if (!affixRowDisplayed(ax)) return null;
    const ref = ax.ref;
    const attr = ax.target && ax.target.attribute;
    if (!attr || typeof ax.val !== "number") return null;
    const base = ax.val * curveRatio;
    const v = presentationFlatForAffixFactor(base, affixFactor);
    const attrName = displayNameForAttr(attr);
    const def = ref ? affixDefById[ref] : null;
    const rawDesc = def ? normalizeAffixSheetDesc(def.desc) : "";
    if (rawDesc && rawDesc.indexOf("::") >= 0) {
      const tokens = buildGearAffixTokenMap(ax, ref, v, attrName);
      let out = expandGearAffixDescTemplate(rawDesc, tokens);
      if (/::[a-zA-Z0-9_]+::/.test(out)) {
        out = legacyAffixLineNumeric(ref, v, attrName);
      }
      return out;
    }
    return legacyAffixLineNumeric(ref, v, attrName);
  }

  function rarityBadgeClass(rarity) {
    const r = rarity || "Common";
    if (RARITY_ORDER.includes(r)) return `rarity-badge rarity-badge--${r}`;
    return "rarity-badge rarity-badge--Common";
  }

  /** Text color class for item names (matches rarity badge hues). */
  function rarityTextClass(rarity) {
    const r = rarity || "Common";
    if (RARITY_ORDER.includes(r)) return `gp-name-rarity gp-name-rarity--${r}`;
    return "gp-name-rarity gp-name-rarity--Common";
  }

  function buildSlotCardTooltipHtml(sel, slotDef, ilvl) {
    if (!sel || !sel.item) return "";
    const it = sel.item;
    const name = itemDisplayName(it);
    const craftSub = itemCraftRecipeSubtitle(it);
    const craftBlock = craftSub
      ? `<div class="gp-tooltip__craftline">${escapeHtml(craftSub)}</div>`
      : "";
    const eff = effectiveItemRarity(sel);
    const lines = affixPreviewLines(sel, ilvl, slotDef);
    const statLines = [];
    const upgradeLines = [];
    for (let i = 0; i < lines.length; i++) {
      const L = lines[i];
      if (L.startsWith("Upgrade:")) upgradeLines.push(L);
      else statLines.push(L);
    }
    let statsHtml = previewPlainLinesAsHtml(statLines);
    for (let u = 0; u < upgradeLines.length; u++) {
      statsHtml += formatWeaponUpgradePreviewLineHtml(upgradeLines[u]);
    }
    const ench = sel.enchantId ? enchantItemById(sel.enchantId) : null;
    const enchHtml = ench
      ? `<div class="gp-tooltip-enchant"><span class="gp-tooltip-enchant__tag">Enchant</span> ${escapeHtml(
          itemDisplayName(ench)
        )}</div>`
      : "";
    const aug = sel.augmentId ? augmentItemById(sel.augmentId) : null;
    const augRoot = aug ? primaryAugmentVendorRoot(aug) : null;
    const augTag = augRoot ? augmentVendorShortLabel(augRoot) : "Augment";
    const augHtml = aug
      ? `<div class="gp-tooltip-augment"><span class="gp-tooltip-augment__tag">${escapeHtml(
          augTag
        )}</span> ${escapeHtml(itemDisplayName(aug))}</div>`
      : "";
    return `
      <div class="gp-tooltip__header">
        <div class="gp-tooltip__icon"></div>
        <div class="gp-tooltip__headtext">
          <div class="gp-tooltip__name ${rarityTextClass(eff)}">${escapeHtml(name)}</div>
          ${craftBlock}
          <div class="gp-tooltip__meta">${escapeHtml(eff)} · Level ${ilvl}</div>
        </div>
      </div>
      <div class="gp-tooltip__stats">${statsHtml}</div>
      ${enchHtml}
      ${augHtml}
    `;
  }

  /** Weapon slot — **`slot.affixFactor`** from **`Slot_Weapon2`** for arsenal (`getAffixFactor@9343`), else **1**. */
  function slotAffixMultiplier(slotDef) {
    return affixFactorForWeaponSlotDef(slotDef);
  }

  /**
   * @param {{ item: object, ilvl?: number, stars?: number, rarityOverride?: string|null, enchantId?: string|null, augmentId?: string|null, viewerClassId?: string, flawless?: boolean }} sel
   * @param {number} plannerTier
   * @param {object} [slotDef] when set, arsenal slots scale preview lines like the game
   */
  function affixPreviewLines(sel, plannerTier, slotDef) {
    const it = effectiveItem(sel);
    if (!it) return [];
    const showGearAffixUi = itemTypeShowsGearAffixUi(it.type);
    const baseIt = sel.item;
    const affixFactor = affixFactorForWeaponSlotDef(slotDef);
    const stars = sel.stars
      ? clamp(Math.round(sel.stars), 0, maxUpgradeStarsForRarity(effectiveItemRarity(sel)))
      : 0;
    const flawless = !!(sel && sel.flawless);
    const tSel = lootCoordinateT(it, plannerTier, stars, flawless);
    const tRef = referenceCurveT(baseIt, plannerTier, sel);
    const multSel = gearCurveGFromT(tSel);
    const multRef = gearCurveGFromT(tRef);
    const curveRatio = multRef > 0 ? multSel / multRef : 1;
    const trinketEquippedLines = [];
    if (itemTypeAncestorIds(it.type).includes("GearTrinket")) {
      for (const row of it.skills || []) {
        const sid = row && row.skill;
        if (typeof sid !== "string") continue;
        const sk = skillById[sid];
        if (!sk) continue;
        if (skillDescText(sk)) {
          trinketEquippedLines.push(GP_PREVIEW_TRINKET_SKILL_PREFIX + sid);
        }
      }
    }

    /**
     * **`getItemAffixes@7543`**: baked **`item.affixes`** / **`getDescriptions`** only when template ilvl matches preview
     * (`shouldUseStaticAffixDescriptions`). Otherwise **`generateItemAffixes`** — **`simulateFlatTotals`**. The regression test
     * only exercises simulation; the UI previously always formatted template **`affixes`** first and skipped simulation whenever
     * any line existed, so previews drifted from tooltip parity.
     */
    const staticDescOnly = shouldUseStaticAffixDescriptions(sel, plannerTier);
    const weaponUpgradePreviewTexts =
      slotDef && slotDef.weaponSlot && stars > 0
        ? weaponUpgradeBonusPreviewLines(it, effectiveItemRarity(sel), stars)
        : [];
    const lines = [];
    if (showGearAffixUi) {
    if (staticDescOnly) {
      for (const ax of it.affixes || []) {
        const line = formatAffixLine(ax, curveRatio, affixFactor);
        if (line) lines.push(line);
      }
    }
    /** Rolled path, or static branch with no baked lines (empty **`affixes`**). */
    if (!staticDescOnly || lines.length === 0) {
      const sim = simulateFlatTotals(it, plannerTier, {
        stars,
        weaponSlot: !!(slotDef && slotDef.weaponSlot),
        viewerClassId: sel.viewerClassId,
        flawless,
        omitWeaponUpgradeExtraFlats: weaponUpgradePreviewTexts.length > 0,
      });
      const scaled = {};
      for (const k of Object.keys(sim)) {
        scaled[k] = presentationFlatForAffixFactor(sim[k], affixFactor);
      }
      const formatted = formatSimulatedStatLines(scaled);
        for (let fi = 0; fi < formatted.length; fi++) lines.push(formatted[fi]);
    }

    /** Preview ilvl ≠ template ilvl: simulation may return no rows while **`item.affixes`** still lists authored flats (e.g. some trinkets). */
    if (!staticDescOnly && lines.length === 0) {
      for (const ax of it.affixes || []) {
        const line = formatAffixLine(ax, curveRatio, affixFactor);
        if (line) lines.push(line);
      }
    }

    for (let bi = 0; bi < weaponUpgradePreviewTexts.length; bi++) {
      lines.push(weaponUpgradePreviewTexts[bi]);
    }
    }

    lines.unshift(...trinketEquippedLines);

    const ench = sel.enchantId ? enchantItemById(sel.enchantId) : null;
    if (ench) {
      const ex = flatEnchantContribution(ench, slotDef, { displayOnly: true });
      mergeEnchantSkillStatusPreviewFlats(ex, ench);
      const formattedEnch = formatSimulatedStatLines(ex);
      for (const L of formattedEnch) lines.push(L);
      for (const row of ench.skills || []) {
        const sid = row && row.skill;
        if (typeof sid !== "string") continue;
        const sk = skillById[sid];
        appendEnchantSkillPreviewLines(lines, sk);
      }
    }

    const aug = sel.augmentId ? augmentItemById(sel.augmentId) : null;
    if (aug) {
      const ax = flatEnchantContribution(aug, slotDef, { displayOnly: true });
      const formattedAug = formatSimulatedStatLines(ax);
      for (const L of formattedAug) lines.push(L);
      for (const row of aug.skills || []) {
        const sid = row && row.skill;
        if (typeof sid !== "string") continue;
        const sk = skillById[sid];
        appendEnchantSkillPreviewLines(lines, sk);
      }
    }

    if (lines.length) return lines;

    if (!showGearAffixUi) return [];

    if (staticDescOnly) return [];

    return [
      `No stat preview (add aptitude/itemType data, or item has no rolled buckets for this slot).`,
    ];
  }

  /**
   * Adds this slot’s gear / enchant / augment flat totals into **`totals`** (same rules as **`sumGearAffixes`**).
   */
  function addGearAffixesFromSlotInto(totals, charLevel, viewerClassId, slotDef, sel) {
    if (!totals || !slotDef || !sel || !sel.item) return;
    const eff = effectiveItem(sel);
    if (!itemTypeShowsGearAffixUi(eff.type)) {
      const enchOnly = sel.enchantId ? enchantItemById(sel.enchantId) : null;
      if (enchOnly) mergeEnchantTotals(totals, enchOnly, slotDef);
      const augOnly = sel.augmentId ? augmentItemById(sel.augmentId) : null;
      if (augOnly) mergeEnchantTotals(totals, augOnly, slotDef);
      return;
    }
    const affixFactor = affixFactorForWeaponSlotDef(slotDef);
    const baseIt = sel.item;
    const tier = clamp(sel.ilvl != null ? sel.ilvl : charLevel, 1, GEAR_LEVEL_MAX);
    const stars = sel.stars
      ? clamp(Math.round(sel.stars), 0, maxUpgradeStarsForRarity(effectiveItemRarity(sel)))
      : 0;
    const flaw = !!(sel && sel.flawless);
    const tSel = lootCoordinateT(eff, tier, stars, flaw);
    const tRef = referenceCurveT(baseIt, tier, sel);
    const multSel = gearCurveGFromT(tSel);
    const multRef = gearCurveGFromT(tRef);
    const curveRatio = multRef > 0 ? multSel / multRef : 1;

    const staticDescOnly = shouldUseStaticAffixDescriptions(sel, tier);
    let usedTemplateFlatAffix = false;
    if (staticDescOnly) {
      for (const ax of eff.affixes || []) {
        if (ax.ref !== "TAttribute_Flat") continue;
        const attr = ax.target && ax.target.attribute;
        if (!attr || typeof ax.val !== "number") continue;
        usedTemplateFlatAffix = true;
        totals[attr] =
          (totals[attr] || 0) + presentationFlatForAffixFactor(ax.val * curveRatio, affixFactor);
      }
    }
    if (!staticDescOnly || !usedTemplateFlatAffix) {
      const sim = simulateFlatTotals(eff, tier, {
        stars,
        weaponSlot: !!slotDef.weaponSlot,
        viewerClassId,
        flawless: flaw,
      });
      for (const k of Object.keys(sim)) {
        totals[k] =
          (totals[k] || 0) + presentationFlatForAffixFactor(sim[k], affixFactor);
      }
      if (!staticDescOnly && Object.keys(sim).length === 0) {
        for (const ax of eff.affixes || []) {
          if (ax.ref !== "TAttribute_Flat") continue;
          const attr = ax.target && ax.target.attribute;
          if (!attr || typeof ax.val !== "number") continue;
          totals[attr] =
            (totals[attr] || 0) +
            presentationFlatForAffixFactor(ax.val * curveRatio, affixFactor);
        }
      }
    }

    const ench = sel.enchantId ? enchantItemById(sel.enchantId) : null;
    if (ench) mergeEnchantTotals(totals, ench, slotDef);
    const aug = sel.augmentId ? augmentItemById(sel.augmentId) : null;
    if (aug) mergeEnchantTotals(totals, aug, slotDef);
  }

  /** Character-sheet / combat gear flats — same **`getItemAffixes`** branch gate as **`affixPreviewLines`**. */
  function sumGearAffixes(charLevel, viewerClassId, selectionSnapshot) {
    const slotMap = selectionSnapshot || selection;
    const totals = {};
    for (const slot of SLOT_DEFS) {
      const sel = slotMap[slot.key];
      if (!slotSelectionIsActive(slot, sel, viewerClassId, charLevel, slotMap)) continue;
      addGearAffixesFromSlotInto(totals, charLevel, viewerClassId, slot, sel);
    }
    return totals;
  }

  function warriorTalentRank(talentSkillId) {
    if (typeof talentSkillId !== "string" || !talentSkillId) return 0;
    const r = talentAllocations[talentSkillId];
    return typeof r === "number" && Number.isFinite(r) && r > 0 ? Math.floor(r) : 0;
  }

  /** **Hold the Line** — sheet **`DamageModifier`** bonus (percentage **points**) from **`Warrior_Talent_HoldTheLine_Status`**. */
  function warriorHoldTheLineDamageModifierPctPoints() {
    const rank = warriorTalentRank(WARRIOR_TALENT_HOLD_THE_LINE_ID);
    if (rank < 1) return 0;
    const st = skillById[WARRIOR_TALENT_HOLD_THE_LINE_STATUS_ID];
    if (!st || !Array.isArray(st.affixes)) return 0;
    let sum = 0;
    for (let i = 0; i < st.affixes.length; i++) {
      const ax = st.affixes[i];
      if (!ax || ax.ref !== "TAttribute_ARatio") continue;
      if ((ax.target && ax.target.attribute) !== "DamageModifier") continue;
      if (!talentAffixRowMatchesRank(ax.conds, rank)) continue;
      if (typeof ax.val === "number" && Number.isFinite(ax.val)) sum += ax.val * 100;
    }
    return sum;
  }

  /** **Magic Conduction** — global **`dmgMult`** as **`DamageModifier`** percentage points (**7 / 15**). */
  function warriorMagicConductionDamageModifierPctPoints() {
    const rank = warriorTalentRank(WARRIOR_TALENT_MAGIC_CONDUCTION_ID);
    if (rank < 1) return 0;
    const sk = skillById[WARRIOR_TALENT_MAGIC_CONDUCTION_ID];
    if (!sk) return 0;
    const bag = mergedVarsForSkillDesc(sk, rank);
    const d = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : 0;
    return d * 100;
  }

  /** **Exposed Essence** — foe **MagicArmor** rating multiplier (**`1 − var1`**). */
  function warriorExposedEssenceMagicArmorPtsMultiplier() {
    if (plannerSelectedClassId() !== "Warrior") return 1;
    const rank = warriorTalentRank(WARRIOR_EXPOSED_ESSENCE_ID);
    if (rank < 1) return 1;
    const sk = skillById[WARRIOR_EXPOSED_ESSENCE_ID];
    if (!sk) return 1;
    const bag = mergedVarsForSkillDesc(sk, rank);
    const v = bag && typeof bag.var1 === "number" && Number.isFinite(bag.var1) ? bag.var1 : 0.05;
    const m = 1 - v;
    return m > 0 && m <= 1 ? m : 1;
  }

  function plannerEffectiveMagicArmorMitigationPts(combatCtx) {
    const ml =
      combatCtx && combatCtx.monsterLevel != null ? combatCtx.monsterLevel : MONSTER_LEVEL_DEFAULT;
    const foeId = combatCtx && combatCtx.foeUnitId != null ? combatCtx.foeUnitId : "median";
    const am = plannerMonsterArmorMagicPts(ml, foeId);
    return am.magicArmorPts * warriorExposedEssenceMagicArmorPtsMultiplier();
  }

  /**
   * **Sever** / **Master-at-arms** / **Surge of Violence** crit adjustments for this **consumer** skill’s preview.
   * @returns {object} shallow copy of **`derived`**
   */
  function applyWarriorTalentCritOverridesForSkillPreview(derived, consumerSk) {
    if (!derived || typeof derived !== "object") return derived;
    const out = { ...derived };
    const sid = consumerSk && consumerSk.id;
    if (typeof sid !== "string" || !sid) return out;

    if (skillIsWeaponSkillForPreview(consumerSk) && warriorTalentRank(WARRIOR_TALENT_SEVER_ID) > 0) {
      const skS = skillById[WARRIOR_TALENT_SEVER_ID];
      const add =
        skS && skS.vars && typeof skS.vars.damage === "number" && Number.isFinite(skS.vars.damage)
          ? skS.vars.damage * 100
          : 20;
      out.CritDamage_pct = (out.CritDamage_pct || 0) + add;
    }
    if (skillIsAttackActionForBuffs(consumerSk) && warriorTalentRank(WARRIOR_TALENT_MASTER_AT_ARMS_ID) > 0) {
      const skM = skillById[WARRIOR_TALENT_MASTER_AT_ARMS_ID];
      const add =
        skM && skM.vars && typeof skM.vars.damage === "number" && Number.isFinite(skM.vars.damage)
          ? skM.vars.damage * 100
          : 15;
      out.CritDamage_pct = (out.CritDamage_pct || 0) + add;
    }
    if (
      sid === WARRIOR_RAGE_STRIKE_ID &&
      warriorTalentRank(WARRIOR_TALENT_SURGE_OF_VIOLENCE_ID) > 0 &&
      plannerDamagePreviewSettings &&
      plannerDamagePreviewSettings.previewSurgeViolenceBoost === true
    ) {
      const skSu = skillById[WARRIOR_TALENT_SURGE_OF_VIOLENCE_ID];
      const add =
        skSu && skSu.vars && typeof skSu.vars.chance === "number" && Number.isFinite(skSu.vars.chance)
          ? skSu.vars.chance * 100
          : 25;
      out.CritChance_pct = (out.CritChance_pct || 0) + add;
    }
    return out;
  }

  /**
   * Per-hit crit sheet overrides (**Mage** **Power Circuit** physical crit, **Amplification**, **High Voltage** +链cast).
   * @param {object|null} previewHit **`computeEffectDamagePreview`** row (**`affinityRoot`**).
   */
  function applySkillPreviewCritDerived(derived, consumerSk, previewHit) {
    const base = applyWarriorTalentCritOverridesForSkillPreview(derived, consumerSk);
    let critDerived = { ...base };
    if (
      consumerSk &&
      skillIsAttackActionForBuffs(consumerSk) &&
      globalBuffHostOnSkillBar(BOW_THRILL_OF_THE_HUNTER_ID) &&
      passiveScriptGlobalMultApplies(BOW_THRILL_OF_THE_HUNTER_ID)
    ) {
      const host = skillById[BOW_THRILL_OF_THE_HUNTER_ID];
      const rank = host ? skillDamageScalingCondsRank(host) : 1;
      if (rank >= 3) {
        const bag = host ? mergedVarsForSkillDesc(host, rank) : null;
        const ch = bag && typeof bag.chance === "number" && Number.isFinite(bag.chance) ? bag.chance : 0.3;
        critDerived.CritChance_pct = (critDerived.CritChance_pct || 0) + ch * 100;
      }
    }
    if (consumerSk && consumerSk.id === STAFF_BLAZING_BEAM_ID && skillDamageScalingCondsRank(consumerSk) >= 2) {
      const outBeam = { ...critDerived };
      const mode = plannerDamagePreviewSettings.critMode || "expected";
      if (mode !== "never") outBeam.CritChance_pct = 100;
      if (plannerSelectedClassId() !== "Mage") return outBeam;
      critDerived = outBeam;
    }
    if (consumerSk && consumerSk.id === FISTS_TWIN_CLAWS_ID && skillDamageScalingCondsRank(consumerSk) >= 2) {
      const outTwin = { ...critDerived };
      const add =
        consumerSk.vars && typeof consumerSk.vars.chance === "number" && Number.isFinite(consumerSk.vars.chance)
          ? consumerSk.vars.chance * 100
          : 15;
      outTwin.CritChance_pct = (outTwin.CritChance_pct || 0) + add;
      if (plannerSelectedClassId() !== "Mage") return outTwin;
      critDerived = outTwin;
    }
    if (consumerSk && consumerSk.id === FISTS_SINK_TO_BOTTOM_ID && skillDamageScalingCondsRank(consumerSk) >= 2) {
      const outSink = { ...critDerived };
      const bag = mergedVarsForSkillDesc(consumerSk, skillDamageScalingCondsRank(consumerSk));
      const add =
        bag && typeof bag.var1 === "number" && Number.isFinite(bag.var1) ? bag.var1 * 100 : 25;
      outSink.CritDamage_pct = (outSink.CritDamage_pct || 0) + add;
      if (plannerSelectedClassId() !== "Mage") return outSink;
      critDerived = outSink;
    }
    if (plannerSelectedClassId() !== "Mage" || !consumerSk) return critDerived;
    const out = { ...critDerived };
    if (
      previewHit &&
      previewHit.affinityRoot === "Physical" &&
      mageTalentRank(MAGE_TALENT_POWER_CIRCUIT_ID) > 0
    ) {
      const st = skillById[MAGE_TALENT_POWER_CIRCUIT_STATUS_ID];
      const r = mageTalentRank(MAGE_TALENT_POWER_CIRCUIT_ID);
      const bag = st ? mergedVarsForSkillDesc(st, r) : {};
      const ch = bag && typeof bag.chance === "number" && Number.isFinite(bag.chance) ? bag.chance : 0.07;
      out.CritChance_pct = (out.CritChance_pct || 0) + ch * 100;
    }
    if (skillRowIsMageBaseAttackType(consumerSk) && mageTalentRank(MAGE_TALENT_AMPLIFICATION_ID) > 0) {
      const skA = skillById[MAGE_TALENT_AMPLIFICATION_ID];
      const r = mageTalentRank(MAGE_TALENT_AMPLIFICATION_ID);
      const bag = skA ? mergedVarsForSkillDesc(skA, r) : {};
      const d = bag && typeof bag.damage === "number" && Number.isFinite(bag.damage) ? bag.damage : 0.15;
      out.CritDamage_pct = (out.CritDamage_pct || 0) + d * 100;
    }
    if (
      mageChaincastAssumptionActive(consumerSk) &&
      skillRowIsMageComboAttackType(consumerSk) &&
      mageTalentRank(MAGE_TALENT_HIGH_VOLTAGE_ID) > 0
    ) {
      const mode = plannerDamagePreviewSettings.critMode || "expected";
      if (mode !== "never") out.CritChance_pct = 100;
    }
    return out;
  }

  function warriorPhysicalCritProbabilityForPreview(derived) {
    if (!derived || typeof derived !== "object") return 0;
    const mode = plannerDamagePreviewSettings.critMode || "expected";
    const pSheet = clamp((derived.CritChance_pct || 0) / 100, 0, 1);
    if (mode === "never") return 0;
    if (mode === "always") return 1;
    return pSheet;
  }

  function warriorExsanguinationDoTCritChance() {
    const rank = warriorTalentRank(WARRIOR_TALENT_EXSANGUINATION_ID);
    if (rank < 1) return 0;
    const sk = skillById[WARRIOR_TALENT_EXSANGUINATION_ID];
    if (!sk) return 0;
    const bag = mergedVarsForSkillDesc(sk, rank);
    const c = bag && typeof bag.chance === "number" && Number.isFinite(bag.chance) ? bag.chance : 0.1;
    return clamp(c, 0, 1);
  }

  /** **Exsanguination**: DoT crit rolled **after** **`hemRounded`** is fixed (sheet crit dmg applies when it crits). */
  function warriorHemorrhageDoTExpectedAfterExsanguination(hemRounded, derived) {
    if (!(hemRounded > 0) || !derived || typeof derived !== "object") return 0;
    const pDot = warriorExsanguinationDoTCritChance();
    if (pDot <= 0) return hemRounded;
    const onCrit = plannerCritDamageStatMultiplier(derived);
    return (1 - pDot) * hemRounded + pDot * hlMathRound(hemRounded * onCrit);
  }

  function skillForEachMergedDamagePreviewHit(sk, combatCtx, fn) {
    if (!sk || !fn || !combatCtx || !combatCtx.sheetTotals || !combatCtx.derived) return;
    const sheetTotals = combatCtx.sheetTotals;
    const derived = combatCtx.derived;
    const previewSources = skillAggregatesReferencedDamageRows(sk)
      ? [sk].concat(referencedSkillsForMergedDamage(sk))
      : [sk];
    for (let ci = 0; ci < previewSources.length; ci++) {
      const src = previewSources[ci];
      if (!src || !src.steps) continue;
      const condRank = skillDamageScalingCondsRank(src);
      const holdTier = skillHoldMergedDamageTierTarget(src);
      for (let si = 0; si < src.steps.length; si++) {
        const step = src.steps[si];
        const effs = step.effects || [];
        for (let ei = 0; ei < effs.length; ei++) {
          const e = effs[ei];
          if (!skillHostStepEffectMatchesMastery(sk, step, e)) continue;
          if (!skillHoldMergedDamageEffectIncluded(step, e, holdTier)) continue;
          const p = computeEffectDamagePreview(e, sheetTotals, derived, combatCtx, condRank);
          if (p) {
            p.scriptHostSkill = src;
            p.previewMergeStep = step;
            fn(p, src, step, e);
          }
        }
      }
    }
  }

  /**
   * Hemorrhage + Infused Wound bleed preview rows, and Cracking Blood expected proc damage (35% proc chance).
   */
  function appendWarriorBleedRelatedPreviewRows(sk, combatCtx, rows) {
    if (!sk || !rows || !combatCtx || !combatCtx.sheetTotals || !combatCtx.derived) return;
    const hemRank = warriorTalentRank(WARRIOR_HEMORRHAGE_TALENT_ID);
    const infusedRank = warriorTalentRank(WARRIOR_TALENT_INFUSED_WOUND_ID);
    const crackRank = warriorTalentRank(WARRIOR_TALENT_CRACKING_BLOOD_ID);
    if (hemRank < 1 && infusedRank < 1 && crackRank < 1) return;

    const derBase = combatCtx.derived;
    const derSkill = applyWarriorTalentCritOverridesForSkillPreview(derBase, sk);

    let sumPhysHem = 0;
    let sumMagicInfused = 0;

    if (hemRank >= 1) {
      const hemSk = skillById[WARRIOR_HEMORRHAGE_TALENT_ID];
      const hemRatio =
        hemSk && hemSk.vars && typeof hemSk.vars.damage === "number" && Number.isFinite(hemSk.vars.damage)
          ? hemSk.vars.damage
          : 0.4;

      skillForEachMergedDamagePreviewHit(sk, combatCtx, (p) => {
        if (p.affinityRoot !== "Physical") return;
        const preCrit = plannerExpectedPreCritExactFromPreview(p, combatCtx, sk, sk, true);
        if (!Number.isFinite(preCrit) || !(preCrit > 0)) return;
        const pCrit = warriorPhysicalCritProbabilityForPreview(derSkill);
        if (pCrit <= 0) return;
        const onCrit = plannerCritDamageStatMultiplier(derSkill);
        const critDamageRounded = hlMathRound(preCrit * onCrit);
        const hemRounded = hlMathRound(hemRatio * critDamageRounded);
        const hemEv = warriorHemorrhageDoTExpectedAfterExsanguination(hemRounded, derSkill);
        sumPhysHem += pCrit * hemEv;

        if (infusedRank >= 1) {
          const iwSk = skillById[WARRIOR_TALENT_INFUSED_WOUND_ID];
          const iwRatio =
            iwSk && iwSk.vars && typeof iwSk.vars.damage === "number" && Number.isFinite(iwSk.vars.damage)
              ? iwSk.vars.damage
              : 0.35;
          const magicRaw = hlMathRound(iwRatio * hemRounded);
          const cl = combatCtx.charLevel != null ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
          const der = combatCtx.derived;
          const pen = der.SpellPenetration_pct || 0;
          const magPts = plannerEffectiveMagicArmorMitigationPts(combatCtx);
          const armorM = 1 - plannerAffinityMitigatedFraction(magPts, pen, cl);
          sumMagicInfused += pCrit * magicRaw * armorM;
        }
      });

      if (sumPhysHem > 0) {
        rows.push({
          valPart: formatDmgAmount(Math.max(0, hlMathRound(sumPhysHem))),
          kindLabel: "Physical damage (Hemorrhage on crit)",
          detail: `${formatSkillPercentFromRatio(hemRatio)} of crit hit, no stat scaling · Exsanguination DoT crit`,
          finalExpectedSum: sumPhysHem,
          damagePreviewHits: [],
        });
      }
      if (sumMagicInfused > 0) {
        rows.push({
          valPart: formatDmgAmount(Math.max(0, hlMathRound(sumMagicInfused))),
          kindLabel: "Magic damage (Infused Wound add-on)",
          detail: `${formatSkillPercentFromRatio(0.35)} of Hemorrhage tick (sheet) · Magic armor (Exposed Essence)`,
          finalExpectedSum: sumMagicInfused,
          damagePreviewHits: [],
        });
      }
    }

    if (crackRank >= 1 && hemRank >= 1) {
      const cbSk = skillById[WARRIOR_TALENT_CRACKING_BLOOD_ID];
      let cbEffect = null;
      if (cbSk && Array.isArray(cbSk.steps)) {
        for (let si = 0; si < cbSk.steps.length; si++) {
          const st = cbSk.steps[si];
          const effs = st && st.effects ? st.effects : [];
          for (let ei = 0; ei < effs.length; ei++) {
            if (effectScalingIsCombatDamagePreview(effs[ei])) {
              cbEffect = effs[ei];
              break;
            }
          }
          if (cbEffect) break;
        }
      }
      if (cbEffect) {
        const pCb = computeEffectDamagePreview(cbEffect, combatCtx.sheetTotals, derBase, combatCtx, 1);
        if (pCb) {
          pCb.scriptHostSkill = cbSk;
          const preCritCb = plannerExpectedPreCritExactFromPreview(pCb, combatCtx, cbSk, cbSk, true);
          const evCb = skillRowHasWeaponDamageJitter(cbSk)
            ? plannerExpectedWeaponJitterEvAfterCritRound(preCritCb, derBase)
            : plannerExpectedDamageEvAfterCritRound(preCritCb, derBase);
          const procChance =
            cbSk.vars && typeof cbSk.vars.chance === "number" && Number.isFinite(cbSk.vars.chance)
              ? cbSk.vars.chance
              : 0.35;
          const crackingEv = procChance * evCb;
          if (crackingEv > 0) {
            rows.push({
              valPart: formatDmgAmount(Math.max(0, hlMathRound(crackingEv))),
              kindLabel: "Magic damage (Cracking Blood proc)",
              detail: `${formatSkillPercentFromRatio(procChance)} chance on Hemorrhage tick`,
              finalExpectedSum: crackingEv,
              damagePreviewHits: [],
            });
          }
        }
      }
    }
  }

  /** Extra line for **Rage Shield** talent tooltip — shield size from **`MaxHealth ×` ratio** on the status row. */
  function warriorRageShieldTalentTooltipHtml(combatCtx) {
    const amt = warriorRageShieldAbsorbPreviewAmount(combatCtx);
    if (amt == null || !Number.isFinite(amt)) return "";
    return `<div class="gp-talent-tip-rage-shield"><span class="gp-muted">Shield absorb (preview): </span><strong>${escapeHtml(
      formatDmgAmount(Math.max(0, amt))
    )}</strong></div>`;
  }

  /** Shield absorb preview for **Rage Shield** (**`MaxHealth ×` ratio**). */
  function warriorRageShieldAbsorbPreviewAmount(combatCtx) {
    if (!combatCtx || !combatCtx.sheetTotals) return null;
    const st = skillById[WARRIOR_TALENT_RAGE_SHIELD_STATUS_ID];
    if (!st || !Array.isArray(st.steps)) return null;
    let ratio = 0.05;
    for (let si = 0; si < st.steps.length; si++) {
      const effs = st.steps[si] && st.steps[si].effects ? st.steps[si].effects : [];
      for (let ei = 0; ei < effs.length; ei++) {
        const e = effs[ei];
        if (!e || e.effect !== 2) continue;
        const sc = e.scaling;
        if (!Array.isArray(sc)) continue;
        for (let ri = 0; ri < sc.length; ri++) {
          const row = sc[ri];
          if (row && row.atb === "MaxHealth" && typeof row.ratio === "number") {
            ratio = row.ratio;
            break;
          }
        }
      }
    }
    const mh = combatCtx.sheetTotals.MaxHealth;
    if (typeof mh !== "number" || !Number.isFinite(mh)) return null;
    return Math.max(0, hlMathRound(mh * ratio));
  }

  function deriveCombatPreview(baseStats, gearFlat, charLevel) {
    const L = ratingDivisorL(charLevel);
    const dex = (baseStats.Dexterity || 0) + (gearFlat.Dexterity || 0);
    const intl = (baseStats.Intellect || 0) + (gearFlat.Intellect || 0);
    const str = (baseStats.Strength || 0) + (gearFlat.Strength || 0);
    const fai = (baseStats.Faith || 0) + (gearFlat.Faith || 0);

    const ccr =
      (baseStats.CritChanceRating || 0) + (gearFlat.CritChanceRating || 0);
    const apr =
      (baseStats.ArmorPenetrationRating || 0) +
      (gearFlat.ArmorPenetrationRating || 0);
    const spr =
      (baseStats.SpellPenetrationRating || 0) +
      (gearFlat.SpellPenetrationRating || 0);
    const fr =
      (baseStats.FervorRating || 0) + (gearFlat.FervorRating || 0);

    const baseCrit =
      (baseStats.CritChance || 0) + (gearFlat.CritChance || 0);
    const critFromPrim = 0.014 * dex + 0.014 * intl;
    const critFromRating = (ccr / L) * RATING_TARGETS.CritChanceRating;

    const baseCritDmg =
      (baseStats.CritDamage || 0) + (gearFlat.CritDamage || 0);
    const critDmgFromPrim = 0.01 * str + 0.01 * fai;

    const armorPenPct =
      (baseStats.ArmorPenetration || 0) +
      (gearFlat.ArmorPenetration || 0) +
      (apr / L) * RATING_TARGETS.ArmorPenetrationRating;
    const spellPenPct =
      (baseStats.SpellPenetration || 0) +
      (gearFlat.SpellPenetration || 0) +
      (spr / L) * RATING_TARGETS.SpellPenetrationRating;
    const fervorPct =
      (baseStats.Fervor || 0) +
      (gearFlat.Fervor || 0) +
      (fr / L) * RATING_TARGETS.FervorRating;

    const damageModifierPct =
      (baseStats.DamageModifier || 0) +
      (gearFlat.DamageModifier || 0) +
      warriorHoldTheLineDamageModifierPctPoints() +
      warriorMagicConductionDamageModifierPctPoints();

    const dodgePct =
      (baseStats.DodgeChance || 0) +
      (gearFlat.DodgeChance || 0) +
      0.009 * dex;

    return {
      L,
      CritChance_pct: baseCrit + critFromPrim + critFromRating,
      CritDamage_pct: baseCritDmg + critDmgFromPrim,
      ArmorPenetration_pct: armorPenPct,
      SpellPenetration_pct: spellPenPct,
      Fervor_pct: fervorPct,
      DamageModifier_pct: damageModifierPct,
      DodgeChance_pct: dodgePct,
      BlockMitigation_pct:
        BLOCK_MITIGATION_BASE_PCT +
        (baseStats.BlockMitigation || 0) +
        (gearFlat.BlockMitigation || 0),
      MagicMastery_pct:
        (baseStats.MagicMastery || 0) + (gearFlat.MagicMastery || 0),
      PhysicalMastery_pct:
        (baseStats.PhysicalMastery || 0) +
        (gearFlat.PhysicalMastery || 0),
      CooldownRecovery_pct:
        (baseStats.CooldownReduction || 0) + (gearFlat.CooldownReduction || 0),
    };
  }

  /** CDB **`attribute.flags`** % display — matches affix / sheet presentation for tooltip values. */
  function summarySheetAttrIsPercentPoints(attrId) {
    const a = attributeById && attributeById[attrId];
    return !!(a && (a.flags & ATTR_FLAG_PERCENT));
  }

  function summaryFormatAttrValueForTip(attrId, v, fmtTipPct, fmtTipInt, fmtTipFixed) {
    if (typeof v !== "number" || Number.isNaN(v)) return "—";
    if (/Rating$/i.test(String(attrId || ""))) return fmtTipInt(Math.round(v));
    if (summarySheetAttrIsPercentPoints(attrId)) return fmtTipPct(v);
    if (PRIMARY_ATTRIBUTE_IDS.includes(attrId)) return fmtTipInt(Math.round(v));
    const abs = Math.abs(v);
    if (abs >= 80 || Number.isInteger(v)) return fmtTipInt(Math.round(v));
    return fmtTipFixed(v, 2);
  }

  function collectSummaryClassSheetLines(classId, charLevel, attrId) {
    const out = [];
    const rows = unitSheet && unitSheet.lines;
    if (!rows) return out;
    const baseHero = rows.find((r) => r.id === "BaseHero");
    const cls = rows.find((r) => r.id === classId);
    if (baseHero) {
      for (const e of baseHero.stats || []) {
        if (e.attribute !== attrId || e.value == null) continue;
        out.push({ label: "Base (all classes)", sub: "BaseHero unit sheet", value: e.value });
      }
    }
    if (cls) {
      for (const e of cls.stats || []) {
        if (e.attribute !== attrId) continue;
        const ls = e.levelScaling;
        if (Array.isArray(ls) && ls.length >= 2 && ls[0].val != null && ls[1].val != null) {
          let v = interpolatePrimary(ls[0].val, ls[1].val, charLevel);
          if (PRIMARY_ATTRIBUTE_IDS.includes(attrId)) v = Math.round(v);
          out.push({
            label: `${classId} class`,
            sub: `level ${charLevel} (curve)`,
            value: v,
          });
        } else if (e.value != null) {
          out.push({ label: `${classId} class`, sub: "flat on unit row", value: e.value });
        }
      }
    }
    return out;
  }

  function collectSummaryGearSlotLinesForAttr(charLevel, classId, selectionSnapshot, attrId) {
    const out = [];
    const slotMap = selectionSnapshot || selection;
    for (let si = 0; si < SLOT_DEFS.length; si++) {
      const slot = SLOT_DEFS[si];
      const sel = slotMap[slot.key];
      if (!sel || !sel.item) continue;
      if (!slotSelectionIsActive(slot, sel, classId, charLevel, slotMap)) continue;
      const part = {};
      addGearAffixesFromSlotInto(part, charLevel, classId, slot, sel);
      const v = part[attrId];
      if (typeof v !== "number" || !Number.isFinite(v) || Math.abs(v) < 1e-12) continue;
      out.push({
        label: slot.label,
        sub: "affixes · stars · enchant · augment where applicable",
        value: v,
      });
    }
    return out;
  }

  function collectSummaryTalentFlatLinesForAttr(classId, attrId) {
    const out = [];
    const valid = collectTalentSkillIdsForClass(classId);
    for (const sid of Object.keys(talentAllocations)) {
      const allocatedRank = talentAllocations[sid];
      if (!valid.has(sid) || !allocatedRank || allocatedRank < 1) continue;
      const sk = skillById[sid];
      if (!sk || !Array.isArray(sk.affixes)) continue;
      let sum = 0;
      for (let ai = 0; ai < sk.affixes.length; ai++) {
        const ax = sk.affixes[ai];
        if (!ax || ax.ref !== "TAttribute_Flat") continue;
        if (ax.mod && ax.mod.dynVal) continue;
        if (!talentAffixRowMatchesRank(ax.conds, allocatedRank)) continue;
        const a = ax.target && ax.target.attribute;
        if (a !== attrId || typeof ax.val !== "number") continue;
        sum += presentationFlatForAffixFactor(ax.val, 1);
      }
      if (Math.abs(sum) < 1e-12) continue;
      out.push({
        label: `Talent: ${skillDisplayName(sk)}`,
        sub: `${allocatedRank} pt · passive flat`,
        value: sum,
      });
    }
    return out;
  }

  function collectSummaryStatusBuffFlatLinesForAttr(classId, selectionSnapshot, attrId, charLevel) {
    const out = [];
    const hostIds = collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel);
    for (const hid of hostIds) {
      if (!passiveScriptGlobalMultApplies(hid)) continue;
      const host = skillById[hid];
      if (!host) continue;
      const hostMid = selectedClassSkillMasteryId(hid, host);
      const rank = skillDamageScalingCondsRank(host, selectionSnapshot);
      const refs = new Set();
      collectStatusRefIdsFromHostSkill(host, refs);
      if (skillIsPreviewableStackingStatusBuff(host)) refs.add(hid);
      for (const stId of refs) {
        if (!statusBuffAppliesForHostMastery(host, stId, hostMid)) continue;
        const statusSk = skillById[stId];
        if (!statusSk) continue;
        const stacks = statusPreviewSheetAffixStacks(statusSk);
        if (stacks <= 0) continue;
        const per = statusPreviewFlatPerStackAtGrantorRank(statusSk, attrId, rank, hostMid);
        if (!per) continue;
        const total = per * stacks;
        if (Math.abs(total) < 1e-12) continue;
        out.push({
          label: `Buff: ${skillDisplayName(statusSk)}`,
          sub: `preview · via ${skillDisplayName(host)} · ×${stacks} stack(s)`,
          value: total,
        });
      }
    }
    return out;
  }

  /** Each entry: **`value`** = additive % points (**`ratio × 100`**). */
  function collectSummaryStatusARatioLinesForAttr(classId, selectionSnapshot, attrId, charLevel) {
    const out = [];
    const hostIds = collectCombatPanelSkillHostIds(classId, selectionSnapshot, charLevel);
    for (const hid of hostIds) {
      if (!passiveScriptGlobalMultApplies(hid)) continue;
      const host = skillById[hid];
      if (!host) continue;
      const hostMid = selectedClassSkillMasteryId(hid, host);
      const rank = skillDamageScalingCondsRank(host, selectionSnapshot);
      const refs = new Set();
      collectStatusRefIdsFromHostSkill(host, refs);
      if (skillIsPreviewableStackingStatusBuff(host)) refs.add(hid);
      for (const stId of refs) {
        if (!statusBuffAppliesForHostMastery(host, stId, hostMid)) continue;
        if (STATUS_PREVIEW_SKIP_HOST_SHEET_ARATIO_IDS.has(stId)) continue;
        const st = skillById[stId];
        if (!st || !Array.isArray(st.affixes)) continue;
        const stacks = statusPreviewSheetAffixStacks(st);
        if (stacks <= 0) continue;
        if (
          stId === "Warrior_BattleShout_Buff" &&
          host.id === "Warrior_BattleShout" &&
          hostMid !== BATTLE_SHOUT_M3_MASTERY_ID
        ) {
          continue;
        }
        for (let ai = 0; ai < st.affixes.length; ai++) {
          const ax = st.affixes[ai];
          if (!ax || ax.ref !== "TAttribute_ARatio") continue;
          if (ax.mod && ax.mod.dynVal && !statusPreviewUsesDynamicBaseAffix(st, ax)) continue;
          const at = ax.target && ax.target.attribute;
          if (at !== attrId || typeof ax.val !== "number") continue;
          if (!talentAffixRowMatchesRank(ax.conds, rank)) continue;
          if (!skillAffixRowMatchesMasteryGate(ax, hostMid)) continue;
          const pctPts = statusPreviewAffixVal(st, ax) * stacks * 100;
          if (Math.abs(pctPts) < 1e-12) continue;
          out.push({
            label: `Buff %: ${skillDisplayName(st)}`,
            sub: `TAttribute_ARatio · via ${skillDisplayName(host)} · ×${stacks} stack(s)`,
            value: pctPts,
            valueKind: "pct",
          });
        }
      }
    }
    return out;
  }

  function collectSummaryConsumableLinesForAttr(attrId) {
    const out = [];
    for (let ki = 0; ki < CONSUMABLE_BUFF_KIND_DEFS.length; ki++) {
      const def = CONSUMABLE_BUFF_KIND_DEFS[ki];
      const id = activeConsumableByKind[def.kind];
      if (!id) continue;
      const it = consumableBuffById[id];
      if (!it) continue;
      const row = itemStaticFlatAffixTotals(it);
      const v = row[attrId];
      if (typeof v !== "number" || !Number.isFinite(v) || Math.abs(v) < 1e-12) continue;
      out.push({ label: `Consumable: ${itemDisplayName(it)}`, sub: def.title, value: v });
    }
    return out;
  }

  function collectSummaryDisciplinePhysicalLine(classId, totalMagicMasterySheetPct) {
    const dyn = sumTalentDynamicMasteryFlats(classId, totalMagicMasterySheetPct);
    const v = dyn.PhysicalMastery;
    if (typeof v !== "number" || !Number.isFinite(v) || Math.abs(v) < 1e-12) return null;
    const sk = skillById["Mage_Talent_Discipline"];
    const ratio =
      sk && sk.vars && typeof sk.vars.var2 === "number" && Number.isFinite(sk.vars.var2)
        ? sk.vars.var2
        : 0;
    return {
      label: "Talent: Discipline",
      sub: `${formatMultiplierLabel(ratio)} × ${formatMultiplierLabel(totalMagicMasterySheetPct)} MagicMastery % (for var2)`,
      value: v,
    };
  }

  function collectSummaryMysticM2Line(classId, attrId) {
    const m = mysticEmpowermentM2MasteryFlatBonus(classId);
    const v = m[attrId];
    if (typeof v !== "number" || !Number.isFinite(v) || Math.abs(v) < 1e-12) return null;
    const choice = masteryBuffChoiceForSkill(MYSTIC_EMPOWERMENT_HOST_ID);
    return {
      label: "Mystic Empowerment (M2 rune)",
      sub: mysticEmpowermentM2BuffChoiceLabel(choice),
      value: v,
    };
  }

  function collectSummaryMagicMasteryForDisciplineBase(classId, charLevel, selectionSnapshot) {
    return sheetMagicMasteryPctBeforeDiscipline(classId, charLevel, selectionSnapshot);
  }

  /**
   * Fixed tooltip HTML for the sidebar **Summary** panel — additive rows mirror {@link deriveCombatPreview} where applicable.
   * @param {string} statKey `primary:Vitality`, `armor`, `critChance`, …
   * @param {object} ctx from {@link renderSummary}
   */
  function plannerSummaryStatTooltipHtml(statKey, ctx) {
    if (!ctx || typeof statKey !== "string" || !statKey) return "";
    const baseStats = ctx.baseStats || {};
    const gearFlat = ctx.gearFlat || {};
    const derived = ctx.derived || {};
    const clRaw = ctx.charLevel;
    const charLevel =
      typeof clRaw === "number" && Number.isFinite(clRaw)
        ? clamp(Math.round(clRaw), 1, CHAR_LEVEL_MAX)
        : CHAR_LEVEL_DEFAULT;
    const L = ratingDivisorL(charLevel);

    function fmtTipPct(n) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      const abs = Math.abs(n);
      const d = abs >= 100 ? 1 : abs >= 10 ? 1 : 2;
      return `${n.toFixed(d).replace(/\.?0+$/, "")}%`;
    }
    function fmtTipSheetPenPct(n) {
      return formatPlannerSheetPenetrationPct(n);
    }
    function fmtTipInt(n) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      return String(Math.round(n));
    }

    function fmtTipFixed(n, dec) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      const d = dec != null ? dec : 2;
      return n.toFixed(d).replace(/\.?0+$/, "");
    }

    function tipHead(title, meta) {
      return (
        `<div class="gp-tooltip__header gp-tooltip__header--summary-stat">` +
        `<div class="gp-tooltip__headtext">` +
        `<div class="gp-tooltip__name">${escapeHtml(title)}</div>` +
        `<div class="gp-tooltip__meta">${escapeHtml(meta)}</div>` +
        `</div></div>`
      );
    }

    function summaryTipRowHtml(labelInnerHtml, valueInnerHtml, valueClass) {
      const vRaw = valueInnerHtml != null ? String(valueInnerHtml).trim() : "";
      const vCls = valueClass === "mult" ? "gp-dmg-tip-row__m" : "gp-dmg-tip-row__v";
      const v =
        vRaw !== ""
          ? `<span class="${vCls}">${valueInnerHtml}</span>`
          : `<span class="gp-dmg-tip-row__v gp-dmg-tip-row__empty"></span>`;
      return (
        `<div class="gp-dmg-tip-row gp-summary-tip-row" role="row">` +
        `<span class="gp-dmg-tip-row__k">${labelInnerHtml}</span>` +
        v +
        `</div>`
      );
    }

    function tipRow(label, valueHtml, multInner) {
      const multRaw = multInner != null ? String(multInner).trim() : "";
      if ((!valueHtml || String(valueHtml).trim() === "") && multRaw && multRaw !== "—") {
        return summaryTipRowHtml(escapeHtml(label), multInner, "mult");
      }
      return summaryTipRowHtml(escapeHtml(label), valueHtml, "value");
    }

    function totalRow(labelInnerHtml, valueHtml) {
      return summaryTipRowHtml(labelInnerHtml, valueHtml, "value");
    }

    function finish(title, meta, body) {
      if (!body) return "";
      return tipHead(title, meta) + `<div class="gp-tooltip-skill-body">${body}</div>`;
    }

    const classIdTip = ctx.classId || plannerSelectedClassId();
    const snapTip = ctx.selectionSnapshot || selection;

    function appendNamedSourceRows(html, rows, attrId) {
      let out = html;
      for (let i = 0; i < rows.length; i++) {
        const r = rows[i];
        const vs =
          r.valueKind === "pct"
            ? fmtTipPct(r.value)
            : summaryFormatAttrValueForTip(attrId, r.value, fmtTipPct, fmtTipInt, fmtTipFixed);
        out += tipRow(r.label, escapeHtml(vs), "—");
      }
      return out;
    }

    function rowsForAttr(attrId) {
      return []
        .concat(collectSummaryClassSheetLines(classIdTip, charLevel, attrId))
        .concat(collectSummaryGearSlotLinesForAttr(charLevel, classIdTip, snapTip, attrId))
        .concat(collectSummaryTalentFlatLinesForAttr(classIdTip, attrId))
        .concat(collectSummaryStatusBuffFlatLinesForAttr(classIdTip, snapTip, attrId, charLevel))
        .concat(collectSummaryConsumableLinesForAttr(attrId));
    }

    if (statKey.startsWith("primary:")) {
      const k = statKey.slice("primary:".length);
      if (!PRIMARY_ATTRIBUTE_IDS.includes(k)) return "";
      const b = baseStats[k] || 0;
      const g = gearFlat[k] || 0;
      const t = b + g;
      let body = appendNamedSourceRows("", rowsForAttr(k), k);
      const ar = collectSummaryStatusARatioLinesForAttr(classIdTip, snapTip, k, charLevel);
      if (ar.length) body = appendNamedSourceRows(body, ar, k);
      const stR = sumPreviewStatusBuffARatios(classIdTip, snapTip, charLevel);
      const rr = stR[k];
      if (typeof rr === "number" && Number.isFinite(rr) && Math.abs(rr) > 1e-12) {
        body += tipRow(
          "Applied preview multiplier",
          "",
          `×${escapeHtml(formatMultiplierLabel(1 + rr))}`
        );
      }
      body += totalRow(`<strong>Summary total</strong>`, escapeHtml(fmtTipInt(t)));
      return finish(k, "Primary attribute · sources", body);
    }

    if (statKey === "armor") {
      const armorBase = ctx.armorBase;
      const armorTotal = ctx.armorTotal;
      const armorMult = ctx.armorMult;
      if (
        typeof armorBase !== "number" ||
        typeof armorTotal !== "number" ||
        typeof armorMult !== "number" ||
        Number.isNaN(armorBase + armorTotal + armorMult)
      ) {
        return "";
      }
      let body = appendNamedSourceRows("", rowsForAttr("Armor"), "Armor");
      const ar = collectSummaryStatusARatioLinesForAttr(classIdTip, snapTip, "Armor");
      if (ar.length) body = appendNamedSourceRows(body, ar, "Armor");
      if (Math.abs(armorMult - 1) > 1e-9) {
        body += tipRow(
          "Armor preview multiplier",
          "",
          `×${escapeHtml(formatMultiplierLabel(armorMult))}`
        );
      }
      body += totalRow(`<strong>Effective armor</strong>`, escapeHtml(fmtTipInt(armorTotal)));
      return finish("Armor", "Defense · sources", body);
    }

    if (statKey === "physMit") {
      const armorTotal = ctx.armorTotal;
      const ml = ctx.monsterLevel;
      const phys = ctx.physMitPct;
      if (
        typeof armorTotal !== "number" ||
        Number.isNaN(armorTotal) ||
        typeof ml !== "number" ||
        typeof phys !== "number" ||
        Number.isNaN(phys)
      ) {
        return "";
      }
      let body =
        `<p>% of physical damage absorbed from armor, using the same mitigation curve as skill damage previews (0% penetration).</p>` +
        tipRow("Effective armor", escapeHtml(fmtTipInt(armorTotal)), "—") +
        tipRow("Foe attacker level", escapeHtml(String(ml)), "—") +
        totalRow(`<strong>Mitigation</strong>`, escapeHtml(fmtTipPct(phys)));
      return finish("Physical damage mitigation", "Exposure (summary)", body);
    }

    if (statKey === "maxHealth") {
      const vit = ctx.vitalityTotal;
      if (typeof vit !== "number" || Number.isNaN(vit)) return "";
      let body =
        `<p><strong>Vitality</strong> — each point adds 3 to this summary line:</p>` +
        appendNamedSourceRows("", rowsForAttr("Vitality"), "Vitality");
      const vr = collectSummaryStatusARatioLinesForAttr(classIdTip, snapTip, "Vitality");
      if (vr.length) body = appendNamedSourceRows(body, vr, "Vitality");
      body += tipRow("Vitality × 3", escapeHtml(fmtTipInt(vit * 3)), "—");
      body +=
        `<p><strong>Flat MaxHealth</strong> on sheet (added after ×3):</p>` +
        appendNamedSourceRows("", rowsForAttr("MaxHealth"), "MaxHealth");
      const tot = vit * 3 + (gearFlat.MaxHealth || 0);
      body += totalRow(`<strong>Approx. max health</strong>`, escapeHtml(fmtTipInt(tot)));
      return finish("Maximum health", "Vitality · MaxHealth", body);
    }

    if (statKey === "healthRegen") {
      const fai = ctx.faithTotal;
      if (typeof fai !== "number" || Number.isNaN(fai)) return "";
      const fromFaith = fai * 0.04;
      let body =
        `<p><strong>Faith</strong> — 0.04 × total Faith for this approximation:</p>` +
        appendNamedSourceRows("", rowsForAttr("Faith"), "Faith");
      const fr = collectSummaryStatusARatioLinesForAttr(classIdTip, snapTip, "Faith");
      if (fr.length) body = appendNamedSourceRows(body, fr, "Faith");
      body += tipRow("Faith × 0.04", escapeHtml(fmtTipFixed(fromFaith, 2)), "—");
      body +=
        `<p><strong>Flat HealthRegen</strong>:</p>` +
        appendNamedSourceRows("", rowsForAttr("HealthRegen"), "HealthRegen");
      const gr = gearFlat.HealthRegen || 0;
      const sum = fromFaith + gr;
      body += totalRow(`<strong>Regen (approx.)</strong>`, escapeHtml(fmtTipFixed(sum, 2)));
      return finish("Health regen", "Faith · HealthRegen", body);
    }

    const dex = (baseStats.Dexterity || 0) + (gearFlat.Dexterity || 0);
    const intl = (baseStats.Intellect || 0) + (gearFlat.Intellect || 0);
    const str = (baseStats.Strength || 0) + (gearFlat.Strength || 0);
    const faiT = (baseStats.Faith || 0) + (gearFlat.Faith || 0);
    const ccr = (baseStats.CritChanceRating || 0) + (gearFlat.CritChanceRating || 0);
    const apr = (baseStats.ArmorPenetrationRating || 0) + (gearFlat.ArmorPenetrationRating || 0);
    const spr = (baseStats.SpellPenetrationRating || 0) + (gearFlat.SpellPenetrationRating || 0);
    const fr = (baseStats.FervorRating || 0) + (gearFlat.FervorRating || 0);

    if (statKey === "critChance") {
      const fPrim = 0.014 * dex + 0.014 * intl;
      const fRat = (ccr / L) * RATING_TARGETS.CritChanceRating;
      let body =
        `<p><strong>CritChance</strong> (% points on sheet):</p>` +
        appendNamedSourceRows("", rowsForAttr("CritChance"), "CritChance");
      body +=
        `<p><strong>CritChanceRating</strong> (converted with divisor L):</p>` +
        appendNamedSourceRows("", rowsForAttr("CritChanceRating"), "CritChanceRating");
      body += tipRow(
        "Dexterity · Intellect",
        escapeHtml(fmtTipPct(fPrim)),
        "—"
      );
      body += tipRow(
        "Crit chance rating → %",
        escapeHtml(fmtTipPct(fRat)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.CritChance_pct)));
      return finish("Crit chance", "Sources + formula", body);
    }

    if (statKey === "critBonus") {
      const fPrim = 0.01 * str + 0.01 * faiT;
      let body =
        `<p><strong>CritDamage</strong> (% points on sheet):</p>` +
        appendNamedSourceRows("", rowsForAttr("CritDamage"), "CritDamage");
      body += tipRow(
        "Strength · Faith",
        escapeHtml(fmtTipPct(fPrim)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.CritDamage_pct)));
      return finish("Crit bonus", "Sources + formula", body);
    }

    if (statKey === "armorPen") {
      const fRat = (apr / L) * RATING_TARGETS.ArmorPenetrationRating;
      let body =
        `<p><strong>ArmorPenetration</strong> (% points):</p>` +
        appendNamedSourceRows("", rowsForAttr("ArmorPenetration"), "ArmorPenetration");
      body +=
        `<p><strong>ArmorPenetrationRating</strong>:</p>` +
        appendNamedSourceRows("", rowsForAttr("ArmorPenetrationRating"), "ArmorPenetrationRating");
      body += tipRow(
        "Rating → %",
        escapeHtml(fmtTipPct(fRat)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipSheetPenPct(derived.ArmorPenetration_pct)));
      return finish("Armor penetration", "Sources + formula", body);
    }

    if (statKey === "spellPen") {
      const fRat = (spr / L) * RATING_TARGETS.SpellPenetrationRating;
      let body =
        `<p><strong>SpellPenetration</strong> (% points):</p>` +
        appendNamedSourceRows("", rowsForAttr("SpellPenetration"), "SpellPenetration");
      body +=
        `<p><strong>SpellPenetrationRating</strong>:</p>` +
        appendNamedSourceRows("", rowsForAttr("SpellPenetrationRating"), "SpellPenetrationRating");
      body += tipRow(
        "Rating → %",
        escapeHtml(fmtTipPct(fRat)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipSheetPenPct(derived.SpellPenetration_pct)));
      return finish("Magic penetration", "Sources + formula", body);
    }

    if (statKey === "fervor") {
      const fRat = (fr / L) * RATING_TARGETS.FervorRating;
      let body =
        `<p><strong>Fervor</strong> (% points):</p>` +
        appendNamedSourceRows("", rowsForAttr("Fervor"), "Fervor");
      body +=
        `<p><strong>FervorRating</strong>:</p>` +
        appendNamedSourceRows("", rowsForAttr("FervorRating"), "FervorRating");
      body += tipRow(
        "Rating → %",
        escapeHtml(fmtTipPct(fRat)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.Fervor_pct)));
      return finish("Fervor", "Sources + formula", body);
    }

    if (statKey === "damageMod") {
      const htl = warriorHoldTheLineDamageModifierPctPoints();
      const mc = warriorMagicConductionDamageModifierPctPoints();
      let body =
        `<p><strong>DamageModifier</strong> (% points on sheet):</p>` +
        appendNamedSourceRows("", rowsForAttr("DamageModifier"), "DamageModifier");
      if (htl > 0)
        body += tipRow(
          "Talent: Hold the Line",
          escapeHtml(fmtTipPct(htl)),
          "—"
        );
      if (mc > 0)
        body += tipRow(
          "Talent: Magic Conduction",
          escapeHtml(fmtTipPct(mc)),
          "—"
        );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.DamageModifier_pct)));
      return finish("Damage modifier", "Sources + talents", body);
    }

    if (statKey === "block") {
      let body = tipRow(
        "Universal block",
        escapeHtml(fmtTipPct(BLOCK_MITIGATION_BASE_PCT)),
        "—"
      );
      body += appendNamedSourceRows(
        `<p><strong>BlockMitigation</strong> from class / gear / buffs / consumables:</p>`,
        rowsForAttr("BlockMitigation"),
        "BlockMitigation"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.BlockMitigation_pct)));
      return finish("Block", "Sources", body);
    }

    if (statKey === "dodge") {
      const fDex = 0.009 * dex;
      let body =
        `<p><strong>DodgeChance</strong> (% points on sheet):</p>` +
        appendNamedSourceRows("", rowsForAttr("DodgeChance"), "DodgeChance");
      body += tipRow(
        "Dexterity",
        escapeHtml(fmtTipPct(fDex)),
        "—"
      );
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.DodgeChance_pct)));
      return finish("Dodge chance", "Sources + formula", body);
    }

    if (statKey === "magicMastery") {
      const rows = rowsForAttr("MagicMastery");
      const m2 = collectSummaryMysticM2Line(classIdTip, "MagicMastery");
      if (m2) rows.push(m2);
      let body = appendNamedSourceRows("", rows, "MagicMastery");
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.MagicMastery_pct)));
      return finish("Magic mastery", "Sources", body);
    }

    if (statKey === "physMastery") {
      const rows = rowsForAttr("PhysicalMastery");
      const magicB = collectSummaryMagicMasteryForDisciplineBase(classIdTip, charLevel, snapTip);
      const disc = collectSummaryDisciplinePhysicalLine(classIdTip, magicB);
      if (disc) rows.push(disc);
      const m2 = collectSummaryMysticM2Line(classIdTip, "PhysicalMastery");
      if (m2) rows.push(m2);
      let body = appendNamedSourceRows("", rows, "PhysicalMastery");
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.PhysicalMastery_pct)));
      return finish("Physical mastery", "Sources", body);
    }

    if (statKey === "cdr") {
      let body =
        `<p><strong>CooldownReduction</strong> (% points · summary label: recovery):</p>` +
        appendNamedSourceRows("", rowsForAttr("CooldownReduction"), "CooldownReduction");
      body += totalRow(`<strong>Total</strong>`, escapeHtml(fmtTipPct(derived.CooldownRecovery_pct)));
      return finish("Cooldown recovery", "Sources", body);
    }

    return "";
  }

  /**
   * @param {HTMLElement} panelEl `#gp-summary-wrap` (or any ancestor of **`.gp-summary-stat-tip`**).
   * @param {object} tipCtx pass-through for {@link plannerSummaryStatTooltipHtml}
   */
  function wireSummaryPanelStatTooltips(panelEl, tipCtx) {
    if (!panelEl || !tipCtx) return;
    const anchors = panelEl.querySelectorAll(".gp-summary-stat-tip");
    for (let i = 0; i < anchors.length; i++) {
      const el = anchors[i];
      if (el.dataset.gpSumWired === "1") continue;
      el.dataset.gpSumWired = "1";
      const show = () => {
        const key = el.dataset.gpSumTip || "";
        const html = plannerSummaryStatTooltipHtml(key, tipCtx);
        if (!html) return;
        showGearPlannerTooltip(el, html, {
          className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill gp-slot-tooltip--skill-dmg-breakdown",
        });
      };
      el.addEventListener("mouseenter", show);
      el.addEventListener("focus", show);
      el.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
      el.addEventListener("blur", scheduleHideGearPlannerTooltip);
    }
  }

  /**
   * @param {object} slotDef
   * @param {string} classId
   * For **armor** and **weapons**, the modal filters by **`item.aptitudes`** vs **`classAptitudeRefs(classId)`** when **`classId`**
   * is set. **Neck, rings, and trinket** slots skip that filter so shared jewelry stays listable for every class.
   */
  function itemsForSlot(slotDef, classId) {
    let types = slotDef.types;
    if (slotDef.weaponSlot) {
      const aptRefs = classId ? classAptitudeRefs(classId) : new Set();
      let list = itemLines.filter((r) => weaponTypes.has(r.type));
      if (slotDef.weaponRole === "off") {
        list = list.filter((r) => canEquipOffSlot(r.type));
      } else if (slotDef.weaponRole === "main") {
        list = list.filter((r) => canEquipMainSlot(r.type));
      } else if (slotDef.weaponRole === "arsenal") {
        list = list.filter((r) => canEquipMainSlot(r.type) || canEquipOffSlot(r.type));
      }
      list = list.filter((r) => itemMatchesClassAptitudes(r, aptRefs));
      list = list.filter((r) => !weaponItemDuplicatesArsenalOrHand(slotDef, r, selection));
      list.sort(sortItemsByRarityDescThenId);
      return list;
    }
    const set = new Set(types);
    let list = itemLines.filter((r) => set.has(r.type));
    if (classId && !SLOT_KEYS_NO_CLASS_APTITUDE_MODAL_FILTER.has(slotDef.key)) {
      const aptRefs = classAptitudeRefs(classId);
      list = list.filter((r) => itemMatchesClassAptitudes(r, aptRefs));
    }
    list.sort(sortItemsByRarityDescThenId);
    return list;
  }

  /**
   * @param {number} charLevel — character level (rating divisor / curves).
   * @param {number} [monsterLevel] — foe **attacker level** for armor mitigation (`385 + 100×Lv` denominator); **must** match **`combatSnapshotForSkills().monsterLevel`** (hidden **`#gp-monster-level`** / foe picker).
   * @param {string} [foeUnitId] — **`combatSnapshotForSkills().foeUnitId`** (`"median"` or **`unit`** id) for the mitigation subtitle.
   */
  function renderSummary(el, baseStats, gearFlat, derived, panelHeading, charLevel, monsterLevel, foeUnitId) {
    function fmt(n) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      const abs = Math.abs(n);
      const d = abs >= 100 ? 0 : abs >= 10 ? 1 : 2;
      return n.toFixed(d).replace(/\.?0+$/, "");
    }

    function fmtPrimary(n) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      return String(Math.round(n));
    }

    function fmtPct(n) {
      if (typeof n !== "number" || Number.isNaN(n)) return "—";
      const abs = Math.abs(n);
      const d = abs >= 100 ? 1 : abs >= 10 ? 1 : 2;
      return `${n.toFixed(d).replace(/\.?0+$/, "")}%`;
    }

    function fmtSheetPenPct(n) {
      return formatPlannerSheetPenetrationPct(n);
    }

    const vit = (baseStats.Vitality || 0) + (gearFlat.Vitality || 0);
    const fai = (baseStats.Faith || 0) + (gearFlat.Faith || 0);
    const clsId = plannerSelectedClassId();
    const armorRatio = sumPreviewStatusBuffARatios(clsId, selection, charLevel);
    const armorBase = (baseStats.Armor || 0) + (gearFlat.Armor || 0);
    const armorMult = 1 + (armorRatio.Armor || 0);
    const armorTotal = armorBase * armorMult;
    const ml =
      typeof monsterLevel === "number" && Number.isFinite(monsterLevel)
        ? clamp(Math.round(monsterLevel), 1, MONSTER_LEVEL_MAX)
        : MONSTER_LEVEL_DEFAULT;
    const physMitPct = plannerAffinityMitigatedFraction(armorTotal, 0, ml) * 100;
    const foeLabRaw = foePlannerDisplayLabel(
      foeUnitId != null && String(foeUnitId).trim() ? String(foeUnitId).trim() : "median"
    );
    const maxHealthApprox = vit * 3 + (gearFlat.MaxHealth || 0);
    const healthRegenApprox = fai * 0.04 + (gearFlat.HealthRegen || 0);

    const h2 =
      typeof panelHeading === "string" && panelHeading.trim()
        ? panelHeading.trim()
        : "Summary";
    const cl =
      typeof charLevel === "number" && Number.isFinite(charLevel)
        ? clamp(Math.round(charLevel), 1, CHAR_LEVEL_MAX)
        : CHAR_LEVEL_DEFAULT;
    let html = `<div class="summary-panel"><h2>${escapeHtml(h2)}</h2>`;

    html += `<h3>Primary attributes</h3><table>`;
    for (const k of PRIMARY_ATTRIBUTE_IDS) {
      const b = baseStats[k] || 0;
      const g = gearFlat[k] || 0;
      const t = b + g;
      html +=
        `<tr><td>${k}</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="primary:${escapeHtml(k)}">` +
        `${fmtPrimary(t)} <span style="opacity:.65">(${fmtPrimary(b)}+${fmtPrimary(g)})</span></span></td></tr>`;
    }
    html += `</table>`;

    html += `<h3>Defense & recovery</h3><table>`;
    const armorNote =
      armorMult > 1 + 1e-9
        ? ` <span style="opacity:.65">(${fmtPrimary(armorBase)} × ${fmtPct((armorMult - 1) * 100)} status)</span>`
        : "";
    html += `<tr><td>Armor</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="armor">${fmtPrimary(
      armorTotal
    )}${armorNote}</span></td></tr>`;
    html += `<tr><td>Physical damage mitigation</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="physMit">${fmtPct(
      physMitPct
    )} <span style="opacity:.65;font-size:0.85em">vs Lv&nbsp;${ml} · ${escapeHtml(foeLabRaw)}</span></span></td></tr>`;
    html += `<tr><td>Maximum health</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="maxHealth">${fmtPrimary(
      maxHealthApprox
    )}</span></td></tr>`;
    html += `<tr><td>Health regen</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="healthRegen">${fmt(
      healthRegenApprox
    )}</span></td></tr>`;
    html += `</table>`;

    html += `<h3>Secondary attributes</h3><table>`;
    const drows = [
      ["Crit chance", derived.CritChance_pct, "critChance", fmtPct],
      ["Crit bonus", derived.CritDamage_pct, "critBonus", fmtPct],
      ["Armor penetration", derived.ArmorPenetration_pct, "armorPen", fmtSheetPenPct],
      ["Magic penetration", derived.SpellPenetration_pct, "spellPen", fmtSheetPenPct],
      ["Fervor", derived.Fervor_pct, "fervor", fmtPct],
      ["Damage modifier", derived.DamageModifier_pct, "damageMod", fmtPct],
      ["Block", derived.BlockMitigation_pct, "block", fmtPct],
      ["Dodge chance", derived.DodgeChance_pct, "dodge", fmtPct],
      ["Magic mastery", derived.MagicMastery_pct, "magicMastery", fmtPct],
      ["Physical mastery", derived.PhysicalMastery_pct, "physMastery", fmtPct],
      ["Cooldown recovery", derived.CooldownRecovery_pct, "cdr", fmtPct],
    ];
    for (const [label, v, tipKey, formatter] of drows) {
      html += `<tr><td>${label}</td><td><span class="gp-summary-stat-tip" tabindex="0" data-gp-sum-tip="${tipKey}">${formatter(
        v
      )}</span></td></tr>`;
    }
    html += `</table></div>`;

    el.innerHTML = html;
    wireSummaryPanelStatTooltips(el, {
      baseStats,
      gearFlat,
      derived,
      charLevel: cl,
      classId: clsId,
      selectionSnapshot: selection,
      monsterLevel: ml,
      foeLabRaw,
      armorBase,
      armorTotal,
      armorMult,
      physMitPct,
      vitalityTotal: vit,
      faithTotal: fai,
    });
  }

  /**
   * Tab buttons **`#gp-tab-*`** toggle **`[role="tabpanel"]`** visibility (**`hidden`** + **`gp-tab--active`**).
   */
  function wireGearPlannerTabs(rootEl) {
    const tablist = rootEl.querySelector(".gp-tabs");
    if (!tablist) return;
    const tabs = tablist.querySelectorAll('[role="tab"]');
    const panels = rootEl.querySelectorAll('.gear-planner__tab-panel[role="tabpanel"]');
    function activate(tabBtn) {
      const panelId = tabBtn.getAttribute("aria-controls");
      if (!panelId) return;
      for (let i = 0; i < tabs.length; i++) {
        const t = tabs[i];
        const on = t === tabBtn;
        t.classList.toggle("gp-tab--active", on);
        t.setAttribute("aria-selected", on ? "true" : "false");
        t.tabIndex = on ? 0 : -1;
      }
      for (let i = 0; i < panels.length; i++) {
        const p = panels[i];
        const show = p.id === panelId;
        if (show) p.removeAttribute("hidden");
        else p.setAttribute("hidden", "");
        p.classList.toggle("gear-planner__tab-panel--active", show);
      }
    }
    tablist.addEventListener("click", (e) => {
      const btn = e.target && e.target.closest && e.target.closest('[role="tab"]');
      if (!btn || !tablist.contains(btn)) return;
      e.preventDefault();
      activate(btn);
    });
    tablist.addEventListener("keydown", (e) => {
      const keys = ["ArrowLeft", "ArrowRight", "Home", "End"];
      if (keys.indexOf(e.key) === -1) return;
      const focusIx = Array.prototype.indexOf.call(tabs, document.activeElement);
      if (focusIx < 0) return;
      let next = focusIx;
      if (e.key === "ArrowRight") next = (focusIx + 1) % tabs.length;
      else if (e.key === "ArrowLeft") next = (focusIx + tabs.length - 1) % tabs.length;
      else if (e.key === "Home") next = 0;
      else if (e.key === "End") next = tabs.length - 1;
      if (next !== focusIx) {
        e.preventDefault();
        tabs[next].focus();
        activate(tabs[next]);
      }
    });
  }

  function getCharLevel(inpLevel) {
    return clamp(parseInt(inpLevel.value, 10) || CHAR_LEVEL_DEFAULT, 1, CHAR_LEVEL_MAX);
  }

  function syncGpModalOpenClass() {
    let settingsOpen = false;
    let saveBuildOpen = false;
    let discardOpen = false;
    let classModalOpen = false;
    try {
      const el = document.getElementById("gp-planner-settings-overlay");
      settingsOpen = !!(el && !el.hidden);
      const saveEl = document.getElementById("gp-save-build-overlay");
      saveBuildOpen = !!(saveEl && !saveEl.hidden);
      const discardEl = document.getElementById("gp-discard-overlay");
      discardOpen = !!(discardEl && !discardEl.hidden);
      const classEl = document.getElementById("gp-class-modal-overlay");
      classModalOpen = !!(classEl && !classEl.hidden);
    } catch (_) {
      settingsOpen = false;
    }
    if (
      modalOverlay ||
      arsenalSkillModalOverlay ||
      settingsOpen ||
      saveBuildOpen ||
      discardOpen ||
      classModalOpen
    ) {
      document.body.classList.add("gp-modal-open");
    } else {
      document.body.classList.remove("gp-modal-open");
    }
  }

  function closeArsenalSkillModal() {
    if (arsenalSkillModalOverlay && arsenalSkillModalOverlay.parentNode) {
      restoreModalFocus(arsenalSkillModalOverlay, null);
      arsenalSkillModalOverlay.parentNode.removeChild(arsenalSkillModalOverlay);
    }
    arsenalSkillModalOverlay = null;
  }

  function closeModal() {
    closeArsenalSkillModal();
    if (modalOverlay && modalOverlay.parentNode) {
      restoreModalFocus(modalOverlay, null);
      modalOverlay.parentNode.removeChild(modalOverlay);
    }
    modalOverlay = null;
    modalSlotKey = null;
    modalSlotItems = [];
    modalHighlightId = null;
    modalPinnedFirstId = null;
    syncGpModalOpenClass();
    clearTimeout(slotTooltipHideTimer);
    slotTooltipHideTimer = null;
    if (slotTooltipEl) slotTooltipEl.hidden = true;
  }

  function modalFocusableElements(container) {
    if (!container || typeof container.querySelectorAll !== "function") return [];
    return Array.from(
      container.querySelectorAll(
        'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])'
      )
    ).filter((el) => {
      if (!el || el.hidden) return false;
      if (el.getAttribute && el.getAttribute("aria-hidden") === "true") return false;
      return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
    });
  }

  function setupModalFocusTrap(overlay, dialogSelector, returnFocusEl) {
    if (!overlay || overlay.__gpFocusTrapReady) return;
    overlay.__gpFocusTrapReady = true;
    overlay.__gpReturnFocusEl = returnFocusEl || (typeof document !== "undefined" ? document.activeElement : null);
    overlay.addEventListener("keydown", (e) => {
      if (e.key !== "Tab") return;
      if (overlay.hidden || (overlay.parentNode == null && overlay.id !== "")) return;
      const dialog = dialogSelector ? overlay.querySelector(dialogSelector) : overlay;
      const focusables = modalFocusableElements(dialog || overlay);
      if (!focusables.length) {
        e.preventDefault();
        if (dialog && typeof dialog.focus === "function") dialog.focus();
        return;
      }
      const first = focusables[0];
      const last = focusables[focusables.length - 1];
      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
      }
    });
  }

  function restoreModalFocus(overlay, fallbackEl) {
    const target = (overlay && overlay.__gpReturnFocusEl) || fallbackEl;
    if (target && typeof target.focus === "function") {
      try {
        target.focus();
      } catch (_) {
        /* ignore */
      }
    }
  }

  /**
   * Modal listing arsenal weapon skills (weapon order). Chooses skill for `pickSkill1` or `pickSkill2`.
   * @param {1|2} slotNum
   * @param {string[]} pickIds
   * @param {{ pickSkill1?: string|null, pickSkill2?: string|null }} arSel
   * @param {object|null} arsWep
   * @param {object|null} combatCtx
   * @param {() => void} onDone
   */
  function openArsenalSkillPickModal(slotNum, pickIds, arSel, arsWep, combatCtx, onDone) {
    closeModal();

    const overlay = document.createElement("div");
    overlay.className = "gp-modal-overlay";
    overlay.setAttribute("role", "dialog");
    overlay.setAttribute("aria-modal", "true");
    overlay.setAttribute("aria-labelledby", "gp-modal-arsenal-skill-heading");

    const wepLabel = arsWep ? itemDisplayName(arsWep) : "Arsenal weapon";

    overlay.innerHTML = `
      <div class="gp-modal gp-modal--arsenal-skills">
        <div class="gp-modal__header">
          <div>
            <h2 class="gp-modal__title" id="gp-modal-arsenal-skill-heading">Choose arsenal ability (slot ${slotNum})</h2>
            <p class="gp-modal__subtitle">${escapeHtml(wepLabel)}</p>
          </div>
          <button type="button" class="gp-modal__close" aria-label="Close" data-action="close-arsenal-skills">×</button>
        </div>
        <div class="gp-modal__body gp-modal__body--arsenal-skills">
          <button type="button" class="gp-modal-arsenal-clear-slot" data-action="clear-slot">Clear this slot</button>
          <div class="gp-modal-arsenal-skill-list" id="gp-modal-arsenal-skill-list"></div>
        </div>
      </div>
    `;

    const listEl = overlay.querySelector("#gp-modal-arsenal-skill-list");
    const clearBtn = overlay.querySelector('[data-action="clear-slot"]');

    function finishClose() {
      closeArsenalSkillModal();
      syncGpModalOpenClass();
    }

    function renderList() {
      listEl.textContent = "";
      if (!pickIds.length) {
        const empty = document.createElement("p");
        empty.className = "gp-modal-arsenal-empty";
        empty.textContent = "No abilities available on this weapon.";
        listEl.appendChild(empty);
        return;
      }
      const ctxArs = combatCtxWithWeaponSlotPower(combatCtx, "arsenal");
      const selectableIds = pickIds.filter((id) => weaponSkillSelectableForArsenalPick(id));
      for (let j = 0; j < selectableIds.length; j++) {
        const sid = selectableIds[j];
        const sk = skillById[sid];
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "slot-arsenal-skill slot-arsenal-skill--modal-row";
        const in1 = arSel.pickSkill1 === sid;
        const in2 = arSel.pickSkill2 === sid;
        if (in1) btn.classList.add("slot-arsenal-skill--picked", "slot-arsenal-skill--slot1");
        if (in2) btn.classList.add("slot-arsenal-skill--picked", "slot-arsenal-skill--slot2");
        if ((slotNum === 1 && in1) || (slotNum === 2 && in2)) {
          btn.classList.add("slot-arsenal-skill--current-slot");
        }

        const iconWrap = document.createElement("div");
        iconWrap.className =
          "slot-arsenal-skill__icon " +
          (skillIconIsPassiveFrame(sk) ? "gp-skill-icon--passive" : "gp-skill-icon--active");
        mountAtlasIcon(iconWrap, sk && sk.gfx ? sk.gfx : null, 36);

        const body = document.createElement("div");
        body.className = "slot-arsenal-skill__body";

        const titleRow = document.createElement("div");
        titleRow.className = "slot-arsenal-skill__title-row";
        const title = document.createElement("span");
        title.className = "slot-arsenal-skill__title";
        title.textContent = skillDisplayName(sk) || sid;
        titleRow.appendChild(title);
        const timingTxt = skillTimingMetaTextJoined(sk);
        if (timingTxt) {
          const cdSpan = document.createElement("span");
          cdSpan.className = "slot-arsenal-skill__cd";
          cdSpan.textContent = timingTxt;
          titleRow.appendChild(cdSpan);
        }
        if (in1 || in2) {
          const badge = document.createElement("span");
          badge.className =
            "slot-arsenal-skill__badge" + (in1 ? " slot-arsenal-skill__badge--1" : " slot-arsenal-skill__badge--2");
          badge.textContent = in1 ? "1" : "2";
          titleRow.appendChild(badge);
        }

        const desc = document.createElement("div");
        desc.className = "slot-arsenal-skill__desc";
        const dhtml = skillDescHtml(sk, ctxArs, weaponSkillDisplayRank(sid));
        if (dhtml) desc.innerHTML = dhtml;

        body.appendChild(titleRow);
        if (dhtml) body.appendChild(desc);
        appendComputedSkillDamageToCard(body, sk, ctxArs);

        btn.appendChild(iconWrap);
        btn.appendChild(body);

        btn.addEventListener("click", () => {
          assignArsenalPickSlot(arSel, slotNum, sid);
          finishClose();
          if (typeof onDone === "function") onDone();
        });

        listEl.appendChild(btn);
      }
    }

    renderList();

    clearBtn.addEventListener("click", () => {
      assignArsenalPickSlot(arSel, slotNum, null);
      finishClose();
      if (typeof onDone === "function") onDone();
    });

    overlay.querySelector('[data-action="close-arsenal-skills"]').addEventListener("click", finishClose);
    overlay.addEventListener("click", (e) => {
      if (e.target === overlay) finishClose();
    });
    overlay.addEventListener("keydown", (e) => {
      if (e.key === "Escape") finishClose();
    });

    arsenalSkillModalOverlay = overlay;
    overlay.tabIndex = -1;
    document.body.appendChild(overlay);
    setupModalFocusTrap(overlay, ".gp-modal", document.activeElement);
    syncGpModalOpenClass();
    setTimeout(() => overlay.focus(), 50);
  }

  function filterModalItems(searchQ, rarityFilter, offhandCompatibleOnly) {
    const q = (searchQ || "").trim().toLowerCase();
    const filtered = modalSlotItems.filter((it) => {
      if (!it || it.id == null) return false;
      if (rarityFilter && rarityFilter !== "__all__" && it.rarity !== rarityFilter) {
        return false;
      }
      if (offhandCompatibleOnly && !weaponCanEquipWithOffhand(it.type)) {
        return false;
      }
      if (!q) return true;
      let name = "";
      let flav = "";
      try {
        name = itemDisplayName(it).toLowerCase();
        flav = itemFlavorText(it).toLowerCase();
      } catch (_) {
        return false;
      }
      const id = String(it.id).toLowerCase();
      const typ = (it.type || "").toLowerCase();
      return (
        name.includes(q) ||
        id.includes(q) ||
        flav.includes(q) ||
        typ.includes(q)
      );
    });
    return filtered;
  }

  /** Put the equipped item (when opening the modal) at the top; sort the rest by rarity. */
  function sortFilteredWithSelectedFirst(filtered, selectedId) {
    const arr = filtered.slice();
    arr.sort(sortItemsByRarityDescThenId);
    if (!selectedId) return arr;
    const ix = arr.findIndex((x) => x.id === selectedId);
    if (ix <= 0) return arr;
    const [picked] = arr.splice(ix, 1);
    arr.unshift(picked);
    return arr;
  }

  function openModal(
    slotKey,
    root,
    getCharLevelFn,
    getClassIdFn,
    getMonsterLevelFn,
    getFoeUnitIdFn,
    onEquipped
  ) {
    const sd = SLOT_DEFS.find((s) => s.key === slotKey);
    if (!sd) return;

    const classId = typeof getClassIdFn === "function" ? getClassIdFn() : "";
    const charLevel = typeof getCharLevelFn === "function" ? getCharLevelFn() : CHAR_LEVEL_DEFAULT;
    let slotItems = itemsForSlot(sd, classId);
    const cur = selection[slotKey];
    const highlightId = cur && cur.item ? cur.item.id : null;
    const arsenalLocked = sd.weaponRole === "arsenal" && charLevel < ARSENAL_UNLOCK_LEVEL;

    const rarities = [...new Set(slotItems.map((x) => x.rarity || "Common"))];
    rarities.sort(
      (a, b) => RARITY_ORDER.indexOf(a) - RARITY_ORDER.indexOf(b)
    );

    // closeModal() clears modal state — must run before assigning modalSlotItems
    closeModal();
    modalSlotKey = slotKey;
    modalSlotItems = slotItems;
    modalHighlightId = highlightId;
    modalPinnedFirstId = highlightId;

    const overlay = document.createElement("div");
    overlay.className = "gp-modal-overlay";
    overlay.setAttribute("role", "dialog");
    overlay.setAttribute("aria-modal", "true");
    overlay.setAttribute("aria-labelledby", "gp-modal-heading");

    /**
     * **`modalFreeIlvl`** — level slider for non-craft previews; unchanged when browsing craft rows (craft uses **`item.level`** per row).
     */
    let modalFreeIlvl = clamp(charLevel, 1, GEAR_LEVEL_MAX);
    if (cur && cur.ilvl != null && !(cur.item && itemFactionIsCraft(cur.item))) {
      modalFreeIlvl = clamp(cur.ilvl, 1, GEAR_LEVEL_MAX);
    }
    const draftIlvlStart = modalFreeIlvl;

    let draftStars = 0;
    let draftRarityOverride = null;
    let draftEnchantId = null;
    let draftAugmentId = null;
    if (cur && cur.item && highlightId && cur.item.id === highlightId) {
      const effR = effectiveItemRarity(cur);
      const mx = maxUpgradeStarsForRarity(effR);
      draftStars = clamp(Math.round(cur.stars || 0), 0, mx);
      draftRarityOverride = cur.rarityOverride || null;
      draftEnchantId = cur.enchantId || null;
      draftAugmentId = cur.augmentId || null;
    }
    const showOffhandCompatibleFilter =
      sd.weaponSlot && (sd.weaponRole === "main" || sd.weaponRole === "arsenal");

    overlay.innerHTML = `
      <div class="gp-modal gp-modal--wide">
        <div class="gp-modal__header">
          <div>
            <h2 class="gp-modal__title" id="gp-modal-heading">${escapeHtml(sd.label)}</h2>
          </div>
          <button type="button" class="gp-modal__close" aria-label="Close" data-action="close">×</button>
        </div>
        <div class="gp-modal__controls">
          <div class="gp-modal__search">
            <label for="gp-modal-search">Search</label>
            <input type="search" id="gp-modal-search" placeholder="Name, type, flavor…" autocomplete="off" />
          </div>
          ${
            showOffhandCompatibleFilter
              ? `<div class="gp-modal__toggle gp-modal__toggle--inline">
                  <input type="checkbox" id="gp-modal-offhand-compatible" />
                  <label for="gp-modal-offhand-compatible">Can equip with off-hand</label>
                </div>`
              : ""
          }
          <div class="gp-modal__rarity">
            <label for="gp-modal-rarity">Rarity</label>
            <select id="gp-modal-rarity">
              <option value="__all__">All rarities</option>
              ${rarities.map((r) => `<option value="${escapeHtml(r)}">${escapeHtml(r)}</option>`).join("")}
            </select>
          </div>
          <div class="gp-modal__ilvl gear-planner__slider-field">
            <div class="gear-planner__slider-label-row">
              <label for="gp-modal-ilvl">Level (1–${GEAR_LEVEL_MAX})</label>
              <span class="gear-planner__slider-val" id="gp-modal-ilvl-val" aria-live="polite">${draftIlvlStart}</span>
            </div>
            <input type="range" id="gp-modal-ilvl" min="1" max="${GEAR_LEVEL_MAX}" value="${draftIlvlStart}" step="1" />
          </div>
        </div>
        <div class="gp-modal__body gp-modal__body--split">
          <div class="gp-modal__col gp-modal__col--list">
            <div class="gp-modal__grid gp-modal__grid--scroll" id="gp-modal-grid"></div>
            <div id="gp-modal-list-augment-mount" class="gp-modal-list-augment-mount" hidden></div>
          </div>
          <aside class="gp-modal__col gp-modal__col--preview" aria-label="Preview">
            <div id="gp-modal-preview" class="gp-modal-preview"></div>
            <div id="gp-modal-slotopts" class="gp-modal-slotopts" hidden></div>
          </aside>
        </div>
        <div class="gp-modal__footer">
          <button type="button" class="gp-btn--danger" data-action="clear">Clear slot</button>
          <button type="button" data-action="cancel">Cancel</button>
          <button type="button" class="gp-btn--primary" data-action="equip" ${
            modalHighlightId && !arsenalLocked ? "" : "disabled"
          }>Equip selected</button>
        </div>
      </div>
    `;

    modalOverlay = overlay;
    document.body.appendChild(overlay);
    setupModalFocusTrap(overlay, ".gp-modal", document.activeElement);
    syncGpModalOpenClass();

    const grid = overlay.querySelector("#gp-modal-grid");
    const inpSearch = overlay.querySelector("#gp-modal-search");
    const selRarityFilter = overlay.querySelector("#gp-modal-rarity");
    const inpIlvl = overlay.querySelector("#gp-modal-ilvl");
    const ilvlValEl = overlay.querySelector("#gp-modal-ilvl-val");
    const previewEl = overlay.querySelector("#gp-modal-preview");
    const slotOptsEl = overlay.querySelector("#gp-modal-slotopts");
    const listColEl = overlay.querySelector(".gp-modal__col--list");
    const listAugmentMount = overlay.querySelector("#gp-modal-list-augment-mount");
    const chkOffhandCompatible = overlay.querySelector("#gp-modal-offhand-compatible");

    let modalAugmentExpanded = false;
    let modalPreviewExpanded = false;

    function applyModalAugmentExpandUi(rootEl) {
      if (!rootEl) return;
      const btn = rootEl.querySelector(".gp-modal-augment__toggle");
      const panel = overlay.querySelector("#gp-modal-augment-panel");
      const hint = rootEl.querySelector(".gp-modal-augment__toggle-hint");
      if (!btn || !panel) return;
      if (listAugmentMount) listAugmentMount.hidden = !modalAugmentExpanded;
      if (grid) grid.hidden = modalAugmentExpanded;
      if (listColEl) listColEl.classList.toggle("gp-modal__col--list-augmenting", modalAugmentExpanded);
      if (hint) {
        hint.textContent = modalAugmentExpanded
          ? "Click again to return to the item list"
          : "Open the augment / enchant picker on the left";
      }
      btn.setAttribute("aria-expanded", modalAugmentExpanded ? "true" : "false");
      btn.setAttribute(
        "title",
        modalAugmentExpanded
          ? "Click again to return to the item list"
          : "Open the augment / enchant picker on the left"
      );
      btn.classList.toggle("gp-modal-augment__toggle--open", modalAugmentExpanded);
      rootEl.classList.toggle("gp-modal-augment--expanded", modalAugmentExpanded);
      rootEl.classList.toggle("gp-modal-augment--collapsed", !modalAugmentExpanded);
    }

    function syncModalSlotOptsColumnVisibility() {
      if (!slotOptsEl) return;
      slotOptsEl.hidden = slotOptsEl.childElementCount === 0;
    }

    /** Gear in this slot when the picker opened — compare preview stats vs this baseline. */
    const modalBaselineSlotSel = cloneSlotSel(cur);

    function modalCombatSnapshot(selectionSnap) {
      const cl =
        typeof getCharLevelFn === "function" ? getCharLevelFn() : CHAR_LEVEL_DEFAULT;
      const cls = typeof getClassIdFn === "function" ? getClassIdFn() : "";
      const ml =
        typeof getMonsterLevelFn === "function"
          ? getMonsterLevelFn()
          : MONSTER_LEVEL_DEFAULT;
      const foe =
        typeof getFoeUnitIdFn === "function" ? getFoeUnitIdFn() : "median";
      const baseStats = computeClassBaseStats(cls, cl);
      const gearFlat = mergeGearTalentFlats(cl, cls, selectionSnap);
      const derived = deriveCombatPreview(baseStats, gearFlat, cl);
      const sheetTotals = mergeCombatSheetTotals(baseStats, gearFlat);
      return {
        sheetTotals,
        derived,
        charLevel: cl,
        monsterLevel: ml,
        foeUnitId: foe,
      };
    }

    function applyModalItemSource() {
      slotItems = itemsForSlot(sd, classId);
      modalSlotItems = slotItems;
      const raritiesNew = [...new Set(slotItems.map((x) => x.rarity || "Common"))];
      raritiesNew.sort((a, b) => RARITY_ORDER.indexOf(a) - RARITY_ORDER.indexOf(b));
      if (selRarityFilter) {
        const prev = selRarityFilter.value;
        selRarityFilter.innerHTML =
          `<option value="__all__">All rarities</option>` +
          raritiesNew.map((r) => `<option value="${escapeHtml(r)}">${escapeHtml(r)}</option>`).join("");
        if ([...selRarityFilter.options].some((o) => o.value === prev)) selRarityFilter.value = prev;
        else selRarityFilter.value = "__all__";
      }
      refreshGrid();
    }

    function persistModalFreeIlvlFromSlider() {
      if (inpIlvl && !inpIlvl.disabled) {
        const v = parseInt(inpIlvl.value, 10);
        if (Number.isFinite(v)) modalFreeIlvl = clamp(v, 1, GEAR_LEVEL_MAX);
      }
    }

    function draftIlvlVal() {
      const hi = modalHighlightId ? itemById[modalHighlightId] : null;
      if (hi && itemFactionIsCraft(hi)) {
        const fx = defaultGearPlannerTierForItem(hi);
        if (fx != null) return fx;
      }
      return modalFreeIlvl;
    }

    function syncModalTierLabel() {
      if (ilvlValEl) ilvlValEl.textContent = String(draftIlvlVal());
    }

    function syncModalCraftLevelUi() {
      const wrap = overlay.querySelector(".gp-modal__ilvl");
      const lbl = overlay.querySelector('label[for="gp-modal-ilvl"]');
      if (!inpIlvl || !wrap) return;
      const hi = modalHighlightId ? itemById[modalHighlightId] : null;
      if (hi && itemFactionIsCraft(hi)) {
        const fx = defaultGearPlannerTierForItem(hi);
        if (fx != null) {
          inpIlvl.disabled = true;
          wrap.classList.add("gp-modal__ilvl--locked");
          if (lbl) lbl.textContent = `Level ${fx} (Craft — fixed)`;
          return;
        }
      }
      inpIlvl.disabled = false;
      inpIlvl.value = String(modalFreeIlvl);
      wrap.classList.remove("gp-modal__ilvl--locked");
      if (lbl) lbl.textContent = `Level (1–${GEAR_LEVEL_MAX})`;
    }

    function syncDraftsToHighlight() {
      const hi = modalHighlightId;
      if (!hi) return;
      if (cur && cur.item && cur.item.id === hi) {
        const effR = effectiveItemRarity(cur);
        const mx = maxUpgradeStarsForRarity(effR);
        draftStars = clamp(Math.round(cur.stars || 0), 0, mx);
        draftRarityOverride = cur.rarityOverride || null;
        draftEnchantId = cur.enchantId || null;
        draftAugmentId = cur.augmentId || null;
      } else {
        draftStars = 0;
        draftRarityOverride = null;
        /** Enchant / augment persist while browsing items; **`sanitizeModalEnchantAugDrafts`** drops invalid picks. */
      }
    }

    function sanitizeModalEnchantAugDrafts(hiItem) {
      if (!hiItem) return;
      const enchList = enchantItemsForSlot(slotKey);
      const augList = augmentItemsForSlot(slotKey, hiItem);
      if (
        draftEnchantId &&
        !enchList.some((x) => x && x.id === draftEnchantId)
      ) {
        draftEnchantId = null;
      }
      if (
        draftAugmentId &&
        !augList.some((x) => x && x.id === draftAugmentId)
      ) {
        draftAugmentId = null;
      }
    }

    function readDraftFromSlotOpts() {
      const inpStars = overlay.querySelector("#gp-modal-opt-stars");
      const selRareOv = overlay.querySelector("#gp-modal-opt-rarity");
      const selEnch = overlay.querySelector("#gp-modal-opt-enchant");
      if (inpStars && inpStars.getAttribute("data-gp-weapon") === "1") {
        const mx = parseInt(inpStars.max, 10) || 0;
        draftStars = clamp(parseInt(inpStars.value, 10) || 0, 0, mx);
      }
      if (selRareOv && selRareOv.getAttribute("data-gp-weapon") === "1") {
        const hiItem = modalHighlightId ? itemById[modalHighlightId] : null;
        if (hiItem) {
          const baseRank = rarityRank(hiItem.rarity);
          const picked = selRareOv.value;
          draftRarityOverride = rarityRank(picked) > baseRank ? picked : null;
        }
      }
      if (selEnch) {
        draftEnchantId = selEnch.value || null;
      }
      const selAug = overlay.querySelector("#gp-modal-opt-augment");
      if (selAug) {
        draftAugmentId = selAug.value || null;
      }
    }

    /** Augment + enchant picker — same **`gp-modal-augment`** / **`gp-augment-pick-*`** UI; expanded list replaces the item column. */
    function rebuildModalAugmentSection() {
      const mount = previewEl && previewEl.querySelector("#gp-modal-augment-mount");
      const listMount = listAugmentMount;
      if (!mount) return;
      mount.innerHTML = "";
      mount.hidden = true;
      if (listMount) {
        listMount.innerHTML = "";
        listMount.hidden = true;
      }
      if (grid) grid.hidden = false;
      if (listColEl) listColEl.classList.remove("gp-modal__col--list-augmenting");
      if (!modalHighlightId) return;
      const hiItem = itemById[modalHighlightId];
      if (!hiItem) return;
      const enchList = enchantItemsForSlot(slotKey);
      const augList = augmentItemsForSlot(slotKey, hiItem);
      if (!augList.length && !enchList.length) return;

      mount.hidden = false;
      const root = document.createElement("div");
      root.className = "gp-modal-augment";

      const toggle = document.createElement("button");
      toggle.type = "button";
      toggle.className = "gp-modal-augment__toggle";
      toggle.setAttribute("aria-controls", "gp-modal-augment-panel");
      toggle.id = "gp-modal-augment-toggle";

      const textCol = document.createElement("span");
      textCol.className = "gp-modal-augment__toggle-text";
      const lab = document.createElement("span");
      lab.className = "gp-modal-augment__toggle-label";
      lab.textContent =
        augList.length && enchList.length
          ? "Augment & enchant"
          : enchList.length
            ? "Enchant"
            : "Augment";
      const hint = document.createElement("span");
      hint.className = "gp-modal-augment__toggle-hint";
      hint.textContent = "Open the augment / enchant picker on the left";
      textCol.appendChild(lab);
      textCol.appendChild(hint);
      const chev = document.createElement("span");
      chev.className = "gp-modal-augment__chev";
      chev.setAttribute("aria-hidden", "true");
      chev.textContent = "◀";
      toggle.appendChild(chev);
      toggle.appendChild(textCol);

      const panel = document.createElement("div");
      panel.className = "gp-modal-augment__panel";
      panel.id = "gp-modal-augment-panel";

      const hiddenEnch = document.createElement("input");
      hiddenEnch.type = "hidden";
      hiddenEnch.id = "gp-modal-opt-enchant";
      hiddenEnch.value = draftEnchantId || "";

      const hiddenAug = document.createElement("input");
      hiddenAug.type = "hidden";
      hiddenAug.id = "gp-modal-opt-augment";
      hiddenAug.value = draftAugmentId || "";

      const listEl = document.createElement("div");
      listEl.className = "gp-modal-augment-pick";
      listEl.setAttribute("role", "radiogroup");
      listEl.setAttribute(
        "aria-label",
        augList.length && enchList.length
          ? "Augments and enchants"
          : enchList.length
            ? "Enchants"
            : "Augment — crafted bonus"
      );

      function setEnchantPickSelection(nextId) {
        const sid = nextId != null && nextId !== "" ? String(nextId) : "";
        hiddenEnch.value = sid;
        listEl.querySelectorAll("[data-enchant-id]").forEach((btn) => {
          const bid = btn.getAttribute("data-enchant-id") || "";
          const on = bid === sid;
          btn.classList.toggle("gp-augment-pick-row--selected", on);
          if (btn.getAttribute("role") === "radio") {
            btn.setAttribute("aria-checked", on ? "true" : "false");
          }
        });
        readDraftFromSlotOpts();
        updatePreview();
      }

      function setAugmentPickSelection(nextId) {
        const scrollEl = overlay.querySelector(".gp-modal-augment-pick");
        const augmentListScrollTop = scrollEl ? scrollEl.scrollTop : null;
        const sid = nextId != null && nextId !== "" ? String(nextId) : "";
        hiddenAug.value = sid;
        listEl.querySelectorAll("[data-augment-id]").forEach((btn) => {
          const bid = btn.getAttribute("data-augment-id") || "";
          const on = bid === sid;
          btn.classList.toggle("gp-augment-pick-row--selected", on);
          if (btn.getAttribute("role") === "radio") {
            btn.setAttribute("aria-checked", on ? "true" : "false");
          }
        });
        readDraftFromSlotOpts();
        updatePreview();
        if (augmentListScrollTop !== null) {
          requestAnimationFrame(() => {
            const nextScrollEl = overlay.querySelector(".gp-modal-augment-pick");
            if (nextScrollEl) nextScrollEl.scrollTop = augmentListScrollTop;
          });
        }
      }

      if (enchList.length) {
        const secEnch = document.createElement("div");
        secEnch.className = "gp-augment-pick-vendor";
        const labEnch = document.createElement("div");
        labEnch.className = "gp-augment-pick-vendor-label";
        labEnch.textContent = enchantSlotSectionLabel(slotKey);
        secEnch.appendChild(labEnch);
        const sortedEnch = enchList.slice().sort(sortItemsByRarityDescThenId);
        for (let ei = 0; ei < sortedEnch.length; ei++) {
          const en = sortedEnch[ei];
          const rowEn = document.createElement("button");
          rowEn.type = "button";
          rowEn.className =
            "gp-augment-pick-row" +
            (draftEnchantId === en.id ? " gp-augment-pick-row--selected" : "");
          rowEn.setAttribute("data-enchant-id", en.id);
          rowEn.setAttribute("role", "radio");
          rowEn.setAttribute("aria-checked", draftEnchantId === en.id ? "true" : "false");
          const effRE = en.rarity || "Common";
          rowEn.innerHTML = `
              <span class="gp-augment-pick-row__icon-wrap"></span>
              <div class="gp-augment-pick-row__identity">
                <div class="gp-augment-pick-row__name ${rarityTextClass(effRE)}">${escapeHtml(itemDisplayName(en))}</div>
                <div class="gp-augment-pick-row__rarity">${escapeHtml(effRE)}</div>
              </div>
              <div class="gp-augment-pick-row__stats">${plannerModifierPreviewHtml(en, sd)}</div>`;
          mountAtlasIcon(rowEn.querySelector(".gp-augment-pick-row__icon-wrap"), en.gfx, 40);
          rowEn.addEventListener("click", () => {
            const cur = (hiddenEnch.value || "").trim();
            if (cur === en.id) setEnchantPickSelection("");
            else setEnchantPickSelection(en.id);
          });
          secEnch.appendChild(rowEn);
        }
        listEl.appendChild(secEnch);
      }

      const byRoot = new Map();
      for (let ai = 0; ai < augList.length; ai++) {
        const ag = augList[ai];
        const vr = primaryAugmentVendorRoot(ag) || "AugmentBlacksmith";
        if (!byRoot.has(vr)) byRoot.set(vr, []);
        byRoot.get(vr).push(ag);
      }
      const groupOrder = ["AugmentBlacksmith", "AugmentJeweller", "AugmentOutfitter"];
      for (let gi = 0; gi < groupOrder.length; gi++) {
        const vr = groupOrder[gi];
        const groupItems = byRoot.get(vr);
        if (!groupItems || !groupItems.length) continue;
        groupItems.sort(sortItemsByRarityDescThenId);

        const vendorSec = document.createElement("div");
        vendorSec.className = "gp-augment-pick-vendor";
        const vLab = document.createElement("div");
        vLab.className = "gp-augment-pick-vendor-label";
        vLab.textContent = augmentVendorShortLabel(vr);
        vendorSec.appendChild(vLab);

        for (let vi = 0; vi < groupItems.length; vi++) {
          const ag = groupItems[vi];
          const row = document.createElement("button");
          row.type = "button";
          row.className =
            "gp-augment-pick-row" +
            (draftAugmentId === ag.id ? " gp-augment-pick-row--selected" : "");
          row.setAttribute("data-augment-id", ag.id);
          row.setAttribute("role", "radio");
          row.setAttribute("aria-checked", draftAugmentId === ag.id ? "true" : "false");
          const effR = ag.rarity || "Common";
          row.innerHTML = `
              <span class="gp-augment-pick-row__icon-wrap"></span>
              <div class="gp-augment-pick-row__identity">
                <div class="gp-augment-pick-row__name ${rarityTextClass(effR)}">${escapeHtml(itemDisplayName(ag))}</div>
                <div class="gp-augment-pick-row__rarity">${escapeHtml(effR)}</div>
              </div>
              <div class="gp-augment-pick-row__stats">${plannerModifierPreviewHtml(ag, sd)}</div>`;
          {
            const iw = row.querySelector(".gp-augment-pick-row__icon-wrap");
            mountAtlasIcon(iw, ag.gfx, 40);
          }
          row.addEventListener("click", () => {
            const cur = (hiddenAug.value || "").trim();
            if (cur === ag.id) setAugmentPickSelection("");
            else setAugmentPickSelection(ag.id);
          });
          vendorSec.appendChild(row);
        }
        listEl.appendChild(vendorSec);
      }

      panel.appendChild(hiddenEnch);
      panel.appendChild(hiddenAug);
      panel.appendChild(listEl);

      toggle.addEventListener("click", () => {
        modalAugmentExpanded = !modalAugmentExpanded;
        applyModalAugmentExpandUi(root);
      });

      root.appendChild(toggle);
      mount.appendChild(root);
      if (listMount) listMount.appendChild(panel);
      applyModalAugmentExpandUi(root);
    }

    function updatePreview() {
      if (!previewEl) return;
      const hi = modalHighlightId;
      const it = hi ? itemById[hi] : null;
      if (!it) {
        previewEl.classList.remove("gp-modal-preview--expanded");
        previewEl.innerHTML = `<div class="gp-modal-preview__empty">Select an item from the list.</div>`;
        syncModalSlotOptsColumnVisibility();
        return;
      }
      readDraftFromSlotOpts();
      const viewerCid = typeof getClassIdFn === "function" ? getClassIdFn() : "";
      const sel = {
        item: it,
        ilvl: draftIlvlVal(),
        stars: draftStars,
        rarityOverride: draftRarityOverride,
        enchantId: draftEnchantId,
        augmentId: draftAugmentId,
        flawless: false,
        ...(viewerCid ? { viewerClassId: viewerCid } : {}),
      };
      const lines = affixPreviewLines(sel, draftIlvlVal(), sd);
      const effR = effectiveItemRarity(sel);
      const flav = itemFlavorText(it);
      const statLines = [];
      const upgradeLines = [];
      for (let i = 0; i < lines.length; i++) {
        const L = lines[i];
        if (L.startsWith("Upgrade:")) upgradeLines.push(L);
        else statLines.push(L);
      }
      let statsHtml = previewPlainLinesAsHtml(statLines);
      for (let u = 0; u < upgradeLines.length; u++) {
        statsHtml += formatWeaponUpgradePreviewLineHtml(upgradeLines[u]);
      }
      const snapEq = buildFullSelectionSnapshot(slotKey, modalBaselineSlotSel);
      const snapPv = buildFullSelectionSnapshot(slotKey, sel);
      const ctxEq = modalCombatSnapshot(snapEq);
      const ctxPv = modalCombatSnapshot(snapPv);
      const diffSec = formatModalSkillDamageDiffSection(
        ctxEq,
        ctxPv,
        viewerCid,
        snapEq,
        snapPv
      );
      const subLine = itemModalSecondarySubtitle(it);
      const subLineHtml = subLine
        ? `<div class="gp-modal-preview__drops" title="${escapeHtml(subLine)}">${escapeHtml(
            subLine
          )}</div>`
        : "";
      const prevAugScrollEl =
        overlay.querySelector(".gp-modal-augment-pick") ||
        overlay.querySelector("#gp-modal-augment-panel");
      const augmentPanelScrollTop = prevAugScrollEl ? prevAugScrollEl.scrollTop : null;
      previewEl.classList.toggle("gp-modal-preview--expanded", modalPreviewExpanded);
      previewEl.innerHTML = `
        <button type="button" class="gp-modal-preview__mobile-toggle" aria-expanded="${modalPreviewExpanded ? "true" : "false"}">
          <span class="gp-modal-preview__mobile-toggle-text">
            <span class="gp-modal-preview__mobile-toggle-kicker">Selected item</span>
            <span class="gp-modal-preview__mobile-toggle-name ${rarityTextClass(effR)}">${escapeHtml(itemDisplayName(it))}</span>
          </span>
          <span class="gp-modal-preview__mobile-toggle-action">${modalPreviewExpanded ? "Hide details" : "Show details"}</span>
        </button>
        <div class="gp-modal-preview__content">
          <div class="gp-modal-preview__top">
            <div class="gp-modal-preview__icon"></div>
            <div class="gp-modal-preview__headtext">
              <div class="gp-modal-preview__name ${rarityTextClass(effR)}">${escapeHtml(itemDisplayName(it))}</div>
              ${subLineHtml}
            </div>
          </div>
          ${flav ? `<p class="gp-modal-preview__flavor">${escapeHtml(flav)}</p>` : ""}
          <div class="gp-modal-preview__stats">${statsHtml}</div>
          <div id="gp-modal-augment-mount" class="gp-modal-augment-mount" hidden></div>
          ${diffSec || ""}
        </div>
      `;
      mountLootIcon(previewEl.querySelector(".gp-modal-preview__icon"), it.gfx, "");
      const previewToggle = previewEl.querySelector(".gp-modal-preview__mobile-toggle");
      if (previewToggle) {
        previewToggle.addEventListener("click", () => {
          modalPreviewExpanded = !modalPreviewExpanded;
          updatePreview();
        });
      }
      wireModalSkillDiffSkillTooltips(previewEl, ctxPv);
      rebuildModalAugmentSection();
      if (augmentPanelScrollTop !== null) {
        requestAnimationFrame(() => {
          const nextAugScrollEl =
            overlay.querySelector(".gp-modal-augment-pick") ||
            overlay.querySelector("#gp-modal-augment-panel");
          if (nextAugScrollEl) nextAugScrollEl.scrollTop = augmentPanelScrollTop;
        });
      }
    }

    function rebuildModalSlotOpts() {
      if (!slotOptsEl) return;
      slotOptsEl.innerHTML = "";
      if (!modalHighlightId) {
        syncModalSlotOptsColumnVisibility();
        return;
      }

      const hiItem = itemById[modalHighlightId];
      if (!hiItem) {
        syncModalSlotOptsColumnVisibility();
        return;
      }

      sanitizeModalEnchantAugDrafts(hiItem);

      const isWeapon = !!sd.weaponSlot;

      if (isWeapon) {
        const selStub = {
          item: hiItem,
          rarityOverride: draftRarityOverride,
          stars: draftStars,
          enchantId: draftEnchantId,
          augmentId: draftAugmentId,
        };
        const effR = effectiveItemRarity(selStub);
        const maxStars = maxUpgradeStarsForRarity(effR);
        draftStars = clamp(draftStars, 0, maxStars);

        const rowS = document.createElement("div");
        rowS.className = "gp-modal-slotopts__row";
        const lblS = document.createElement("label");
        lblS.className = "gp-modal-slotopts__label";
        lblS.setAttribute("for", "gp-modal-opt-stars");
        lblS.textContent = "Upgrade";
        const inpStars = document.createElement("input");
        inpStars.type = "range";
        inpStars.id = "gp-modal-opt-stars";
        inpStars.setAttribute("data-gp-weapon", "1");
        inpStars.min = "0";
        inpStars.max = String(maxStars);
        inpStars.step = "1";
        inpStars.value = String(draftStars);
        const starVal = document.createElement("span");
        starVal.className = "gp-modal-slotopts__val";
        starVal.textContent = `${draftStars}/${maxStars}`;
        inpStars.addEventListener("input", () => {
          readDraftFromSlotOpts();
          starVal.textContent = `${draftStars}/${maxStars}`;
          updatePreview();
        });
        rowS.appendChild(lblS);
        rowS.appendChild(inpStars);
        rowS.appendChild(starVal);
        slotOptsEl.appendChild(rowS);

        const rowR = document.createElement("div");
        rowR.className = "gp-modal-slotopts__row";
        const lblR = document.createElement("label");
        lblR.className = "gp-modal-slotopts__label";
        lblR.setAttribute("for", "gp-modal-opt-rarity");
        lblR.textContent = "Rarity";
        const selR = document.createElement("select");
        selR.id = "gp-modal-opt-rarity";
        selR.className = "gp-modal-slotopts__select";
        selR.setAttribute("data-gp-weapon", "1");
        const baseRank = rarityRank(hiItem.rarity);
        for (const r of RARITY_ORDER) {
          if (rarityRank(r) < baseRank) continue;
          const o = document.createElement("option");
          o.value = r;
          o.textContent = r;
          selR.appendChild(o);
        }
        const displayedRarity =
          draftRarityOverride && rarityRank(draftRarityOverride) >= baseRank
            ? draftRarityOverride
            : hiItem.rarity;
        selR.value = displayedRarity;
        selR.addEventListener("change", () => {
          readDraftFromSlotOpts();
          const mx = maxUpgradeStarsForRarity(
            effectiveItemRarity({
              item: hiItem,
              rarityOverride: draftRarityOverride,
              stars: draftStars,
            })
          );
          draftStars = clamp(draftStars, 0, mx);
          rebuildModalSlotOpts();
          updatePreview();
        });
        rowR.appendChild(lblR);
        rowR.appendChild(selR);
        slotOptsEl.appendChild(rowR);
      }

      syncModalSlotOptsColumnVisibility();
    }

    function modalItemPickCardStatsHtml(it, tierForCard) {
      const viewerCid = typeof getClassIdFn === "function" ? getClassIdFn() : "";
      const simSel = {
        item: it,
        ilvl: tierForCard,
        stars: 0,
        rarityOverride: null,
        enchantId: null,
        ...(viewerCid ? { viewerClassId: viewerCid } : {}),
      };
      const rawLines = affixPreviewLines(simSel, tierForCard, sd);
      const statOnly = rawLines.filter((L) => !L.startsWith("Upgrade:") && !/(enchant)\s*$/.test(L));
      const maxRows = 6;
      const slice = statOnly.slice(0, maxRows);
      const statsMini = previewPlainLinesAsHtml(slice);
      const moreHint =
        statOnly.length > maxRows
          ? `<div class="gp-item-pick__more">+${statOnly.length - maxRows} more…</div>`
          : "";
      return statsMini + moreHint;
    }

    function updateModalGridSelection() {
      if (!grid) return;
      grid.querySelectorAll(".gp-item-pick[data-item-id]").forEach((btn) => {
        const id = btn.dataset.itemId;
        btn.classList.toggle("gp-item-pick--selected", id === modalHighlightId);
      });
    }

    function updateModalGridStats() {
      if (!grid) return;
      const ilvlQ = modalFreeIlvl;
      grid.querySelectorAll(".gp-item-pick[data-item-id]").forEach((btn) => {
        const it = itemById[btn.dataset.itemId];
        if (!it) return;
        const craftT = itemFactionIsCraft(it) ? defaultGearPlannerTierForItem(it) : null;
        const tierForCard = craftT != null ? craftT : ilvlQ;
        const statsEl = btn.querySelector(".gp-item-pick__card-stats");
        if (statsEl) statsEl.innerHTML = modalItemPickCardStatsHtml(it, tierForCard);
      });
      syncModalTierLabel();
    }

    function selectModalGridItem(it) {
      if (!it || it.id == null) return;
      persistModalFreeIlvlFromSlider();
      modalHighlightId = it.id;
      syncModalCraftLevelUi();
      syncModalTierLabel();
      updateModalGridSelection();
      syncDraftsToHighlight();
      rebuildModalSlotOpts();
      updatePreview();
      const equipBtn = overlay.querySelector('[data-action="equip"]');
      if (equipBtn) equipBtn.disabled = false;
    }

    function paintModalGrid() {
      if (!grid) return;
      const filteredRaw = filterModalItems(
        inpSearch && inpSearch.value,
        selRarityFilter && selRarityFilter.value,
        chkOffhandCompatible && chkOffhandCompatible.checked
      );
      const filtered = sortFilteredWithSelectedFirst(filteredRaw, modalPinnedFirstId);
      if (!filtered.length) {
        grid.innerHTML = `<div class="gp-modal__empty">No items match your filters.</div>`;
        syncModalTierLabel();
        return;
      }
      grid.innerHTML = "";
      /** Level slider applies to non-craft rows only; craft rows always preview at **`item.level`**. */
      const ilvlQ = modalFreeIlvl;
      let painted = 0;
      for (const it of filtered) {
        if (!it || it.id == null) continue;
        try {
          const craftT = itemFactionIsCraft(it) ? defaultGearPlannerTierForItem(it) : null;
          const tierForCard = craftT != null ? craftT : ilvlQ;
          const btn = document.createElement("button");
          btn.type = "button";
          btn.className =
            "gp-item-pick gp-item-pick--compact gp-item-pick--card" +
            (modalHighlightId === it.id ? " gp-item-pick--selected" : "");
          btn.dataset.itemId = it.id;
          const effR = it.rarity || "Common";
          const statsBlock = modalItemPickCardStatsHtml(it, tierForCard);
          const subLine = itemModalSecondarySubtitle(it);
          const subLineHtml = subLine
            ? `<div class="gp-item-pick__drops" title="${escapeHtml(subLine)}">${escapeHtml(
                subLine
              )}</div>`
            : "";
          btn.innerHTML = `
          <div class="gp-item-pick__row-inner">
            <div class="gp-item-pick__icon"></div>
            <div class="gp-item-pick__text">
              <div class="gp-item-pick__name ${rarityTextClass(effR)}">${escapeHtml(itemDisplayName(it))}</div>
              ${subLineHtml}
              <div class="gp-item-pick__card-stats">${statsBlock}</div>
            </div>
          </div>
        `;
          mountLootIcon(btn.querySelector(".gp-item-pick__icon"), it.gfx, "");

          btn.addEventListener("click", () => {
            selectModalGridItem(it);
          });

          btn.addEventListener("dblclick", () => {
            selectModalGridItem(it);
            equipSelected();
          });

          grid.appendChild(btn);
          painted++;
        } catch (err) {
          console.warn("gear-planner: skipped modal row for", it && it.id, err);
        }
      }
      if (!painted) {
        grid.innerHTML = `<div class="gp-modal__empty">Could not render item rows (see console).</div>`;
      }
      syncModalTierLabel();
      syncModalCraftLevelUi();
    }

    function refreshGrid() {
      paintModalGrid();
    }

    function equipSelected() {
      if (!modalHighlightId) return;
      if (arsenalLocked) return;
      const it = itemLines.find((x) => x.id === modalHighlightId);
      if (!it) return;
      if (weaponItemDuplicatesArsenalOrHand(sd, it, selection)) return;
      readDraftFromSlotOpts();

      const prevId = selection[slotKey].item && selection[slotKey].item.id;

      selection[slotKey].item = it;
      if (itemFactionIsCraft(it)) {
        const fx = defaultGearPlannerTierForItem(it);
        selection[slotKey].ilvl = fx != null ? fx : draftIlvlVal();
      } else {
        selection[slotKey].ilvl = draftIlvlVal();
      }
      selection[slotKey].stars = sd.weaponSlot ? draftStars : 0;
      selection[slotKey].rarityOverride = sd.weaponSlot ? draftRarityOverride : null;
      selection[slotKey].enchantId = draftEnchantId || null;
      selection[slotKey].augmentId = draftAugmentId || null;
      selection[slotKey].flawless = false;

      if (slotKey === "arsenal" && prevId && prevId !== it.id) {
        selection.arsenal.pickSkill1 = null;
        selection.arsenal.pickSkill2 = null;
      }
      clampArsenalSkillPicks();

      if (slotKey === "mainHand" && weaponOccupiesBothHands(it.type)) {
        selection.offHand.item = null;
        selection.offHand.rarityOverride = null;
        selection.offHand.stars = 0;
        selection.offHand.enchantId = null;
        selection.offHand.augmentId = null;
        selection.offHand.flawless = false;
      }
      closeModal();
      onEquipped();
    }

    inpSearch.addEventListener("input", refreshGrid);
    selRarityFilter.addEventListener("change", refreshGrid);
    if (chkOffhandCompatible) {
      chkOffhandCompatible.addEventListener("change", refreshGrid);
    }
    inpIlvl.addEventListener("input", () => {
      persistModalFreeIlvlFromSlider();
      updateModalGridStats();
      updatePreview();
    });

    overlay.querySelector('[data-action="close"]').addEventListener("click", closeModal);
    overlay.querySelector('[data-action="cancel"]').addEventListener("click", closeModal);
    overlay.querySelector('[data-action="clear"]').addEventListener("click", () => {
      const cl = getCharLevelFn();
      if (slotKey === "arsenal") {
        clearArsenalSlot(cl);
      } else {
        selection[slotKey].item = null;
        selection[slotKey].ilvl = cl;
        selection[slotKey].rarityOverride = null;
        selection[slotKey].stars = 0;
        selection[slotKey].enchantId = null;
        selection[slotKey].augmentId = null;
        selection[slotKey].flawless = false;
      }
      closeModal();
      onEquipped();
    });
    overlay.querySelector('[data-action="equip"]').addEventListener("click", equipSelected);

    overlay.addEventListener("click", (e) => {
      if (e.target === overlay) closeModal();
    });

    overlay.addEventListener("keydown", (e) => {
      if (e.key === "Escape") closeModal();
    });

    refreshGrid();
    rebuildModalSlotOpts();
    updatePreview();

    setTimeout(() => inpSearch.focus(), 50);
  }

  function enchantItemsForSlot(slotKey) {
    const cat = slotEnchantCategory(slotKey);
    if (!cat) return [];
    return itemLines
      .filter((r) => itemTypeAncestorIds(r.type).includes(cat))
      .filter((r) => itemHasDisplayName(r))
      .sort(sortItemsByRarityDescThenId);
  }

  /**
   * @param {object} sd slot def
   * @param {HTMLElement} parentEl
   * @param {(inp: HTMLInputElement) => number} getCharLevelFn
   * @param {{ openItemModal: (key: string) => void, refresh: () => void }} handlers
   * @param {() => string} [getClassIdFn] — forwarded into **`simulateFlatTotals`** opts as **`viewerClassId`** (reserved; aptitude rows are not filtered by class — matches **`generateItemAffixes`**).
   */
  function renderSlotCard(sd, parentEl, getCharLevelFn, handlers, getClassIdFn) {
    const sel = selection[sd.key];
    const it = sel.item;
    const charLevel = typeof getCharLevelFn === "function" ? getCharLevelFn() : CHAR_LEVEL_DEFAULT;
    const classId = typeof getClassIdFn === "function" ? getClassIdFn() : "";
    const inactiveReason = slotInactiveReason(sd, sel, classId, charLevel, selection);
    const lockedEmptyReason =
      !it && sd.weaponRole === "arsenal" && charLevel < ARSENAL_UNLOCK_LEVEL
        ? `Unlocks at level ${ARSENAL_UNLOCK_LEVEL}`
        : "";
    let ilvl = sel.ilvl != null ? sel.ilvl : charLevel;
    if (it && itemFactionIsCraft(it)) {
      const fx = defaultGearPlannerTierForItem(it);
      if (fx != null) ilvl = fx;
    }

    const wrap = document.createElement("div");
    wrap.className = "slot-card-wrap";

    const btn = document.createElement("button");
    btn.type = "button";
    btn.className =
      "slot-card" +
      (it ? "" : " slot-card--empty") +
      (inactiveReason || lockedEmptyReason ? " slot-card--inactive" : "") +
      (lockedEmptyReason ? " slot-card--locked" : "");
    btn.dataset.slotKey = sd.key;
    if (inactiveReason || lockedEmptyReason) {
      btn.setAttribute("aria-disabled", "true");
      btn.title = inactiveReason || lockedEmptyReason;
    }

    const effRarity = it ? effectiveItemRarity(sel) : null;

    const craftSub = it && itemFactionIsCraft(it) ? itemCraftRecipeSubtitle(it) : "";
    const craftRow = craftSub
      ? `<div class="slot-card__drops">${escapeHtml(craftSub)}</div>`
      : "";

    const stateRow =
      inactiveReason || lockedEmptyReason
        ? `<div class="slot-card__inactive-reason">${escapeHtml(inactiveReason || lockedEmptyReason)}</div>`
        : "";
    const metaName = it
      ? `<div class="slot-card__name ${rarityTextClass(effRarity || it.rarity)}">${escapeHtml(itemDisplayName(it))}</div>
         ${craftRow}
         <div class="slot-card__sub">Level ${ilvl}${
             itemFactionIsCraft(it)
               ? ` <span class="slot-card__level-fixed" title="Craft items use a fixed required level">(fixed)</span>`
               : ""
           }</div>
         ${stateRow}`
      : `<div class="slot-card__hint">${escapeHtml(
          lockedEmptyReason || "Click to choose an item…"
        )}</div>`;

    btn.innerHTML = `
      <div class="slot-card__label">${escapeHtml(sd.label)}</div>
      <div class="slot-card__body">
        <div class="slot-card__icon-wrap"><div class="slot-card__icon-inner"></div></div>
        <div class="slot-card__meta">
          ${metaName}
        </div>
      </div>
    `;

    const iconWrap = btn.querySelector(".slot-card__icon-wrap");
    const iconInner = btn.querySelector(".slot-card__icon-inner");
    applySlotRarityFrame(iconWrap, it ? effRarity || it.rarity : "Common");
    if (it) {
      mountLootIcon(iconInner, it.gfx, "");
    } else if (!SLOT_KEYS_NO_EMPTY_ICON.has(sd.key)) {
      const emptyGfx = SLOT_EMPTY_GFX[sd.key];
      if (emptyGfx) mountAtlasIcon(iconInner, emptyGfx, 44);
      else mountLootIcon(iconInner, null, "");
    }

    function selForTooltip() {
      const cid = getClassIdFn ? getClassIdFn() : "";
      return cid ? { ...sel, viewerClassId: cid } : sel;
    }

    if (it) {
      btn.addEventListener("mouseenter", () => {
        showGearPlannerTooltip(btn, buildSlotCardTooltipHtml(selForTooltip(), sd, ilvl), {
          decorate: (tip) => {
            const iw = tip.querySelector(".gp-tooltip__icon");
            if (iw) mountLootIcon(iw, it.gfx, "");
          },
        });
      });
      btn.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
      btn.addEventListener("focus", () => {
        showGearPlannerTooltip(btn, buildSlotCardTooltipHtml(selForTooltip(), sd, ilvl), {
          decorate: (tip) => {
            const iw = tip.querySelector(".gp-tooltip__icon");
            if (iw) mountLootIcon(iw, it.gfx, "");
          },
        });
      });
      btn.addEventListener("blur", scheduleHideGearPlannerTooltip);
    }

    btn.addEventListener("click", () => {
      if (lockedEmptyReason) return;
      handlers.openItemModal(sd.key);
    });

    wrap.appendChild(btn);

    parentEl.appendChild(wrap);
  }

  /**
   * Main hand + weapon skill strip + off-hand + arsenal pair (column 3).
   * **`getCombatSnapshotForSkills`** supplies combat ctx for tooltips / arsenal pick modal (must stay fresh across foe & level changes).
   */
  function renderWeaponColumn(parentEl, getCharLevelFn, handlers, getClassIdFn, getCombatSnapshotForSkills) {
    const mainSd = SLOT_DEFS.find((s) => s.key === "mainHand");
    const offSd = SLOT_DEFS.find((s) => s.key === "offHand");
    const arsSd = SLOT_DEFS.find((s) => s.key === "arsenal");

    const wrap = document.createElement("div");
    wrap.className = "slot-grid__weapon-stack";

    const mainBlock = document.createElement("div");
    mainBlock.className = "slot-weapon-main";
    renderSlotCard(mainSd, mainBlock, getCharLevelFn, handlers, getClassIdFn);

    const strip = document.createElement("div");
    strip.className = "slot-weapon-skills";
    strip.setAttribute("role", "group");
    strip.setAttribute("aria-label", "Main-hand weapon skills");
    const mh = selection.mainHand && selection.mainHand.item;
    const curClassId = typeof getClassIdFn === "function" ? getClassIdFn() : "";
    const curLevel = typeof getCharLevelFn === "function" ? getCharLevelFn() : CHAR_LEVEL_DEFAULT;
    const mainActive =
      mh && mainSd && slotSelectionIsActive(mainSd, selection.mainHand, curClassId, curLevel, selection);
    if (mainActive) {
      const layout = weaponSkillStripLayout(mh);
      for (let i = 0; i < layout.length; i++) {
        const sid = layout[i].id;
        const skRow = skillById[sid];
        const cell = document.createElement("button");
        cell.type = "button";
        cell.className =
          "slot-weapon-skills__cell " +
          (layout[i].passive ? "slot-weapon-skills__cell--passive gp-skill-icon--passive" : "gp-skill-icon--active");
        cell.setAttribute(
          "aria-label",
          [skillDisplayName(skRow) || sid, skillTimingMetaTextJoined(skRow)].filter(Boolean).join(", ")
        );
        const passive = !!layout[i].passive;
        const gfx = skRow && skRow.gfx ? skRow.gfx : null;
        cell.addEventListener("mouseenter", () => {
          const ctx = getCombatSnapshotForSkills();
          const tipCtx = combatCtxWithWeaponSlotPower(ctx, "mainHand");
          const tipHtml = buildWeaponSkillTooltipHtml(skRow, sid, ctx, {
            passive,
            weaponSlotKeyForPower: "mainHand",
          });
          showGearPlannerTooltip(cell, tipHtml, {
            className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill",
            decorate: (tip) => {
              decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, skRow, sid, tipCtx, gfx);
            },
          });
        });
        cell.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
        cell.addEventListener("focus", () => {
          const ctx = getCombatSnapshotForSkills();
          const tipCtx = combatCtxWithWeaponSlotPower(ctx, "mainHand");
          const tipHtml = buildWeaponSkillTooltipHtml(skRow, sid, ctx, {
            passive,
            weaponSlotKeyForPower: "mainHand",
          });
          showGearPlannerTooltip(cell, tipHtml, {
            className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill",
            decorate: (tip) => {
              decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, skRow, sid, tipCtx, gfx);
            },
          });
        });
        cell.addEventListener("blur", scheduleHideGearPlannerTooltip);
        mountAtlasIcon(cell, gfx, 34);
        strip.appendChild(cell);
      }
    }
    if (!strip.childNodes.length) {
      strip.innerHTML = `<span class="slot-weapon-skills__placeholder">Weapon skills appear here</span>`;
    }

    const offWrap = document.createElement("div");
    offWrap.className = "slot-weapon-off";
    const mainIt = selection.mainHand && selection.mainHand.item;
    if (mainActive && mainIt && weaponOccupiesBothHands(mainIt.type)) {
      const blocked = document.createElement("div");
      blocked.className = "slot-card slot-card--blocked";
      blocked.innerHTML = `
        <div class="slot-card__label">${escapeHtml(offSd.label)}</div>
        <div class="slot-card__body">
          <div class="slot-card__meta">
            <div class="slot-card__hint">Blocked — two-handed weapon equipped</div>
          </div>
        </div>`;
      offWrap.appendChild(blocked);
    } else {
      renderSlotCard(offSd, offWrap, getCharLevelFn, handlers, getClassIdFn);
    }

    const arsenalRow = document.createElement("div");
    arsenalRow.className = "slot-grid__arsenal-pair";
    const arsSlots = document.createElement("div");
    arsSlots.className = "slot-grid__arsenal-slots";
    renderSlotCard(arsSd, arsSlots, getCharLevelFn, handlers, getClassIdFn);
    arsenalRow.appendChild(arsSlots);

    const arsWep = selection.arsenal && selection.arsenal.item;
    const arsenalActive =
      arsWep && arsSd && slotSelectionIsActive(arsSd, selection.arsenal, curClassId, curLevel, selection);
    if (arsenalActive) {
      const pickIds = weaponSkillPickIds(arsWep);
      const picksWrap = document.createElement("div");
      picksWrap.className = "slot-grid__arsenal-picks";
      const hint = document.createElement("p");
      hint.className = "slot-grid__arsenal-picks__hint";
      hint.textContent = "Two ability slots — click a slot to choose from this weapon’s skills.";
      picksWrap.appendChild(hint);

      const slotsRow = document.createElement("div");
      slotsRow.className = "slot-grid__arsenal-pick-slots";
      slotsRow.setAttribute("role", "group");
      slotsRow.setAttribute("aria-label", "Arsenal weapon abilities");

      const arSel = selection.arsenal;

      function renderArsenalPickSlot(slotNum) {
        const sid = slotNum === 1 ? arSel.pickSkill1 : arSel.pickSkill2;
        const sk = sid ? skillById[sid] : null;
        const slotBtn = document.createElement("button");
        slotBtn.type = "button";
        slotBtn.className =
          "slot-arsenal-pick-slot" + (slotNum === 1 ? " slot-arsenal-pick-slot--1" : " slot-arsenal-pick-slot--2");
        slotBtn.setAttribute(
          "aria-label",
          `Arsenal ability slot ${slotNum}${
            sid
              ? ` — ${[skillDisplayName(sk) || sid, skillTimingMetaTextJoined(sk)].filter(Boolean).join(", ")}`
              : ", empty"
          }`
        );

        const iconWrap = document.createElement("div");
        iconWrap.className =
          "slot-arsenal-pick-slot__icon " +
          (sk && skillIconIsPassiveFrame(sk) ? "gp-skill-icon--passive" : "gp-skill-icon--active");
        if (sk && sk.gfx) {
          mountAtlasIcon(iconWrap, sk.gfx, 36);
        } else {
          iconWrap.innerHTML = `<span class="slot-arsenal-pick-slot__empty-icon" aria-hidden="true">+</span>`;
        }

        const textCol = document.createElement("div");
        textCol.className = "slot-arsenal-pick-slot__text";
        const lab = document.createElement("div");
        lab.className = "slot-arsenal-pick-slot__label";
        lab.textContent = `Ability ${slotNum}`;
        const nameEl = document.createElement("div");
        nameEl.className = "slot-arsenal-pick-slot__name";
        nameEl.textContent = sk ? skillDisplayName(sk) || sid : "Choose…";

        textCol.appendChild(lab);
        textCol.appendChild(nameEl);
        if (sk && skillTimingMetaTextJoined(sk)) {
          const cdEl = document.createElement("div");
          cdEl.className = "slot-arsenal-pick-slot__cd";
          cdEl.textContent = skillTimingMetaTextJoined(sk);
          textCol.appendChild(cdEl);
        }

        slotBtn.appendChild(iconWrap);
        slotBtn.appendChild(textCol);

        if (sk && sid) {
          const passivePick = skillIconIsPassiveFrame(sk);
          const gfxTip = sk.gfx || null;
          slotBtn.addEventListener("mouseenter", () => {
            const ctx = getCombatSnapshotForSkills();
            const tipCtx = combatCtxWithWeaponSlotPower(ctx, "arsenal");
            const tipHtml = buildWeaponSkillTooltipHtml(sk, sid, ctx, {
            passive: passivePick,
            weaponSlotKeyForPower: "arsenal",
          });
            showGearPlannerTooltip(slotBtn, tipHtml, {
              className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill",
              decorate: (tip) => {
                decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, sk, sid, tipCtx, gfxTip);
              },
            });
          });
          slotBtn.addEventListener("mouseleave", scheduleHideGearPlannerTooltip);
          slotBtn.addEventListener("focus", () => {
            const ctx = getCombatSnapshotForSkills();
            const tipCtx = combatCtxWithWeaponSlotPower(ctx, "arsenal");
            const tipHtml = buildWeaponSkillTooltipHtml(sk, sid, ctx, {
            passive: passivePick,
            weaponSlotKeyForPower: "arsenal",
          });
            showGearPlannerTooltip(slotBtn, tipHtml, {
              className: "gp-slot-tooltip gp-slot-tooltip--weapon-skill",
              decorate: (tip) => {
                decorateGearPlannerSkillTooltipWithDamageBreakdown(tip, sk, sid, tipCtx, gfxTip);
              },
            });
          });
          slotBtn.addEventListener("blur", scheduleHideGearPlannerTooltip);
        }

        slotBtn.addEventListener("click", () => {
          openArsenalSkillPickModal(
            slotNum,
            pickIds,
            arSel,
            arsWep,
            getCombatSnapshotForSkills(),
            () => handlers.refresh()
          );
        });

        return slotBtn;
      }

      slotsRow.appendChild(renderArsenalPickSlot(1));
      slotsRow.appendChild(renderArsenalPickSlot(2));
      picksWrap.appendChild(slotsRow);
      arsenalRow.appendChild(picksWrap);
    } else if (curLevel < ARSENAL_UNLOCK_LEVEL) {
      const locked = document.createElement("div");
      locked.className = "slot-grid__arsenal-locked";
      locked.textContent = `Arsenal unlocks at level ${ARSENAL_UNLOCK_LEVEL}. Equipped arsenal weapons are disabled until then.`;
      arsenalRow.appendChild(locked);
    }

    wrap.appendChild(mainBlock);
    wrap.appendChild(strip);
    wrap.appendChild(offWrap);
    wrap.appendChild(arsenalRow);
    parentEl.appendChild(wrap);
  }

  function syncStatusBuffStackRowsInTextCol(textCol) {
    if (!textCol) return;
    textCol.querySelectorAll(".gp-char-skill__stack-row").forEach((stackRow) => {
      const statusId = stackRow.getAttribute("data-status-id");
      if (!statusId) return;
      const st = skillById[statusId];
      if (!st) return;
      const cur = statusPreviewStackCount(st);
      const inp = stackRow.querySelector(".gp-char-skill__status-stack-input");
      if (inp) inp.value = String(cur);
      stackRow.querySelectorAll(".gp-char-skill__rank-btn").forEach((sb) => {
        const sv = parseInt(sb.textContent, 10);
        if (!Number.isFinite(sv)) return;
        const on = sv === cur;
        sb.setAttribute("aria-pressed", on ? "true" : "false");
        sb.classList.toggle("gp-char-skill__rank-btn--active", on);
      });
    });
  }

  function appendFinisherComboPointRow(textCol) {
    if (!textCol) return;
    const maxCp = finisherMaxComboPoints();
    const cur = previewFinisherComboPointsUsed();
    const row = document.createElement("div");
    row.className = "gp-char-skill__rank-row gp-char-skill__combo-row";
    row.setAttribute("role", "group");
    row.setAttribute("aria-label", "Finisher combo points for damage preview");
    const lab = document.createElement("span");
    lab.className = "gp-char-skill__rank-lab";
    lab.textContent = `Combo pts (max ${maxCp})`;
    row.appendChild(lab);
    for (let cp = 0; cp <= maxCp; cp++) {
      const btn = document.createElement("button");
      btn.type = "button";
      btn.className = "gp-char-skill__rank-btn";
      btn.textContent = String(cp);
      btn.title =
        cp === 0
          ? "Finisher with no combo points spent (+0% from combo)."
          : `Spend ${cp} combo point(s) — +${Math.round(cp * 30)}% damage (30% per point).`;
      btn.setAttribute("aria-pressed", cp === cur ? "true" : "false");
      if (cp === cur) btn.classList.add("gp-char-skill__rank-btn--active");
      btn.addEventListener("click", (ev) => {
        ev.preventDefault();
        if (cp === maxCp) plannerDamagePreviewSettings.previewFinisherComboPoints = null;
        else plannerDamagePreviewSettings.previewFinisherComboPoints = cp;
        if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      row.appendChild(btn);
    }
    const descEl = textCol.querySelector(".gp-char-skill__desc");
    if (descEl && descEl.parentNode === textCol) descEl.insertAdjacentElement("afterend", row);
    else textCol.appendChild(row);
  }

  function appendUrgeFinisherStreakRow(textCol, sk) {
    if (!textCol) return;
    if (!sk || selectedClassSkillMasteryId(URGE_TO_KILL_HOST_ID, sk) !== URGE_TO_KILL_M1_MASTERY_ID) return;
    const row = document.createElement("div");
    row.className = "gp-char-skill__rank-row gp-char-skill__urge-row";
    row.setAttribute("role", "group");
    row.setAttribute("aria-label", "Consecutive Finisher hits for Urge to Kill");
    const lab = document.createElement("span");
    lab.className = "gp-char-skill__rank-lab";
    lab.textContent = "Finisher streak";
    row.appendChild(lab);
    const inp = document.createElement("input");
    inp.type = "number";
    inp.min = "0";
    inp.max = "99";
    inp.step = "1";
    inp.className = "gp-char-skill__urge-input";
    inp.value = String(previewUrgeFinisherStreakCount());
    inp.title = "Each consecutive Finisher adds +10% to the next Finisher when Urge to Kill affects other skills.";
    inp.addEventListener("change", () => {
      const n = parseInt(inp.value, 10);
      plannerDamagePreviewSettings.previewUrgeFinisherStreak =
        Number.isFinite(n) && n > 0 ? clamp(Math.floor(n), 0, 99) : 0;
      if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
    });
    row.appendChild(inp);
    textCol.appendChild(row);
  }

  /** **Surge of Violence**: preview assumes +25% crit chance on **Raging Smash** — toggle on Final Combo Attack cards only. */
  function appendSurgeViolenceFinalComboRow(textCol, sid) {
    if (!textCol || typeof sid !== "string" || !sid) return;
    if (!skillIsFinalComboAttackId(sid)) return;
    if (warriorTalentRank(WARRIOR_TALENT_SURGE_OF_VIOLENCE_ID) < 1) return;
    const row = document.createElement("div");
    row.className = "gp-char-skill__surge-row";
    row.setAttribute("role", "group");
    row.setAttribute("aria-label", "Surge of Violence — Raging Smash crit preview");
    const lab = document.createElement("label");
    lab.className = "gp-char-skill__surge-row__label";
    const inp = document.createElement("input");
    inp.type = "checkbox";
    inp.checked = plannerDamagePreviewSettings.previewSurgeViolenceBoost === true;
    inp.title =
      "When checked, damage previews assume Surge of Violence is active: +25% critical strike chance on Raging Smash.";
    inp.addEventListener("change", () => {
      plannerDamagePreviewSettings.previewSurgeViolenceBoost = inp.checked;
      if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
    });
    const span = document.createElement("span");
    span.className = "gp-char-skill__surge-row__txt";
    span.textContent = "Surge of Violence (+25% crit chance on Raging Smash preview)";
    lab.appendChild(inp);
    lab.appendChild(span);
    row.appendChild(lab);
    textCol.appendChild(row);
  }

  function appendStatusBuffStackRowsToSkillCard(textCol, statusSk, hostSk) {
    if (!textCol || !statusSk || !statusSk.id) return;
    if (!skillIsPreviewableStackingStatusBuff(statusSk)) return;
    const statusId = statusSk.id;
    const requiredMid = statusPreviewControlRequiredMasteryId(statusSk);
    if (requiredMid) {
      const host = hostSk || statusSk;
      if (!host || selectedClassSkillMasteryId(host.id, host) !== requiredMid) return;
    }
    const maxS = skillStatusMaxStacksFromProps(statusSk);
    const cur = statusPreviewStackCount(statusSk);
    const stackRow = document.createElement("div");
    stackRow.className = "gp-char-skill__rank-row gp-char-skill__stack-row";
    stackRow.setAttribute("data-status-id", statusId);
    stackRow.setAttribute("role", "group");
    stackRow.setAttribute("aria-label", "Damage preview: status buff stacks");
    const stackLab = document.createElement("span");
    stackLab.className = "gp-char-skill__rank-lab";
    stackLab.textContent = "Buff stacks";
    stackRow.appendChild(stackLab);
    if (statusId === CRUSADER_STATUS_ID) {
      const host = skillById[CRUSADER_HOST_ID];
      if (!host || selectedClassSkillMasteryId(CRUSADER_HOST_ID, host) !== CRUSADER_M2_MASTERY_ID) return;
      stackLab.textContent = "Prayers judged";
      const inp = document.createElement("input");
      inp.type = "number";
      inp.min = "0";
      inp.max = String(maxS);
      inp.step = "1";
      inp.className = "gp-char-skill__urge-input gp-char-skill__status-stack-input";
      inp.value = String(cur);
      inp.title = "Righteousness: each judged Prayer increases Crusader's buff effects by 1%.";
      inp.addEventListener("change", () => {
        const n = parseInt(inp.value, 10);
        const next = Number.isFinite(n) && n > 0 ? clamp(Math.floor(n), 0, maxS) : 0;
        if (!plannerDamagePreviewSettings.previewStatusStacksBySkillId || typeof plannerDamagePreviewSettings.previewStatusStacksBySkillId !== "object") {
          plannerDamagePreviewSettings.previewStatusStacksBySkillId = {};
        }
        if (next > 0) plannerDamagePreviewSettings.previewStatusStacksBySkillId[statusId] = next;
        else delete plannerDamagePreviewSettings.previewStatusStacksBySkillId[statusId];
        inp.value = String(next);
        if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      stackRow.appendChild(inp);
      textCol.appendChild(stackRow);
      return;
    }
    for (let sv = 0; sv <= maxS; sv++) {
      const sb = document.createElement("button");
      sb.type = "button";
      sb.className = "gp-char-skill__rank-btn";
      sb.textContent = String(sv);
      sb.title =
        sv === 0
          ? "Turn this status buff off for damage previews and sheet totals."
          : sv === maxS
            ? `Full stacks (${maxS}) — default. Adds this row's flat affixes × ${maxS} to previews.`
            : `Assume ${sv} stack(s) for damage previews (max ${maxS}).`;
      sb.setAttribute("aria-pressed", sv === cur ? "true" : "false");
      if (sv === cur) sb.classList.add("gp-char-skill__rank-btn--active");
      sb.addEventListener("click", (ev) => {
        ev.preventDefault();
        if (!plannerDamagePreviewSettings.previewStatusStacksBySkillId || typeof plannerDamagePreviewSettings.previewStatusStacksBySkillId !== "object") {
          plannerDamagePreviewSettings.previewStatusStacksBySkillId = {};
        }
        if (sv === maxS) delete plannerDamagePreviewSettings.previewStatusStacksBySkillId[statusId];
        else plannerDamagePreviewSettings.previewStatusStacksBySkillId[statusId] = sv;
        if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      stackRow.appendChild(sb);
    }
    textCol.appendChild(stackRow);
  }

  function appendTideRisingUppercutStackRow(textCol, sid) {
    if (!textCol || sid !== FISTS_TIDE_RISING_UPPERCUT_ID) return;
    const statusSk = skillById[FISTS_TIDE_RISING_STATUS_ID];
    if (!statusSk) return;
    const maxS = skillStatusMaxStacksFromProps(statusSk) || 10;
    const cur = statusPreviewStackCount(statusSk);
    const stackRow = document.createElement("div");
    stackRow.className = "gp-char-skill__rank-row gp-char-skill__stack-row";
    stackRow.setAttribute("data-status-id", FISTS_TIDE_RISING_STATUS_ID);
    stackRow.setAttribute("role", "group");
    stackRow.setAttribute("aria-label", "Tide Rising stacks for damage preview");
    const stackLab = document.createElement("span");
    stackLab.className = "gp-char-skill__rank-lab";
    stackLab.textContent = "Tide stacks";
    stackRow.appendChild(stackLab);
    for (let sv = 0; sv <= maxS; sv++) {
      const sb = document.createElement("button");
      sb.type = "button";
      sb.className = "gp-char-skill__rank-btn";
      sb.textContent = String(sv);
      sb.title =
        sv === 0
          ? "No Tide Rising stacks."
          : `Assume ${sv} Tide Rising stack(s): damage is multiplied by ${formatMultiplierLabel(1 + 0.5 * sv)} before rounding.`;
      sb.setAttribute("aria-pressed", sv === cur ? "true" : "false");
      if (sv === cur) sb.classList.add("gp-char-skill__rank-btn--active");
      sb.addEventListener("click", (ev) => {
        ev.preventDefault();
        if (!plannerDamagePreviewSettings.previewStatusStacksBySkillId || typeof plannerDamagePreviewSettings.previewStatusStacksBySkillId !== "object") {
          plannerDamagePreviewSettings.previewStatusStacksBySkillId = {};
        }
        if (sv === maxS) delete plannerDamagePreviewSettings.previewStatusStacksBySkillId[FISTS_TIDE_RISING_STATUS_ID];
        else plannerDamagePreviewSettings.previewStatusStacksBySkillId[FISTS_TIDE_RISING_STATUS_ID] = sv;
        if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      stackRow.appendChild(sb);
    }
    textCol.appendChild(stackRow);
  }

  function skillShowsGlobalBuffCornerToggle(sk, sid, opts) {
    const o = opts || {};
    if (!sk || typeof sid !== "string" || !sid) return false;
    if (sid === BLADELEAF_SWARMSTRIKE_HOST_ID) return true;
    if (sid === BOW_THRILL_OF_THE_HUNTER_ID) return true;
    if (sid === STAFF_PYROCLASM_ID) return true;
    if (skillIconIsPassiveFrame(sk)) {
      if (skillDamageScriptConditionalsFromSkill(sk).length > 0) return true;
      if (sid === DA_WATER_PASSIVE_ID) return true;
      return false;
    }
    if (o.weaponSlotKey) return false;
    return classSkillIsNonDamageBuffContributor(sk);
  }

  function syncGlobalBuffCornerToggleUi(card, sid) {
    const tg = card && card.querySelector(".gp-char-skill__passive-corner-toggle");
    if (!tg || !sid) return;
    const on = passiveScriptGlobalMultApplies(sid);
    tg.setAttribute("aria-checked", on ? "true" : "false");
    card.classList.toggle("gp-char-skill--passive-card", true);
    card.classList.toggle("gp-char-skill--passive-off", !on);
    tg.title = on
      ? "Affects other skills (on). Click to disable — greys this card and removes its buff from other skills’ damage previews."
      : "Affects other skills (off). Click to enable — this skill will apply to other skills’ previews when its toggles are on.";
    tg.setAttribute(
      "aria-label",
      on
        ? "Skill applies to other skills’ damage previews, on. Press to turn off."
        : "Skill applies to other skills’ damage previews, off. Press to turn on."
    );
  }

  function appendGlobalBuffCornerToggle(card, sid) {
    if (!card || !sid) return;
    let tg = card.querySelector(".gp-char-skill__passive-corner-toggle");
    if (!tg) {
      tg = document.createElement("button");
      tg.type = "button";
      tg.className = "gp-char-skill__passive-corner-toggle";
      tg.setAttribute("role", "switch");
      tg.addEventListener("click", (ev) => {
        ev.preventDefault();
        passiveScriptGlobalMultSet(sid, !passiveScriptGlobalMultApplies(sid));
        syncGlobalBuffCornerToggleUi(card, sid);
        if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      card.appendChild(tg);
    }
    syncGlobalBuffCornerToggleUi(card, sid);
  }

  function appendSkillCard(container, sk, sid, metaUnlock, combatCtx, weaponEffectiveRank, weaponSlotKeyForPower) {
    const card = document.createElement("div");
    card.className = "gp-char-skill";
    if (typeof sid === "string" && sid) card.setAttribute("data-skill-id", sid);
    if (weaponSlotKeyForPower) card.setAttribute("data-weapon-slot", weaponSlotKeyForPower);
    const top = document.createElement("div");
    top.className = "gp-char-skill__top";
    const iconWrap = document.createElement("div");
    iconWrap.className =
      "gp-char-skill__icon-wrap " +
      (sk && skillIconIsPassiveFrame(sk) ? "gp-skill-icon--passive" : "gp-skill-icon--active");
    mountAtlasIcon(iconWrap, sk && sk.gfx ? sk.gfx : null, 44);
    const textCol = document.createElement("div");
    textCol.className = "gp-char-skill__text";
    const title = document.createElement("div");
    title.className = "gp-char-skill__title";
    const unlock = metaUnlock || "";
    title.innerHTML = `${escapeHtml(skillDisplayName(sk) || sid)}<span class="gp-char-skill__meta">${escapeHtml(
      unlock + skillTimingMetaInline(sk)
    )}</span>`;
    const desc = document.createElement("div");
    desc.className = "gp-char-skill__desc";
    const ctxForSkill =
      weaponSlotKeyForPower && combatCtx
        ? combatCtxWithWeaponSlotPower(combatCtx, weaponSlotKeyForPower)
        : combatCtx;
    const effWeaponRank =
      weaponSlotKeyForPower && sid
        ? weaponSkillDisplayRank(sid)
        : weaponEffectiveRank != null && Number.isFinite(weaponEffectiveRank)
          ? Math.max(1, Math.floor(weaponEffectiveRank))
          : undefined;
    if (weaponSlotKeyForPower && sid) {
      const rankRow = document.createElement("div");
      rankRow.className = "gp-char-skill__rank-row";
      rankRow.setAttribute("role", "group");
      rankRow.setAttribute("aria-label", "Weapon skill preview rank");
      const rankLab = document.createElement("span");
      rankLab.className = "gp-char-skill__rank-lab";
      rankLab.textContent = "Rank";
      rankRow.appendChild(rankLab);
      for (let rv = 1; rv <= 3; rv++) {
        const rb = document.createElement("button");
        rb.type = "button";
        rb.className = "gp-char-skill__rank-btn";
        rb.textContent = String(rv);
        rb.title = `Preview damage and description at rank ${rv}`;
        rb.setAttribute("aria-pressed", rv === effWeaponRank ? "true" : "false");
        if (rv === effWeaponRank) rb.classList.add("gp-char-skill__rank-btn--active");
        rb.addEventListener("click", (ev) => {
          ev.preventDefault();
          weaponSkillPanelRankById[sid] = rv;
          if (typeof plannerRefreshSkillsPanelsHook === "function") plannerRefreshSkillsPanelsHook();
          else if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
        });
        rankRow.appendChild(rb);
      }
      textCol.appendChild(title);
      textCol.appendChild(rankRow);
    } else {
      textCol.appendChild(title);
    }
    const isPassiveCard = !!(sk && skillIconIsPassiveFrame(sk));
    desc.innerHTML = skillDescHtml(sk, ctxForSkill, effWeaponRank);
    textCol.appendChild(desc);
    if (!weaponSlotKeyForPower && sid === FINISHER_SKILL_ID) appendFinisherComboPointRow(textCol);
    if (!weaponSlotKeyForPower && !isPassiveCard && typeof sid === "string" && sid) {
      const masteryEntries = skillMasteryEntries(sk);
      if (masteryEntries.length) {
        const selectedMid = selectedClassSkillMasteryId(sid, sk);
        const masteryWrap = document.createElement("div");
        masteryWrap.className = "gp-char-skill__mastery";
        masteryWrap.setAttribute("role", "group");
        masteryWrap.setAttribute("aria-label", "Skill rune");
        const masteryHd = document.createElement("div");
        masteryHd.className = "gp-char-skill__mastery-hd";
        masteryHd.textContent = "Rune";
        masteryWrap.appendChild(masteryHd);
        const runeRow = document.createElement("div");
        runeRow.className = "gp-char-skill__mastery-runes";
        for (let mi = 0; mi < masteryEntries.length; mi++) {
          const entry = masteryEntries[mi];
          const rb = document.createElement("button");
          rb.type = "button";
          rb.className = "gp-char-skill__mastery-rune";
          rb.dataset.masteryId = entry.id;
          rb.title = skillMasteryDisplayName(entry) || entry.id;
          rb.setAttribute("aria-pressed", entry.id === selectedMid ? "true" : "false");
          if (entry.id === selectedMid) rb.classList.add("gp-char-skill__mastery-rune--active");
          const icon = document.createElement("span");
          icon.className = "gp-char-skill__mastery-rune__icon";
          if (entry.gfx) mountAtlasIcon(icon, entry.gfx, 40);
          rb.appendChild(icon);
          rb.addEventListener("click", (ev) => {
            ev.preventDefault();
            const current = selectedClassSkillMasteryId(sid, sk);
            if (entry.id === current) setClassSkillMasteryId(sid, null);
            else setClassSkillMasteryId(sid, entry.id);
            if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
          });
          runeRow.appendChild(rb);
        }
        masteryWrap.appendChild(runeRow);
        const activeEntry = selectedMid ? masteryEntryById(sk, selectedMid) : null;
        const masteryDesc = document.createElement("div");
        masteryDesc.className = "gp-char-skill__mastery-desc";
        if (activeEntry) {
          masteryDesc.innerHTML = `<span class="gp-char-skill__mastery-desc-name">${escapeHtml(
            skillMasteryDisplayName(activeEntry)
          )}</span> ${masteryDescHtml(activeEntry, sk, ctxForSkill)}`;
        } else {
          masteryDesc.innerHTML =
            `<span class="gp-muted">No rune selected — click a rune to apply its effect to damage previews.</span>`;
        }
        masteryWrap.appendChild(masteryDesc);
        syncMysticEmpowermentM2BuffChoice(masteryWrap, sid, sk, ctxForSkill);
        textCol.appendChild(masteryWrap);
      }
    }
    const scriptClauses =
      sk && typeof sid === "string" && sid ? skillDamageScriptConditionalsFromSkill(sk) : [];
    if (sk && typeof sid === "string" && sid) {
      if (scriptClauses.length) {
        const scriptWrap = document.createElement("div");
        scriptWrap.className = "gp-char-skill__script";
        const scriptHd = document.createElement("div");
        scriptHd.className = "gp-char-skill__script-hd";
        scriptHd.textContent = "Conditionals";
        const scriptList = document.createElement("div");
        scriptList.className = "gp-char-skill__script-list";
        for (let sci = 0; sci < scriptClauses.length; sci++) {
          const c = scriptClauses[sci];
          const lab = document.createElement("label");
          lab.className = "gp-char-skill__script-pill";
          lab.title = c.label;
          const inp = document.createElement("input");
          inp.type = "checkbox";
          inp.checked = skillScriptAssumptionIsEnabled(sid, c.id);
          inp.addEventListener("change", () => {
            skillScriptAssumptionSet(sid, c.id, inp.checked);
            if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
          });
          const shell = document.createElement("span");
          shell.className = "gp-char-skill__script-pill__shell";
          const span = document.createElement("span");
          span.className = "gp-char-skill__script-pill__txt";
          span.textContent = c.pill || c.varKey || "Bonus";
          shell.appendChild(span);
          lab.appendChild(inp);
          lab.appendChild(shell);
          scriptList.appendChild(lab);
        }
        scriptWrap.appendChild(scriptHd);
        scriptWrap.appendChild(scriptList);
        textCol.appendChild(scriptWrap);
      }
      const hostStatusBuffs = previewableStatusBuffsForHostSkill(sk);
      if (hostStatusBuffs.length) {
        for (let hsi = 0; hsi < hostStatusBuffs.length; hsi++) {
          appendStatusBuffStackRowsToSkillCard(textCol, hostStatusBuffs[hsi], sk);
        }
      } else if (skillIsPreviewableStackingStatusBuff(sk)) {
        appendStatusBuffStackRowsToSkillCard(textCol, sk, sk);
      }
      appendTideRisingUppercutStackRow(textCol, sid);
      if (sid === URGE_TO_KILL_HOST_ID) appendUrgeFinisherStreakRow(textCol, sk);
      appendSurgeViolenceFinalComboRow(textCol, sid);
    }
    appendComputedSkillDamageToCard(textCol, sk, ctxForSkill);
    top.appendChild(iconWrap);
    top.appendChild(textCol);
    card.appendChild(top);
    wireCharSkillCardDamageTooltips(card, sk, sid, ctxForSkill);
    container.appendChild(card);
  }

  function renderMageConduitsPanel(container, combatCtx) {
    const charLevel = combatCtx && Number.isFinite(combatCtx.charLevel) ? combatCtx.charLevel : CHAR_LEVEL_DEFAULT;
    sanitizeMageConduitSelection(charLevel);
    const available = mageAvailableConduitSkillIds();
    const selected = mageSelectedConduitSkillIds(charLevel);
    const selectedSet = new Set(selected);
    const slots = mageConduitSlotCount(charLevel);

    const sec = document.createElement("section");
    sec.className = "gp-skills-category gp-mage-conduits";
    sec.innerHTML = `<h3 class="gp-skills-category__title">Conduits</h3>
      <p class="gp-skills-category__sub">Choose ${slots} conduit${slots === 1 ? "" : "s"} to equip. Only selected conduits affect sheet totals and damage previews.</p>`;

    const picker = document.createElement("div");
    picker.className = "gp-mage-conduits__picker";
    picker.setAttribute("role", "group");
    picker.setAttribute("aria-label", "Mage conduits");
    for (let i = 0; i < available.length; i++) {
      const sid = available[i];
      const sk = skillById[sid];
      if (!sk) continue;
      const on = selectedSet.has(sid);
      const full = !on && selected.length >= slots;
      const btn = document.createElement("button");
      btn.type = "button";
      btn.className = "gp-mage-conduit-pick";
      if (on) btn.classList.add("gp-mage-conduit-pick--active");
      btn.setAttribute("aria-pressed", on ? "true" : "false");
      btn.disabled = full;
      btn.title = full
        ? `You can equip ${slots} conduit${slots === 1 ? "" : "s"} at this level.`
        : on
          ? `Unequip ${skillDisplayName(sk) || sid}`
          : `Equip ${skillDisplayName(sk) || sid}`;
      const icon = document.createElement("span");
      icon.className = "gp-mage-conduit-pick__icon";
      mountAtlasIcon(icon, sk.gfx || null, 34);
      const txt = document.createElement("span");
      txt.className = "gp-mage-conduit-pick__text";
      txt.textContent = skillDisplayName(sk) || sid;
      btn.appendChild(icon);
      btn.appendChild(txt);
      btn.addEventListener("click", (ev) => {
        ev.preventDefault();
        setMageConduitSelected(sid, !on, charLevel);
        if (typeof plannerRefreshSkillsPanelsHook === "function") plannerRefreshSkillsPanelsHook();
        else if (typeof plannerRecomputePreviewHook === "function") plannerRecomputePreviewHook();
      });
      picker.appendChild(btn);
    }
    sec.appendChild(picker);

    const body = document.createElement("div");
    body.className = "gp-skills-category__body gp-mage-conduits__selected";
    for (let slot = 0; slot < slots; slot++) {
      const sid = selected[slot];
      const sk = sid ? skillById[sid] : null;
      if (sk) {
        appendSkillCard(body, sk, sid, "", combatCtx);
      } else {
        const empty = document.createElement("div");
        empty.className = "gp-mage-conduits__empty";
        empty.textContent = `Empty conduit slot ${slot + 1}`;
        body.appendChild(empty);
      }
    }
    sec.appendChild(body);
    container.appendChild(sec);
  }

